-- Poems batch 207
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('b84829bc-d826-45b5-b62b-5c925b74bf26','法孫天龍長老思賢請贊','釋慧開','宋','宋诗','song-poetry','','[]','咄這村僧，百拙千醜。',111,'全唐诗/poet.song.195000.json','["咄這村僧，百拙千醜。", "用處顢頇，舉止磔斗。", "秉惡毒鉗鎚，碎情塵窠臼。", "佛祖飲氣吞聲，魔外望風拱手。", "有時漢語胡言，總當談玄說妙。", "有時把拍板門槌，唱雲門曲合胡笳調。", "有時指圓覺場作牛欄，有時喚普光殿爲馬廐。", "如斯孟浪爲人，鈍置月林之後。"]'),
('478ea091-f0fc-473f-8db5-1738be88999c','日本覺心長老請贊','釋慧開','宋','宋诗','song-poetry','','[]','用迷子訣，飛紅爐雪。',60,'全唐诗/poet.song.195000.json','["用迷子訣，飛紅爐雪。", "一喝當鋒，崖崩石裂。", "化生蛇作活龍，點黄金爲生鐵。", "去縛解粘，抽釘拔楔。", "更將佛祖不傳機，此界他方俱漏泄。"]'),
('b37198bd-ab0e-4e0d-8cf4-0f93d1e99dcd','南劍州伏虎巖請師開山請贊','釋慧開','宋','宋诗','song-poetry','','[]','箇樣村僧，也甚奇怪。',70,'全唐诗/poet.song.195000.json','["箇樣村僧，也甚奇怪。", "身如椰子，膽似天大。", "蟒蛇窟裡安禪，猛虎穴中劄寨。", "無端於微塵國裡，轉大法輪，擊大法鼓。", "却向刀山劍樹上，成等正覺，弄者一解。"]'),
('c9409fba-ad6c-4fcd-b7af-7849dc1c5035','徒弟普顯請贊','釋慧開','宋','宋诗','song-poetry','','[]','形如枯木倚巖隈，不擬天庭降蟄雷。',32,'全唐诗/poet.song.195000.json','["形如枯木倚巖隈，不擬天庭降蟄雷。", "忽遇東君行正令，曇華獨顯一枝開。"]'),
('59878a79-e98c-4447-9706-2ad2554a8036','護國嗣源長老請贊','釋慧開','宋','宋诗','song-poetry','','[]','龍牀角畔，建古招提。',40,'全唐诗/poet.song.195000.json','["龍牀角畔，建古招提。", "一滴渾無，嗣曹源正派。", "寸絲不掛，付夜半伽梨。", "成家喜見破家兒。"]'),
('454ce480-c144-42ac-b4fc-0c8869666af9','徒弟普山請贊','釋慧開','宋','宋诗','song-poetry','','[]','頭髮鬔鬆，耳輪卓朔。',41,'全唐诗/poet.song.195000.json','["頭髮鬔鬆，耳輪卓朔。", "踞坐當軒，權衡在握。", "任你德山臨濟棒喝交馳，到他面前一點用不著。"]'),
('c0f1d129-90ae-4575-bd46-c3c40d6c6870','護國嗣本長老請贊','釋慧開','宋','宋诗','song-poetry','','[]','法身無相，徒更形容。',36,'全唐诗/poet.song.195000.json','["法身無相，徒更形容。", "本來面目，逼塞虛空。", "浩蕩十方能變化，行看九萬自摶風。"]'),
('ace0e9b8-151c-436b-9ac4-5cb2e3f3d9f0','辭世偈','釋慧開','宋','宋诗','song-poetry','','[]','虛空不生，虛空不滅。',20,'全唐诗/poet.song.195000.json','["虛空不生，虛空不滅。", "證得虛空，虛空不別。"]'),
('ce696612-c0af-48b4-a4d6-89fcf00ada08','播大唐辭世偈云','釋慧開','宋','宋诗','song-poetry','','[]','書偈畢跏趺而逝都知王太尉隨即敷。',16,'全唐诗/poet.song.195000.json','["書偈畢跏趺而逝都知王太尉隨即敷。"]'),
('4cae7bd2-df50-4b21-b00e-9d5c538e78a6','禪宗無門關總頌','釋慧開','宋','宋诗','song-poetry','','[]','大道無門，千差有路。',20,'全唐诗/poet.song.195000.json','["大道無門，千差有路。", "透得此關，乾坤獨步。"]'),
('83c415a4-efca-45d1-8cc3-4716212ed42c','頌古四十八首  其一','釋慧開','宋','宋诗','song-poetry','','[]','狗子佛性，全提正令。',20,'全唐诗/poet.song.195000.json','["狗子佛性，全提正令。", "纔涉有無，喪身失命。"]'),
('d4754df0-41df-4e9b-a715-f28dd7cd50cc','頌古四十八首  其二','釋慧開','宋','宋诗','song-poetry','','[]','不落不昧，兩采一賽。',20,'全唐诗/poet.song.195000.json','["不落不昧，兩采一賽。", "不昧不落，千錯萬錯。"]'),
('a9eebdcd-d8ad-4564-a6a5-a0905dcbd0ab','頌古四十八首  其三','釋慧開','宋','宋诗','song-poetry','','[]','俱胝鈍置老天龍，利刃單提勘小童。',32,'全唐诗/poet.song.195000.json','["俱胝鈍置老天龍，利刃單提勘小童。", "巨靈擡手無多子，分破華山千萬重。"]'),
('7373296a-6750-4059-8797-fc44769c3211','頌古四十八首  其四','釋慧開','宋','宋诗','song-poetry','','[]','癡人面前，不可說夢。',20,'全唐诗/poet.song.195000.json','["癡人面前，不可說夢。", "胡子無鬚，惺惺添懵。"]'),
('03aef004-52ad-4496-83e6-adf4adfd0a2a','頌古四十八首  其五','釋慧開','宋','宋诗','song-poetry','','[]','香嚴真杜撰，惡毒無盡限。',24,'全唐诗/poet.song.195000.json','["香嚴真杜撰，惡毒無盡限。", "啞却衲僧口，通身迸鬼眼。"]'),
('57816c09-74d3-448d-88cb-96986e27ea86','頌古四十八首  其六','釋慧開','宋','宋诗','song-poetry','','[]','拈起花來，尾巴已露。',20,'全唐诗/poet.song.195000.json','["拈起花來，尾巴已露。", "迦葉破顔，人天罔措。"]'),
('8fbde822-df18-4fe8-8312-d5fb50fd2757','頌古四十八首  其七','釋慧開','宋','宋诗','song-poetry','','[]','只爲分明極，翻令所得遲。',24,'全唐诗/poet.song.195000.json','["只爲分明極，翻令所得遲。", "早知燈是火，飯熟已多時。"]'),
('c517769b-8ecc-47ea-a410-4b45cef0a71f','頌古四十八首  其八','釋慧開','宋','宋诗','song-poetry','','[]','機輪轉處，達者猶迷。',20,'全唐诗/poet.song.195000.json','["機輪轉處，達者猶迷。", "四維上下，南北東西。"]'),
('980d1c05-386c-4900-a299-49b52a8b1ece','頌古四十八首  其九','釋慧開','宋','宋诗','song-poetry','','[]','了身何似了心休，了得心兮身不愁。',32,'全唐诗/poet.song.195000.json','["了身何似了心休，了得心兮身不愁。", "若也身心俱了了，神仙何必更封侯。"]'),
('7b3eb089-619e-4a75-b953-1efb3a3c5d03','頌古四十八首  其一○','釋慧開','宋','宋诗','song-poetry','','[]','貧似范丹，氣如項羽。',20,'全唐诗/poet.song.195000.json','["貧似范丹，氣如項羽。", "活計雖無，敢與鬭富。"]'),
('4d352c6c-78f0-4727-a415-426c1d371fc1','頌古四十八首  其一一','釋慧開','宋','宋诗','song-poetry','','[]','眼流星，機掣電。',16,'全唐诗/poet.song.195000.json','["眼流星，機掣電。", "殺人刀，活人劍。"]'),
('7c071cd6-47d6-46a1-9600-a32f42f80b47','頌古四十八首  其一二','釋慧開','宋','宋诗','song-poetry','','[]','學道之人不識真，只爲從前認識神。',32,'全唐诗/poet.song.195000.json','["學道之人不識真，只爲從前認識神。", "無量劫來生死本，癡人喚作本來人。"]'),
('1d053f18-2c1e-44c3-8eb3-5d061e6fc233','頌古四十八首  其一三','釋慧開','宋','宋诗','song-poetry','','[]','識得最初句，便會末後句。',24,'全唐诗/poet.song.195000.json','["識得最初句，便會末後句。", "末後與最初，不是者一句。"]'),
('a1acacc4-6c9f-4daa-b63e-1c979eb3b253','頌古四十八首  其一四','釋慧開','宋','宋诗','song-poetry','','[]','趙州若在，倒行此令。',20,'全唐诗/poet.song.195000.json','["趙州若在，倒行此令。", "奪却刀子，南泉乞命。"]'),
('11140e51-ca19-4924-ab85-f975480893d4','頌古四十八首  其一五','釋慧開','宋','宋诗','song-poetry','','[]','獅子教兒迷子訣，擬前跳躑早翻身。',32,'全唐诗/poet.song.195000.json','["獅子教兒迷子訣，擬前跳躑早翻身。", "無端再敘當頭著，前箭猶輕後箭深。"]'),
('447ac0e5-0f31-4e77-a4fc-3e94194eb57c','頌古四十八首  其一六','釋慧開','宋','宋诗','song-poetry','','[]','會則事同一家，不會萬別千差。',28,'全唐诗/poet.song.195000.json','["會則事同一家，不會萬別千差。", "不會事同一家，會則萬別千差。"]'),
('de55174b-72da-4890-a041-14fcac51e117','頌古四十八首  其一七','釋慧開','宋','宋诗','song-poetry','','[]','鐵枷無孔要人擔，累及兒孫不等閑。',32,'全唐诗/poet.song.195000.json','["鐵枷無孔要人擔，累及兒孫不等閑。", "欲得撐門并拄戶，更須赤脚上刀山。"]'),
('0fbe4843-10aa-493f-8706-23a748037f94','頌古四十八首  其一八','釋慧開','宋','宋诗','song-poetry','','[]','突出麻三斤，言親意更親。',24,'全唐诗/poet.song.195000.json','["突出麻三斤，言親意更親。", "來說是非者，便是是非人。"]'),
('cd00b411-b122-4476-be32-c35a5a4de450','頌古四十八首  其一九','釋慧開','宋','宋诗','song-poetry','','[]','春有百花秋有月，夏有凉風冬有雪。',32,'全唐诗/poet.song.195000.json','["春有百花秋有月，夏有凉風冬有雪。", "若無閑事挂心頭，便是人間好時節。"]'),
('1dfe561b-79cf-4467-a915-5bc5ff72df6c','頌古四十八首  其二○','釋慧開','宋','宋诗','song-poetry','','[]','擡脚踏翻香水海，低頭俯視四禪天。',29,'全唐诗/poet.song.195000.json','["擡脚踏翻香水海，低頭俯視四禪天。", "一箇渾身無處著，請續一句。"]'),
('9874ed74-177b-4dba-b579-8b9db743533b','頌古四十八首  其二一','釋慧開','宋','宋诗','song-poetry','','[]','閃電光，擊石火。',16,'全唐诗/poet.song.195000.json','["閃電光，擊石火。", "眨得眼，已蹉過。"]'),
('4925b44c-4d7c-4e96-97a5-3f53451774f5','頌古四十八首  其二二','釋慧開','宋','宋诗','song-poetry','','[]','問處何如答處親，幾人於此眼生筋。',32,'全唐诗/poet.song.195000.json','["問處何如答處親，幾人於此眼生筋。", "兄呼弟應揚家醜，不屬陰陽別是春。"]'),
('d2db26eb-3d95-4e84-b9c8-a99935d67904','頌古四十八首  其二三','釋慧開','宋','宋诗','song-poetry','','[]','描不成兮畫不就，贊不及兮休生受。',32,'全唐诗/poet.song.195000.json','["描不成兮畫不就，贊不及兮休生受。", "本來面目沒處藏，世界壞時渠不朽。"]'),
('209c0ed9-e085-44a5-9ca4-c364e0c2d2b4','頌古四十八首  其二四','釋慧開','宋','宋诗','song-poetry','','[]','不露風骨句，未語先分付。',24,'全唐诗/poet.song.195000.json','["不露風骨句，未語先分付。", "進步口喃喃，知君大罔措。"]'),
('347ca892-76df-44f7-b4d2-91a6ea9a9824','頌古四十八首  其二五','釋慧開','宋','宋诗','song-poetry','','[]','白日青天，夢中說夢。',20,'全唐诗/poet.song.195000.json','["白日青天，夢中說夢。", "捏怪捏怪，誑謼一衆。"]'),
('c42693e2-5481-48b8-bbef-cb8a338af90e','頌古四十八首  其二六','釋慧開','宋','宋诗','song-poetry','','[]','卷起明明徹太空，太空猶未合吾宗。',32,'全唐诗/poet.song.195000.json','["卷起明明徹太空，太空猶未合吾宗。", "爭似從空都放下，綿綿密密不通風。"]'),
('bdeba6da-fbd9-4978-ad0a-e2ed79a1831b','頌古四十八首  其二七','釋慧開','宋','宋诗','song-poetry','','[]','叮嚀損君德，無言真有功。',24,'全唐诗/poet.song.195000.json','["叮嚀損君德，無言真有功。", "任從滄海變，終不爲君通。"]'),
('ac8a1823-01d3-4e88-bc85-c9ce9bc7de47','頌古四十八首  其二八','釋慧開','宋','宋诗','song-poetry','','[]','聞名不如見面，見面不如聞名。',28,'全唐诗/poet.song.195000.json','["聞名不如見面，見面不如聞名。", "雖然救得鼻孔，爭奈瞎却眼睛。"]'),
('c2848117-bfb3-47aa-b1ff-b664500725c5','頌古四十八首  其二九','釋慧開','宋','宋诗','song-poetry','','[]','風幡心動，一狀領過。',20,'全唐诗/poet.song.195000.json','["風幡心動，一狀領過。", "只知開口，不覺話墮。"]'),
('2f60763a-9d86-4d80-9a7a-8b82dc5fefe6','頌古四十八首  其三○','釋慧開','宋','宋诗','song-poetry','','[]','青天白日，切忌尋覓。',20,'全唐诗/poet.song.195000.json','["青天白日，切忌尋覓。", "更問如何，抱贓叫屈。"]'),
('3253a32b-c636-42fa-b1a0-2ad91eefc870','頌古四十八首  其三一','釋慧開','宋','宋诗','song-poetry','','[]','問既一般，答亦相似。',20,'全唐诗/poet.song.195000.json','["問既一般，答亦相似。", "飯裏有砂，泥中有刺。"]'),
('dd883a3f-f503-4260-adac-bf07cd0a5e15','頌古四十八首  其三二','釋慧開','宋','宋诗','song-poetry','','[]','劍刃上行，冰稜上走。',20,'全唐诗/poet.song.195000.json','["劍刃上行，冰稜上走。", "不涉階梯，懸崖撒手。"]'),
('1c3b3ee6-e983-4a88-a90f-3d824c4f729f','頌古四十八首  其三三','釋慧開','宋','宋诗','song-poetry','','[]','路逢劍客須呈，不遇詩人莫獻。',28,'全唐诗/poet.song.195000.json','["路逢劍客須呈，不遇詩人莫獻。", "逢人且說三分，未可全施一片。"]'),
('16e936fa-47a8-462d-8e0b-671123ec0d41','頌古四十八首  其三四','釋慧開','宋','宋诗','song-poetry','','[]','天晴日頭出，雨下地上濕。',24,'全唐诗/poet.song.195000.json','["天晴日頭出，雨下地上濕。", "盡情都說了，只恐信不及。"]'),
('4f615be1-21f3-429c-8e93-60ab93d05dc4','頌古四十八首  其三五','釋慧開','宋','宋诗','song-poetry','','[]','雲月是同，溪山各異。',20,'全唐诗/poet.song.195000.json','["雲月是同，溪山各異。", "萬福萬福，是一是二。"]'),
('6272c586-6779-4477-8f24-104d2cc03e5c','頌古四十八首  其三六','釋慧開','宋','宋诗','song-poetry','','[]','路逢達道人，不將語默對。',24,'全唐诗/poet.song.195000.json','["路逢達道人，不將語默對。", "攔腮劈面拳，直下會便會。"]'),
('0876c598-caa1-41e7-b5d8-6542ed0cb969','頌古四十八首  其三七','釋慧開','宋','宋诗','song-poetry','','[]','言無展事，語不投機。',20,'全唐诗/poet.song.195000.json','["言無展事，語不投機。", "承言者喪，滯句者迷。"]'),
('c3eaa55c-c122-4bfe-8e40-5eea1d309a26','頌古四十八首  其三八','釋慧開','宋','宋诗','song-poetry','','[]','過去墮坑塹，回來却被壞。',24,'全唐诗/poet.song.195000.json','["過去墮坑塹，回來却被壞。", "者些尾巴子，直是甚奇怪。"]'),
('e03601d6-40db-4237-bbe9-bde0ef5947d5','頌古四十八首  其三九','釋慧開','宋','宋诗','song-poetry','','[]','急流垂釣，貪餌者著。',20,'全唐诗/poet.song.195000.json','["急流垂釣，貪餌者著。", "口縫纔開，性命喪却。"]'),
('945ae046-79ef-4716-ba07-8608def1e945','頌古四十八首  其四○','釋慧開','宋','宋诗','song-poetry','','[]','颺下笊籬并木杓，當陽一突絕周遮。',32,'全唐诗/poet.song.195000.json','["颺下笊籬并木杓，當陽一突絕周遮。", "百丈重關攔不住，脚尖趯出佛如麻。"]'),
('126dcbdb-7ffc-4fa0-a010-fadfd447137f','頌古四十八首  其四一','釋慧開','宋','宋诗','song-poetry','','[]','西來直指，事因囑起。',20,'全唐诗/poet.song.195000.json','["西來直指，事因囑起。", "撓聒叢林，元來是你。"]'),
('abc4e153-d21e-40e6-b92d-a0c733a06ade','頌古四十八首  其四二','釋慧開','宋','宋诗','song-poetry','','[]','出得出不得，渠儂得自由。',24,'全唐诗/poet.song.195000.json','["出得出不得，渠儂得自由。", "神頭并鬼面，敗闕當風流。"]'),
('acf7ba34-8886-4222-bb1a-da43f876fe0e','頌古四十八首  其四三','釋慧開','宋','宋诗','song-poetry','','[]','拈起竹篦，行殺活令。',20,'全唐诗/poet.song.195000.json','["拈起竹篦，行殺活令。", "背觸交馳，佛祖乞命。"]'),
('94802045-235f-49e2-9173-18c9183396b1','頌古四十八首  其四四','釋慧開','宋','宋诗','song-poetry','','[]','諸方深與淺，都在掌握中。',24,'全唐诗/poet.song.195000.json','["諸方深與淺，都在掌握中。", "撐天并拄地，隨處振宗風。"]'),
('bc32eb10-9a77-4775-8aab-2980351421e0','頌古四十八首  其四五','釋慧開','宋','宋诗','song-poetry','','[]','他弓莫挽，他馬莫騎。',20,'全唐诗/poet.song.195000.json','["他弓莫挽，他馬莫騎。", "他非莫辨，他事莫知。"]'),
('eb17dd85-8ccc-4b01-b708-4a919bb0358a','頌古四十八首  其四六','釋慧開','宋','宋诗','song-poetry','','[]','瞎却頂門眼，錯認定盤星。',24,'全唐诗/poet.song.195000.json','["瞎却頂門眼，錯認定盤星。", "拚身能捨命，一盲引衆盲。"]'),
('ccb36e16-574f-4186-b040-33182cf7c592','頌古四十八首  其四七','釋慧開','宋','宋诗','song-poetry','','[]','一念普觀無量劫，無量劫事即如今。',32,'全唐诗/poet.song.195000.json','["一念普觀無量劫，無量劫事即如今。", "如今覷破箇一念，覷破如今覷底人。"]'),
('ef91a21a-99de-4732-939c-866557d47d0d','頌古四十八首  其四八','釋慧開','宋','宋诗','song-poetry','','[]','未舉步時先已到，未動舌時先說了。',32,'全唐诗/poet.song.195000.json','["未舉步時先已到，未動舌時先說了。", "直饒著著在機先，更須知有向上竅。"]'),
('6ed53051-4032-4cee-b251-0b4c34db290b','黄龍三關  其一','釋慧開','宋','宋诗','song-poetry','','[]','我手何似佛手，摸得枕頭背後。',28,'全唐诗/poet.song.195000.json','["我手何似佛手，摸得枕頭背後。", "不覺大笑呵呵，元來通身是手。"]'),
('78d354b4-1cbc-41e7-920d-2ebcebd4e962','黄龍三關  其二','釋慧開','宋','宋诗','song-poetry','','[]','我脚何似馿脚，未舉步時踏著。',28,'全唐诗/poet.song.195000.json','["我脚何似馿脚，未舉步時踏著。", "一任四海橫行，倒跨楊岐三脚。"]'),
('cdbc0f84-2604-4aed-af85-1e57d08f1af1','黄龍三關  其三','釋慧開','宋','宋诗','song-poetry','','[]','人人有箇生緣，各各透徹機先。',28,'全唐诗/poet.song.195000.json','["人人有箇生緣，各各透徹機先。", "那吒析骨還父，五祖豈藉爺緣。"]'),
('ce1b9ee0-c2fd-4f58-a554-75e1ac550ece','黄龍三關  其四','釋慧開','宋','宋诗','song-poetry','','[]','佛手馿脚生緣，非佛非道非禪。',28,'全唐诗/poet.song.195000.json','["佛手馿脚生緣，非佛非道非禪。", "莫怪無門關險，結盡衲子深冤。"]'),
('d507df1f-6fc1-45fc-81f7-d0fa158ce66a','日本覺心禪人遠來炷香請益求詩迅筆贈之','釋慧開','宋','宋诗','song-poetry','','[]','心即是佛佛即心，心佛元同亙古今。',32,'全唐诗/poet.song.195000.json','["心即是佛佛即心，心佛元同亙古今。", "覺悟古今心是佛，不須向外別追尋。"]'),
('10c7461c-787e-4907-b1fb-1e47118be15e','人至收書知得心座元安樂蒙惠數珠水晶者金重十二錢一收訖山偈奉贈','釋慧開','宋','宋诗','song-poetry','','[]','百八摩尼顆顆圓，遼天鼻孔一齊穿。',32,'全唐诗/poet.song.195000.json','["百八摩尼顆顆圓，遼天鼻孔一齊穿。", "恒河砂數佛菩薩，每日呼來跳一圈。"]'),
('f6a09fb5-0b99-47d2-b96b-3a966ac17668','請無門首座立僧山偈奉謝','釋宗壽','宋','宋诗','song-poetry','','[]','瑞巖近日有無門，掇向繩床判古今。',32,'全唐诗/poet.song.195000.json','["瑞巖近日有無門，掇向繩床判古今。", "凡聖路頭俱截斷，幾多蟠蟄起雷音。"]'),
('28e11c43-7fb5-40f5-9816-cc7840ca2fcb','寄題永福董宰溪莊圖','方大琮','宋','宋诗','song-poetry','','[]','羨君胸次有丘壑，眼底塵凡一洗之。',64,'全唐诗/poet.song.195000.json','["羨君胸次有丘壑，眼底塵凡一洗之。", "地獻溪湖供入畫，天私風月要昌詩。", "貴人豈復知盤谷，名世應須學武夷。", "政恐主翁方宦達，買山雖早入山遲。"]'),
('e5b57136-ff1b-420b-98cb-acc87464eff4','寄題董宰讀書軒','方大琮','宋','宋诗','song-poetry','','[]','坐衙彈琴和且平，退衙讀書鏘有聲。',160,'全唐诗/poet.song.195000.json','["坐衙彈琴和且平，退衙讀書鏘有聲。", "琴聲書聲兩相和，和氣散作花滿城。", "示知言游不可作，雅俗二者難兼行。", "曩余不敏坐此處，軒窗塵土安有名。", "堂前薇花寂寂笑，此殆文吏非書生。", "君非異人何能爾，吏事不廢心轉清。", "牒紛案聚判筆走，庭空吏散詩句成。", "嘗聞歐公居夷陵，日討故牘繙研精。", "金陵宰鄞政習禮，天津客已愁鵑鳴。", "懷哉尹君志古道，請把此案爲商評。"]'),
('2c037a21-ed16-406f-b956-c21002a424d4','挽趙南塘  其一','方大琮','宋','宋诗','song-poetry','','[]','初開學禁預招延，俄滯周南四十年。',64,'全唐诗/poet.song.195000.json','["初開學禁預招延，俄滯周南四十年。", "大振文詞驚海內，肯將訓詁讓儒先。", "孤忠自許漢遺老，高氣直凌唐謫仙。", "鳳昔覽輝今已矣，危樓百尺尚依然。"]'),
('9bffbdc4-a06f-4697-9436-88b6a92b2133','挽趙南塘  其二','方大琮','宋','宋诗','song-poetry','','[]','晚起蘇公以禮郎，侍經掌制位文昌。',64,'全唐诗/poet.song.195000.json','["晚起蘇公以禮郎，侍經掌制位文昌。", "端平氣脈真堪寄，元祐光陰惜未長。", "馬邑深憂形諫墨，鸞臺寧徙恥書黄。", "門生最是知心者，追記微言淚數行。"]'),
('62f30b12-acd6-49e6-bff4-5e5a829f8ede','壽鄉守張秘閣  其一','方大琮','宋','宋诗','song-poetry','','[]','秋氣高寒公始生，稟姿多得聖之清。',64,'全唐诗/poet.song.195000.json','["秋氣高寒公始生，稟姿多得聖之清。", "官箴未許冰爲潔，心事真堪月比明。", "久合紫囊還再世，却令皂蓋歷三城。", "憑誰盡紀前張政，只聽村謠里唱聲。"]'),
('1150b7c0-2f83-4ec8-9d01-d7e604678b85','壽鄉守張秘閣  其二','方大琮','宋','宋诗','song-poetry','','[]','家學源流今吏師，寬嚴殊劑亦殊施。',64,'全唐诗/poet.song.195000.json','["家學源流今吏師，寬嚴殊劑亦殊施。", "豪宗咸服薤一本，野老齊歌麥兩岐。", "最課休聲無地着，芳名姱節有天知。", "請將郡志從頭數，高直蓬山更有誰。"]'),
('4241778a-3761-426a-97d7-9fa7670436e3','壽鄉守張秘閣  其三','方大琮','宋','宋诗','song-poetry','','[]','老去遇公爲地主，賸將恩意煦摧頹。',64,'全唐诗/poet.song.195000.json','["老去遇公爲地主，賸將恩意煦摧頹。", "龜魚得蔭眠偏穩，鷗鷺忘機熟不猜。", "方喜璽褒天下最，又聞玉節日邊來。", "豐年一飽誰之賜，好把禾頭祝壽杯。"]'),
('03046347-18fd-4731-b778-b02d5c13348c','送俊明李提舉  其一','方大琮','宋','宋诗','song-poetry','','[]','有美羊城一鉅儒，菊坡氣脈最關渠。',64,'全唐诗/poet.song.195000.json','["有美羊城一鉅儒，菊坡氣脈最關渠。", "村高懶宿郎官被，色養姑乘使者車。", "曩日綠林功未賞，今年清社事堪書。", "福星何事輕移去，久矣世無公毀譽。"]'),
('110c1983-ad8e-4b99-8068-02258fd13950','送俊明李提舉  其二','方大琮','宋','宋诗','song-poetry','','[]','幸甚聯臺餘五月，戶庭微細事皆知。',64,'全唐诗/poet.song.195000.json','["幸甚聯臺餘五月，戶庭微細事皆知。", "山中菊徑多歸思，膝下萊衣少脫時。", "吏散庭空無滯牒，客來酒盡只新詩。", "耳聞眼見誰虛實，寫與行人作口碑。"]'),
('6d1638d1-ce11-4b19-b734-e1cc6687545d','送俊明李提舉  其三','方大琮','宋','宋诗','song-poetry','','[]','時賢落落甚晨星，世事如棋局又新。',64,'全唐诗/poet.song.195000.json','["時賢落落甚晨星，世事如棋局又新。", "赤白交馳邊面急，腐紅銷盡國中貧。", "誰令野有橫舟者，應是朝無惜寶人。", "握手不堪離思滿，願公自愛廟堂身。"]'),
('765ac8a0-cd0b-4849-829b-426fbabac6b1','送廣東趙舶使','方大琮','宋','宋诗','song-poetry','','[]','百禽收舌後，一鶚凌清秋。',168,'全唐诗/poet.song.195000.json','["百禽收舌後，一鶚凌清秋。", "滄波渺浩蕩，中有萬斛舟。", "劫灰燒不盡，宗老擅風流。", "典刑尚千載，雅奧根九疇。", "忠憤疏中壘，功名起武侯。", "載彼北方學，來爲南國游。", "膻風痛洗濯，蠻俗頼懷柔。", "偶然得聯事，顧影豈其儔。", "逢迎時一笑，傾吐不復留。", "抵掌說西事，强顔愧楚囚。", "見晚別何早，含情酒澆愁。", "惟有加餐祝，作歌住行輈。", "有詔願亟起，且莫事耡耰。", "顧我何爲者，一毛在九牛。"]'),
('e100c854-b31d-4ac7-952e-f69df4b7c07d','送李兄赴省','方大琮','宋','宋诗','song-poetry','','[]','乃翁場屋負高名，裏許工夫共講明。',64,'全唐诗/poet.song.195000.json','["乃翁場屋負高名，裏許工夫共講明。", "謝氏弟兄輝玉樹，韋侯父子薄金籝。", "世科莫訝爭寒畯，少作曾看到老成。", "此去親傳衣鉢在，想非溫飽志平生。"]'),
('e331e57c-db4e-481b-804e-4accde1c8bb9','宴徐大參','方大琮','宋','宋诗','song-poetry','','[]','麟符久合換貂蟬，又向鄉邦擁十年。',64,'全唐诗/poet.song.195000.json','["麟符久合換貂蟬，又向鄉邦擁十年。", "眼赤腰黄天寵澤，顔紅鬢綠地神仙。", "極知晝繡堪行染，見說宵衣正渴賢。", "好事還殊門外路，人看四輩下翩翩。"]'),
('a8236ec3-4180-4a10-b676-9ce8bab4afcf','自詠','蔡格','宋','宋诗','song-poetry','','[]','富貴良非願，林泉畢此生。',48,'全唐诗/poet.song.195000.json','["富貴良非願，林泉畢此生。", "酒因隨量飲，詩或偶然成。", "秋水和烟釣，春田带雨耕。", "頹然無縫塔，且不費經營。"]'),
('ae3baa1e-a9fb-4d25-89dc-2c1bc3f84f51','山居  其一','蔡格','宋','宋诗','song-poetry','','[]','一雨秋涼爽氣新，秋聲栗栗轉傷神。',32,'全唐诗/poet.song.195000.json','["一雨秋涼爽氣新，秋聲栗栗轉傷神。", "根株半載培多少，倏忽流光不待人。"]'),
('d28a4e64-3095-4bab-877b-c10b68adba52','山居  其二','蔡格','宋','宋诗','song-poetry','','[]','刊刪理障覓天根，心體昭昭會一原。',32,'全唐诗/poet.song.195000.json','["刊刪理障覓天根，心體昭昭會一原。", "歲暮更宜深燕養，莫埋書冊動風旛。"]'),
('101d65e8-a6f9-494a-95c9-eaa05a7093ec','山居  其三','蔡格','宋','宋诗','song-poetry','','[]','觀雲聽雨逐番新，清晝綠蔭更可人。',32,'全唐诗/poet.song.195000.json','["觀雲聽雨逐番新，清晝綠蔭更可人。", "滿眼箇中無限趣，當窗憩久樂天真。"]'),
('0e6bf377-79e4-4a61-ab5f-c2934342b4f6','山居  其四','蔡格','宋','宋诗','song-poetry','','[]','心遠不妨車馬過，地偏漸聽月風來。',32,'全唐诗/poet.song.195000.json','["心遠不妨車馬過，地偏漸聽月風來。", "參差竹木皆清景，唯有梅枝手自栽。"]'),
('3db37da8-5937-4ec1-a767-0a839549764a','山居  其五','蔡格','宋','宋诗','song-poetry','','[]','大禹聖人惜寸陰，嗟我悠悠老已侵。',32,'全唐诗/poet.song.195000.json','["大禹聖人惜寸陰，嗟我悠悠老已侵。", "七年病蓄三年艾，猶勝龍鍾轉陸沉。"]'),
('77164701-6688-4e49-ad46-d96dbd62eb11','山居  其六','蔡格','宋','宋诗','song-poetry','','[]','硬着脊梁休放肩，肩挑重負路漫延。',32,'全唐诗/poet.song.195000.json','["硬着脊梁休放肩，肩挑重負路漫延。", "生前氣力無停歇，一息奄奄尚向前。"]'),
('71424f05-f923-45e3-9e71-a6813f356e19','山居  其七','蔡格','宋','宋诗','song-poetry','','[]','寤寐前修相感深，一巾衣鉢此傳心。',32,'全唐诗/poet.song.195000.json','["寤寐前修相感深，一巾衣鉢此傳心。", "叮嚀莫問如來界，本體工夫在此尋。"]'),
('9188ed4d-a5ec-4e53-9c9f-1db5cca4d404','山居  其八','蔡格','宋','宋诗','song-poetry','','[]','天下無如聞道樂，人間惟有養心高。',32,'全唐诗/poet.song.195000.json','["天下無如聞道樂，人間惟有養心高。", "烟花過眼須臾滅，明德馨香萬古牢。"]'),
('16de27db-6bc3-408d-bd0f-1b27160ae92c','山居  其九','蔡格','宋','宋诗','song-poetry','','[]','逆境須同順境寬，熟仁堅志這中觀。',32,'全唐诗/poet.song.195000.json','["逆境須同順境寬，熟仁堅志這中觀。", "英雄何限經坷坎，一片精光本自完。"]'),
('2fdf06f8-e22f-473b-a688-73888194bd21','山居  其一○','蔡格','宋','宋诗','song-poetry','','[]','老年隨分做工夫，黄卷靜披世味無。',32,'全唐诗/poet.song.195000.json','["老年隨分做工夫，黄卷靜披世味無。", "倦整池邊春睡足，凭欄遥看鳥相呼。"]'),
('3ea2653e-c9d1-4150-be3e-b1791b4fbdc6','山居  其一一','蔡格','宋','宋诗','song-poetry','','[]','此身終老太平年，何事修真顛倒顛。',32,'全唐诗/poet.song.195000.json','["此身終老太平年，何事修真顛倒顛。", "但得開顔隨日賞，醉眠花下也神仙。"]'),
('0b4d545f-c5a3-4117-b07d-3bcb3e825704','山居  其一二','蔡格','宋','宋诗','song-poetry','','[]','野花幽草滿庭除，生意綿綿接太虛。',32,'全唐诗/poet.song.195000.json','["野花幽草滿庭除，生意綿綿接太虛。", "獨坐空齋無一事，呼童三徑樂教鋤。"]'),
('a966f408-d4f9-4fb6-972d-f230e955f8c3','山居  其一三','蔡格','宋','宋诗','song-poetry','','[]','何思何慮只寂然，由來習靜類修禪。',32,'全唐诗/poet.song.195000.json','["何思何慮只寂然，由來習靜類修禪。", "一去無多路□□，直啟玄關叩洞天。"]'),
('01f27300-a172-4624-853c-fa09ba5ecc20','無題','陳大用','宋','宋诗','song-poetry','','[]','閑拈紅葉欲題詩，待得詩成又懶題。',32,'全唐诗/poet.song.195000.json','["閑拈紅葉欲題詩，待得詩成又懶題。", "心事不隨流水去，月明人在赤橋西。"]'),
('86621b05-3ac5-470a-952b-33904c8b9bc6','臨終偈','朱真靜','宋','宋诗','song-poetry','','[]','去來如一，真性湛然。',20,'全唐诗/poet.song.195000.json','["去來如一，真性湛然。", "風收雲散，月在青天。"]'),
('77371a81-d9d5-4898-afb0-b83ce7867184','石室庵夜坐','朱真靜','宋','宋诗','song-poetry','','[]','青燈寒焰弄微明，燈與幽人一樣清。',32,'全唐诗/poet.song.195000.json','["青燈寒焰弄微明，燈與幽人一樣清。", "案上黄庭渾嬾看，時聞敗葉打窗聲。"]'),
('18c80837-348b-4297-9f48-c312d5c3153e','入山採藥遇異人','朱真靜','宋','宋诗','song-poetry','','[]','緊著芒鞋高繫裙，野猿相狎許同羣。',32,'全唐诗/poet.song.195000.json','["緊著芒鞋高繫裙，野猿相狎許同羣。", "綠蘿林裏採茶去，踏碎青山一片雲。"]'),
('25f0116f-3d37-4e76-b321-82e949479b15','又題座右窗間','朱真靜','宋','宋诗','song-poetry','','[]','經書不是語虛無，荆棘叢中有坦塗。',32,'全唐诗/poet.song.195000.json','["經書不是語虛無，荆棘叢中有坦塗。", "不遇至人真口訣，誤人錯下死工夫。"]'),
('2d84bd6c-4e23-4dc9-9cda-65f03f05a429','題石室庵前竹上','朱真靜','宋','宋诗','song-poetry','','[]','十年身與鬼爲鄰，曾見巖花幾度春。',32,'全唐诗/poet.song.195000.json','["十年身與鬼爲鄰，曾見巖花幾度春。", "莫怪柴門終日閉，怕將塵事惱閒人。"]'),
('b96415d8-a332-40af-9a95-bc19b187d1d6','示女','徐某','宋','宋诗','song-poetry','','[]','深宮富貴事風流，莫忘生身老骨頭。',32,'全唐诗/poet.song.195000.json','["深宮富貴事風流，莫忘生身老骨頭。", "因與太師歡笑處，爲吾方便覓彭州。"]'),
('9371d906-8540-4347-9ce6-b941fee9acbb','送胡季昭謫象州','劉夢才','宋','宋诗','song-poetry','','[]','紹興寶慶百年餘，古往今來說二胡。',64,'全唐诗/poet.song.195000.json','["紹興寶慶百年餘，古往今來說二胡。", "論事直須彈懇切，立朝端不忍阿諛。", "兩賢幸屬吾州有，萬事何曾公議無。", "象郡新寧不同詔，九重天子正儀圖。"]'),
('eaf515c2-225d-4921-bdd0-f6bd9cb6ba05','徐進齋得古銅香爐具象鼻眼博古圖謂之象鬲屬余賦之雖不足言詩聊記曾見  其一','俞文豹','宋','宋诗','song-poetry','','[]','在象數前鍾鼻眼，出囂塵外鑄形模。',32,'全唐诗/poet.song.195000.json','["在象數前鍾鼻眼，出囂塵外鑄形模。", "傳香到手親曾見，全勝人看博古圖。"]'),
('0c83228b-7d03-4569-98d7-6ed0af3ad510','徐進齋得古銅香爐具象鼻眼博古圖謂之象鬲屬余賦之雖不足言詩聊記曾見  其二','俞文豹','宋','宋诗','song-poetry','','[]','願得身遊海外天，蓬萊頂上覓沈箋。',32,'全唐诗/poet.song.195000.json','["願得身遊海外天，蓬萊頂上覓沈箋。", "爲君喚起槐安夢，細讀南華內外篇。"]'),
('87e0bde4-a7d0-489f-a764-59b4ac590f88','余有三恨一無子二無助三無成抱茲苦心娛以文字既絕筆於斯錄復長吟以繫之  其一','俞文豹','宋','宋诗','song-poetry','','[]','可笑春蠶有許癡，年年辛苦爲他誰。',32,'全唐诗/poet.song.195000.json','["可笑春蠶有許癡，年年辛苦爲他誰。", "恰如貧女飛梭了，挂體何曾有一絲。"]'),
('f9e1fc99-ba92-4b30-be07-3349f9df471f','余有三恨一無子二無助三無成抱茲苦心娛以文字既絕筆於斯錄復長吟以繫之  其二','俞文豹','宋','宋诗','song-poetry','','[]','天不奈何無可問，世皆如此有誰聽。',32,'全唐诗/poet.song.195000.json','["天不奈何無可問，世皆如此有誰聽。", "爲儂指點春知處，惟有垂楊眼獨青。"]'),
('c495bc5d-4997-4524-93de-3a88e1d41f4a','句','俞文豹','宋','宋诗','song-poetry','','[]','脚根須管虛中實，眼界當於窄處寬。',16,'全唐诗/poet.song.195000.json','["脚根須管虛中實，眼界當於窄處寬。"]'),
('e63302c9-e0e0-4d79-a067-a8d271d02988','夜遊','顧夢日','宋','宋诗','song-poetry','','[]','路轉歌聲杳，夜深雲露濃。',24,'全唐诗/poet.song.195000.json','["路轉歌聲杳，夜深雲露濃。", "美人行月下，秋水汎芙蓉。"]'),
('83f95e9a-b954-4834-82fb-86885d3711ab','句','楊穎士','宋','宋诗','song-poetry','','[]','儻來軒冕何須問，分定功名不在忙。',16,'全唐诗/poet.song.195000.json','["儻來軒冕何須問，分定功名不在忙。"]'),
('891ad613-4364-4731-a3f1-99466c46a6a4','句  其一','余洪道','宋','宋诗','song-poetry','','[]','世上聲名無買處，人間官職有來時。',16,'全唐诗/poet.song.195000.json','["世上聲名無買處，人間官職有來時。"]'),
('6a2b43ba-4e6e-4078-962a-185ecaecf424','句  其二','余洪道','宋','宋诗','song-poetry','','[]','須知凡卉空千萬，不似寒花只兩三。',16,'全唐诗/poet.song.195000.json','["須知凡卉空千萬，不似寒花只兩三。"]'),
('ebed3ef4-5af8-4d95-a919-0a87ae8313f7','句  其三','余洪道','宋','宋诗','song-poetry','','[]','著心計較般般錯，退步思量事事寬。',16,'全唐诗/poet.song.195000.json','["著心計較般般錯，退步思量事事寬。"]'),
('a6db1918-aeb5-486e-ae13-5259d5f7d113','句','蕭曰復','宋','宋诗','song-poetry','','[]','民得食天全命脈，令從心地起根芽。',16,'全唐诗/poet.song.195000.json','["民得食天全命脈，令從心地起根芽。"]'),
('d48bf0bb-e41c-4431-b72f-d9441ffa1cbf','句','朱梅居','宋','宋诗','song-poetry','','[]','物態却從無處有，世情偏向苦中甜。',16,'全唐诗/poet.song.195000.json','["物態却從無處有，世情偏向苦中甜。"]'),
('77bbb9f3-1002-467f-b704-2a8e774bf461','人影','俞桂英','宋','宋诗','song-poetry','','[]','身外復添汝，無言隨去留。',48,'全唐诗/poet.song.195000.json','["身外復添汝，無言隨去留。", "自從生便有，直到死方休。", "步月常相逐，臨溪元不流。", "靜中明道眼，總是一虛浮。"]'),
('2974bbb0-8aee-45a6-9128-a3e1ddb942fa','句  其一','俞桂英','宋','宋诗','song-poetry','','[]','一點梅香到，三分酒力消。',12,'全唐诗/poet.song.195000.json','["一點梅香到，三分酒力消。"]'),
('32e44092-0e08-4e24-ae93-e4ba60ea7e4f','句  其二','俞桂英','宋','宋诗','song-poetry','','[]','母念子行遠，兒云爺未歸。',12,'全唐诗/poet.song.195000.json','["母念子行遠，兒云爺未歸。"]'),
('352b819a-5065-45c5-88a4-8e077acc77c7','句  其三','俞桂英','宋','宋诗','song-poetry','','[]','白雲一樹鶴孤宿，明月滿樓鐘鼓聲。',16,'全唐诗/poet.song.195000.json','["白雲一樹鶴孤宿，明月滿樓鐘鼓聲。"]'),
('1ce40793-4f6b-46ed-a7d1-f1e63833bb81','句  其四','俞桂英','宋','宋诗','song-poetry','','[]','百無一事身爲客，十有九分心在家。',16,'全唐诗/poet.song.195000.json','["百無一事身爲客，十有九分心在家。"]'),
('662d3fd2-7c00-45e7-8128-5bb7bd2ff7c4','豆腐詩','王老者','宋','宋诗','song-poetry','','[]','朝朝只與磨爲親，推轉無邊大法輪。',32,'全唐诗/poet.song.195000.json','["朝朝只與磨爲親，推轉無邊大法輪。", "碾出一團真白玉，將歸回向未來人。"]'),
('b906f8d8-9b41-45e6-b5ab-8e127d1a7f86','澹山巖','郭三聘','宋','宋诗','song-poetry','','[]','憶昔遊澹巖，文社四爲侶。',156,'全唐诗/poet.song.195000.json','["憶昔遊澹巖，文社四爲侶。", "相逢各年少，抱負俱有素。", "訓狐聖得知，夜半叫已屢。", "主人知客來，倒屣相告語。", "且言龍王神，多有靈異處。", "殷勤叩科名，吉兆齊確許。", "未成三先達，陸續霄漢去。", "轉盼三十載，獨我尚困沮。", "行將賈餘勇，猶幸有孤注。", "乘興偶重游，寓敬香一炷。", "再拜問龍王，前約何可負。", "朱衣願點頭，成就在此舉。", "擬欲鑱堅珉，紀此一奇趣。"]'),
('347ea097-0d9b-4da9-bafc-79a5e4ecfdb6','寄題鄭熙寧夫玉軒','林表民','宋','宋诗','song-poetry','','[]','良玉本不琢，大音無希聲。',120,'全唐诗/poet.song.195000.json','["良玉本不琢，大音無希聲。", "觀君命軒意，欲以詩自鳴。", "君詩志古調，考擊參差韺。", "泠泠澗泉泣，切切谿條清。", "孚尹露涵采，潤美月泛英。", "昔聞洛山中，種者須其成。", "非希咸陽價，匵韞那敢輕。", "用之薦穹昊，何但鬼神驚。", "凉欲覺庭葉，夜疏耿鐙驚。", "一讀一啟予，古調真難評。"]'),
('c2c6ddc0-e176-4778-94a0-aa368ab19b95','重建神秀樓','林表民','宋','宋诗','song-poetry','','[]','慨昔淳熙初，忠定守郡時。',204,'全唐诗/poet.song.195000.json','["慨昔淳熙初，忠定守郡時。", "樹樓城南門，衆秀皆來歸。", "插空繚千嶠，注海合兩溪。", "雲眉扁古隸，蛟鳳躍出飛。", "西瞻建標霞，東頫採菊籬。", "循環一甲子，天假茲良期。", "象賢宣祖烈，布政軼吏師。", "乘暇陟危級，更新敞前規。", "肆開落成宴，鐙月交明輝。", "傑棟小芳桂，修梁薄辛夷。", "空闊渺納納，青紅濕離離。", "太平畢文簡，慶曆元厚之。", "猗彼三碩輔，勳業疇或非。", "公今繼其躅，歲月幾推移。", "魏謩寶遺笏，鄭武緇舊衣。", "過者登斯樓，咸誦金石詞。", "却笑楚臣作，空因秋氣悲。"]'),
('2b8e23a6-a441-4d6c-9468-99193ecfbf05','簡許遠元寮','林表民','宋','宋诗','song-poetry','','[]','問雲從何來，明月翳光景。',84,'全唐诗/poet.song.195000.json','["問雲從何來，明月翳光景。", "須臾忽破散，依舊寒炯炯。", "問月何能照，月亦不自領。", "雲來非我過，雲去非我幸。", "無心付無事，雖巧不能逞。", "幽人起寤嘆，婆娑弄清影。", "世人有萬端，令人發深省。"]'),
('49ec508b-7052-4f26-a8bb-3adc49644ec0','送天台李明府貫一歸越','林表民','宋','宋诗','song-poetry','','[]','赤城譚舊令，爲政且鳴琴。',48,'全唐诗/poet.song.195000.json','["赤城譚舊令，爲政且鳴琴。", "澗瀑知清操，山雲識苦吟。", "自甘微賤拙，誰信勒碑深。", "歸路春風近，烟花繞禁林。"]'),
('6aa9614f-cf08-4e10-95a0-c8d35b431726','餞台倅王司令幾叔參釐天府','林表民','宋','宋诗','song-poetry','','[]','黼坐頒泥檢，黄圖駕玉星。',48,'全唐诗/poet.song.195000.json','["黼坐頒泥檢，黄圖駕玉星。", "自應攄學業，端不藉門庭。", "凍日湖梅白，春風院柳青。", "從今亨路去，台嶺記曾經。"]'),
('695b1334-e66d-4299-b580-218fafa4a3d2','山齋書事','林表民','宋','宋诗','song-poetry','','[]','掩卷聽蟬韻，憑欄數雁行。',48,'全唐诗/poet.song.195000.json','["掩卷聽蟬韻，憑欄數雁行。", "井風梧葉雨，籬月菊花霜。", "又見秋將老，那堪夜更長。", "愁吟無語共，殘灺落書床。"]'),
('d0ff6058-73e8-489c-8a84-215165582b89','挽都梁太守洪季輔寺丞','林表民','宋','宋诗','song-poetry','','[]','鼓吹舟歸日，軍門巷哭時。',48,'全唐诗/poet.song.195000.json','["鼓吹舟歸日，軍門巷哭時。", "身拋淮郡印，事入峴山碑。", "敵在家何用，城危孰與持。", "墓門今已閉，千載使人悲。"]'),
('1bac4352-653b-43ea-b59b-b388b1d5d8b2','次韻酬陳之道明府見贈','林表民','宋','宋诗','song-poetry','','[]','爲政鄱君日，劬然似苦吟。',48,'全唐诗/poet.song.195000.json','["爲政鄱君日，劬然似苦吟。", "光前還照後，行古却居今。", "危世道猶直，故山春正深。", "露生觀庶物，清坐更觀心。"]'),
('988ce870-6f77-4079-b8a3-2dfa4bb5587f','送王季和文知施州二首  其一','林表民','宋','宋诗','song-poetry','','[]','皂蓋蠶叢去，青祗鳳曆頒。',48,'全唐诗/poet.song.195000.json','["皂蓋蠶叢去，青祗鳳曆頒。", "雪林猿叫峽，春院鳥啼山。", "文字傳三楚，恩威化八蠻。", "政成明主召，九虎啟天關。"]'),
('297c475a-a40a-4af7-bf00-25891adb7deb','送王季和文知施州二首  其二','林表民','宋','宋诗','song-poetry','','[]','宿幸依劉表，時蒙說項斯。',48,'全唐诗/poet.song.195000.json','["宿幸依劉表，時蒙說項斯。", "方爲感知賦，遽作送行詩。", "萬里通吳蜀，千山隔夢思。", "江頭野梅發，應記共吟時。"]'),
('49e219e0-5e98-4083-a63d-12b29ef7a048','送浄應老道源往浙右','林表民','宋','宋诗','song-poetry','','[]','片雲離海嶼，吳地去隨緣。',48,'全唐诗/poet.song.195000.json','["片雲離海嶼，吳地去隨緣。", "托鉢應行乞，升牀亦坐禪。", "舟停上塘雪，寺隔過山烟。", "刺史知聞舊，無須覓鏡傳。"]'),
('706a977e-7a48-4248-8256-ba19e3d9cd36','訪懷遇師','林表民','宋','宋诗','song-poetry','','[]','獨隠重巖裏，全無物役心。',48,'全唐诗/poet.song.195000.json','["獨隠重巖裏，全無物役心。", "禪因秋月悟，詩對晚雲吟。", "訪古猿驚錫，拋生鳥上林。", "相知今十載，不憚遠來尋。"]'),
('de16cc02-75be-4743-8b8d-0dfc5089d60a','送祖太長老住虎丘','林表民','宋','宋诗','song-poetry','','[]','吳國前朝寺，懸知補處難。',48,'全唐诗/poet.song.195000.json','["吳國前朝寺，懸知補處難。", "岳雲迎外度，海月定中觀。", "子去揮犀拂，吾當賣布單。", "梅花知別意，無語澹相看。"]'),
('a3a217b1-7d76-479c-9c08-898288949da4','初夏別墅','林表民','宋','宋诗','song-poetry','','[]','池館春方謝，連朝雨似烟。',48,'全唐诗/poet.song.195000.json','["池館春方謝，連朝雨似烟。", "亂荷藏睡鷺，繁木集嘶蟬。", "地僻觀書樂，心清得句玄。", "野僧時過我，携手弄雲泉。"]'),
('b288c2b7-c57c-4a82-bdfa-1baaa277ab41','寄餞趙清中主上元簿','林表民','宋','宋诗','song-poetry','','[]','六代舊都遺跡在，詞人懷古去登臨。',64,'全唐诗/poet.song.195000.json','["六代舊都遺跡在，詞人懷古去登臨。", "長干塔上青山遠，玄武湖邊碧草深。", "肯把簿書遮望眼，但圖方略副焦心。", "平江大海雖吾願，臺閣須材必訪尋。"]'),
('6d990b11-4e41-4fc5-8251-3f5ab7695a8d','寄聖水老法照','林表民','宋','宋诗','song-poetry','','[]','五載禪林結浄緣，又飛一錫過甘泉。',64,'全唐诗/poet.song.195000.json','["五載禪林結浄緣，又飛一錫過甘泉。", "曉池洗鉢雲常潤，夜閣繙經月自圓。", "碧眼誰參庭畔柏，赤身難並社中蓮。", "飽看勝景多佳句，好爲閑人寄一篇。"]'),
('4a7eefb2-24f0-4b93-ba4d-c2e69700b163','送薛子範明府歸永嘉','林表民','宋','宋诗','song-poetry','','[]','天台邑債今還了，未上清班意若何。',64,'全唐诗/poet.song.195000.json','["天台邑債今還了，未上清班意若何。", "行李比如初到少，鬢絲贏得近來多。", "民輸界首攀車送，君向城隅枉騎過。", "恨滿東風不能到，柳邊鶑語即驪歌。"]'),
('5302b335-fa51-4114-9bea-06ee90888bf8','次韻劉允叔丈主簿讀予所編天台集見贈之作','林表民','宋','宋诗','song-poetry','','[]','樓頭殘月映儲胥，人在西窗酒醒餘。',64,'全唐诗/poet.song.195000.json','["樓頭殘月映儲胥，人在西窗酒醒餘。", "夢裏都忘閬風路，吟邊如到玉霄居。", "鄰牆共作無何飲，別墅期看未見書。", "祇恐弓旌便招去，漢家答詔待相如。"]'),
('ab885d40-fcdd-4ad2-a038-47178082fa01','輓王房州伯洪','林表民','宋','宋诗','song-poetry','','[]','崇牙出鎮古邊頭，名與龔黄共一流。',64,'全唐诗/poet.song.195000.json','["崇牙出鎮古邊頭，名與龔黄共一流。", "方見勒碑歌善政，忽驚罷市哭仁侯。", "燕飛古巷人千里，梅落寒溪月一樓。", "前事已非那可問，晚雲零落綠山稠。"]'),
('221d2a49-f9f6-4906-8510-f7da3b4070a8','輓開府宋公','林表民','宋','宋诗','song-poetry','','[]','五朝大老今誰是，曉月長庚可愴然。',64,'全唐诗/poet.song.195000.json','["五朝大老今誰是，曉月長庚可愴然。", "王某曾當揮制日，伏生將及授書年。", "雁峰去就朱輪養，台嶺歸從白布纏。", "秩視冢司優贈典，夜臺光寵射穹躔。"]'),
('2b9bfc9c-6c0e-4507-8593-11af20fe9699','輓新昌王明府吉甫','林表民','宋','宋诗','song-poetry','','[]','不見高人祇自悲，每哦佳句望烏衣。',64,'全唐诗/poet.song.195000.json','["不見高人祇自悲，每哦佳句望烏衣。", "浣花風月參謀去，採藥溪山茂宰歸。", "萬里險艱頭已白，半生功業夢還非。", "阿戎盍上青雲路，奕世清門要發揮。"]'),
('e32c8e9e-bed3-4da7-bf58-9c4eebf79b76','輓處士張君','林表民','宋','宋诗','song-poetry','','[]','扣龍泉了探慈湖，倦矣歸携一束書。',64,'全唐诗/poet.song.195000.json','["扣龍泉了探慈湖，倦矣歸携一束書。", "白首功名銷壯氣，清溪游釣樂閑居。", "山人寧有趨戎幕，方伯今誰顧草廬。", "鄉舊凋零無復見，北風吹雨更愁予。"]'),
('59591633-dc7d-49fc-a73e-4527d8110e05','次韻沈興之稅院歲暮即事二首  其一','林表民','宋','宋诗','song-poetry','','[]','一簷寒雨滴愁聲，贏得松齋睡思清。',64,'全唐诗/poet.song.195000.json','["一簷寒雨滴愁聲，贏得松齋睡思清。", "急景不知年又謝，壯心空悵事無成。", "溫存凍壁火初舉，陵轢破窗風自鳴。", "多謝故交相慰藉，浪捐珠璧使人驚。"]'),
('55a7c4de-30b5-47d1-b944-31263c1ec28e','次韻沈興之稅院歲暮即事二首  其二','林表民','宋','宋诗','song-poetry','','[]','穿雲時有一鴻聲，喚雪風來冷更清。',64,'全唐诗/poet.song.195000.json','["穿雲時有一鴻聲，喚雪風來冷更清。", "臘意未教梅萼老，春風先放柳條成。", "亂離每嘆兵難戢，貧賤還憂道不鳴。", "節物一番空自好，暗添年紀却堪驚。"]'),
('e84e53eb-4651-4443-bb28-8b9c9304a80e','題大慈寺兼簡照講師','林表民','宋','宋诗','song-poetry','','[]','來從金地過銀地，智者修禪古道場。',64,'全唐诗/poet.song.195000.json','["來從金地過銀地，智者修禪古道場。", "疊嶂倚空圍日月，穹聳松壑飽風霜。", "碑文多是唐人刻，經卷猶隨煬帝藏。", "偶值故交初入院，一鐙留宿水聲房。"]'),
('4239aa6e-f161-4590-93e2-9b5faf3b5126','梁民曹以二首爲小園木香光寵次韻抒謝  其一','林表民','宋','宋诗','song-poetry','','[]','春風珠幰走青虬，清夜西園誰共遊。',32,'全唐诗/poet.song.195000.json','["春風珠幰走青虬，清夜西園誰共遊。", "十里水邊渾似雪，喚船應是誤王猷。"]'),
('56eeb7ca-6435-4c5a-9b5e-1ee27db3cbcd','梁民曹以二首爲小園木香光寵次韻抒謝  其二','林表民','宋','宋诗','song-poetry','','[]','攀條折蘂屬騷人，遲恐顛風掃玉塵。',32,'全唐诗/poet.song.195000.json','["攀條折蘂屬騷人，遲恐顛風掃玉塵。", "如付枕囊供醉寢，繁香薰骨解留春。"]'),
('a7e99efb-1ceb-472f-bd54-5bbcd32fa2e3','天台邵明府履善遺牡丹各賦一絕  其一','林表民','宋','宋诗','song-poetry','','[]','人間興廢手搏沙，喬木猶存少故家。',32,'全唐诗/poet.song.195000.json','["人間興廢手搏沙，喬木猶存少故家。", "不見石邊題甲乙，空餘姓氏落名花。"]'),
('e4e57fc1-ef34-4282-96a1-1214066dd0e5','天台邵明府履善遺牡丹各賦一絕  其二','林表民','宋','宋诗','song-poetry','','[]','一春苦雨又憂花，爛盡秧根穀再芽。',32,'全唐诗/poet.song.195000.json','["一春苦雨又憂花，爛盡秧根穀再芽。", "見說雲頭紅可喜，老農猶恐是朝霞。"]'),
('0bf70064-88bf-4a11-b985-6aaf40d6942c','天台邵明府履善遺牡丹各賦一絕  其三','林表民','宋','宋诗','song-poetry','','[]','可是東皇雨露深，不成一字亦腰金。',32,'全唐诗/poet.song.195000.json','["可是東皇雨露深，不成一字亦腰金。", "世間大有麒麟楦，對此誰能起媿心。"]'),
('c2debddb-fe07-4757-aeee-c5ae96dd8c4e','天台邵明府履善遺牡丹各賦一絕  其四','林表民','宋','宋诗','song-poetry','','[]','一枝美過玉柈盂，歲晚何由復遇蘇。',32,'全唐诗/poet.song.195000.json','["一枝美過玉柈盂，歲晚何由復遇蘇。", "我欲命名名不得，有名無實不如無。"]'),
('f557b910-4937-48db-acc2-593cf9d14b21','懷仙橋','林表民','宋','宋诗','song-poetry','','[]','晴雷晝夜激奔湍，澗草巖花亦耐寒。',32,'全唐诗/poet.song.195000.json','["晴雷晝夜激奔湍，澗草巖花亦耐寒。", "劉阮茫茫空仰止，恐乘風月一鞭鸞。"]'),
('cfc81692-822d-4654-b484-3be437b85daa','送倪平仲高士歸天台  其一','林表民','宋','宋诗','song-poetry','','[]','綠章封事步虛仙，來自東皇太乙邊。',32,'全唐诗/poet.song.195000.json','["綠章封事步虛仙，來自東皇太乙邊。", "滿袖明珠出光怪，又隨溪月上歸船。"]'),
('a5fa9917-74ff-4c2a-be03-ce0c0142a141','送倪平仲高士歸天台  其二','林表民','宋','宋诗','song-poetry','','[]','桐柏山高空翠寒，夜深星斗近仙壇。',32,'全唐诗/poet.song.195000.json','["桐柏山高空翠寒，夜深星斗近仙壇。", "下宮銀瀑三千丈，付與詩人雨後看。"]'),
('b80c456a-ab0e-4221-ab9d-4619f1c1276e','同謝鄒訪平老','林表民','宋','宋诗','song-poetry','','[]','江湖包笠今閑却，默坐惟繙貝葉文。',32,'全唐诗/poet.song.195000.json','["江湖包笠今閑却，默坐惟繙貝葉文。", "耳重懶聞時俗事，客來聊薦一甌雲。"]'),
('63da0c8c-35cf-43f8-b16f-c633b84ee673','送宗鏡上人歸剡因寄聲高九萬孫季蕃  其一','林表民','宋','宋诗','song-poetry','','[]','送師歸隠鏡山中，萬壑千巖指顧間。',32,'全唐诗/poet.song.195000.json','["送師歸隠鏡山中，萬壑千巖指顧間。", "菊磵花翁如見問，爲言憔悴老江關。"]'),
('d506a9c2-ea11-4f75-b125-9ae92e2f8617','送宗鏡上人歸剡因寄聲高九萬孫季蕃  其二','林表民','宋','宋诗','song-poetry','','[]','神剜天劃成巖洞，橫亙危梁接應真。',32,'全唐诗/poet.song.195000.json','["神剜天劃成巖洞，橫亙危梁接應真。", "垂下玉虹三百丈，雪花飛濺一山春。"]'),
('7c131395-e7d4-4a16-a08b-10760ccf8b30','送宗鏡上人歸剡因寄聲高九萬孫季蕃  其三','林表民','宋','宋诗','song-poetry','','[]','一僧禮拜能行過，下面人看膽亦寒。',32,'全唐诗/poet.song.195000.json','["一僧禮拜能行過，下面人看膽亦寒。", "月出幻成銀色界，始知方廣在林端。"]'),
('6283b96d-356a-4693-82db-644382f415b1','送宗鏡上人歸剡因寄聲高九萬孫季蕃  其四','林表民','宋','宋诗','song-poetry','','[]','隨處禪房有水聲，我來石上坐忘形。',32,'全唐诗/poet.song.195000.json','["隨處禪房有水聲，我來石上坐忘形。", "臨行更酌潭中淥，要洗多生業障清。"]'),
('3526b2ed-ee05-45fa-8dcc-75c961dad0d9','夜登桐柏上清閣','林表民','宋','宋诗','song-poetry','','[]','雨過中宵夜滿空，一山松竹韻溪風。',32,'全唐诗/poet.song.195000.json','["雨過中宵夜滿空，一山松竹韻溪風。", "披衣獨上上清閣，身在半天雲氣中。"]'),
('ed3b019b-7dbd-45ff-b5ca-4bf6675214a1','新昌道中','林表民','宋','宋诗','song-poetry','','[]','殘村時有兩三家，繚繞清溪路更賒。',32,'全唐诗/poet.song.195000.json','["殘村時有兩三家，繚繞清溪路更賒。", "客裏不知春去盡，滿山風雨落桐花。"]'),
('0667c5e3-55a9-45dc-bedb-c0875508def4','剡中詩','林表民','宋','宋诗','song-poetry','','[]','遺蹤曾記晉諸賢，乘興今無雪後船。',32,'全唐诗/poet.song.195000.json','["遺蹤曾記晉諸賢，乘興今無雪後船。", "斷塹毀垣難借問，磚文猶著太康年。"]'),
('60ef54ce-7484-4590-b5f2-98eaf6873380','題方叔所藏馬中遠春牧晚歸圖','林表民','宋','宋诗','song-poetry','','[]','一抹東風樹色新，牛羊莽莽散平原。',32,'全唐诗/poet.song.195000.json','["一抹東風樹色新，牛羊莽莽散平原。", "微烟細草知歸路，竹塢人家半掩門。"]'),
('18014d93-f8e5-4a29-ace6-39661310cb92','次韻王亞夫景存縣尉送春二首  其一','林表民','宋','宋诗','song-poetry','','[]','欲勸東君盡一杯，臨岐無語獨遲回。',32,'全唐诗/poet.song.195000.json','["欲勸東君盡一杯，臨岐無語獨遲回。", "晚風自有留連意，遞得鶑聲過柳來。"]'),
('c6a9be1e-b609-421d-9d0f-e802eea13ff4','次韻王亞夫景存縣尉送春二首  其二','林表民','宋','宋诗','song-poetry','','[]','登臨長是愛清暉，晚歲知心亦自稀。',32,'全唐诗/poet.song.195000.json','["登臨長是愛清暉，晚歲知心亦自稀。", "永晝松齋掩書坐，却看梁燕引雛歸。"]'),
('a0c5d457-a529-493f-a1a7-2820bea73a20','題六馬圖二首  其一','林表民','宋','宋诗','song-poetry','','[]','駿影爭馳意氣雄，被塵晴苑碧溶溶。',32,'全唐诗/poet.song.195000.json','["駿影爭馳意氣雄，被塵晴苑碧溶溶。", "誰將妙筆開生面，霧鬣風鬃慘淡容。"]'),
('14c78d64-3614-4acd-93ae-ea8034d5faa2','題六馬圖二首  其二','林表民','宋','宋诗','song-poetry','','[]','龍媒要是龍眠筆，意在能空冀北群。',32,'全唐诗/poet.song.195000.json','["龍媒要是龍眠筆，意在能空冀北群。", "老我惟知賞神駿，何時變化上青雲。"]'),
('56ea13c2-342f-4d22-8305-f9cc4f439017','同錢則父登郡城觀予所和梅仲潛金山弔東魯林表民逢吉詩淮民同賦一絕','林表民','宋','宋诗','song-poetry','','[]','水落寒沙晚照收，沙邊誰復艤孤舟。',32,'全唐诗/poet.song.195000.json','["水落寒沙晚照收，沙邊誰復艤孤舟。", "鮑昭自作蕪城賦，難寫江南不盡愁。"]'),
('870c6904-c57d-45da-9aa9-c7c947f6a631','西湖','林表民','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十三樓寺朝餐飯，六一泉亭晚舉觴。',32,'全唐诗/poet.song.195000.json','["十三樓寺朝餐飯，六一泉亭晚舉觴。", "千古湖山難模處，淡烟微雨更斜陽。"]'),
('9dc3f536-4252-471b-ab5b-6f7172474e07','題徐無競所藏花光仁老墨梅','林表民','宋','宋诗','song-poetry','','[]','江路冥迷飛霰密，道人定起幽情逸。',64,'全唐诗/poet.song.195000.json','["江路冥迷飛霰密，道人定起幽情逸。", "忽邀龍子幻新妝，粉淡香乾春一筆。", "寒梢瘦著苔衣昏，壞色空留夢裏身。", "幾回月墮交疏曉，霜髮相看不知老。"]'),
('cff6acee-95aa-4d02-8c39-b1e7e10815a3','寄懷仙居贊府尤貴端','林表民','宋','宋诗','song-poetry','','[]','樂安山水佳，遊屐獨未至。',156,'全唐诗/poet.song.195000.json','["樂安山水佳，遊屐獨未至。", "復有縣佐賢，欲見形夢寐。", "憶昨交際初，篝燈飲文字。", "數卷出寶儲，三人若鼎峙。", "相忘略形骸，同道許氣義。", "間之欻半朞，仰止惟一志。", "咸言居官清，或說立趣異。", "對松悟詩玄，飲水樂書味。", "於此可怡悅，視彼持遊戲。", "芸隠示倡酬，玉川辱簡記。", "不敏既重慚，有礙亦每喟。", "牖月揖耿光，瓶梅想幽致。", "思苦夜無眠，吟成托郵騎。"]'),
('7947c531-b47b-4fe3-b4db-fb6a9b3a6bec','試石鼓墨得月字韻','王邁','宋','宋诗','song-poetry','','[]','水聲響崢嶸，山勢高嵂矹。',168,'全唐诗/poet.song.195000.json','["水聲響崢嶸，山勢高嵂矹。", "我居山水間，瞥焉五閲月。", "看山寬眼界，聽水清詩骨。", "妙理在濁醪，淡交寄薇蕨。", "翻書明月軒，瀹茗清泉窟。", "一雨釀黄梅，連朝來不歇。", "雲疏漏簷光，晴意猶鶻突。", "卓午睡瞢騰，起來足不襪。", "搔首獨無言，書空時咄咄。", "天宇未清夷，世途良臲𡰈。", "丈夫志未酬，徒有衝冠髮。", "俛頭習科舉，與俗聊汩汩。", "壯圖要有待，非久黔吾突。", "富貴漸逼人，榮途軔須發。"]'),
('e17447d5-80ad-458b-a3f0-5bfb0ff4f781','題元山蔡行可對青亭','王邁','宋','宋诗','song-poetry','','[]','終日在山中，不見山可愛。',192,'全唐诗/poet.song.195000.json','["終日在山中，不見山可愛。", "欲識愛山趣，須在山之外。", "南山不古今，悠然與意會。", "西山無朝暮，佳致固長在。", "蔡君金玉人，結亭避闤闠。", "面面蒼璧屏，坐卧與青對。", "晚曦射紫翠，宿雨濯藍黛。", "能消幾兩屐，不賞此奇槩。", "芙蓉爲君裳，蘭茝爲君佩。", "今非避世時，乃學陶謝輩。", "諸公富唱酬，拔戟各成隊。", "我出一轉語，功成身始退。", "君爲端明胄，忠孝後必大。", "山靈縱有盟，一出合破戒。", "蒼生正有求，富貴不渠貸。", "山債會一償，相期在晚歲。"]'),
('a976e32a-0273-4289-9626-c7dcf24b2c2f','題弟綱舉之奉仙之室曰小蓬萊','王邁','宋','宋诗','song-poetry','','[]','吾祖有方平，曾與麻姑會。',168,'全唐诗/poet.song.195000.json','["吾祖有方平，曾與麻姑會。", "滄溟化爲田，彈指五百歲。", "又有仙人喬，神游八極外。", "朝舄作鳬飛，世緣比蟬蛻。", "寥寥千載後，之子得正派。", "風度亦可人，春秋况未艾。", "朝搬紫河車，暮結飛霞佩。", "嚴事鍾與呂，信心終不退。", "經營白玉壇，肖象儼相對。", "四面來青山，獻奇飛羽盖。", "爐熏徹玉虛，劍水清塵界。", "瓊笈閲千函，丹方探三昧。", "誰謂三鳬遥，近在吾境內。", "蓬萊若云小，孰能爲之大。"]'),
('8a91c16e-00cf-4007-b118-321547f0690c','跋黄京甫必昌提幹四書講義','王邁','宋','宋诗','song-poetry','','[]','吾友黄京甫，器資厚以渾。',168,'全唐诗/poet.song.195000.json','["吾友黄京甫，器資厚以渾。", "自了場屋債，徧參諸老門。", "四書不釋手，日旰忘晨飱。", "超悟到聖處，不能忘于言。", "序講凡五篇，字字比璵璠。", "伊洛有心印，傳受百聖源。", "紫陽有心燈，矚破萬世昏。", "得君再紬繹，提要鉤其玄。", "如印一洗滌，篆籀宛然存。", "如燈增膏油，光焰大且繁。", "我昔從師友，是書粗討論。", "老大學不進，德性焉能尊。", "因君重感慨，舊聞日當溫。", "願言剪枝葉，作意事本根。"]'),
('a64a5d74-0dd1-41ef-a261-206af73cdf6f','甲戌九月日有食之紀異三十韻','王邁','宋','宋诗','song-poetry','','[]','甲戌九月秋，朔旦見災眚。',288,'全唐诗/poet.song.195000.json','["甲戌九月秋，朔旦見災眚。", "孛彗犯太陽，凄凄如月冷。", "方其始虧時，宛然蟲食皿。", "食之至於既，當空懸黑餠。", "髣髴存輪圈，中陷猶枯井。", "雲間星晝見，草木森弄影。", "天地寂無聲，疑似非人境。", "問之道旁翁，欲語喉先哽。", "翁今九十餘，眼未見此景。", "爰有蟣虱臣，拜跪淚沾領。", "天高聽則卑，宜鑒愚臣請。", "日者陽之宗，千古光常炳。", "此日何不臧，臣心憂耿耿。", "或者天愛君，先事示之警。", "流金爲湯戒，洚水爲堯儆。", "雖重一時憂，何傷天歷永。", "吾君今堯湯，四海元元幸。", "公道大開明，朝列肅而整。", "祇恐萬一間，左右容憸悻。", "方秋陰用事，陽微陰漸逞。", "不去讒慝根，懼作忠良穽。", "天乃出怪異，意欲悟觀省。", "吾國必有人，伏蒲輸骨鯁。", "吾君必開納，小心知畏謹。"]'),
('e0c2fd21-dd49-4e2e-aff7-a4308ad7db98','讀林去華居厚主簿省題','王邁','宋','宋诗','song-poetry','','[]','病夫夜不眠，五鼓始交睫。',264,'全唐诗/poet.song.195000.json','["病夫夜不眠，五鼓始交睫。", "懶起比吳蠶，清夢飛莊蝶。", "恭承高軒過，不及倒屣接。", "惠我百篇詩，珠璣何煒燁。", "五言比長城，一望皆危堞。", "壯如廣陵散，悲似陽關疊。", "音韻最清圓，格律尤妥帖。", "登壇裨將降，咒水小巫怯。", "永嘉富人物，往躅足追躡。", "經術止齋陳，文章水心葉。", "林君游其門，早負賢關篋。", "鄉校設臯比，戶外紛屨屧。", "科目苦無憑，取捨如漁獵。", "入網多弱翰，上鈎希巨鬣。", "西廊上奏篇，甲第僅書捷。", "低頭矮屋中，壯氣不萎薾。", "研朱點周易，修此清浄業。", "焚香讀楚詞，時作真行帖。", "臺府歲舉員，求者例有挾。", "孤士乏梯媒，剛腸羞婦妾。", "諸公縱憐才，或被權勢劫。", "誰能推輓之，士論得欣愜。"]'),
('881cbb13-1a90-48ae-b27a-8e0c403e6bf0','東歸同年三山王簿賓之趙戶立父連簿仁父黄上舍偕行分道買樽酌別','王邁','宋','宋诗','song-poetry','','[]','我從京華來，溽暑不可邇。',252,'全唐诗/poet.song.195000.json','["我從京華來，溽暑不可邇。", "藍縷一征衣，邂逅四君子。", "臭味同芝蘭，鄉井連桑梓。", "王君吾兄行，派出銅川氏。", "一飲吞百盃，一揮爛十紙。", "此是鑾坡人，非久棲鸞枳。", "黄君天庠英，貴名方日起。", "三年拜賜師，行雪殽函恥。", "後來幾英豪，願作榜下士。", "小連真可人，犀玉浮冰峙。", "再鼓氣不衰，收科趾前美。", "朋山萬青衿，求識習鑿齒。", "立父天族英，雅非膏粱比。", "青桂近嬋娟，紅蕖映青泚。", "名駒産天廐，一日當萬里。", "今夕知何夕，德星偶同晷。", "明月入觥船，凉颸生劍履。", "相逢吳山頭，相別閩江觜。", "交情托管鮑，同年序許李。", "明日懷美人，娟娟隔秋水。", "何以慰我思，馳書寄雙鯉。"]'),
('3262e39b-02d3-49f8-8add-f991b45bf566','東歸至衢城十五里頭','王邁','宋','宋诗','song-poetry','','[]','征衣犯火雲，來自長安道。',288,'全唐诗/poet.song.195000.json','["征衣犯火雲，來自長安道。", "浹背汗淋漓，遵程行數跛。", "險阻已備嘗，習氣覺如掃。", "京華紈袴兒，顔色差强好。", "玉斝酌玻瓈，金盤飣水果。", "享此竟無端，榮枯太顛倒。", "嗟余數之奇，涉世嗟枯槁。", "青雲志未酬，午夜心如擣。", "浪蹈軟紅塵，有懷白雲老。", "决策賦歸歟，受此大轗軻。", "倚杖立沉吟，持盃澆磊砢。", "生平忠憤心，皎皎通穹昊。", "一身不足憂，世途深可悼。", "往歲淮甸間，邊吏困科瑣。", "金鼓聲漲天，溝壑填肝腦。", "一旦計之窮，首謀伏天討。", "眈眈慾無厭，百計需金寶。", "今者馳使車，囊橐費賫裹。", "乳臭坐廟堂，苟免及身禍。", "誰知鴻雁鳴，朝夕不相保。", "旱蝗莫爲災，四望無青草。", "我輩獨何心，日夕憂江左。", "豈不欲救之，勢力顧未可。", "敬持一瓣香，好爲蒼生禱。"]'),
('76789f38-8dde-45b5-9cd4-ac808180a080','父執德化陳宰叔高槩寄詩和之','王邁','宋','宋诗','song-poetry','','[]','欲作好官易，與時同俯仰。',204,'全唐诗/poet.song.195000.json','["欲作好官易，與時同俯仰。", "欲作好人難，前修嚴矱矩。", "馬安爲巧宦，孔光位宰輔。", "貽臭汗青中，詬駡之所聚。", "胡威清比父，魏謩直肖祖。", "世家有若人，百不一二數。", "夫君少壯時，筆力迫韓杜。", "晚歲宰一同，治最方卓魯。", "中都清要官，唾手可搏取。", "徑掛神武冠，去國身如羽。", "隠几挹青山，稱觴環綵舞。", "導養學熊鶴，鉛汞成龍虎。", "妙香參鼻觀，虛白生靈宇。", "興來聳文筆，象物蒙藻黼。", "客至開香醪，鯨量少儔伍。", "我登清風堂，人今道則古。", "敬宣與狎崇，所擇聽張禹。"]'),
('e9a8936b-d8ad-40d6-9a5a-a8b1cc662391','別永福張景山','王邁','宋','宋诗','song-poetry','','[]','我友滿天下，面交如斗量。',204,'全唐诗/poet.song.195000.json','["我友滿天下，面交如斗量。", "最晚得張子，羣中孤鳳凰。", "秀氣分高蓋，妙年侔洛陽。", "趨向頗近道，才具已老蒼。", "蘭若參文盟，過眼五月彊。", "別我求贈言，握手吐肝腸。", "學貴根書茂，積貯焉可忘。", "如行千里路，須具三月糧。", "文亦有活法，先使意氣張。", "如破勍敵壘，須擒賊中王。", "子家藹文獻，庭砌多琳琅。", "歸歟力種績，宜親師友良。", "植本日以大，養氣日以昌。", "學豐敷爲文，如富出所藏。", "襟期要犖犖，俗物徒茫茫。", "他日泉石下，候氣視北方。", "知有滔滔者，非予誰其當。"]'),
('13942ba0-b61c-4b2c-b851-487da4a02e75','白髮吟','王邁','宋','宋诗','song-poetry','','[]','明發覽青銅，寸白墜華簪。',216,'全唐诗/poet.song.195000.json','["明發覽青銅，寸白墜華簪。", "懸知不能免，豈意遽見侵。", "憶昔隨羣兒，總角混青衿。", "縱弱不好弄，既冠知惜陰。", "時開磊塊胸，澆之以古今。", "二十偕計書，進士路欹嶔。", "遲遲十四年，一第酬苦心。", "今年已六六，暮景來駸駸。", "一髮照我眸，衆髮立森森。", "忽然一失笑，政要渠相尋。", "有田願種玉，有腰願垂金。", "富貴豈不好，勞鹿那能禁。", "何如一床書，侑之綠綺琴。", "遠參蘭茝香，清玩山水音。", "高歌月滿架，醉卧斗橫參。", "待教頭半白，掛冠老山林。", "飲犢青草浦，盟鷗白沙潯。", "憑虛喚張陸，聽我白髮吟。"]'),
('bc4c9cd9-7511-45f2-b2c9-0cd535d5bb3d','白髮嘆  其一','王邁','宋','宋诗','song-poetry','','[]','日月轉四時，團團輾清昊。',156,'全唐诗/poet.song.195000.json','["日月轉四時，團團輾清昊。", "人生一世間，輕塵棲弱草。", "寒暑不相貸，容鬢豈常好。", "嗟予涉世紛，聞道苦不早。", "塵勞縱掀簸，冉冉風中葆。", "行年將四十，素標已插腦。", "星星纔數莖，爛熳色勝縞。", "耘鑷雖暫無，安能遏衰槁。", "黄精似可餌，已白恐難掃。", "幸有琴心文，真訣堪却老。", "華池溉隠芝，青青可常保。", "斯理不吾欺，從今勤探討。", "要當驗他時，難爲常人道。"]'),
('33312bc3-6904-4383-8aa6-23fd6bed9a3e','白髮嘆  其二','王邁','宋','宋诗','song-poetry','','[]','青銅作明鑑，皎皎鋪晴昊。',156,'全唐诗/poet.song.195000.json','["青銅作明鑑，皎皎鋪晴昊。", "照我沐初晞，幾縷經霜草。", "本無適俗韻，頗識林園好。", "何爲浪自苦，落得衰顔早。", "懸知日夜改，青絲成素葆。", "達人遺世累，土木視肝腦。", "那於形骸間，計校玄與縞。", "彼獨何人哉，而我嘆枯槁。", "壯年不可挽，過日如霜掃。", "但有歲寒心，不逐冰霜老。", "誓開三徑荒，種藝雜庸保。", "雖無大藥資，尚得恣幽討。", "此外盡悠悠，置之不復道。"]'),
('30df495e-7a1b-4088-b3c4-f6cb9a823967','題江郎石','王邁','宋','宋诗','song-poetry','','[]','崒嵂天外來，生平眼不識。',252,'全唐诗/poet.song.195000.json','["崒嵂天外來，生平眼不識。", "道傍問行人，指此爲何石。", "云是江郎神，茲地顯靈迹。", "岳瀆孕精靈，陰陽陶器質。", "壁立千萬仞，葱然翠欲滴。", "縹緲出塵寰，上與太清迫。", "伏如蛟龍蟠，聳如麒麟逸。", "開如旌旗揚，斂如圭綬直。", "交酬如大賓，相敬見顔色。", "特立如正女，齋莊不可昵。", "勇如毛大夫，囊錐推穎出。", "烈如藺相如，挺身衛全璧。", "勁如傅介子，叱咤在三尺。", "直如太史公，巉巖操史筆。", "裒萃許精英，狀出大奇特。", "誰言造化工，於物無雕刻。", "我來揖清標，倚杖立歎息。", "年來天柱傾，誰是扶持力。", "願移此靈根，支拄天西北。", "三光五岳氣，要使合爲一。", "血食千萬年，與國同無極。"]'),
('ebcaefcf-3ef4-4b3d-b94b-67ba44355e81','和趙簿題席麻林居士小隠四韻  其一','王邁','宋','宋诗','song-poetry','','[]','公子有奇節，歲寒心印松。',48,'全唐诗/poet.song.195000.json','["公子有奇節，歲寒心印松。", "千邱仍萬壑，是中雅能容。", "晚來萬事懶，獨有詩不慵。", "諸郎富文采，筆端聳孤峰。"]'),
('dca40f4d-6e0c-443b-a2b0-e5f7d995df97','和趙簿題席麻林居士小隠四韻  其二','王邁','宋','宋诗','song-poetry','','[]','繞園萬竿竹，奇壑千丈松。',48,'全唐诗/poet.song.195000.json','["繞園萬竿竹，奇壑千丈松。", "此物匹高士，坐羞桃李容。", "客至談世故，接之令人慵。", "相看兩不厭，晴昊倚高峰。"]'),
('954cbbf7-3f24-45bd-af02-c9dfb76dcf56','和趙簿題席麻林居士小隠四韻  其三','王邁','宋','宋诗','song-poetry','','[]','棋聲響蒼石，茶竈燒枯松。',48,'全唐诗/poet.song.195000.json','["棋聲響蒼石，茶竈燒枯松。", "故人惠然來，風竹爲先容。", "野性曠而適，機心疏更慵。", "生憐謝安石，携妓汙名峰。"]'),
('7d8e0a46-7667-4213-92ef-ab7850fcc5fa','和趙簿題席麻林居士小隠四韻  其四','王邁','宋','宋诗','song-poetry','','[]','笙簧豈不韻，雅景受風松。',48,'全唐诗/poet.song.195000.json','["笙簧豈不韻，雅景受風松。", "紈綺可爲裳，靈均采芙蓉。", "古來曠達士，世膩亦太慵。", "可望不可押，人如雲外峰。"]'),
('218e808c-be1b-4d2b-b647-5216278aeb06','題趙別駕委齋詩','王邁','宋','宋诗','song-poetry','','[]','別駕來訪別，徵我委齋詩。',288,'全唐诗/poet.song.195000.json','["別駕來訪別，徵我委齋詩。", "敢問委之說，別駕自發揮。", "萬事悉委分，吾何容心爲。", "抱槧游文屋，去取委所司。", "一戰偶得雋，敢誇詞藻奇。", "隨牒走仕途，薦舉委所知。", "一朝獲通籍，敢恃妍媚姿。", "不見百里奚，非黠亦非癡。", "爵祿委倘來，飯牛牛自肥。", "不見塞上翁，無喜亦無悲。", "得喪委自然，失馬馬復歸。", "委懷在琴書，栗里真吾師。", "委順聽時命，香山不吾欺。", "吾以名吾齋，曰委不亦宜。", "王子曰不然，我言異於斯。", "人性涵萬善，其位配兩儀。", "凡天所委付，受者不得辭。", "行藏道汙隆，進退時安危。", "委禹以治水，胼胝敢言疲。", "委尹以復辟，寵利非謀私。", "經制委姬旦，述作委仲尼。", "今古理無二，聖賢人可希。", "綱常或淪斁，委我開訓彝。", "楊墨路必闢，韓莊門宜麾。"]'),
('9b60f2fd-853d-49a9-88b5-a2f013429272','送族姪千里歸漳浦','王邁','宋','宋诗','song-poetry','','[]','吾宗居漳濱，枌社足不到。',264,'全唐诗/poet.song.195000.json','["吾宗居漳濱，枌社足不到。", "迫歲携琴書，迢迢以謁告。", "草木同臭味，水火隨濕燥。", "行色念辛酸，開樽勤燕勞。", "葭管陽方升，凌室冰新破。", "語言頗有味，知子爲跨竈。", "日暮望白雲，江頭理歸柂。", "別我乞贈言，求以爲宗好。", "謝安自薦玄，杜子每念佐。", "子真玄佐流，我譽不爲過。", "惟學無他逵，損益在勤惰。", "我昔少年日，螢雪功自課。", "嘔肝綴文詞，懸膽警坐卧。", "甑寒心自憐，筆凍指欲墮。", "牛羊事芻牧，鴻雁謀粱稻。", "慈親日待養，一第天所報。", "願子繼自今，書田深種播。", "定力要堅持，居安謹無躁。", "青雲信有梯，我已爲前導。", "後來當有人，衮衮如響和。", "洗耳候凱音，嘉節迫吹帽。", "呼童辦楮英，爲子征西賀。"]'),
('fb135aae-0dc4-4289-ba18-a8861bb87afb','四十自壽','王邁','宋','宋诗','song-poetry','','[]','前四十年非，追之已莫返。',72,'全唐诗/poet.song.195000.json','["前四十年非，追之已莫返。", "後四十年是，圖之良未晚。", "水涸自見涘，木落知見本。", "善者契吾機，今復猶不遠。", "養生先節慾，葆粹在懲忿。", "聖賢人可爲，勿使善惡混。"]'),
('6dc01755-c2a4-4ea2-aa07-5848fd0acde4','寄居元職方北第呈西鄰盛進士','王邁','宋','宋诗','song-poetry','','[]','解褐去鄉里，宦游一紀餘。',144,'全唐诗/poet.song.195000.json','["解褐去鄉里，宦游一紀餘。", "抱慼今來歸，茫然無屋廬。", "暮瞻還林鳥，朝羨趨淵魚。", "淵林各有歸，曾不魚鳥如。", "元侯雅好義，假我舍北居。", "入門掃埃𡏖，閑草以次鋤。", "貧賤誰顧門，豈必容高車。", "餘杭衆富家，碧瓦侵太虛。", "土木雖無情，亦與儒冠疏。", "所幸並舍賢，昔年同詩書。", "何茲瓦礫陋，復爾鄰璠璵。", "鄉田及同井，此義無忽諸。"]'),
('c9f956ce-e979-4ac0-97f4-b5b6b3be3b30','寄同年新塗王宰夢弼','王邁','宋','宋诗','song-poetry','','[]','玉笥高嵯峨，異石光燦皠。',288,'全唐诗/poet.song.195000.json','["玉笥高嵯峨，異石光燦皠。", "紫蓋有佳人，出爲花縣宰。", "佳人秀吾宗，天姿最高塏。", "飲水抱絲絃，紉蘭纕蕙茝。", "疇昔糾郡掾，辯獄亦幾殆。", "人命我所爭，斗粟何足愛。", "上官翻相知，剡薦異寮寀。", "及膺民社寄，直道肯自悔。", "以柔克高明，爲政尚慈愷。", "農扈飽春和，荒年獨不餒。", "猾吏履薄霜，洗手畏納賄。", "桑間雉正馴，壁上魚多鯘。", "昔我在湘幙，相從垂兩載。", "書生守方拙，時粧不入隊。", "惟君雅知心，刮目賞奇磊。", "君有桃李栽，我獨芙蓉采。", "無何風木悲，天乎余何罪。", "歸歟泣焄蒿，久矣嬰病痗。", "除夜接君書，烏欄墨璀璀。", "訪問死生餘，警語鞭不逮。", "爲言剛近仁，直性終難改。", "近乃加和平，痛自鏟光彩。", "萬事必宗道，衆流須納海。", "隨時少屈伸，正直固常在。"]'),
('cf61f2ea-c15d-4348-add1-ef354185e315','靈白湖歸憩林氏墳庵僧出能誦予舊詩設茗椀蒲食以詩贈之兼寄呈林六十兄','王邁','宋','宋诗','song-poetry','','[]','霜風襲客裘，朝日曬農背。',180,'全唐诗/poet.song.195000.json','["霜風襲客裘，朝日曬農背。", "誰遣役此軀，隠痛在五內。", "宿草漸重生，跼蹐處覆載。", "扶衰策瘦筇，乞靈問龜蔡。", "往來纔信宿，屏息過闤闠。", "夙駕三十里，僕夫已告憊。", "小庵闞道旁，丈室藏法界。", "叩扉僧出迎，面熟不猜怪。", "白髮久不梳，爬癢得痛快。", "荷設茗椀供，仍有蒲食配。", "去此已五霜，重來發孤慨。", "一飽猶可謀，三釜已不逮。", "退藏心甚甘，世故肯相貸。", "博陵隠君子，堂萱春未艾。", "悠悠我之思，此日君當愛。"]'),
('d1bacf9c-36b1-4e51-8821-b34a34f15e9a','簡延平李公足擇善','王邁','宋','宋诗','song-poetry','','[]','昔人重相思，千里且命駕。',180,'全唐诗/poet.song.195000.json','["昔人重相思，千里且命駕。", "我家去游洋，相望纔四舍。", "偃息豈不思，吉服詎可借。", "惟憑一雁翔，敢望雙鳬下。", "日者聞琴堂，墨綬將解卸。", "東閣領羣英，勝遊當首夏。", "惠然訪九仙，雲物爭迎迓。", "拂石納晚凉，秉燭娛清夜。", "吉碑共摩挲，吉夢相矜詫。", "物色故老言，赤鯉何年化。", "題詩富錦囊，仙境爲增價。", "是地近吾廬，過從何未暇。", "初傳尚半疑，後信良多訝。", "世態如浮雲，炎凉更代謝。", "高誼定不然，寄聲來慰藉。"]'),
('e8c5a88e-f3d5-4f3e-a5fc-e91468db851e','簡林公似','王邁','宋','宋诗','song-poetry','','[]','窮猿不擇木，祥鳳宜棲竹。',144,'全唐诗/poet.song.195000.json','["窮猿不擇木，祥鳳宜棲竹。", "高門結駟榮，陋巷一瓢足。", "仕有時爲貧，貧乃急於祿。", "夫君何所欠，百事盡從欲。", "新諧種玉婚，大敞堆金屋。", "鏡裏顔尚朱，庭前萱正綠。", "中州不徜徉，炎海甘馳逐。", "遂令君子心，度以小人腹。", "我貧甚去年，全家久食粥。", "獨醒妬人醉，譏誚那免俗。", "名節千載光，富貴一炊熟。", "朋友嚴簡書，敢以石攻玉。"]'),
('b0e9814a-266c-4e50-8bc9-0dfc84484437','寄浙漕王子文野以思君令人老五字爲韻得詩五首  其一','王邁','宋','宋诗','song-poetry','','[]','長沙一傾蓋，情好如塤箎。',108,'全唐诗/poet.song.195000.json','["長沙一傾蓋，情好如塤箎。", "間關十寒暑，何時不相思。", "君爲睢邸教，再挹冰玉姿。", "升堂拜壽母，摩頂識馨兒。", "敘舊方戀戀，臨分轉依依。", "自是成鴻燕，羽翼竟差池。", "音問久不接，清宵夢見之。", "魚腹得尺素，羊胛經幾炊。", "陳雷不可作，千載同襟期。"]'),
('456ea384-310f-49db-b965-bd981a704fd8','寄浙漕王子文野以思君令人老五字爲韻得詩五首  其二','王邁','宋','宋诗','song-poetry','','[]','我友半湖海，知心吾子文。',108,'全唐诗/poet.song.195000.json','["我友半湖海，知心吾子文。", "君忙我已老，事事不如君。", "君生通貴家，我出寒素門。", "君披貂毛裘，我著犢鼻褌。", "戲綵君有母，列鼎共凊溫。", "我早失烏哺，空山悵白雲。", "弱冠君有子，世科將襲芬。", "我子方垂髫，詩禮未有聞。", "凡此皆不如，官職不必論。"]'),
('85b1492f-73ca-4ca8-b18a-63531c07917b','寄浙漕王子文野以思君令人老五字爲韻得詩五首  其三','王邁','宋','宋诗','song-poetry','','[]','原明有申公，公休繼文正。',108,'全唐诗/poet.song.195000.json','["原明有申公，公休繼文正。", "後來諸名家，有子多不令。", "堂堂先太史，孤峭立萬仞。", "身不爲從官，美謚君所命。", "子文爲之子，壯歲名已盛。", "榮華付倘來，節義傳心印。", "波流石不移，火熾玉寧盡。", "嚮來牋天疏，每讀必起敬。", "相期輝國史，何止續家乘。"]'),
('d7e9d734-23e0-4efb-a063-df141d7fc201','寄浙漕王子文野以思君令人老五字爲韻得詩五首  其四','王邁','宋','宋诗','song-poetry','','[]','西山門下士，雜襲如魚鱗。',108,'全唐诗/poet.song.195000.json','["西山門下士，雜襲如魚鱗。", "惟我與子文，受愛異他人。", "送我長沙序，言言足書紳。", "贈君樵川詩，字字示寵珍。", "潛齋養正堂，兩記尤諄諄。", "爲君說太玄，藏心養靈根。", "爲我演蒙頤，山立靜澄神。", "先生愛吾徒，不啻子弟親。", "將何報此德，相與玉其身。"]'),
('db621dfe-9767-46a6-8cfe-206eb7fcf2f7','寄浙漕王子文野以思君令人老五字爲韻得詩五首  其五','王邁','宋','宋诗','song-poetry','','[]','我本麋鹿羣，官職不要討。',108,'全唐诗/poet.song.195000.json','["我本麋鹿羣，官職不要討。", "儋石倘有儲，山林堪佚老。", "焚香旦告天，非爲其私禱。", "一願屢豐年，田疇足禾稻。", "二願息兵戈，塗地無肝腦。", "飲水樂在中，茹芝顔轉好。", "篤信而好學，守死以善道。", "佩此八字符，傳爲子孫寶。", "作詩寫殷勤，未省蒙印可。"]'),
('abba51f1-808f-445d-8ae2-87cd07da2fcb','與友人飲分等字韻','王邁','宋','宋诗','song-poetry','','[]','君詩敵曹劉，我才慚碩頲。',108,'全唐诗/poet.song.195000.json','["君詩敵曹劉，我才慚碩頲。", "隠几共團圞，醉鄉從酩酊。", "强吟蹙眉尖，得句蒙首肯。", "吟蛩聲咿咿，銀燭光耿耿。", "相看不惜夜，自足攻逆境。", "搜腹憐龜腸，朶頤傍羊鼎。", "論文固非儔，義氣略相等。", "世情似紙輕，交道如菰冷。", "願堅松柏心，歲寒青挺挺。"]'),
('e8e29445-db70-406b-9d21-eacb4c300cb9','贈傳神莊士儀','王邁','宋','宋诗','song-poetry','','[]','畫工亦無數，好手不可遇。',156,'全唐诗/poet.song.195000.json','["畫工亦無數，好手不可遇。", "非是畫事難，難得畫中趣。", "况寫佳士照，又不比行路。", "莊生頗工此，爲我掃尺素。", "儼然山澤臞，詩肩瘦鳬鷺。", "老色雖上顔，庾塵莫能污。", "生畫甚迫真，餘子等孩孺。", "得錢散酒家，無心問婚娶。", "醉被風雪欺，術招鬼神妬。", "長安多貴人，朱門富紈絝。", "使聞生之名，當即懸金募。", "我貧亦如生，正以詩窮故。", "一畫博一詩，兩手相分付。"]'),
('7961e652-589a-4929-abfe-ba5f4fed45d8','殿廷初考諸同舍約共賦詩','王邁','宋','宋诗','song-poetry','','[]','紹丑夏五初，皇帝下明詔。',276,'全唐诗/poet.song.195000.json','["紹丑夏五初，皇帝下明詔。", "大廷策羣英，虛心問道要。", "初考凡六員，同時赴宣召。", "宮講絜齋子，典刑真克肖。", "胄丞道鄉孫，道心長返照。", "何殊鐘在簴，宛如刀出鞘。", "谷口亦何人，才德俱富邵。", "走也分塵埃，識見等螢爝。", "亦獲在選中，所得過所料。", "宮燭分夜輝，御香供早燒。", "羣羽競赴矰，衆鱗爭入釣。", "意氣雲龍翔，精神風虎嘯。", "或巽入柔行，或疾聲大叫。", "或自出機軸，或工事竊剽。", "或寫雲和音，或鼓折楊調。", "或作朝鳳鳴，或吟蚯蚓竅。", "好惡隨品題，寧復相譏誚。", "上方富春秋，明齊日月耀。", "涓露增滄溟，微塵填嶽嶠。", "乙覽公平章，甲科須直峭。", "諷必納祈招，箴必容庭燎。", "國步頼扶持，民痍需砭療。", "詰朝已竣事，杯行可以釂。"]'),
('5859f2af-6d37-44b5-aa14-4e93c4a4ec8f','謝京尹惠酒饌','王邁','宋','宋诗','song-poetry','','[]','逐客次江干，復此風雨夜。',228,'全唐诗/poet.song.195000.json','["逐客次江干，復此風雨夜。", "元戎念寂寥，更僕相慰藉。", "醽醁實珍肴，寵光生邸舍。", "妻孥共感慼，道路或猜訝。", "謂此偃蹇蹤，橫被彎弓射。", "彼哉簧正巧，或者石猶下。", "同志欲過從，避黨輒驚怕。", "曾謂十連尊，理煩無頃暇。", "惠顧及無聊，多言莫爲謝。", "平生仗信義，正色叱姦詐。", "此樣不入時，致入人話靶。", "明時方獻文，安得有謗駡。", "獨以殿廬中，語言少假借。", "遂犯螳螂怒，間坐鴟鴞嚇。", "先期入簾幕，坐是罹罟擭。", "公施不報恩，高義等嵩華。", "一言挾纊溫，所嗜非酒炙。", "天日方清明，罪過宜宥赦。", "白璧可洗瑕，煩公叩造化。"]'),
('d2c94dbd-66a2-4601-b71b-ef4f45a1471e','簡同年刁時中俊卿詩','王邁','宋','宋诗','song-poetry','','[]','讀君老農詩，一讀三太息。',288,'全唐诗/poet.song.195000.json','["讀君老農詩，一讀三太息。", "君方未第時，憂民真懇惻。", "直筆誅縣官，言言虹貫日。", "縣官怒其訕，移文加誚斥。", "君笑答之書，抗辭如矢直。", "旁觀爭吐舌，此士勇無匹。", "今君已得官，一飯必念國。", "民爲國本根，豈不思培植。", "其如邊事殷，賦役煩且亟。", "虎營間二千，鳩工日數百。", "硬土燒熾窑，高崗輿巨石。", "山骨慘無青，犢皮腥带赤。", "羸者頳其肩，饑者菜其色。", "憔悴動天愁，搬移驚地脈。", "吏饕鷹隼如，攫拏何顧惜。", "交炭不論斤，每十必加一。", "量竹不計圍，每丈必贏尺。", "軍則新有營，誰念民無室。", "吏則日飽鮮，誰憫民艱食。", "州家費不貲，帑藏空儲積。", "間有小人儒，旁獻生財策。", "大帥令龔黄，豈願聞此畫。", "夏潦苦不多，秋旱勢如炙。", "願君在莒心，端不渝疇昔。"]'),
('a9c677af-c14b-409c-8436-e97e3f62084d','簡復齋陳寺丞子表夫知丞併呈真西山','王邁','宋','宋诗','song-poetry','','[]','復齋吾之師，高山儼標致。',288,'全唐诗/poet.song.195000.json','["復齋吾之師，高山儼標致。", "僕嘗函丈間，乞得四箴字。", "及來仕京華，登門願受記。", "復齋首肯之，贈言簡而毅。", "殺身可成仁，舍生甘取義。", "此生尚可輕，圭黍眇爵位。", "僕退書之紳，雋永言有味。", "充員京兆幕，萬一可行志。", "赧顔斥吏胥，冷眼視權貴。", "婉嫿孤無朋，旁觀輒相忌。", "朝肆緝緝讒，暮遭申申詈。", "聖主初臨軒，不才叨考試。", "諸賢憚生語，一律愛軟媚。", "我喜衆所驚，人取我必棄。", "間有植私恩，了不恤公議。", "枘鑿不相投，罟擭焉得避。", "襆被去候潮，襁褓有幼稚。", "少需辰之良，解纜辭清渭。", "邂逅復齋子，入京方卸轡。", "爲言東湖上，英才日以萃。", "窮伊洛淵源，傳紫陽位置。", "要使莆三邑，薰爲善良地。", "僕也間斯言，歸心生兩翅。", "平生真西山，赤心愛善類。"]'),
('807c47d2-f27a-4efa-bcba-7fb761d99517','親舊問盜作詩四十韻以答之亦可備野史之錄','王邁','宋','宋诗','song-poetry','','[]','我來自京師，己丑之十月。',288,'全唐诗/poet.song.195000.json','["我來自京師，己丑之十月。", "道之建劍間，行行遇兵卒。", "問之何爲行，對言聲哽咽。", "初只因臨汀，鹽商時出沒。", "縣官事張皇，星夜聞帥鉞。", "帥出乃捕兵，此曹輒猖獗。", "加之江西寇，恃嶮護巢穴。", "向來誤殺降，貽禍今尤烈。", "合黨肆紛披，交鋒爭桀黠。", "聚落四百村，室廬遭毀爇。", "轉徙臨昭陽，孤城危一髮。", "帥方實歸裝，視此苦不切。", "惟漕暨庾臺，協心圖撲滅。", "移文責十連，義激詞語辣。", "就檄劉權軍，專城植鎩𢧕。", "又有一老尉，賈勇抗鴟鶻。", "頼此所居民，猶苟旦暮活。", "我聞此卒言，憂憤中腸熱。", "及歸抵吾廬，保伍亦團結。", "或恐汀邵寇，餘燼尚分裂。", "或疑鼠狗徒，乘間敢竊發。", "吾鄉號樂國，目不見寸鐵。", "一聞鉦鼓聲，縮頭畏如鱉。", "新歲或訛言，城居竟搬挈。"]'),
('0c10361b-f0c7-4c37-b14d-5ee3e255aa0b','鄭昂叔和余問盜詩末及山東事弟姪輩又問山東本末再用前韻答之','王邁','宋','宋诗','song-poetry','','[]','江左百年來，英雄老歲月。',288,'全唐诗/poet.song.195000.json','["江左百年來，英雄老歲月。", "空糜東南財，坐廩驕惰卒。", "嘉定懲開禧，廢食因一咽。", "國論規便安，神州聽淪沒。", "和戎益金繒，諱戰鈍斧鉞。", "邇者天禍之，韃靼逞狂獗。", "一舉殄金人，犁庭掃其穴。", "金如釜中魚，靼如火烈烈。", "乘間蠻觸衡，復有山東黠。", "長驅淮甸間，大縱山陽爇。", "或屠制帥家，或髠守臣髮。", "魚肉我王人，首領春葱切。", "塗炭我生靈，聚落炊烟滅。", "嫚書揭通衢，著語太辛辣。", "供帳王者居，左纛將軍紱。", "往來青齊區，健比霜天鶻。", "一名娘子軍，掎角同生活。", "狼心肆陸梁，烽燧競熏熱。", "我事南方强，謂可以恩結。", "衣裳一顛倒，茅土甘疏裂。", "納侮忍包羞，容姦噤不發。", "誰與生厲階，正爾錯鑄鐵。", "彼計甚詐狙，吾謀類跛鱉。", "歲幣久樁儲，復爲彼齎挈。"]'),
('8f31b037-aaed-4735-b295-12d1eda66766','弔何巖','王邁','宋','宋诗','song-poetry','','[]','可憐何巖民，何罪遭此劫。',288,'全唐诗/poet.song.195000.json','["可憐何巖民，何罪遭此劫。", "寇攘發他邦，警報經旬浹。", "官府過張皇，民居少寧貼。", "昨方科箭翎，今又催甲葉。", "厚斂招提金，名色何所挾。", "昌言募土兵，相與守城堞。", "繡衣意其欺，急下徵兵帖。", "束手無一人，差官許專輒。", "縣官至何巖，丁壯被威脅。", "黔首畏墨黥，依違謀未協。", "口或出怨咨，心實先震懾。", "官兵胡爲來，紛然肆漁獵。", "室廬罹燬燒，老稚殘鋒鋏。", "山徑至通逵，輿尸交積疊。", "敢梟平人首，僞奏譙門捷。", "殺民汝何勇，殺賊汝何怯。", "此鄉風俗淳，武斷無豪俠。", "目不識戈矛，家盡事耕饁。", "豈應有叛謀，誰子爲荆聶。", "黄巾縱挺威，吾地足未涉。", "官吏大不仁，使爾血先喋。", "千家聚落蕃，幾代農桑業。", "一望成邱墟，獨非我臣妾。", "安知此怪事，不入賊間諜。"]'),
('2ae5a444-8138-4bd2-b359-2a86aacd04af','信手閲清溪詩一首依韻即事','王邁','宋','宋诗','song-poetry','','[]','久雨妨好春，朝暮無休息。',228,'全唐诗/poet.song.195000.json','["久雨妨好春，朝暮無休息。", "出門欲有行，苔滑泥餘尺。", "四望人烟稀，千山鳥聲寂。", "饕寒不肯歸，青帝覺無力。", "况有黄巾徒，鄰郊漸相迫。", "虐焰挺戈予，連車掠金帛。", "王旅猶稽留，民兵半覆沒。", "羊狠來莫當，鼠竄去無迹。", "踐蹂清野塵，原草不能碧。", "世運何乖張，生靈罹此厄。", "丁壯抱枵腸，駢頭受科率。", "氛妖誰掃清，氣象太窘窄。", "書生憂國懷，半夜轉加劇。", "相倚如輔車，忍視爲胡越。", "富家太不仁，增價糶斗石。", "但愛囊橐豐，不憂狗鼠黠。", "甘爲盜貯儲，遑恤人饑渴。", "兇渠曷日殲，苦潦何時歇。", "作詩愧北征，聊以志歲月。"]'),
('ac3fc6e3-b76f-4414-a6f2-5917099d6e4b','携筇出尤嶺嶺頭坐俟輿夫不至','王邁','宋','宋诗','song-poetry','','[]','我居南麓下，頗利君子遯。',144,'全唐诗/poet.song.195000.json','["我居南麓下，頗利君子遯。", "如何溽暑初，涉此複嶺峻。", "瘦藤代筍輿，路熟不待問。", "拂石小盤跚，心愛木陰潤。", "清風解人意，陸續松杉韻。", "掬泉嚥茗芽，竊賞此味俊。", "我坐亦良久，我僕行何鈍。", "平生性麋鹿，合有幽閑分。", "舉足履世途，退尺進僅寸。", "曾此小遲速，而足置喜慍。", "繼今出處同，冥心法天運。", "斯游悟窮通，持與達者論。"]'),
('f59381f3-058c-4a40-95b0-805329d87915','送黄成甫殿講被召','王邁','宋','宋诗','song-poetry','','[]','泉爲閩望郡，山海來航梯。',288,'全唐诗/poet.song.195000.json','["泉爲閩望郡，山海來航梯。", "琛貢交異域，珠貝象玳瓈。", "腥風易涴人，濁如雨後泥。", "不屑受點污，除非辟塵犀。", "南渡賢太守，前稱王梅溪。", "中間西山真，後有苕川倪。", "近歲李竹湖，四賢玉雪齊。", "他守非不賢，多以慾境迷。", "一罅苟可投，趨者由旁蹊。", "利心長萌蘗，公道生蒺藜。", "鴞見腐鼠嚇，鳳甘梧桐棲。", "物性殊潔穢，人品隨高低。", "君侯第一人，壯氣干虹蜺。", "天墀一長鳴，萬馬不敢嘶。", "爲州上異最，趨覲下宸奎。", "歸裝試檢點，定無南物齎。", "時艱方急賢，君命焉可稽。", "巨艦方解維，穹車正發輗。", "憶昔端平初，衆正咸登躋。", "如人墮夢境，忽聽警旦雞。", "云何不常泰，一變成孤睽。", "大老遽淪謝，善類誰提撕。", "菊坡未起南，鶴山斥歸西。", "朽屋費撐拄，洪流欠障隄。"]'),
('30dcb35e-339d-42e1-a184-869c136a3eb2','有客一首寄溫陵史君趙侍郎涯','王邁','宋','宋诗','song-poetry','','[]','有客至自泉，爲我出嘉話。',288,'全唐诗/poet.song.195000.json','["有客至自泉，爲我出嘉話。", "泉得趙史君，誰人不稱快。", "天生冰玉姿，系出龜琴派。", "標峻埒昭回，氣清融沆瀣。", "方在諫省時，朝紳推鯁介。", "及膺承宣命，未到心已解。", "真李報政後，紀綱日大壞。", "有坐泉山堂，不守盂水戒。", "戶庭交賈胡，寶貨通買賣。", "繼者廉而慈，卧疴力衰憊。", "暴吏恃饕官，誅求及菅蒯。", "大姓及細民，怨仇起眥睚。", "我公方下車，當食輒興喟。", "寮屬愛貪泉，爭飲不爲怪。", "予將輩元結，誰肯伍樊噲。", "職曹與舶屬，時號大駔儈。", "兩疏劾四兇，人喜如爬疥。", "州胥富蓋藏，至則繫以械。", "曰此其渠魁，豈止爲罥絓。", "縣官庇黠胥，期限稍寬解。", "山判吁可驚，即日命追解。", "惟仁必有勇，勇去禾中稗。", "良善苦勢家，至則行决夬。", "府史例橐姦，今乃聽自敗。"]'),
('8a70935c-ca9c-4ac8-ad78-b9489567e46a','題洪知觀靜齋','王邁','宋','宋诗','song-poetry','','[]','蠻觸當戰衝，蚌鷸據爭境。',216,'全唐诗/poet.song.195000.json','["蠻觸當戰衝，蚌鷸據爭境。", "相持無了期，復命終歸靜。", "人事苦紛拏，世態異炎冷。", "遠抱異俗觀，照以清明景。", "余生涉畏途，所至虞機穽。", "求富恥執鞭，圖名成畫餠。", "道侶得洪師，喚我夢中醒。", "師如辟塵犀，神觀最清警。", "葆粹息天倪，運斤優匠郢。", "結茅規數椽，討勝事幽屏。", "楹檻疏以明，規撫肅而整。", "晝永篆飛烟，風來幡弄影。", "開卷課黄庭，煮茶汲清井。", "以靜名其軒，會處心自省。", "吾廬雜塵囂，相望限一嶺。", "煩師縮地脈，得我便造請。", "別來火雲張，今見霜宇浄。", "寄詩當梅花，一笑師當領。"]'),
('2175eaff-1b87-4de0-a2e4-15901f9246cc','學易齋','王邁','宋','宋诗','song-poetry','','[]','太極分陰陽，生生之謂易。',96,'全唐诗/poet.song.195000.json','["太極分陰陽，生生之謂易。", "易有乾之元，生意露消息。", "先生易中行，日用而飲食。", "全體純是仁，本自玄中得。", "克己下工夫，心臺皎如日。", "處則爲顔曾，出則爲禹稷。", "所以學易齋，孜孜奉天職。", "滿腔皆春和，八荒開壽域。"]'),
('668360d6-9d4f-4b08-946f-48e1a30f0be2','題余君肅曰嚴忍齋','王邁','宋','宋诗','song-poetry','','[]','君肅吾良朋，天資秀而穎。',240,'全唐诗/poet.song.195000.json','["君肅吾良朋，天資秀而穎。", "以忍名其齋，求余爲序引。", "余聞刃制心，其字謂之忍。", "一忍寬百憂，百動歸一靜。", "人心本至明，萬善集虛境。", "外物一障之，天真隨晦泯。", "意猿肆頡頏，氣馬浪馳騁。", "以忍作防閑，如物有繩準。", "聖賢養心學，最切是懲忿。", "愚者一不校，魯者三自省。", "行行無取才，宜爲夫子哂。", "師德豈懦夫，見善必操秉。", "唾面令自乾，可以愧不逞。", "公藝忠孝人，家法肅而整。", "九世有盤盂，一字其要領。", "願子繼自今，去過貴乎敏。", "育德必體蒙，辨義直觀井。", "意融妄盡消，心清事亦省。", "我少染習氣，近亦痛除屏。", "作詩雖警君，且欲以自警。"]'),
('8ad47b63-1330-41d9-983d-758d726ed909','堅固堂','王邁','宋','宋诗','song-poetry','','[]','五常之有信，猶土相生植。',96,'全唐诗/poet.song.195000.json','["五常之有信，猶土相生植。", "四端有諸己，體用歸於實。", "先生於實地，外方而內直。", "硬作鐵脊梁，許身衛社稷。", "神授五字符，得大堅固力。", "不爲聲色摇，不爲利害怵。", "所以堅固堂，山立而玉色。", "願言愛精神，自壽以壽國。"]'),
('2c546e28-78aa-4181-9abe-e5c4e46b792a','常惺惺室','王邁','宋','宋诗','song-poetry','','[]','性命一同源，萬善天所賦。',96,'全唐诗/poet.song.195000.json','["性命一同源，萬善天所賦。", "五行水生智，正以虛明故。", "先生原命宮，水與金夾輔。", "清質自生明，冰壺澄月露。", "窮理以致用，幹事必正固。", "與國作蓍龜，應物公權度。", "所以常惺惺，一室神明護。", "室中主人公，壽比喬松數。"]'),
('f7c40443-eb38-4f57-a7bc-216e7d1f0764','代簡奉寄三山方時父遇游幾叟明復','王邁','宋','宋诗','song-poetry','','[]','昔我游三山，稠中得二友。',288,'全唐诗/poet.song.195000.json','["昔我游三山，稠中得二友。", "初交方時父，後識游幾叟。", "大比獻能書，厥歲在丁酉。", "垂釣文海中，修鱗上鈎否。", "蔡簿校文回，曰方其所取。", "有高說夫者，姓名出其右。", "高游本弟昆，紫荆偶分剖。", "游雖遲再薦，楚弓楚人有。", "余評時父才，進士中少耦。", "詞絕似秦七，詩已迫黄九。", "幾叟尤不凡，耿耿良自負。", "英辭沮金石，直氣干星斗。", "等是青雲人，科第爭前後。", "射策對天墀，會須爲舉首。", "三年一掄魁，須服天下口。", "毋爲陳誠之，要作張無垢。", "狂生分不才，垂老未覺醜。", "嚮坐太饒舌，相看擁衆手。", "六階何惜鎸，百謫亦甘受。", "不愛騎鶴姿，看人作太守。", "只讀相牛經，教子事農畝。", "乏地堪置錐，仰天頻擊缶。", "二君最知心，一別忽許久。", "作詩分寄之，或賞千金帚。"]'),
('69164146-2d50-4b12-b43e-bdf79a79c3d9','寄陳士登元龍士登書問盜且責予不貽書當路爲剪除計予方以罪歸有言誰見省作詩謝之','王邁','宋','宋诗','song-poetry','','[]','悠悠我之思，東里陳驚坐。',288,'全唐诗/poet.song.195000.json','["悠悠我之思，東里陳驚坐。", "更闌夢持環，晝永心摇纛。", "一春苦風雨，我困南山餓。", "君樓百尺高，頭上天幾大。", "於我未忘情，更僕修夙好。", "耿耿憂世懷，急於聞警報。", "爲憐上四州，豺虎正喧噪。", "虐焰欲熏天，獲人爭斬剉。", "將州豈不武，棄縣如洟唾。", "官軍望而奔，所至徼宴犒。", "鄰境近憂惶，刁斗急巡邏。", "君責我以書，何時乃高卧。", "曷不出良籌，亟爲當路告。", "當局自能迷，看局當不蹉。", "我壯君之言，義起千夫愞。", "顧方謹三緘，此戒那可破。", "諸賢各有謀，何欠儂一箇。", "君家昔太邱，能愧梁上盜。", "毋爲陳君短，此語更傳播。", "吾家昔彥方，能正屠牛暴。", "勿使王君知，叩頭甘謝過。", "兩家俱德門，今有若人麽。", "前時何巖警，召亂在縣左。", "頼君告少仙，全活幾髫髦。"]'),
('f32b4650-da6c-436d-8f93-da460bb2e814','送表弟陳一鳴堯章入京','王邁','宋','宋诗','song-poetry','','[]','科目狹爲途，英雄多短氣。',228,'全唐诗/poet.song.195000.json','["科目狹爲途，英雄多短氣。", "賓賢詔一頒，應舉紛如蝟。", "低心逐時趨，練語避忌諱。", "得者固僥踰，失者徒歔欷。", "巨鱗不上鈎，修翼不入罻。", "鄉選亦孔艱，計臺征以彙。", "我嘗校蘭省，厥歲在乙未。", "時收甲乙科，多是戊己尉。", "國步矧多艱，志士發長喟。", "襄蜀漲氛妖，江淮方鼎沸。", "毛錐無能爲，長劍使人畏。", "朝能立寸功，暮可攫富貴。", "二子趨玉京，道遠不吝費。", "進身假梯媒，流品孰涇渭。", "世科藉此登，親望始寬慰。", "老我謬憂時，周嫠遑恤緯。", "諸公忌生語，悉力攻謗誹。", "藿食可充饑，荷裳尚堪衣。", "功名付君等，山林吾有味。"]'),
('84855689-dca5-4bc6-9395-fa4f5b5924a9','以喜聞過墨贈吾婿鄭純父玸','王邁','宋','宋诗','song-poetry','','[]','西蜀游文昌，贈我墨兩箇。',288,'全唐诗/poet.song.195000.json','["西蜀游文昌，贈我墨兩箇。", "墨上署嘉名，名曰喜聞過。", "過失人誰無，剛褊柔易愞。", "衆人巧自文，君子喜人告。", "予性失之剛，所患在急躁。", "未嘗不佩韋，因循及老大。", "不能如師德，受人對面唾。", "至使巧宦徒，目爲背時貨。", "子性失之柔，鮮有特立操。", "嗜慾微萌芽，左右紛投好。", "不能如乖崖，按劍警坐卧。", "中心欠所主，恐似風摇纛。", "乃翁匹前修，德行圭中瑁。", "承家合有人，前猷宜久蹈。", "賢母慈且嚴，熊膽親調和。", "養志最爲難，家聲出堂奧。", "吾女正抱疴，朝夕煩拊勞。", "要相敬如賓，毋縱欲長傲。", "女亦嘗聞詩，綠衣戒顛倒。", "候其疾之瘳，蘋蘩能采芼。", "內行儻不愆，事業當遠到。", "賢者後必昌，積善天所報。", "持墨爲子箴，進德謹勿惰。", "墨卿子良師，莫被渠看破。"]'),
('c50bf900-f515-4ed4-a4a4-be64e4912a4f','送春有感','王邁','宋','宋诗','song-poetry','','[]','東君行趣裝，桃李事如夢。',204,'全唐诗/poet.song.195000.json','["東君行趣裝，桃李事如夢。", "蝶懶欲息游，鶑老不好弄。", "殘紅正可憐，更禁風雨送。", "榆莢羞獨飛，却惱楊花共。", "去年於此時，客食紅塵鬨。", "眼看豪俠兒，躍馬青絲鞚。", "美姝舞娉婷，吹簫來紫鳳。", "開樽六一亭，偃蓋飛來洞。", "我亦强行吟，詩成和者衆。", "時序易推移，人事少閒空。", "翻思年時樂，已如耳邊哄。", "清曉坐孤寺，晴曦照華棟。", "沙平嘴带鷗，山遠腰橫蝀。", "閲書眼倍明，拈筆手猶凍。", "掃地焚甲煎，呼童開臘甕。", "汲井得甘泉，瀹茗試新貢。", "短章寫我懷，謾遣兒曹諷。"]'),
('a61b0220-f0dd-4cf8-9d2c-687b8f7b76a5','獵者','王邁','宋','宋诗','song-poetry','','[]','山中有獵者，設網張四隅。',156,'全唐诗/poet.song.195000.json','["山中有獵者，設網張四隅。", "稚麞爲所絓，性命懸庖厨。", "母麞至網外，躑躅相悲呼。", "明知獵者意，於己併覬覦。", "柰愛不可割，投網與子俱。", "獵者偶省悟，攢眉發長吁。", "縱之與偕活，長揖謝獵徒。", "焚網毀毒矢，放鷹逐韓盧。", "人物强非類，天性元不殊。", "愛母寢皮猿，惜子喬腹魚。", "人均作此念，可廢佃與漁。", "獵者仁孝心，洞然貫體膚。", "彼爲中國穽，愧見此獵無。"]'),
('e5ca3c3f-8e42-4ce1-8bcd-2ebe9248d63d','壽方右史德順大琮生朝','王邁','宋','宋诗','song-poetry','','[]','大哉天地仁，生意無盡藏。',288,'全唐诗/poet.song.195000.json','["大哉天地仁，生意無盡藏。", "芳春三月時，五陽正敷暢。", "在卦則爲夬，澤下於天上。", "篤生萬人英，出應蒼生望。", "退然處鄉閭，溫恭加直諒。", "萬頃波汪汪，一團和盎盎。", "凜然立朝廷，讜論動旒纊。", "張膽輸藎忠，頳顔斥庸妄。", "寧爲鳳鳴陽，不作馬立仗。", "玉皇笑點頭，諫疏堪屏障。", "讒者何人斯，嚴科欲監謗。", "綱常盡斁淪，天日忍欺誑。", "白璧汙蒼蠅，鳴珂辭翠閬。", "膏屯施未光，幹蠱遂高尚。", "郭外新結廬，野色耽虛曠。", "積書遺兒孫，開斝延輩行。", "及此紱麟旦，仙壺敞方丈。", "台宿煥祥輝，矞雲賓景貺。", "有客前稱觥，致詞太豪放。", "海內今何時，四面波濤漲。", "督府冊元戎，廟坐轅門帳。", "妖氛不能清，惻焉頼汝將。", "都堂留一老，手携靈壽杖。", "顛危不能扶，又焉用彼相。"]'),
('a662b4b0-1f44-4bff-911c-324227c7eafb','書懷奉簡黄成甫史君','王邁','宋','宋诗','song-poetry','','[]','憶昔紹定元，被命考廷策。',288,'全唐诗/poet.song.195000.json','["憶昔紹定元，被命考廷策。", "偶過袁君房，玉墀日將夕。", "案頭得君文，喜躍越三百。", "張燭朗誦之，相與手加額。", "若人作掄魁，餘子當辟易。", "時有詳定官，嫌君多指斥。", "衆默余獨爭，言厲面發赤。", "紫宸一傳臚，璧水推巨擘。", "諸君始相賀，時相頗不懌。", "爰有小人儒，從旁肆蠭螫。", "諫官工逢迎，霜簡肆捃摭。", "此事人能言，本末甚明白。", "暨于端平初，天奪老姦魄。", "散地起忠良，邱園紛束帛。", "君老登瀛洲，講筵賜重席。", "余亦試玉堂，朝有愈之跡。", "啜茶熏玉虯，投餠呼金鯽。", "同校南宮文，等是西山客。", "無何陣脚動，君出爲方伯。", "館中失名流，我輩苦嘆惜。", "西山遽仙去，局面日改革。", "余入對未央，苦語出肝膈。", "淮南冤未消，元載家當籍。", "外黨分牛李，內寵怙秦虢。"]'),
('0a8ce309-5208-4064-88a7-d0c615650c3d','寄惠州陳史君真卿','王邁','宋','宋诗','song-poetry','','[]','千仞羅浮山，蓬萊分左股。',288,'全唐诗/poet.song.195000.json','["千仞羅浮山，蓬萊分左股。", "有詔陳太丘，剖符爲地主。", "皇皇太丘門，德星之所聚。", "前光盛胚胎，後來紛衆甫。", "共惟休齋公，遺教垂鄒魯。", "君侯其聞孫，風烈不忝祖。", "繼以詩書帥，遺愛比召杜。", "君侯其英嗣，真清亦如父。", "嚮者位于朝，穹官可拾取。", "不能枉尺尋，矧肯效媚嫵。", "翩然乞一麾，來此開藩府。", "此郡舊富饒，廣中號樂土。", "年來困軍須，炎火無冷釜。", "鄰盜闖其藩，燒痕未全補。", "噓枯待仁風，醒暍仰膏雨。", "迎輅兩朱幡，驩呼十萬戶。", "朝宣上德意，夕問民疾苦。", "爲渠作豐年，愁嘆變歌舞。", "得結數十輩，萬物氣可吐。", "行奏循良功，入布承明武。", "走也山林人，本無素宦譜。", "妄言宗社事，屢犯君相怒。", "緝緝惡樊繩，眈眈畏關虎。", "歸歟結茆庵，課僕理蔬圃。"]'),
('ffa0ebfe-ea14-405f-9b37-77945c7e39e4','還氈行','王邁','宋','宋诗','song-poetry','','[]','老屋數十椽，下濕上又破。',288,'全唐诗/poet.song.195000.json','["老屋數十椽，下濕上又破。", "無端野狐精，昏夜入爲盜。", "竊我三重氈，目之爲奇貨。", "持以獻朱門，曰此堪媚竈。", "自余失此物，志意不少挫。", "苦節凌歲寒，羞顔薄時好。", "命義守大閑，潛深仍伏澳。", "客從北方來，特以吉語告。", "舊物將見還，前甑元不墮。", "余笑與客言，的有此說麽。", "孔光坐廣堂，當局已昏耄。", "余嘗對天仗，正色數渠過。", "其心不能容，未免含疾媢。", "石顯在宮闈，威福弄幽奧。", "余又疏擊之，見面定渠唾。", "其術方盛行，及此必圖報。", "客乃寬余心，少安謹勿躁。", "聖主赦宿愆，仁恩等天幬。", "昭相愛善類，德量如海大。", "讒者害莫成，匪伊氈自到。", "未幾符其言，客喜相問勞。", "勸客勿爲喜，我且爲時悼。", "米石三十千，杭人死饑餓。", "敵寨七百里，淮人共斬剉。"]'),
('ffcebea9-0fb0-4b1a-92a4-c6e8bc7d913e','述夢','王邁','宋','宋诗','song-poetry','','[]','午枕避塵囂，夢乘銀潢槎。',144,'全唐诗/poet.song.195000.json','["午枕避塵囂，夢乘銀潢槎。", "好風吹衣袂，墮我天之涯。", "羣仙赴號召，驂鳳來香車。", "一見如故舊，絲麟酌流霞。", "或鞭石爲羊，或握棗如瓜。", "中有汗漫生，盤礴埋丹砂。", "誰言仙有道，挾術相矜夸。", "顧我亦可學，正坐一念差。", "我笑謝之言，仙凡各有家。", "悠悠御風還，聚散如團沙。", "繩床一欠伸，茲遊真幻耶。", "咄咄置勿論，呼童煮新茶。"]'),
('5d738c9b-0f44-453a-b9d3-395621d7825d','辛未中元記夢夢與一僧談世事良久問答中有凡事如此汝曹勉之之語既而造一境如仙家居厥明用夢中八字爲偈末章反騷  其一','王邁','宋','宋诗','song-poetry','','[]','一念稍分明，天壤異仙凡。',72,'全唐诗/poet.song.195000.json','["一念稍分明，天壤異仙凡。", "諸相等歸妄，天真要無厖。", "凡物非我有，秋毫不可貪。", "只此爲上乘，其諸總虛談。", "無字經可閲，無言禪可參。", "白雲過前山，明月映空潭。"]'),
('2540b3ea-a4c0-4989-9bd4-776799b25434','辛未中元記夢夢與一僧談世事良久問答中有凡事如此汝曹勉之之語既而造一境如仙家居厥明用夢中八字爲偈末章反騷  其二','王邁','宋','宋诗','song-poetry','','[]','蘧蘧一夢中，了了三生意。',72,'全唐诗/poet.song.195000.json','["蘧蘧一夢中，了了三生意。", "法界如許寬，此生亦特寄。", "誰言玉局仙，元本是法器。", "不解自磨礲，因人亦成事。", "强顔游人間，聊作逢場戲。", "山色溪聲中，略得些滋味。"]'),
('c4953faf-931f-44c7-a208-5065a91b1be9','辛未中元記夢夢與一僧談世事良久問答中有凡事如此汝曹勉之之語既而造一境如仙家居厥明用夢中八字爲偈末章反騷  其三','王邁','宋','宋诗','song-poetry','','[]','石塔本無縫，吐光萬丈餘。',72,'全唐诗/poet.song.195000.json','["石塔本無縫，吐光萬丈餘。", "不是風火扇，又非喉管噓。", "此光胡爲來，塔亦不知渠。", "解作如是觀，身心長自如。", "塔身俱著實，光心等是虛。", "虛實歸一致，無乘亦無除。"]'),
('95b9d6a3-fb82-4fd5-b73c-7d6ebebbd3b1','辛未中元記夢夢與一僧談世事良久問答中有凡事如此汝曹勉之之語既而造一境如仙家居厥明用夢中八字爲偈末章反騷  其四','王邁','宋','宋诗','song-poetry','','[]','鑿空談荒唐，我正不爲此。',72,'全唐诗/poet.song.195000.json','["鑿空談荒唐，我正不爲此。", "故知又故爲，頗悟前生是。", "憑誰照前因，斯言特戲耳。", "既是無今古，如何分彼己。", "須彌一點塵，萬劫一彈指。", "無失亦無憂，無得亦無喜。"]'),
('1c7a934b-f58b-451b-8ade-d5d61ce8fdef','辛未中元記夢夢與一僧談世事良久問答中有凡事如此汝曹勉之之語既而造一境如仙家居厥明用夢中八字爲偈末章反騷  其五','王邁','宋','宋诗','song-poetry','','[]','禪悅既無門，仙居在何所。',72,'全唐诗/poet.song.195000.json','["禪悅既無門，仙居在何所。", "與渠無半面，一見相爾汝。", "霓裳製未成，翩翩欲高舉。", "身如一羽輕，去天才尺許。", "胡爲造此境，問之不吾語。", "正緣崆峒中，蕭然無物貯。"]'),
('ef4e6524-03cd-446a-9254-91859dd820ca','辛未中元記夢夢與一僧談世事良久問答中有凡事如此汝曹勉之之語既而造一境如仙家居厥明用夢中八字爲偈末章反騷  其六','王邁','宋','宋诗','song-poetry','','[]','世人欲不死，焚香事大羅。',72,'全唐诗/poet.song.195000.json','["世人欲不死，焚香事大羅。", "死後欲超生，將身靠彌陀。", "个裏不透徹，仙佛如子何。", "我素不持戒，焉能斷腥臊。", "獨有一寸珪，明白不可磨。", "學仙與學佛，此事付兒曹。"]'),
('802fbdf4-bedc-44c5-b610-ec544a49b352','辛未中元記夢夢與一僧談世事良久問答中有凡事如此汝曹勉之之語既而造一境如仙家居厥明用夢中八字爲偈末章反騷  其七','王邁','宋','宋诗','song-poetry','','[]','擣薺餐鐵杵，此味知者鮮。',72,'全唐诗/poet.song.195000.json','["擣薺餐鐵杵，此味知者鮮。", "乘車入鼠穴，聞者知其舛。", "打鐵作門限，鬼笑定不免。", "點雪紅爐中，達觀理甚顯。", "當局自然迷，正欠撥一轉。", "上馬奔前程，此著須自勉。"]'),
('ad8c0c80-241f-4928-ad7c-5f22c7cddc97','辛未中元記夢夢與一僧談世事良久問答中有凡事如此汝曹勉之之語既而造一境如仙家居厥明用夢中八字爲偈末章反騷  其八','王邁','宋','宋诗','song-poetry','','[]','盤中有止水，歷歷見鬚眉。',72,'全唐诗/poet.song.195000.json','["盤中有止水，歷歷見鬚眉。", "能定乃能應，人心固如斯。", "至誠本如神，聖賢不吾欺。", "鳴鶴方在陰，其子輒和之。", "天未降時雨，山川雲已知。", "誰能舍我龜，而觀爾朶頤。"]'),
('ca6c3738-9479-40b4-8e6a-bfad7f6e470f','贈談星達士','王邁','宋','宋诗','song-poetry','','[]','列肆競談星，謬者十八九。',288,'全唐诗/poet.song.195000.json','["列肆競談星，謬者十八九。", "達士何許人，儔中推好手。", "精步宿羅胸，縱談鬼擘口。", "技絕固招窮，鶉衣不掩肘。", "朅來訪臞翁，意欲相擊扣。", "翁命翁自知，不問子休咎。", "蒼生命甚危，子亦知乎否。", "魏闕妖狐翔，吳江水獸吼。", "馮夷肆陸梁，富媼難載負。", "强寇噬邊州，湖堧經踐蹂。", "王師戰且弱，鉞鈍甲兵朽。", "流民滿江濆，溝洫紛骸髏。", "京米貴於金，十千可一斗。", "暮夜光燭天，彗星大於帚。", "災眚此非常，其敢飲以酒。", "都人極皇皇，如魚驚在笱。", "國脈眇一絲，病固有從受。", "西山薨於前，鶴山繼於後。", "洪蔣與李徐，俱作修文友。", "吳訃漫塘翁，廣哭菊坡叟。", "天爲國生賢，福賢理宜厚。", "何事數鉅公，不爲國耆耉。", "周堪劉向亡，老光握靈壽。", "元城了翁去，賊京得皓首。"]'),
('0e2b232c-6ad2-4d29-9191-a206151da775','水口上舟呈同行傅月山萇','王邁','宋','宋诗','song-poetry','','[]','泝流上嵩江，江闊流益峻。',276,'全唐诗/poet.song.195000.json','["泝流上嵩江，江闊流益峻。", "時方良月初，打頭惡風信。", "老翁把柂立，首叫尾必應。", "大男前運篙，風激水還噴。", "小男上拽縴，石行跲復奮。", "後退輒丈尋，前躋不尺寸。", "偪仄一堵中，危坐易慵困。", "冷雨去復來，前山邈難認。", "江天暮漸低，好風來一瞬。", "帆飽去如飛，兩程疑可併。", "舉杯囑月山，凡物有定分。", "壯年登王官，轉盼更五閏。", "星沙罹閔艱，日轂轉顛頓。", "方頭忤時流，失脚落陷穽。", "巧宦疾以馳，笑我拙而鈍。", "如登今日舟，易退難於進。", "自知平生事，百欠無一剩。", "饑寒驅出山，歌笑破羣悶。", "獨有不自欺，心可與天印。", "人爲固多端，天定或能勝。", "願如晚來風，先逆後乃順。", "得酒且酌斟，升沉付天運。", "有窮必有通，無喜亦無慍。"]'),
('d6b6485a-e9bd-49ab-9ba8-3fbcca252546','送林公似有之宰古田  其一','王邁','宋','宋诗','song-poetry','','[]','余與林公似，生長南山南。',168,'全唐诗/poet.song.195000.json','["余與林公似，生長南山南。", "吾翁與乃翁，宿望俱不凡。", "或晚登黄甲，祿不霑斗甔。", "或困頓場屋，補勞僅青衫。", "執手授遺編，尚友遷繼談。", "家法無諂語，妙理靜中參。", "丁丑俱一第，苦盡稍回甘。", "蹭蹬二十年，令纔換頭銜。", "嚮來同登者，青雲徧騰驂。", "吾輩慣冰檗，世好殊酸鹹。", "君去宰壯縣，栽花興方酣。", "我乃賦歸與，悔狂口宜緘。", "棘蠅來營營，關虎卧眈眈。", "頹波從汩沒，砥柱高巉巖。"]'),
('90ef3a4e-5752-430a-ba8f-56d648e8717d','送林公似有之宰古田  其二','王邁','宋','宋诗','song-poetry','','[]','孤士脫選階，如出百丈塹。',192,'全唐诗/poet.song.195000.json','["孤士脫選階，如出百丈塹。", "舉員必及格，桂籍始一占。", "宰邑非不榮，吏塵豈宜厭。", "平生學愛心，小試乃可驗。", "今時邑大夫，不軫閻閭念。", "非財不經營，所欲須屬饜。", "創第要高華，買姬求美艷。", "驕色肆頡頏，嚴科行聚斂。", "攫肉比饑鷹，噬膚如獰獫。", "但規己豐腴，皇恤民亡阽。", "吁嗟饕餮徒，信是搢紳忝。", "中人易轉移，習俗多薰染。", "林君最高明，百行無一欠。", "俗然君不然，白璧絕瑕玷。", "狂生作此詩，未病投鍼砭。", "愛助極拳拳，苦語忘其僭。"]'),
('71a480af-e98a-4bca-9981-820f9f4082c2','寄林教授龜從','王邁','宋','宋诗','song-poetry','','[]','我生麋鹿羣，巖穴性所樂。',288,'全唐诗/poet.song.195000.json','["我生麋鹿羣，巖穴性所樂。", "寓城看病女，蹤跡良踸踔。", "神明倘見憐，醫藥須課效。", "便當歸舊廬，誰愛入此閙。", "炎暑甚蒸炮，矮屋如籠罩。", "欠伸尺蠖形，低垂木雞貌。", "清晨得君書，銜繫新州教。", "慈恩敘同年，轉盼夢一覺。", "我於端平初，蓬山叨直儤。", "批鱗咈神龍，編鬚犯關豹。", "一斥褫三官，連年絕廩稍。", "我罪坐狂愚，令受人繫敲。", "君胡二十年，無由極比較。", "今又深入南，正坐不能巧。", "羣兒益紛拏，疾足逞超趠。", "我輩履羊腸，所歷極确磽。", "宦海走千帆，好風縱篙棹。", "我輩航一葦，無緣出泥淖。", "世道日以艱，大厦摧棟橈。", "邊塵日以紛，衝梯設矢砲。", "逆潮陸成淵，苦旱水飛窖。", "餓莩盈通途，驕兒縱烈爆。", "君視此何時，有官如荷校。", "猶戒我韜藏，前尤勿再傚。"]'),
('1a6afb00-6b5f-4f9a-8af0-39fb4d9eeb45','跋林學士宋卿帖','王邁','宋','宋诗','song-poetry','','[]','朝爲一旅人，暮拾九品官。',288,'全唐诗/poet.song.195000.json','["朝爲一旅人，暮拾九品官。", "趾高氣且浮，反面視孤寒。", "昔聞韓魏公，義風塞人寰。", "赤舄坐晝錦，有客排其關。", "孤身無所賫，乞公玉盥盤。", "公笑授之去，感涕雙汍瀾。", "我始得此事，謂可聳俗觀。", "家傳書甚悉，國史載不完。", "今見學士帖，爛然銀鈎蟠。", "方其一第初，半載游長安。", "持書遺鄉朋，客費無虛閑。", "近得奩中貲，分壯貧士顔。", "寧我食無魚，不忍渠無餐。", "寧我裾無華，不忍渠衣單。", "臭味何所愛，敢言囊之慳。", "猶愈輕薄兒，一笑黄金拚。", "我來閲遺書，據案發長歎。", "縱橫纔片紙，突兀已萬間。", "魏公爲上相，庇士易爲懽。", "林公初筮仕，爲此良獨難。", "景仰前輩人，高節騫雲山。", "原下不可作，清風何時還。", "泚筆哦此詩，寄名烏絲欄。", "庶幾一見者，可以激偷頑。"]'),
('85245651-d024-455d-9761-824cc52bfbd5','反艷歌曲復三山林斗南','王邁','宋','宋诗','song-poetry','','[]','誰作艷歌曲，律清語不塵。',168,'全唐诗/poet.song.195000.json','["誰作艷歌曲，律清語不塵。", "雜之古樂府，意態甚迫真。", "謂余欠嫵媚，宜爲衆女嗔。", "方憐長門閉，漸喜湯沐新。", "此曲豈不俊，所儗非吾倫。", "生爲奇男子，先辨許國身。", "有手要折檻，不炙許史門。", "有頭要叩墀，不拜五侯塵。", "昵昵兒女語，煦煦婦人仁。", "夕泣緣失寵，朝欣爲承恩。", "此非奴事張，定是妾效秦。", "是爲赤有臭，何止黄不純。", "因君詞婉美，感我意酸辛。", "正恐漆園女，嗤點我輩人。"]'),
('9f26a957-a5bf-47dc-bd50-1de8be4b0b44','送地栗與囊山應叟和尚','王邁','宋','宋诗','song-poetry','','[]','淤泥生蓮花，不如生地栗。',48,'全唐诗/poet.song.195000.json','["淤泥生蓮花，不如生地栗。", "蓮花生好看，地栗却好喫。", "看底只是虛，喫底却是實。", "虛實總不如，般若波羅密。"]'),
('620e9e1c-c794-44c0-9a18-78e103109112','題九鯉湖','王邁','宋','宋诗','song-poetry','','[]','仙人蟬蛻幾經年，山水勝處今依然。',128,'全唐诗/poet.song.195000.json','["仙人蟬蛻幾經年，山水勝處今依然。", "長驅九龍叱雷電，高跨九鯉升雲烟。", "武夷九曲此幻相，靈砂九轉成丹鉛。", "黄雞白犬得一舐，翩翩高舉紅輪邊。", "我家去此可三舍，欲識仙竈無因緣。", "朅來乞取方匕劑，要使凡骨成飛仙。", "羣仙駢頭顧我語，笑指巨鰲在深淵。", "覓丹他日來未晚，且與一釣六鰲連。"]'),
('d4b401fd-092a-4ab5-ad3c-d0c4e9a21425','立夏前五日出郊送春','王邁','宋','宋诗','song-poetry','','[]','前回馬首絡青春，春我相逢皆故人。',80,'全唐诗/poet.song.195000.json','["前回馬首絡青春，春我相逢皆故人。", "今朝出門忽失笑，春如五日之京兆。", "鶑癡蝶騃不知愁，惟有杜鵑啼到曉。", "春到園林郵傳哉，藤陰次第庇莓苔。", "願春長在人長健，何惜與春歸去來。"]'),
('157c878a-df0f-4d7a-8d4d-683e90007b6d','墨歌寄林明叔','王邁','宋','宋诗','song-poetry','','[]','贈君古墨三寸許，君知此墨從來處。',128,'全唐诗/poet.song.195000.json','["贈君古墨三寸許，君知此墨從來處。", "溧陽石化幾千年，鋼鐵臼經三萬杵。", "昔我得之於異人，使我拾襲藏爲珍。", "我今以半爲君遺，物以少貴君勿嗔。", "來歲八月西風裏，我曹忼慨辦行李。", "書囊無底將不去，檢點笥中惟有此。", "用時須留一匕餘，丹墀大對要煩渠。", "更有浯溪紀功石，待問君王乞墨書。"]'),
('1c78d5a1-39f3-4fd4-b8c0-43235859982a','黄君任景伊西上','王邁','宋','宋诗','song-poetry','','[]','杞梓非凡材，騏騄非凡馬。',184,'全唐诗/poet.song.195000.json','["杞梓非凡材，騏騄非凡馬。", "樸樕不入公輸門，賞駿豈無伯樂者。", "龍泉真寶劍，焦尾亦名琴。", "張華有眼識紫氣，子期解聽流水音。", "凡物時爲之否泰，橫寶在道衆所愛。", "十年讀書得一友，送之西征吾意快。", "梅花馨，雪花明，仙霞直上逼雲津。", "別君不作兒女語，萬卷詩書早致身。", "柳綿飛，榆莢舞，軟紅塵中花如雨。", "逢君一笑上青樓，破費黄金買金縷。", "那時君已在瀛洲，而我正爲京華游。", "便教後舉入黄甲，早是輸君此一籌。"]'),
('78950f75-00bf-4393-be96-53ea0f2fa251','送洪承信儒發西上','王邁','宋','宋诗','song-poetry','','[]','詩賦不直一杯水，明經談笑博青紫。',160,'全唐诗/poet.song.195000.json','["詩賦不直一杯水，明經談笑博青紫。", "兩石爭如識一丁，長槍得勝毛錐子。", "夫君稽古歲月深，雕蟲童習素所恥。", "奮身刀劍亦借徑，未能免俗聊爾耳。", "朝來免胄翰墨場，妙發穿楊三昧矢。", "神人換鼻許正郎，朱衣點頭相行李。", "仙霞絕頂雪漫天，快上扶摇九萬里。", "明春躍馬白玉京，都人爭看龍燒尾。", "應笑向來點額人，方上橋門趨劍履。", "便須破費千黄金，邀儂一醉長安市。"]'),
('8a81ddc7-6b97-4dd4-9fd4-e6320a0af432','送朱典卿履常參學','王邁','宋','宋诗','song-poetry','','[]','文章久矣乏正氣，作者付誰傳位置。',128,'全唐诗/poet.song.195000.json','["文章久矣乏正氣，作者付誰傳位置。", "天庠晚乃得朱君，鐘呂一鳴康瓠棄。", "君看今歲大廷魁，一種風骨何尪羸。", "吾曹此名未立耳，立則萬口須銜枚。", "君今乘槎問星漢，名已籍仙政何患。", "蠶繭工夫何足籌，龍墀勳業須早辦。", "作詩贈君當馬鞭，梅花送春入冷邊。", "與君同舍我無緣，天其或者須同年。"]'),
('e641cf1f-8fb1-47b2-9ab7-de7b65ed6700','和毗陵傅知錄送其姪得雋廣童科','王邁','宋','宋诗','song-poetry','','[]','渥洼驥子展足長，朝發燕都夕夜郎。',106,'全唐诗/poet.song.195000.json','["渥洼驥子展足長，朝發燕都夕夜郎。", "一腹如椰貯夜光，揮毫落紙爛成章。", "誦書三筴無遺忘，風采聳動中書堂。", "伯父一見金玉相，聲之以詩鳴鳳凰。", "顧我外氏出義陽，忝與此郎爲雁行。", "竊效昌黎序送童子張，期子更閲幾星霜，姓名金榜相頡頏。"]'),
('af8f055d-0969-4184-a4bc-174317ae9698','聞倪尚書赴詔','王邁','宋','宋诗','song-poetry','','[]','老倪昔以戇去國，時無一語爲王留。',208,'全唐诗/poet.song.195000.json','["老倪昔以戇去國，時無一語爲王留。", "自從醫國失扁鵲，民之瘼矣矧可瘳。", "滿朝爭慕舌爲柔，忍恥戴天事世仇。", "間有一念及王事，祇能低頭效楚囚。", "漢家朝得一汲直，淮南即日干戈休。", "夷甫清談倡薄俗，坐視平陸沉神州。", "殘寇六年汙京汴，羣魚假息釜中游。", "陛下至仁一南北，天假機會忍不投。", "顧盼左右求所倚，張仲孝友吾故侯。", "亟下一紙起高卧，明堂一柱清廟球。", "書生聞詔喜不寐，江左有人吾何憂。", "翻思死者不可生，誰爲中興壯其猷。", "未必軍中有老范，且乞王所容居州。"]'),
('dd1c090c-0257-4078-ab09-35bac5b5422d','賀表兄傅仁仲常後院生男','王邁','宋','宋诗','song-poetry','','[]','昔君與我夜對床，知君著意選專房。',192,'全唐诗/poet.song.195000.json','["昔君與我夜對床，知君著意選專房。", "爲言東鄰有女寶，胡不貯之芸輝堂。", "君時爲我一慫慂，以斗量金買嬌寵。", "小君有德比孟光，不妬不嗔迴盼重。", "懸知仙果結子遲，三年乃字玉麟兒。", "君家多産渥洼種，英物生來骨定奇。", "莫嫌外家不足數，有子端能貴其母。", "舊聞絡秀有伯仁，今見英娘生阿武。", "萱堂一笑顔生春，從此含飴日弄孫。", "他日公侯當衮衮，鳳將九子俱青雲。", "犀錢利市人爭覓，我獨流涎不能得。", "假饒此事卿無功，不道薦賢功第一。"]'),
('82e83469-0442-41e3-912f-74dd8feeb5b0','西征艤舟清洲投宿野店夜漏下數刻主媼爲作粥與同行一飽成詩','王邁','宋','宋诗','song-poetry','','[]','君不見淮陰徹侯未得志，胯下從人真短氣。',134,'全唐诗/poet.song.195000.json','["君不見淮陰徹侯未得志，胯下從人真短氣。", "漂母以食拱而前，心許王孫當富貴。", "又不見文叔宏濟艱難時，大樹將軍身從之。", "一夕相顧有餒色，蕪蔞之粥甘如飴。", "丈夫自負不草草，剛腸似石那能拗。", "得時要拯萬人饑，讀書肯自謀溫飽。", "諸公兼我非窮人，窮途謾爾君勿嗔。", "他年五鼎享臺饋，須記此夕清洲濱。"]'),
('f084a0a7-d6ff-4db6-b641-561a9d5a7e7e','就許宰求雲岫倡和集','王邁','宋','宋诗','song-poetry','','[]','昔者杜老夜聽許十詩，爲言風騷共推激。',195,'全唐诗/poet.song.195000.json','["昔者杜老夜聽許十詩，爲言風騷共推激。", "如何汗青失其傳，覽杜集者爲許惜。", "我曾得倡和之巨編，暗中驚喜拾拱璧。", "泰岳之後無虛人，宗派元自一家出。", "馳筒往返者誰歟，雲岫先生詩巨擘。", "文鸞彩鳳迭應酬，響撼翠梧徹金石。", "血駒紫燕爭追馳，容與蟻封中徐疾。", "留卷把玩不忍歸，痛快差類愈頭檄。", "應知至寶疇敢私，天下有目皆願識。", "刊之堅梓廣流行，作我縣齋大奇特。", "詩名要與宇宙齊，豈比五臺詩卷逸。", "自從秋孟授鋟工，跂予望之朝連夕。"]'),
('79bc30d8-9990-4663-b091-3125e0a99c26','闕題','王邁','宋','宋诗','song-poetry','','[]','拙成可抵萬金璧。',216,'全唐诗/poet.song.195000.json','["拙成可抵萬金璧。", "從古至今不偶合，如何二妙一時出。", "僕也若調烏鵲鳴，斂翅甘受黄鶴擘。", "自從手授大雅文，孺子低頭拜黄石。", "數韻未足寫形容，先生響報何捷疾。", "兒嬌勝拾隋氏珠，母喜如捧毛生檄。", "自憐生長通德鄉，每沐達尊垂異識。", "爲題碑刻墨未乾，招入詩盟筆尤特。", "前無宋艷與班香，奄有庾清兼鮑逸。", "歲晚家食誰與娛，持此可慰風雨夕。", "先生自取太勞謙，提奬孤寒美多溢。", "大匠旁觀自汗顔，伯樂一顧價增百。", "琴堂聞亦有妙賡，迄遣奚奴爲物色。", "當官多是廢言詩，敏手何曾妨霹靂。"]'),
('ef20e218-1dbe-46c5-a87d-88f3c243f8a6','許宰和篇至再用韻謝','王邁','宋','宋诗','song-poetry','','[]','陶令束带對督郵，歸來高興潛有激。',224,'全唐诗/poet.song.195000.json','["陶令束带對督郵，歸來高興潛有激。", "昌黎縣齋飽讀書，自謂此日足可惜。", "二賢詩留天地間，千載寶之爲雙璧。", "當官不妨文字樂，似此人物不時出。", "宦海風濤縣爲甚，文書束筍紛莫擘。", "許侯敏手良不難，錯節居然逢匠石。", "寬租農扈享豐登，講學如流蘇廢疾。", "筆力重於丈二殳，詩筒敏似尺一檄。", "句中之眼獨心知，貽奪陶韓少人識。", "鄉有達尊性愛士，縣榻於堂賞英特。", "冰車雪輾笑鈍遲，不爾續題尤富溢。", "窮冬四壁坐無聊，渴思一字車渠百。", "走僕乞取稛載歸，底用黄金壯顔色。", "祇恐天上六丁聞，一夜取將煩霹靂。"]'),
('384d1ca8-356d-4f25-902f-3b37c8ab3073','陳侍郎見激字韻和以見寄復用韻謝','王邁','宋','宋诗','song-poetry','','[]','先生德量萬頃波，撓之不濁無湍激。',256,'全唐诗/poet.song.195000.json','["先生德量萬頃波，撓之不濁無湍激。", "文章亦如萬斛泉，酌之不竭何慳惜。", "滄浪亭下把釣竿，雙筆堂前看蒼璧。", "時逢問字客及門，倒屣不要人扶出。", "飲酣戲索烏欄書，吟罷笑拈麟脯擘。", "一詩直萬雞林金，衙官坡谷奴劉石。", "得者須熏玉蕤香，覽而玩之痊百疾。", "堂堂元帥坐詞壇，餘子誰堪承羽檄。", "許侯端是忘年交，具眼朗然爲賞識。", "雲岫詩卷盈錦囊，自欣邂逅有勝特。", "先生筋力似裴公，侯比香山才更逸。", "凉臺燠館富唱酬，如見古人今之夕。", "斐然小子謾成章，所美信美安敢溢。", "有來珍翰費吹噓，展閲再三感千百。", "當偕巨帙什襲藏，寒谷先期有春色。", "新年更擬打作碑，薦福莫教雷霹靂。"]'),
('d251bfed-db42-4feb-b216-aa03b1ffc981','贈術士陳談天','王邁','宋','宋诗','song-poetry','','[]','我生之辰日在亢，斗牛之宿晻無耀。',224,'全唐诗/poet.song.195000.json','["我生之辰日在亢，斗牛之宿晻無耀。", "獨有首尾二虣星，角立昴氐爭繫標。", "一生奇蹇良苦之，已分青雲輸年少。", "每逢星史說經躔，探手止之頭屢掉。", "談天一日叩齋扉，信口陽秋天下妙。", "數靈不用蓍草占，機祕時將道眼照。", "玄中巧奪君平胎，聖處深入渾沌竅。", "俗人籌星亂如麻，蠡測管窺工竊剽。", "聽君談唾如秦青，字字宮商合腔調。", "如何孤身無所賞，萍梗風波任浮漂。", "正緣苦泄造化機，真宰忌之神所誚。", "方知多技故多窮，凡事皆然君莫笑。", "雖然知己豈無人，試往京城謁權要。", "一絲莫久牛蹄灣，滄海六鰲待君釣。"]'),
('ac30b14a-f9d3-4280-be33-b36a9fd27a65','贈郭五星','王邁','宋','宋诗','song-poetry','','[]','五陵豪家輕薄兒，驕傲成癖不可醫。',160,'全唐诗/poet.song.195000.json','["五陵豪家輕薄兒，驕傲成癖不可醫。", "揮金買笑紅塵市，老死不曉寒與饑。", "囊螢案雪單貧士，杯水生涯北窗裏。", "途窮山鬼恣揶揄，命壓人頭提不起。", "郭君昔從先人遊，萬丈壯氣橫高秋。", "天無老眼不見錄，匆匆白了少年頭。", "一日訪余道艱窶，杯酒未闌淚如雨。", "揲蓍有術金不換，鶉衣百結無人補。", "我聞君語鼻亦酸，誤身直是坐儒冠。", "英雄未遇隠於卜，時人莫作白眼看。"]'),
('d202c609-9cb3-4e23-b0b7-3a3f5b97cd67','贈川官五星先生','王邁','宋','宋诗','song-poetry','','[]','談星之士如星密，得似川官萬之一。',128,'全唐诗/poet.song.195000.json','["談星之士如星密，得似川官萬之一。", "牙籌到手疾如飛，口觜翻瀾眼波碧。", "相逢笑問雌甲辰，掀髯慫惥曲江春。", "自憐蹭蹬負歲月，敢謂渠儂許可真。", "明時取士非唐比，忠臆不空人所恥。", "三籌交臂輸少年，只較劉蕡差勝爾。", "川官重來話榮枯，聲言溫飽非所圖。", "他時散漫遊江湖，未省還能訪我無。"]'),
('f7d5d727-a1ab-44e4-8592-4d90a1abbcbd','讀誠齋新酒歌仍效其體','王邁','宋','宋诗','song-poetry','','[]','先生出奇作新酒，自作自歌自爲壽。',176,'全唐诗/poet.song.195000.json','["先生出奇作新酒，自作自歌自爲壽。", "酒徒若欲舉吾盃，先挽天河濯渠手。", "誰知先生詩更奇，刊落陳言付芻狗。", "俗人欲誦先生詩，先吸天漿潄渠口。", "古來作酒稱杜康，作詩只說杜草堂。", "舉世無人傳得方，奄有二杜惟一楊。", "先生此味誰能嘗，却曾見此糟蟹黄。", "一片入口風韻長，餘子祇慕大官羊。", "天公生我太遲後，不作先生牛馬走。", "低頭乞取酒百壺，嚥下先生詩萬首。", "先生騎鯨上天遊，問著許儂知味否。"]'),
('cf36a490-244e-484a-8621-0e68e0430ab2','蔡實甫能酒而道中無可口者見其吻噪成長篇戲之','王邁','宋','宋诗','song-poetry','','[]','吾祖方平至君家，絲麟談笑酌流霞。',128,'全唐诗/poet.song.195000.json','["吾祖方平至君家，絲麟談笑酌流霞。", "麻姑綽約時在坐，癢處思得姑爪爬。", "我今與君豈其裔，彈指又經千百歲。", "文采風流今尚存，仙風道骨知誰繼。", "今宵月明明更多，有客無酒如月何。", "唇乾吻噪甚背癢，安得玉壺瀉金波。", "白玉樓臺月如晝，屋貯阿嬌車載酒。", "元君再會儻可期，我當起舞爲君壽。"]'),
('955391b2-7526-414a-bb0c-255b5ae108aa','送陳君保作喆赴廣漕','王邁','宋','宋诗','song-poetry','','[]','昔我與君俱妙齡，同時充貢鄉曲英。',352,'全唐诗/poet.song.195000.json','["昔我與君俱妙齡，同時充貢鄉曲英。", "君携令名遜伯氏，天性好義甚好名。", "薄俗斗粟有德色，君視名第鴻毛輕。", "此事今無古亦少，百鳥羣中孤鳳鳴。", "老天相知苦不早，囊書匣劍猶書生。", "累年文屋提鐵騎，共我掎角參齊盟。", "我于再戰偶得雋，君雖屢衂無弱兵。", "長鬚忽持雙鯉至，短褐欲訪五羊城。", "紅粉蛛絲期已近，金灘鸂鶒眼偏明。", "知君圖南非左計，九萬扶摇第一程。", "疇昔韓蘇行脚處，一草一木被光明。", "鱷魚久出海若避，白鶴詩留泉石清。", "葛仙丹井未湮沒，伏波銅柱餘崢嶸。", "君行窺奇摘海異，澆沃磊塊氣愈盈。", "閩士南征可車載，間有鐵中夸錚錚。", "商瑚夏璉只君是，此寶豈久道邊橫。", "吹送鶚書風借便，殿前奏賦摩空聲。", "當家魁相衣缽在，會趾前美大門閎。", "壽母一笑春生頰，繡輿錦誥來將迎。", "牽衣兒女莫惜別，爲君爲親在此行。", "計程何日到庾嶺，梅花雪片飛瓊瑛。", "魁占羣芳差易耳，相期心事在和羹。"]'),
('774d5e53-4254-4baf-a057-869bfb48d578','二十韻寄潮陽宰余君實日華','王邁','宋','宋诗','song-poetry','','[]','昔日潮守有昌黎，恩波萬頃橫鱷溪。',304,'全唐诗/poet.song.195000.json','["昔日潮守有昌黎，恩波萬頃橫鱷溪。", "五百年後得余令，棠陰上與韓本齊。", "故家縣譜熟展布，砉然牛刀優割雞。", "朞年已報三異政，節愛堂扁煥新題。", "手摩民瘼心隠痛，藥石其肯靳刀圭。", "老農終歲不識吏，廢疇荒隴皆鋤犁。", "邑有豪俠擅武斷，缿筩告訴來髫齯。", "仁者之勇一發露，愛苗亟欲芟稗稊。", "誰爲鼠輩巧道地，周道如砥生蒺藜。", "公車未采輿人誦，端士先爲橫議擠。", "朝中有語稍辨雪，言者愕立惜噬臍。", "侯朝聞命暮就道，束書之外他無齎。", "出廛五日纔百里，截鐙卧轍相提携。", "乞留有狀白府治，辭以君命安敢稽。", "香花隨乘推不去，丁壯遮拜嬰孩啼。", "不知朝廷聞得否，天下貪吏濁如泥。", "毀譽失真例如此，狂瀾既倒誰能隄。", "書生有舌不善佞，今拜東野頭須低。", "詩成翻恨天門遠，何人乞我青雲梯。"]'),
('c5c34d87-9b7d-43fd-b47e-f84a7f0d3268','謝陳尉宏父惠潮陽蕉絲碑刻因求宿諾韓文','王邁','宋','宋诗','song-poetry','','[]','寒儒食貧面四壁，更苦春寒寒到骨。',64,'全唐诗/poet.song.195000.json','["寒儒食貧面四壁，更苦春寒寒到骨。", "故人天末有書來，不寄綈袍寄絺綌。", "感君高誼挾纊溫，况有石刻華吾軒。", "何時揩拭眵昏眼，待看昌黎玉潔文。"]'),
('8207e144-561b-441e-b577-a15708a6f834','邵武山人楊壽卿臨別索詩','王邁','宋','宋诗','song-poetry','','[]','楚峰之下有地仙，隻手把握山水權。',128,'全唐诗/poet.song.195000.json','["楚峰之下有地仙，隻手把握山水權。", "青烏白鶴去不返，此郎高舉拍其肩。", "年來海內稱絕倡，眸子瞭然通意匠。", "巧尋地脈如良醫，妙畫山形如智將。", "高談曾折王侯腰，湖海隨身一酒瓢。", "僕痡馬瘦醉不省，術工鬼妬窮之招。", "龍眼豹睛休分別，螻蟻侯王等同穴。", "待儂回向心地初，林下班荆共君說。"]'),
('00ede5c2-e7f3-4dac-8d2b-83e48f13b2d4','讀坡詩','王邁','宋','宋诗','song-poetry','','[]','先生詩筆覷天巧，國中往往無曹鮑。',160,'全唐诗/poet.song.195000.json','["先生詩筆覷天巧，國中往往無曹鮑。", "一讀快如檄愈頭，抓癢底用麻姑爪。", "千古詞林有若人，誰復庸中誇佼佼。", "當年流落見丹心，懸知世道終難拗。", "玉堂豈不願公留，羣吠其如尨也狡。", "出入風波千萬里，葛巾野服混蠻獠。", "饑來隻字不堪煮，豆粥一盂粗可飽。", "跋前疐後竟何成，贏得清名占箕昴。", "與公同時富貴人，名字磨滅隨蟣蚤。", "丈夫當爲不朽計，方寸莫被饑寒擾。"]'),
('831e1578-33db-44e0-a9ab-60d34fad3542','題致爽軒詩','王邁','宋','宋诗','song-poetry','','[]','明珠積斗滿金籝，時人逐臭如蒼蠅。',160,'全唐诗/poet.song.195000.json','["明珠積斗滿金籝，時人逐臭如蒼蠅。", "公子一過掩其鼻，長物何足汙吾清。", "蕊珠午夜鳴玉珂，五侯門下肩相摩。", "公子有腰不可折，勢利不屈惟高歌。", "試問公子何所欲，有山數笏青如玉。", "我將致之襟袖間，山若肯來吾願足。", "淵明靈運不再生，青山白雲誰主盟。", "佳哉公子有具眼，終日看山無俗情。", "我來假館翁不靳，山下梅花動詩興。", "一語刮破俗子盲，兩字清高用不盡。"]'),
('35980a1e-2716-4b44-8119-4cea5fee59b0','贈林薪','王邁','宋','宋诗','song-poetry','','[]','丈夫惟窮不可諱，僕妾于人真短氣。',160,'全唐诗/poet.song.195000.json','["丈夫惟窮不可諱，僕妾于人真短氣。", "一技能精百不憂，有功翰墨尤足貴。", "林生家世本業儒，讀書不利改傭書。", "計窮未肯與書絕，又學裁翦兼黏糊。", "就中頗得三昧訣，翻騰碑畫更奇絕。", "持此可療寒與饑，十指便當張儀舌。", "昔我于生義理明，以我之困知生貧。", "我今一字不堪煮，生猶有技可資身。", "鄴侯書堂高不過，好事人少俗人多。", "把筆贈生以此歌，有劍無廩奈生何。"]'),
('d801661f-902f-4cab-97a6-e97455ad5316','謝政府饋金','王邁','宋','宋诗','song-poetry','','[]','大廷昔日曾空臆，時論忌人太疏直。',144,'全唐诗/poet.song.195000.json','["大廷昔日曾空臆，時論忌人太疏直。", "名公正色力主盟，寘之甲科免居乙。", "殿廬今日忝校文，甘言如飴心所嫉。", "或者欲植桃李恩，慨然爲下雌黄筆。", "頭方直是不能圓，入險固應陰下石。", "我公天下盡門生，僕荷知音心感激。", "幸無贓墨辱門牆，猶免語人顔發赤。", "感公具眼照人才，墜履遺簪猶愛惜。", "臨歸多謝饋兼金，何日能爲還白璧。"]'),
('245ba9b2-9209-4d32-8a97-f5a3ce57d997','臂鷹詩','王邁','宋','宋诗','song-poetry','','[]','東鄰年少養獰鷹，置之臂上拊玩頻。',80,'全唐诗/poet.song.195000.json','["東鄰年少養獰鷹，置之臂上拊玩頻。", "呼來麾去性日馴，癡兒偶然見之嗔。", "鷹張利爪挐兒身，眇其隻目視主人。", "主人初以鷹爲戲，一日悔欲自斷臂。", "非我類者其心異，吾賦鷹詩所以志。"]'),
('d85e1d9b-560c-4ab0-ba9a-39f481feda80','啄木鳥','王邁','宋','宋诗','song-poetry','','[]','啄木復啄木，汝啄抑何毒。',148,'全唐诗/poet.song.195000.json','["啄木復啄木，汝啄抑何毒。", "千株萬株端明松，五月六月來清風。", "木于汝何惡，朝朝暮暮啄。", "勸汝利觜宜少停，戕木之生吾忍聽，已有弋者在後亭。", "微蟲初何識，亦能對以臆。", "天子愛元元，宵衣念艱食。", "連年值禾饑，窮閭多菜色。", "縣官急督租，吏饕饑需索。", "啄木比刻木，何者爲可疾。", "木生與民生，何者爲當恤。", "可彈者不彈，爲我謝彼弋。"]'),
('ea020bbb-1753-4d73-981c-e79d31f3c962','送莆守趙孟堅汝固司舶溫陵','王邁','宋','宋诗','song-poetry','','[]','君不見有唐元結守舂陵，湘湖一道盜縱橫。',262,'全唐诗/poet.song.195000.json','["君不見有唐元結守舂陵，湘湖一道盜縱橫。", "獨元所治一無犯，鎮撫孤壘如金城。", "又不見祁公曾作乾州牧，移鎮鳳翔何迅速。", "兩州之民境上爭，先把州麾後鈞軸。", "使君來莆全似元，精明旗幟張轅門。", "威風惠雨相劘拂，鼠輩不敢闖吾藩。", "使君去莆仍似杜，截鐙遮留喧道路。", "吾莆赤子方有依，泉何爲者爭吾父。", "我將軟語勞莆人，此地幸與泉爲鄰。", "刁斗相聞鄒近魯，瘠肥不比越視秦。", "使君風采壓人望，莆亦倚泉爲保障。", "渠魁縛致藁街前，四野腥膻行滌蕩。", "長淮以北多風埃，社稷正倚經綸才。", "出平西賊入衮繡，一韓一范何人哉。", "書生自顧老無力，不能從公取俘馘。", "願將詩頌紀中興，濃墨大字書浯石。"]'),
('28916bc3-34fb-4bab-9fb5-3d062059d600','惠安頼惟允汝恭乞崇清老椿芳桂四大字爲賦二詩  其一','王邁','宋','宋诗','song-poetry','','[]','混元盤古爲之母，汗漫安期爲之友。',80,'全唐诗/poet.song.195000.json','["混元盤古爲之母，汗漫安期爲之友。", "枝條上掛蜺連蜷，劫火不壞其天全。", "雷雨不驚其生厚，春秋巧歷莫能知。", "知我者有蒙莊叟，君持此物爲親壽。", "老陳作字光摩斗，人兮椿兮共長久。"]'),
('3c8b176f-bf0b-4bec-bc81-9834eaab3f0a','惠安頼惟允汝恭乞崇清老椿芳桂四大字爲賦二詩  其二','王邁','宋','宋诗','song-poetry','','[]','蘂宮仙子携黄雲，挼之成屑來繽紛。',88,'全唐诗/poet.song.195000.json','["蘂宮仙子携黄雲，挼之成屑來繽紛。", "百和天香兔爲擣，蟾蜍竊之從月奔。", "色香假合成此樹，天上香飄天下聞。", "花神乞種到后土，蒙天一笑移其根。", "知君腰有補月斤，斫取高枝揚遠芬，留其賸者遺子孫。"]'),
('36fceaee-eafa-4fb9-97d3-373017fc49c9','代賀崇清陳侍郎正仲讜誕辰','王邁','宋','宋诗','song-poetry','','[]','曾夢乘槎泛銀潢，不遇張騫遇東方。',288,'全唐诗/poet.song.195000.json','["曾夢乘槎泛銀潢，不遇張騫遇東方。", "爲言神仙事渺茫，仙府不在白雲鄉。", "丹台幻作儒珍閣，蓬島飛來雙筆堂。", "鶴車千乘集雲軸，玉塵萬斛紛雪香。", "是中仙翁永難老，嘗侍香案近玉皇。", "歸來手握山水印，傲睨羲昊輕軒裳。", "新詩醉墨美無度，奄有元白兼鍾王。", "身在巖壑心廊廟，絲鬢垂頷顔蒼蒼。", "與公同時一輩人，半隨蒲荻零秋霜。", "元老崔嵬獨山立，歲寒不改雪中篁。", "九月十五夜未艾，長庚伴月光煌煌。", "台星壽星合爲一，今夕何夕見此祥。", "翠娥滿引九仙醖，菊英入盞宮樣黄。", "珠明玉潤陪笑粲，起舞璫佩鳴丁當。", "李蹊森森密無縫，佳句往往溢詩囊。", "我於門闌最晚出，瓣香致禱意則長。", "如聞郡國事方殷，須起老手爲平章。", "待教衛武了相業，方許潞公歸洛陽。"]'),
('067c1264-1aa1-456f-8ddb-0dfebc3b9226','溫陵萬安橋謁忠惠蔡公祠堂留題','王邁','宋','宋诗','song-poetry','','[]','欲知公之忠，須誦三諫詩。',148,'全唐诗/poet.song.195000.json','["欲知公之忠，須誦三諫詩。", "欲知公之惠，須讀萬安碑。", "朝廷得公重，天下失公悲。", "騎鯨今幾年，悠悠人見思。", "今人愧前脩，風流不可追。", "立朝無剛容，突梯仍脂韋。", "字民乏廉聲，敲扑急繭絲。", "不知富貴有磨滅，芳名姱節無窮時。", "遊子晚出公之鄉，兒時斂袵公清規。", "吁嗟九原不可作，每於清夜夢見之。", "所以今日拜公像，浩歌出門雙淚垂。"]'),
('83d6cbb1-9dd2-4910-8e96-3300b10f88ac','和致政林存齋稚圭','王邁','宋','宋诗','song-poetry','','[]','東鄰南極老人星，音吐洪亮眼晶熒。',216,'全唐诗/poet.song.195000.json','["東鄰南極老人星，音吐洪亮眼晶熒。", "諸郎箇箇佳寧馨，長者早占千佛經。", "仲季銳如刃發硎，三珠粲爛照戶庭。", "老人散策傲郊坰，健筆哦詩驚六丁，仰天高唱雨霖鈴。", "餐和毓粹養靈扃，煉得元身如鶴形。", "文堂縱談耳驚霆，硬語盍作盤盂銘。", "笑渠教諂兒懶聽，只今人物混渭涇。", "賢者聚散類梗萍，報復未已况調停。", "我狂畏暑卧風櫺，日夕西望憂朝廷。", "何時乾坤得清寧，未信日月長昏冥。", "不必餔糟學獨醒，不煩餐菊制頹齡。", "支駕皇輿待騋駉，問訊誰坐東西廳。", "老成自昔有典刑，尚父須符渭卜靈。"]'),
('988543f8-7b06-47c2-b224-672d3209f1fb','贈蕭棠仲致政','王邁','宋','宋诗','song-poetry','','[]','昔年鼓篋游膠庠，集英同日瞻天光。',320,'全唐诗/poet.song.195000.json','["昔年鼓篋游膠庠，集英同日瞻天光。", "金門初開獸環動，曈曈曉日升扶桑。", "宮簾高捲開御扇，祥風習習飄天香。", "殿庭神麗冠劍肅，巍巍玉几臨中央。", "銀袍七百趨龍尾，拜恩稽首心歡康。", "晚從銀臺出廣陌，寶鞍快馬爭騰驤。", "團司涓日敘黄甲，義比天倫鴻雁行。", "瓊苑宴開慈惠浹，宸章寵錫歌明良。", "後來相繼隨宮牒，東西南北遥相望。", "萍開風轉有時合，邂逅一見難預量。", "非才叨竊愆咎積，自顧補報無毫芒。", "朝廷寬大不終棄，領郡尚得來南漳。", "下車問政訪耆舊，知公辭榮歸故鄉。", "神武衣冠已久掛，冥鴻羽翮方高翔。", "遺賢雖爲明時惜，承顔獨喜私願償。", "共驚歲月何飄忽，相對鬢髮俱滄浪。", "至言不吝揮玉麈，妙句屢蒙開錦囊。", "已歎高風激貪懦，更敦雅契超尋常。", "區區感慰豈有極，聊寫一二成短章。", "蕪音不足繼真作，讀過幸勿留巾箱。"]'),
('be8fcacc-54db-40c3-a377-65292d314612','春月白鶴吟寄魏鶴山','王邁','宋','宋诗','song-poetry','','[]','鶴去兮渠陽，雪衣兮相羊。',252,'全唐诗/poet.song.195000.json','["鶴去兮渠陽，雪衣兮相羊。", "啄芳洲兮飲碧湘，如青城之棲兮流矢中傷。", "鶴來兮錢塘，朱頂兮昂藏。", "浴太液兮下建章，如九皋之唳兮聲徹上蒼。", "鶴歸兮臨邛之崗，嗥朔風兮立曉霜。", "捫參歷井兮水雲鄉，如遼東之返兮華表飛揚。", "昔者去兮，狂梟毒獍相賀乎偃月堂。", "迨其來兮，文鸞祥鳳相得乎漢未央。", "今其歸兮，馴鷗狎鷺相待乎午橋莊。", "善類無依兮，若空乎振鷺之行。", "留行無語兮，誰扼乎羣鳥之吭。", "歸去來於鶴何加損兮，關世道之否臧。", "有雁兮南翔，翼短兮心長。", "避繒弋兮飽稻粱，望胎仙兮天一方。", "思蹇産兮結中腸，此仙之壽兮未易量。", "天若祚宋兮，當復來而爲治世之祥。"]'),
('3242b63c-ddb9-48b9-919a-061309bdc803','題聽蛙軒','王邁','宋','宋诗','song-poetry','','[]','白杜詩人大方家，詩兩牛腰書五車。',260,'全唐诗/poet.song.195000.json','["白杜詩人大方家，詩兩牛腰書五車。", "高談世事坐捫虱，大扁丈室名聽蛙。", "我見東野低頭拜，三年未了聽蛙債。", "蛙有何好君賞音，從黽得蛙自尊大。", "君胡不聽高岡丹鳳鳴，又胡不聽華亭鶴唳聲。", "答云二物不間出，吾與此蛙別有情。", "年來鳳去避矰弋，梧桐其棲竹其食。", "有時伸喙鳴朝陽，反被妖烏豪鷂擊。", "鶴亦遠引歸遼東，無緣得近華清宮。", "縱鳴九皋許嘹唳，流矢傷翼愁天翁。", "不如且聽蛙聲好，喚回夢覺春池早。", "縱饒翡翠上苕蘭，差勝蛩螿啼露草。", "王子掉頭曰不然，夫君標致如胎仙。", "富家有子比雛鵷，吾道豈得長迍邅。", "不妨少待兩三年，一鳴驚人飛沖天。", "羣蛙蜿蝡何足憐，棄置官池任啾喧。"]'),
('d0394853-e944-48db-9721-c2e590528b31','柏梁體簡龔少益','王邁','宋','宋诗','song-poetry','','[]','青山四面畫圖張，溪流月下鳴湯湯。',240,'全唐诗/poet.song.195000.json','["青山四面畫圖張，溪流月下鳴湯湯。", "山之下兮水之旁，有人結茅作書堂。", "誦聲灑灑流琳琅，使我一聽樂洋洋。", "應問誰爲師匠良，風流相種如龔郎。", "天孫付以錦繡腸，一揮十紙爛成章。", "上與奎宿爭光芒，器成未售此焉藏。", "吁嗟無地堪翺翔，塵纓自濯歌滄浪。", "床頭金盡羞慳囊，山鬼吹燈夜恓惶。", "蚊雷聚噪肆頡頏，仗劍起舞涕泗滂。", "勸君停劍無庸傷，時平賢路如康莊。", "鸞鳳引喙鳴高崗，時危此道隘且荒。", "橫寶在道暗無光，運行如此休慨慷。", "男兒立身當自强，精金須經百鍊剛。", "膜外榮枯等粃糠，惟忠惟孝不可忘。", "請君傾耳聽柏梁，謂余不信來對床。"]'),
('997cbe51-3aa8-41ca-9cdb-d5911e76b407','謝阮儒隠爲畫墨梅床屏','王邁','宋','宋诗','song-poetry','','[]','畸人平生偏愛奇，愛梅成癖不可醫。',290,'全唐诗/poet.song.195000.json','["畸人平生偏愛奇，愛梅成癖不可醫。", "書带堂前忽見之，相羊不去燃吟髭。", "今夕何夕秋爲期，芙蓉映日紅葳蕤，籬菊傲霜紛離披。", "南枝春信未有涯，安得此粲對酒巵。", "元是大阮解作無聲詩，寫梅幻相爲娛嬉。", "想當解衣盤礴下筆時，吸取清氣入肝脾。", "先融雪嶺作墨池，坐變秋陽成春暉。", "使我初見渾不疑，旋覺風骨全是顔容非。", "恍如臙支馬上坐明妃，緇塵生汗白玉肌。", "又如鴟夷船底載西子，烟波慘淡雙蛾眉。", "雪堂仙去渺莫追，補之位置傳者誰。", "君今此寶世間希，芒端寒燠巧推移。", "花神上訴真宰悲，何爲苦泄造化機。", "我有東絹滑如脂，裝潢爲屏作枕幃。", "平章衆畫何品宜，笑我嗜好與君相背馳，不愛崇桃積李鬭芳菲。", "請君快掃橫斜竹外枝，歲寒心事正要渠相知。"]'),
('1bfe6b72-d945-4418-9ba6-d37593d71c52','觀獵行','王邁','宋','宋诗','song-poetry','','[]','落日飛山上，山下人呼獵。',187,'全唐诗/poet.song.195000.json','["落日飛山上，山下人呼獵。", "出門縱步觀，無遑需屐屧。", "至則聞獵人，喧然肆牙頰。", "或言岐徑多，御者因追躡。", "或言御徒希，聲勢不相接。", "或言器械鈍，馳逐無所挾。", "或言盧犬頑，獸走不能劫。", "余笑與之言，善獵氣不懾。", "汝方未獵時，戰氣先萎薾。", "弱者力不支，勇者膽亦怯。", "微哉一雉不能擒，虎豹之血其可喋。", "汝不聞去歲淮甸間，熊羆百萬臨危堞。", "往往被甲皆汝曹，何怪師行無凱捷。", "嗚呼安得善獵與善兵，使我一見而心愜。"]'),
('2423eb8c-0e1d-4bd4-8a3b-518aeab361fd','梅花吟','王邁','宋','宋诗','song-poetry','','[]','君不見山前山後雪成堆，朔風撼地聲如雷。',99,'全唐诗/poet.song.195000.json','["君不見山前山後雪成堆，朔風撼地聲如雷。", "孤根忍死受寒凍，須作百花頭上魁。", "尋春遊子不愛惜，馬蹄踐蹂花狼籍。", "芳姿不肯被消磨，飽盡炎凉方結實。", "實成始得主人知，進登玉陛調鼎胹。", "那時滋味甜如飴，無忘霜風吹折時。"]'),
('1b921ed1-928b-46eb-8672-68489cd8c430','過建陽范氏桂林館見其向日娛賓亭館已屬他人詩以弔之','王邁','宋','宋诗','song-poetry','','[]','桂林當日如春煖，花木清妍差可款。',162,'全唐诗/poet.song.195000.json','["桂林當日如春煖，花木清妍差可款。", "主人好事玉泉香，行客留題錦囊滿。", "桂林今日如冰寒，頹垣壞壁他人管。", "窮冬莫贈范叔袍，過午誰餉子桑飯。", "君不見李家偃月堂，金魚玉珮鳴丁當。", "冰山一倒扶不起，月固無恙堂已荒。", "又不見董家藏金塢，翠幕珠幃貯歌舞。", "誰知當時賞心事，不救後來燃臍苦。", "請君聽我吟桂林，悲歡成敗更相尋。", "人生富貴如郵傳，古往今來幾桂林。"]'),
('20e1f917-c915-43de-8bbb-a3c8ae31ae60','讀渡江諸將傳','王邁','宋','宋诗','song-poetry','','[]','讀到諸賢傳，令人淚灑衣。',48,'全唐诗/poet.song.195000.json','["讀到諸賢傳，令人淚灑衣。", "功高成怨府，權盛是危機。", "勇似韓彭有，心如廉藺希。", "中原豈天上，尺土不能歸。"]'),
('a7c70121-7e12-4a64-b149-0b0c1ed9f44f','賢牧堂','王邁','宋','宋诗','song-poetry','','[]','賢牧存遺愛，邦人重此祠。',48,'全唐诗/poet.song.195000.json','["賢牧存遺愛，邦人重此祠。", "典刑前輩幾，德政後來誰。", "來日清泉濯，歸時隻鶴隨。", "不須看石碣，人口是豐碑。"]'),
('e90adf76-3d99-4b8c-8c5f-a3b0c3a4cc20','秋榜已揭不寐','王邁','宋','宋诗','song-poetry','','[]','寒重難爲坐，宵長可奈眠。',48,'全唐诗/poet.song.195000.json','["寒重難爲坐，宵長可奈眠。", "老天不解事，特地閏今年。", "風助蛩聲苦，霜和月色妍。", "抱衾成百感，嚼句憶坡仙。"]'),
('fbe7b2fc-39e6-4cb6-93b3-a22a1651cfa1','春晚山行問酒主媼以瓶罄告','王邁','宋','宋诗','song-poetry','','[]','霜曉寒於臘，日中方有春。',48,'全唐诗/poet.song.195000.json','["霜曉寒於臘，日中方有春。", "雲頭纔作暮，風力又欺人。", "老犢眠方穩，雛鶑語未真。", "停驂謀一醉，不酌酒家貧。"]'),
('b4e4f404-3cc5-4726-9bdc-ebda0d31d4a8','轎中五言','王邁','宋','宋诗','song-poetry','','[]','卯酒工爲醉，春衫怯曉寒。',48,'全唐诗/poet.song.195000.json','["卯酒工爲醉，春衫怯曉寒。", "籃輿有何味，脚力且圖閒。", "得句點頭笑，拈書信手翻。", "僕夫行且止，我愛眼前山。"]'),
('a331f4a7-6c30-4316-8431-72c896607d05','次韻調甘內掾','王邁','宋','宋诗','song-poetry','','[]','韓掾才情妙，吟成苦夜長。',48,'全唐诗/poet.song.195000.json','["韓掾才情妙，吟成苦夜長。", "歌殘如意鐵，夢斷合歡床。", "鼓瑟湘雲暖，吹笙嶺月凉。", "舊時雙燕子，飛入謝家堂。"]'),
('88b3ad18-c947-494b-a7a8-21594f76bad5','鵝坑先塋晚歸','王邁','宋','宋诗','song-poetry','','[]','詰曲穿荒徑，高平見遠山。',48,'全唐诗/poet.song.195000.json','["詰曲穿荒徑，高平見遠山。", "溪乾呈石紫，林峭露楓丹。", "不道歸來晚，惟愁句未安。", "片雲真解事，放出月團團。"]'),
('ead673d5-1035-4b04-b6d9-755a74a25bb3','夢林清叔','王邁','宋','宋诗','song-poetry','','[]','已分幽明隔，無端入夢來。',48,'全唐诗/poet.song.195000.json','["已分幽明隔，無端入夢來。", "交情今已矣，汝死亦冤哉。", "白骨今何在，滄波去不回。", "蛟龍慎勿食，之子謫仙才。"]'),
('066e8ee8-9434-49d6-83a8-4e1443d3d6f5','冬孟駕出親享太廟連日雨是朝大霽都人云凡四次如此矣  其一','王邁','宋','宋诗','song-poetry','','[]','玉宇曈矓曉，瓊京略綽寒。',48,'全唐诗/poet.song.195000.json','["玉宇曈矓曉，瓊京略綽寒。", "紫衣千騎從，黄繖萬人看。", "日景新開霽，天顔賸有歡。", "駕回春滿殿，聖母喜加餐。"]'),
('9fdfe3b6-247a-4cc4-b6ae-add311db6fe9','冬孟駕出親享太廟連日雨是朝大霽都人云凡四次如此矣  其二','王邁','宋','宋诗','song-poetry','','[]','穀旦街塵浄，滿城春意多。',48,'全唐诗/poet.song.195000.json','["穀旦街塵浄，滿城春意多。", "威儀清警蹕，鹵簿扈鑾和。", "從騎黄金勒，回班白玉珂。", "恩榮誰不羨，報上合如何。"]'),
('a5dcc5a0-1ae3-4b3f-83a5-2c6145967433','送陳宗諭進叔晉接赴慶元添倅及乃弟泰來四首  其一','王邁','宋','宋诗','song-poetry','','[]','向來寅陛對，冷語頗冰人。',48,'全唐诗/poet.song.195000.json','["向來寅陛對，冷語頗冰人。", "未犯神龍怒，先遭老鳳嗔。", "宗庠隨却步，家食不憂貧。", "公語何嘗泯，題輿寵渥新。"]'),
('c61c4bfe-a9be-43fb-9044-993dbb6c3ab7','送陳宗諭進叔晉接赴慶元添倅及乃弟泰來四首  其二','王邁','宋','宋诗','song-poetry','','[]','謾說題輿樂，誰知憂國心。',48,'全唐诗/poet.song.195000.json','["謾說題輿樂，誰知憂國心。", "城狐方伺隙，邊馬已如林。", "去上緹屏最，行陳丹扆箴。", "脂韋何足算，百煉是精金。"]'),
('683e81a1-ae35-4824-aeae-97d0b9062d6a','送陳宗諭進叔晉接赴慶元添倅及乃弟泰來四首  其三','王邁','宋','宋诗','song-poetry','','[]','若見青山老，煩言僕寄聲。',48,'全唐诗/poet.song.195000.json','["若見青山老，煩言僕寄聲。", "入新無好况，依舊是狂生。", "國事今如許，庸醫見亦驚。", "不知靈壽杖，還解拄天傾。"]'),
('9e7b1bce-f184-48a8-a4f6-64d13f8a140d','送陳宗諭進叔晉接赴慶元添倅及乃弟泰來四首  其四','王邁','宋','宋诗','song-poetry','','[]','玉季吾心友，經行話舊游。',48,'全唐诗/poet.song.195000.json','["玉季吾心友，經行話舊游。", "定知龍有種，又快鶚橫秋。", "對策空丹臆，爲兄賽一籌。", "功名相迫遂，只許片時留。"]'),
('dd61b4aa-5148-4355-a21a-ca7ea2c12c17','別劉孟容峸提幹二首  其一','王邁','宋','宋诗','song-poetry','','[]','孟容吾畏友，春日去朝京。',48,'全唐诗/poet.song.195000.json','["孟容吾畏友，春日去朝京。", "蔗境詩多好，蓮池官最清。", "坐誣緣舉將，取忌爲時名。", "諸老端平歲，同詞爲辨明。"]'),
('b726cfbe-396f-4585-97ef-08c59567bc75','別劉孟容峸提幹二首  其二','王邁','宋','宋诗','song-poetry','','[]','吾莆諸壽雋，習靜魯靈光。',48,'全唐诗/poet.song.195000.json','["吾莆諸壽雋，習靜魯靈光。", "有子麒麟種，羣孫鴛鷺行。", "此行青眼衆，見謂白眉良。", "通籍何愁晚，庭椿樂未央。"]'),
('2f06e0f6-2141-4499-8ba8-c483b188cc2c','送林師道似之赴寧都尉二首  其一','王邁','宋','宋诗','song-poetry','','[]','造謗端平歲，時髦一網空。',48,'全唐诗/poet.song.195000.json','["造謗端平歲，時髦一網空。", "君爲梨嶺後，名在蘂宮中。", "躐等輕餘子，知音邁鉅公。", "莫嫌登第晚，試看艾軒翁。"]'),
('aa43b02d-ea51-4a28-957c-bfc8313c21f0','送林師道似之赴寧都尉二首  其二','王邁','宋','宋诗','song-poetry','','[]','及物官無小，平生志所存。',48,'全唐诗/poet.song.195000.json','["及物官無小，平生志所存。", "一條冰出壑，五色棒懸門。", "皂蓋邦魁彥，繡衣鄉達尊。", "儻能念寒畯，梅市得春溫。"]'),
('a7fe0c18-ebc1-4a08-bcf2-ac06e6b02cfe','送鄭邛叔珪之博羅尉四首  其一','王邁','宋','宋诗','song-poetry','','[]','奇士束科目，炯如金在沙。',48,'全唐诗/poet.song.195000.json','["奇士束科目，炯如金在沙。", "孤吟娛草带，幾度見槐花。", "此舉衣纔綠，相看鬢欲華。", "泥金墨猶濕，已報熟葵瓜。"]'),
('e69d3e04-a970-4040-814b-dea690761892','送鄭邛叔珪之博羅尉四首  其二','王邁','宋','宋诗','song-poetry','','[]','三十年朋友，詩筒幾往還。',48,'全唐诗/poet.song.195000.json','["三十年朋友，詩筒幾往還。", "君纔遊宦海，我正賦囚山。", "灘鶒何時下，沙鷗鎮日閒。", "升沉蹤跡異，心事却相關。"]'),
('68b97b01-1486-4097-a1e2-cc6739e600fd','送鄭邛叔珪之博羅尉四首  其三','王邁','宋','宋诗','song-poetry','','[]','初宦南游日，去年西嘯時。',48,'全唐诗/poet.song.195000.json','["初宦南游日，去年西嘯時。", "豈無風竹興，剩有雪梅詩。", "一尉聊且浼，諸公定見知。", "勉旃行好事，遠業此其基。"]'),
('b1e33cac-ff10-4e00-b8c5-6299bbb45626','送鄭邛叔珪之博羅尉四首  其四','王邁','宋','宋诗','song-poetry','','[]','是邑經兵火，今纔補少痕。',48,'全唐诗/poet.song.195000.json','["是邑經兵火，今纔補少痕。", "要教民擊壤，毋遣吏椎門。", "文惠殘碑在，坡仙醉墨存。", "公餘勤物色，幽興入琴樽。"]'),
('7645b383-24c8-483a-b7cf-41910a03e2ff','送朱君錫珪尉德化二首  其一','王邁','宋','宋诗','song-poetry','','[]','皷篋游環璧，如君最妙齡。',52,'全唐诗/poet.song.195000.json','["皷篋游環璧，如君最妙齡。", "阿{隬/女}開絳幔，大阮共爐亭。", "力學案堆雪，收科蟄奮霆。", "莫嫌梅市小，有路透青冥。"]'),
('3e4fd194-a459-4dca-a1b1-66076a454117','送朱君錫珪尉德化二首  其二','王邁','宋','宋诗','song-poetry','','[]','隣邑宜初宦，輕軒最便家。',48,'全唐诗/poet.song.195000.json','["隣邑宜初宦，輕軒最便家。", "親顔悅萱草，詩料有梅花。", "佳兆雙飛鶒，夷途萬里驊。", "好培經世業，他日步清華。"]'),
('97f5242f-3805-4c51-9aaf-b015171cbbf6','送張能父天定赴瑞州教二首  其一','王邁','宋','宋诗','song-poetry','','[]','孟子稱三樂，廣文兼有之。',48,'全唐诗/poet.song.195000.json','["孟子稱三樂，廣文兼有之。", "壽椿齊百歲，常棣秀連枝。", "初筮筠江郡，尊爲芹泮師。", "英才需教育，遠業立鎡基。"]'),
('d03dfdfc-2d5e-45f4-b199-20036888eadc','送張能父天定赴瑞州教二首  其二','王邁','宋','宋诗','song-poetry','','[]','太學穿楊巧，青春斫桂榮。',48,'全唐诗/poet.song.195000.json','["太學穿楊巧，青春斫桂榮。", "心燈傳老宿，文印授諸生。", "德履華嵩重，襟期玉雪清。", "君王他日問，張姓複其名。"]'),
('5c26fb0f-4a6d-4d02-84a6-f0d2f66da342','送陳汝功起宰永春二首  其一','王邁','宋','宋诗','song-poetry','','[]','通了金閨籍，須教邑債還。',48,'全唐诗/poet.song.195000.json','["通了金閨籍，須教邑債還。", "尚威民作敵，徙善吏容奸。", "世久無彭澤，人今識魯山。", "平生經濟學，隨力救時艱。"]'),
('a28e4c07-846b-4794-b301-5ef7501d3b89','送陳汝功起宰永春二首  其二','王邁','宋','宋诗','song-poetry','','[]','一第垂三紀，卿評占得多。',48,'全唐诗/poet.song.195000.json','["一第垂三紀，卿評占得多。", "生涯似韋布，談笑試絃歌。", "夏校士師道，春臺民飲和。", "政成行奏最，好去立言坡。"]'),
('2e6b339c-babe-4464-9c34-be3149d93a81','送劉無競克遜司門赴召三首  其一','王邁','宋','宋诗','song-poetry','','[]','吾郡稱多士，君家總俊游。',48,'全唐诗/poet.song.195000.json','["吾郡稱多士，君家總俊游。", "仲方在閒散，伯又襲編修。", "道與時升降，賓隨主去留。", "郵亭還祖餞，別意爽於秋。"]'),
('9e81fbd9-7235-4854-8872-7f7f5ccdc774','送劉無競克遜司門赴召三首  其二','王邁','宋','宋诗','song-poetry','','[]','上了朱轓最，催還白玉京。',48,'全唐诗/poet.song.195000.json','["上了朱轓最，催還白玉京。", "兄憐子由別，母勸器之行。", "醫國言須切，謀身策尚平。", "友朋空愛助，君自有權衡。"]'),
('519f45ad-784d-4793-8189-941718583fd5','送劉無競克遜司門赴召三首  其三','王邁','宋','宋诗','song-poetry','','[]','更化僅如許，和戎覺又非。',48,'全唐诗/poet.song.195000.json','["更化僅如許，和戎覺又非。", "邊陲風色惡，人物曉星稀。", "國事迷當局，時賢赴急機。", "周嫠空憤切，不慮歲無衣。"]'),
('9068ee31-a7ce-4b67-a7ef-4a212bd1185c','送龔少貽北赴汀州司戶','王邁','宋','宋诗','song-poetry','','[]','莊敏與文獻，諸孫總俊髦。',48,'全唐诗/poet.song.195000.json','["莊敏與文獻，諸孫總俊髦。", "此郎如玉樹，初筮即珠曹。", "官小人能大，心清名自高。", "公餘須力學，流俗易滔滔。"]'),
('96ed8410-f8f1-46d0-b5b3-e8cb34a4bed9','送吳夢大監稅赴潮州圃灣二首  其一','王邁','宋','宋诗','song-poetry','','[]','詩禮名家子，錚錚早有聲。',48,'全唐诗/poet.song.195000.json','["詩禮名家子，錚錚早有聲。", "右班聊借徑，在計更司征。", "霜日孤標凈，湖山一鬨平。", "圖南九萬里，此去是頭程。"]'),
('12ee16d2-cdc9-4cdb-84fd-39e366ba1d00','送吳夢大監稅赴潮州圃灣二首  其二','王邁','宋','宋诗','song-poetry','','[]','一命官無小，心思及物同。',48,'全唐诗/poet.song.195000.json','["一命官無小，心思及物同。", "高風超俗見，隻手救人窮。", "宦路梅花白，親庭萱草紅。", "賢明尤易事，最喜遇南豐。"]'),
('06c932a4-57f9-45b2-9c75-15f98debd417','愛女','王邁','宋','宋诗','song-poetry','','[]','愛女有家後，沉痾未下床。',48,'全唐诗/poet.song.195000.json','["愛女有家後，沉痾未下床。", "問巫羞左道，市藥嘆空囊。", "攻悶三杯酒，祈安一瓣香。", "祠山消息好，秋杪得還鄉。"]'),
('80623935-16af-4c0c-bbc0-0c4de55c5067','送良沃州賦得石上松','王邁','宋','宋诗','song-poetry','','[]','南山巖石上，鬰鬰長青松。',48,'全唐诗/poet.song.195000.json','["南山巖石上，鬰鬰長青松。", "樛枝全似鐵，老幹半成龍。", "法雨流根潤，慈雲護影重。", "吾師掛錫處，苔蘚近來封。"]'),
('efe2185e-a5ee-4d97-9983-3264e03cff4f','題名士蔡偉叔宣子文集','王邁','宋','宋诗','song-poetry','','[]','書眼昏眵久，今逢刮膜篦。',48,'全唐诗/poet.song.195000.json','["書眼昏眵久，今逢刮膜篦。", "詩編雲岫序，文卷水心題。", "富艷濯江錦，清寒印月犀。", "行行遇知己，莫歎橐無齎。"]'),
('de88338c-da10-4ad1-868b-db5e0f300d8c','仙水歸程','王邁','宋','宋诗','song-poetry','','[]','九鯉湖邊路，重來盟未寒。',48,'全唐诗/poet.song.195000.json','["九鯉湖邊路，重來盟未寒。", "折花挼水獻，策杖馭風還。", "宦海波濤惡，仙家日月閒。", "前生丹在否，歲晚要重丸。"]'),
('737af83a-077c-454c-a9d6-39cd7b0dbb46','簡仙遊宰黄瀛甫登二首  其一','王邁','宋','宋诗','song-poetry','','[]','爲喜雙鳬舄，將臨九鯉鄉。',48,'全唐诗/poet.song.195000.json','["爲喜雙鳬舄，將臨九鯉鄉。", "民貧嗟轍涸，吏橫正鴟張。", "誰與催賢令，速來仁一方。", "茅簷茨屋下，延頸望春陽。"]'),
('85ab5f21-e868-4054-badd-54058e683d25','簡仙遊宰黄瀛甫登二首  其二','王邁','宋','宋诗','song-poetry','','[]','詩要淵明賦，琴須宓子鳴。',48,'全唐诗/poet.song.195000.json','["詩要淵明賦，琴須宓子鳴。", "幸哉吾百里，行矣見雙清。", "民瘼需綏撫，人才待作成。", "豬肝非我嗜，無事累高明。"]'),
('aaa258f2-fdfc-4ac6-aa4d-19e9f29c3bf0','池上歸道間即事二首  其一','王邁','宋','宋诗','song-poetry','','[]','一雨惱春思，今朝得快晴。',48,'全唐诗/poet.song.195000.json','["一雨惱春思，今朝得快晴。", "水波隨日動，麥浪受風平。", "野意來無極，籃輿穩更輕。", "抵家何事好，稚子亦驩迎。"]'),
('8a135920-3788-4d7e-af50-6aff335368df','池上歸道間即事二首  其二','王邁','宋','宋诗','song-poetry','','[]','寒食清明近，知春不久歸。',48,'全唐诗/poet.song.195000.json','["寒食清明近，知春不久歸。", "眼驚紅作陣，心愛綠成圍。", "宿鷺立晴瀨，栖鴉掀夕暉。", "狂遊付年少，我已省前非。"]'),
('eb6c17e6-8236-487e-bb1e-e429ee7e57d9','癡兒','王邁','宋','宋诗','song-poetry','','[]','癡兒纔五歲，器局稍精明。',48,'全唐诗/poet.song.195000.json','["癡兒纔五歲，器局稍精明。", "弄筆誇郎罷，窺鸞效女兄。", "顧瞻眸子俊，酬答舌頭輕。", "但願身長健，看渠骨骼成。"]'),
('3458719c-f2da-4087-b338-79e2c5751258','聽兒德胙讀書呈邱景實知一教授','王邁','宋','宋诗','song-poetry','','[]','我被儒官誤，如今又教渠。',48,'全唐诗/poet.song.195000.json','["我被儒官誤，如今又教渠。", "但令識數字，不要讀多書。", "帝憚汲生戇，人嫌賈誼疏。", "君看朱紫貴，不害腹空虛。"]'),
('55f3b9bf-e271-4003-8c35-3c788389a647','山中讀誠齋詩','王邁','宋','宋诗','song-poetry','','[]','四海誠齋老，千年百卷詩。',48,'全唐诗/poet.song.195000.json','["四海誠齋老，千年百卷詩。", "不親門下炙，却恨我生遲。", "嚼句有何味，班荆坐許時。", "大羹元淡泊，妙處少人知。"]'),
('60b3a3d8-b2ce-40ef-9f8d-448758583fe7','人日設安籙醮有送菊花一盆四幹直上開花數百顆不減重陽喜而成詩','王邁','宋','宋诗','song-poetry','','[]','弱幹簪頭大，鮮葩蠟樣黄。',48,'全唐诗/poet.song.195000.json','["弱幹簪頭大，鮮葩蠟樣黄。", "携來煩稚子，喜甚見重陽。", "不與浮花並，看渠晚節香。", "今宵持供聖，一粲動天皇。"]'),
('b7142407-4423-42e5-a1ef-d691d7a0cd10','多病','王邁','宋','宋诗','song-poetry','','[]','客問新來况，新來病更多。',48,'全唐诗/poet.song.195000.json','["客問新來况，新來病更多。", "憂時添老色，慍小損天和。", "不夢榮華境，祇尋安樂窩。", "年豐米猶賤，加飯笑廉頗。"]'),
('97145f9b-2768-4cbf-8606-f805f9837e02','看蔣玉父有珍炙膏肓','王邁','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','炷艾劇炎火，端躬如泰山。',48,'全唐诗/poet.song.195000.json','["炷艾劇炎火，端躬如泰山。", "醫師工指授，豎子覺毛寒。", "鐵脊梁須壯，銀河水不乾。", "明知寧忍痛，絕慾信爲難。"]'),
('2ca257a9-a657-423d-ac5d-393dead1f75a','歲晚','王邁','宋','宋诗','song-poetry','','[]','月映林塘澹，風含笑語凉。',48,'全唐诗/poet.song.195000.json','["月映林塘澹，風含笑語凉。", "俯窺憐綠凈，小立佇幽香。", "携幼尋新菂，扶衰坐野航。", "延緣久未已，歲晚惜流光。"]'),
('fe7f0292-ad01-4c5c-ba5f-0ef2f40430bb','闕題','王邁','宋','宋诗','song-poetry','','[]','文正爲州日，曾留此段奇。',48,'全唐诗/poet.song.195000.json','["文正爲州日，曾留此段奇。", "靈臺貯清白，廢井迸漣漪。", "神護蛟龍宅，波通日月池。", "紛紛攫金者，不畏此泉知。"]'),
('594a7bee-fba3-4321-a845-d6163ff78719','輓寧宗皇帝章六首  其一','王邁','宋','宋诗','song-poetry','','[]','驛報行天下，君王棄萬幾。',48,'全唐诗/poet.song.195000.json','["驛報行天下，君王棄萬幾。", "鶴翔雲漢遠，龍向鼎湖飛。", "杞國天初陷，咸池日尚微。", "臨軒思往事，血淚不停揮。"]'),
('d97a744a-b30c-468b-a1ee-35188de039e4','輓寧宗皇帝章六首  其二','王邁','宋','宋诗','song-poetry','','[]','帝業親耆定，皇圖日靖嘉。',48,'全唐诗/poet.song.195000.json','["帝業親耆定，皇圖日靖嘉。", "憂民比仁祖，在位邁重華。", "謨烈詒千載，車書混一家。", "最悲行蹕地，哀些咽簫笳。"]'),
('f45f8440-0f7c-4c22-a44a-b4fed3e3da8b','輓寧宗皇帝章六首  其三','王邁','宋','宋诗','song-poetry','','[]','聖化調新瑟，仁師慰望霓。',48,'全唐诗/poet.song.195000.json','["聖化調新瑟，仁師慰望霓。", "方還趙全璧，旋復禹玄圭。", "聲教恢鄒魯，威靈暢女鞮。", "浯碑堪恨處，聖壽不天齊。"]'),
('37049ba8-1ef7-4bb0-a8b0-f8b015b37cf0','輓寧宗皇帝章六首  其四','王邁','宋','宋诗','song-poetry','','[]','至道天同大，清心水不渾。',48,'全唐诗/poet.song.195000.json','["至道天同大，清心水不渾。", "六宮行幸少，尺宅煉真存。", "厭代金鑾殿，收魂玉帝垣。", "星辰羅上界，還奉太微尊。"]'),
('5459d9f9-0f7b-4a7f-a008-21340ef3362d','輓寧宗皇帝章六首  其五','王邁','宋','宋诗','song-poetry','','[]','憂治勤宵旰，生經爽鼎鉶。',48,'全唐诗/poet.song.195000.json','["憂治勤宵旰，生經爽鼎鉶。", "玉巵臨瑞節，畫翠愴昕廷。", "草木秋零落，乾坤晝晦冥。", "扶持宗社計，列聖在天靈。"]'),
('905af63b-ae4b-4e1a-9c6a-d806178a2267','輓寧宗皇帝章六首  其六','王邁','宋','宋诗','song-poetry','','[]','方啟中興運，旋開萬世功。',48,'全唐诗/poet.song.195000.json','["方啟中興運，旋開萬世功。", "人心憂漆室，神斷定青宮。", "識見幾微表，安危指顧中。", "孤臣讀遺詔，無語泣西風。"]'),
('efc82f90-ef34-4c0a-ba13-bf5e63472c0e','輓崇清陳侍郎五首  其一','王邁','宋','宋诗','song-poetry','','[]','太學修名立，甘泉晚節香。',48,'全唐诗/poet.song.195000.json','["太學修名立，甘泉晚節香。", "巋然周大老，好在魯靈光。", "餘慶滄浪水，清規壽俊坊。", "典刑今可挹，通德合名鄉。"]'),
('1fa866f6-4d5c-4bb2-9f67-40f8145f2a24','輓崇清陳侍郎五首  其二','王邁','宋','宋诗','song-poetry','','[]','峨豸居烏府，時方豹守關。',48,'全唐诗/poet.song.195000.json','["峨豸居烏府，時方豹守關。", "吾惟操白簡，渠謾倚冰山。", "六館爲增氣，羣憸覺汗顔。", "左遷無慍色，青史自斑斑。"]'),
('995ce765-3cb0-4993-95bf-62e112766d03','輓崇清陳侍郎五首  其三','王邁','宋','宋诗','song-poetry','','[]','當軸開邊釁，朝紳半詭隨。',48,'全唐诗/poet.song.195000.json','["當軸開邊釁，朝紳半詭隨。", "公方司獻納，言必及安危。", "願飾湟中備，毋輕馬邑師。", "當時雖枘鑿，今日若蓍龜。"]'),
('63ca5f45-60df-4e4e-b65e-558827934427','輓崇清陳侍郎五首  其四','王邁','宋','宋诗','song-poetry','','[]','勇退歸雲岫，投閒十四年。',48,'全唐诗/poet.song.195000.json','["勇退歸雲岫，投閒十四年。", "莆中無此樣，地上有行仙。", "健筆凌坡老，清詩輩樂天。", "何人綴遺稿，與作不刊傳。"]'),
('6648c803-7203-4101-a7e7-8b02d720db29','輓崇清陳侍郎五首  其五','王邁','宋','宋诗','song-poetry','','[]','小試濟川手，東西兩玉虹。',48,'全唐诗/poet.song.195000.json','["小試濟川手，東西兩玉虹。", "誰知千載計，更在十年中。", "砥柱老彌壯，恩波流不窮。", "向來香一瓣，心事與天通。"]'),
('22aec63e-484f-4b1b-b501-58df1d0b2e86','輓平昌戴丞東二首  其一','王邁','宋','宋诗','song-poetry','','[]','文籙傳三昧，詞壇白雪吟。',48,'全唐诗/poet.song.195000.json','["文籙傳三昧，詞壇白雪吟。", "奇才困場屋，晚歲綴紳簪。", "所歷官雖小，去思人到今。", "挂冠垂九秩，福善見天心。"]'),
('757c1e37-6f9d-45a0-ae25-6917cb6b49e9','輓平昌戴丞東二首  其二','王邁','宋','宋诗','song-poetry','','[]','倒蔗入佳境，寒花留晚香。',48,'全唐诗/poet.song.195000.json','["倒蔗入佳境，寒花留晚香。", "福田三古剎，恩澤四輿梁。", "鶴化空華表，牛眠占吉藏。", "他年青與紫，恒塞桂枝堂。"]'),
('8b0af58a-5447-4707-8399-ec89f38a142f','輓鄭昂叔珪母蔡夫人二首  其一','王邁','宋','宋诗','song-poetry','','[]','鍾秀端明裔，來嬪通德家。',48,'全唐诗/poet.song.195000.json','["鍾秀端明裔，來嬪通德家。", "早甘寒水玉，晚愛白蓮花。", "樂施陰功厚，回班慶事賒。", "他年龍鳳麓，贈典有光華。"]'),
('c42b9bc3-fe65-4460-814d-42df6f059993','輓鄭昂叔珪母蔡夫人二首  其二','王邁','宋','宋诗','song-poetry','','[]','絳幔談經日，熊丸茹苦時。',48,'全唐诗/poet.song.195000.json','["絳幔談經日，熊丸茹苦時。", "屢修堂上拜，親炙母中師。", "每羨萱堂樂，今成薤露悲。", "一生同令子，共泣蓼莪詩。"]'),
('e00cbfd1-65b1-426e-a654-2a5791d39510','二月朔日得詩二十六韻','王邁','宋','宋诗','song-poetry','','[]','二月方書朔，新晴景物饒。',288,'全唐诗/poet.song.195000.json','["二月方書朔，新晴景物饒。", "今春添一閏，是月始元朝。", "一枕初回夢，千官想正朝。", "橫魚金繫带，鳴騎玉爲鑣。", "歸第無餘事，流風競貴驕。", "歌翻羯羊鼓，舞襯鳳凰簫。", "爛醉東西玉，爭妍大小喬。", "湖山行處樂，日月暗中消。", "軒冕吾何羨，巾車隠者招。", "林泉供嘯傲，杖屨足逍遥。", "砌笋和泥掘，盆花引水澆。", "酒爐衣可準，茶竈火頻燒。", "冷眼蛾投燭，灰心鹿覆蕉。", "慣分田父席，懶折督郵腰。", "繙閱書連架，賡酬詩滿瓢。", "只知貧亦好，未覺興無聊。", "所恨黄巾熾，能爲鄰境祅。", "四郊羣嘯聚，十室九焚焦。", "舊臘月虧蝕，新年地震摇。", "臺占頻告異，塗說洊興妖。", "带甲多淪沒，抽丁困役徭。", "備防家買劍，巡邏境鳴刁。", "惡少鋒尤烈，渠魁首未梟。", "豺狼行逐逐，鴻雁羽翛翛。"]'),
('6a244849-9467-41ed-b217-d59152fdfcaf','潘世表來訪臨別贈二十韻','王邁','宋','宋诗','song-poetry','','[]','病眼緣春困，晨興爲子明。',264,'全唐诗/poet.song.195000.json','["病眼緣春困，晨興爲子明。", "未應談世故，政恐累吾清。", "書况近何若，襟期久不傾。", "春來已多日，課辦幾何程。", "我懶覺成慣，人憐太瘦生。", "招窮詩作祟，攻悶酒爲兵。", "昨著僧房宿，思尋友舊盟。", "時時整行李，往往嘆浮萍。", "一動歸歟興，長歌去矣行。", "小軒頻偃蹇，分物息經營。", "綠愛彌牆幄，紅驚糝地英。", "感時愁杜宇，喚夢賞鸝鶊。", "秩馬來迢遞，論文會合并。", "匆匆爲草具，鬰鬰有蘭馨。", "如許遽言別，深知不盡情。", "惜花二三月，送客短長亭。", "萬事眼前幻，一杯身後名。", "相期在忠孝，冷笑付枯榮。", "問學無窮盡，文章合老成。", "倘來聊爾爾，所立要錚錚。", "此去逢同社，爲儂好寄聲。", "有需新句子，此稿不妨呈。"]'),
('63353b5f-d3e3-43a1-909f-eb5fb58278c9','春月閲報成詩寄呈方漕信儒孚若','王邁','宋','宋诗','song-poetry','','[]','邊耗遽如許，廟謨先定無。',168,'全唐诗/poet.song.195000.json','["邊耗遽如許，廟謨先定無。", "書生良不武，夜半亦長吁。", "關表成餘幾，山陽援正孤。", "黄塵號鬼魅，落日走猩鼯。", "甲士疲鏖戰，丁夫困轉輸。", "臨淮一带水，諸將萬金軀。", "宛地誰收馬，延秋忌有烏。", "畢魂空慘淡，曦鬼定揶揄。", "公外英雄少，生來忠孝俱。", "全將身作膽，曾以口降胡。", "方喜規模偉，翻爲文法拘。", "正塗多植枳，公論冷如菰。", "嚙雪全初節，凌烟勉後圖。", "未應歌舞地，冷眼看侏儒。"]'),
('9d2e0f70-88df-4606-b32f-00c6f2ded9e6','人日六言五首  其一','王邁','宋','宋诗','song-poetry','','[]','功名朝三暮四，學問人百己千。',28,'全唐诗/poet.song.195000.json','["功名朝三暮四，學問人百己千。", "古今無限卿相，方冊惟著聖賢。"]'),
('780d4415-6c5f-4af4-b9a4-8ff8fdc1e1bb','人日六言五首  其二','王邁','宋','宋诗','song-poetry','','[]','誦詩心醉六義，讀易夢吞三爻。',28,'全唐诗/poet.song.195000.json','["誦詩心醉六義，讀易夢吞三爻。", "毛鄭寸長我取，羲文千載神交。"]'),
('0e3c777a-1ee6-4f40-8524-f0714e8cdcbd','人日六言五首  其三','王邁','宋','宋诗','song-poetry','','[]','飲食鮮能知味，巫醫各有單傳。',28,'全唐诗/poet.song.195000.json','["飲食鮮能知味，巫醫各有單傳。", "要得胸中活法，勿求紙上空言。"]'),
('7b3fa5dd-cbae-49eb-b180-97f5ea91c65b','人日六言五首  其四','王邁','宋','宋诗','song-poetry','','[]','六經桑麻穀粟，諸子綺縠奇珍。',28,'全唐诗/poet.song.195000.json','["六經桑麻穀粟，諸子綺縠奇珍。", "常常灌溉胸次，久久功用入神。"]'),
('8851403c-dfe4-4c1e-b72f-68856c4f0cfa','人日六言五首  其五','王邁','宋','宋诗','song-poetry','','[]','歲月滔滔流水，友朋落落踈星。',28,'全唐诗/poet.song.195000.json','["歲月滔滔流水，友朋落落踈星。", "載酒誰諏奇字，焚香自讀騷經。"]'),
('de32d9a8-5eb0-42a2-baef-ac53f543b0b0','和書樓叔遇叔題小蓬萊','王邁','宋','宋诗','song-poetry','','[]','月砌雲階不染埃，疑從天上幻將來。',64,'全唐诗/poet.song.195000.json','["月砌雲階不染埃，疑從天上幻將來。", "一龕儼坐鍾兼呂，二老相從聃與萊。", "丹劑好從金鼎鍊，玄關須要玉匙開。", "他年勳業如粗了，待約羣仙笑語陪。"]'),
('56f0af46-8fe5-43d7-913a-d759ab3c249b','歲晚偶題','王邁','宋','宋诗','song-poetry','','[]','飲冰食蘗坐窮閻，旋覺星星上鬢髯。',63,'全唐诗/poet.song.195000.json','["飲冰食蘗坐窮閻，旋覺星星上鬢髯。", "百尺樓中從偃卧，五侯門下任暄炎。", "寒花最愛香來晚，倒蔗須教末見甜。", "壽相誰知三甲，新年願得一丁添。"]'),
('cd6447a0-8665-454a-a09a-4a095dd198e9','除夜洗硯','王邁','宋','宋诗','song-poetry','','[]','多謝吾家即墨侯，朝濡暮染富春秋。',64,'全唐诗/poet.song.195000.json','["多謝吾家即墨侯，朝濡暮染富春秋。", "爲供文字逢青眼，要策功名趁黑頭。", "濯以清泉塵已蛻，衣之文錦翠如虬。", "呼童除夜陳豐饌，少勞精神併汝酬。"]'),
('c0e54ec9-13f7-4e43-abaf-95c946460951','寄謝希賢先覺表兄','王邁','宋','宋诗','song-poetry','','[]','昔君弱冠我猶兒，黄卷青燈茅屋西。',64,'全唐诗/poet.song.195000.json','["昔君弱冠我猶兒，黄卷青燈茅屋西。", "父對人談稱衛玠，母因客過器王珪。", "別來阻寄尺書鯉，夢裏時親日角犀。", "風快偶然翔短翼，不應鴻鵠久卑栖。"]'),
('75c01fd5-e5ea-4667-9550-d9f06e29ba67','丁丑同蔣力父東歸至城詩以別之','王邁','宋','宋诗','song-poetry','','[]','發軔神皋愁熱甚，解驂鄉井得凉多。',64,'全唐诗/poet.song.195000.json','["發軔神皋愁熱甚，解驂鄉井得凉多。", "半生相托左右手，一日同收甲乙科。", "老我已鋤年少習，期君共守歲寒柯。", "榮華富貴邯鄲枕，惟孝惟忠久不磨。"]'),
('aa44dee2-0e4d-43ac-942b-201ae0a41a40','晚過白沙','王邁','宋','宋诗','song-poetry','','[]','浪踏麻鞋破曉行，林梢猶自带殘星。',64,'全唐诗/poet.song.195000.json','["浪踏麻鞋破曉行，林梢猶自带殘星。", "氣吞宇宙原無餒，心醉功名未覺醒。", "紅雨無端汙行色，白雲知我憶親庭。", "平生慣作江湖客，得酒相看眼倍青。"]'),
('2ef0b62e-8a2f-4e26-a66a-e59483adeb0a','二月十六日到仙水未第前屢得夢','王邁','宋','宋诗','song-poetry','','[]','雙轂相催羊胛熟，三年方遂鯉湖遊。',64,'全唐诗/poet.song.195000.json','["雙轂相催羊胛熟，三年方遂鯉湖遊。", "羣仙笑問來何晚，世故相牽不自由。", "昨夢回思聊爾爾，他時稍足便休休。", "寄聲岩下鵝冠子，丹竈何妨爲我留。"]'),
('70c328e3-1888-4938-b1bb-d04d269f6bb0','謝仙遊許宰伯詡立續題名記招飲二首記乃崇清侍郎作  其一','王邁','宋','宋诗','song-poetry','','[]','栽花次第滿河陽，誰結寒根桃李場。',64,'全唐诗/poet.song.195000.json','["栽花次第滿河陽，誰結寒根桃李場。", "鰲在三山驚贔屭，鳬飛雙舄費揄揚。", "春風折屐緣聞捷，臘雪開筵重借光。", "他日明堂需大木，桷榱或得入平章。"]'),
('2816f131-b77f-4a6d-95cf-3a2aa31c67b5','謝仙遊許宰伯詡立續題名記招飲二首記乃崇清侍郎作  其二','王邁','宋','宋诗','song-poetry','','[]','憶昔琴堂宴士時，至今人誦壯行詩。',64,'全唐诗/poet.song.195000.json','["憶昔琴堂宴士時，至今人誦壯行詩。", "政緣勇氣填然躍，遂竊科名副所期。", "鄉橐摛詞光吐鳳，邦侯瑑美穩蟠螭。", "乞留片石棠陰下，要寫春風德政碑。"]'),
('7cf43eec-3419-417a-98c6-97add931fd66','賀許宰伯詡再考','王邁','宋','宋诗','song-poetry','','[]','宰官才具萬人豪，鷄小如何下得刀。',64,'全唐诗/poet.song.195000.json','["宰官才具萬人豪，鷄小如何下得刀。", "奏課再經書上上，理繁祇見辦多多。", "錦囊有卷牛腰重，裝橐無金馬骨高。", "欲賀政成憐我懶，篇詩付與邑人歌。"]'),
('94540e3d-d6f8-4ed2-aaa9-bb8732802028','壽仙遊許宰','王邁','宋','宋诗','song-poetry','','[]','南極秋來光燭天，琴堂此夕壽詩仙。',64,'全唐诗/poet.song.195000.json','["南極秋來光燭天，琴堂此夕壽詩仙。", "龐公戊子孰小大，寇相中元相後先。", "製錦從容才有刃，嚼丹賦詠筆如椽。", "交梨火棗君家物，從此蓬萊不計年。"]'),
('a42b5ec9-c6bf-44dc-9c3b-1bab07367f68','桃蹊梅塢','王邁','宋','宋诗','song-poetry','','[]','踈踈密密自成行，共趁春妍鬭曉粧。',64,'全唐诗/poet.song.195000.json','["踈踈密密自成行，共趁春妍鬭曉粧。", "移得武陵溪上種，傳來大庾嶺頭香。", "玄都道士風流別，東閣詩人興味長。", "喚取園丁勤物色，合將何樹比甘棠。"]'),
('d6480490-f2c5-483a-a7ec-292d4f240393','和崇清侍郎招飲超燕堂韻','王邁','宋','宋诗','song-poetry','','[]','超燕堂開一面春，却教寒畯亦充賓。',64,'全唐诗/poet.song.195000.json','["超燕堂開一面春，却教寒畯亦充賓。", "西清班裏推名從，南極躔中見老人。", "草聖已傳碑不朽，花神覺與思俱新。", "鄉邦桃李誰培植，直待魁然宰輔真。"]'),
('1a238554-6715-4f8c-bde9-64a0f3666ef8','再和陳侍郎子知丞寄桂香酒新到又令孫司戶出柑爲勸','王邁','宋','宋诗','song-poetry','','[]','栢葉椒花未報春，陽和先到四筵賓。',64,'全唐诗/poet.song.195000.json','["栢葉椒花未報春，陽和先到四筵賓。", "傳觀秀句堪呈佛，諦聽清談太迫人。", "子舍香醪浮甕碧，孫枝名果薦盤新。", "却將甘旨分寒陋，尤見先生愛士真。"]'),
('3ee2371d-7903-41f5-a89e-d6b1025e4173','寒食呈陳崇清','王邁','宋','宋诗','song-poetry','','[]','一百五日寒食節，八十六翁行地仙。',64,'全唐诗/poet.song.195000.json','["一百五日寒食節，八十六翁行地仙。", "曲水飛觴酬勝景，漢宮傳燭憶青烟。", "三春幸自添餘閏，雙筆今題第幾篇。", "俛仰興懷兒輩事，先生有樂在壺天。"]'),
('44d86475-b1f8-4207-ab0e-fb223a4bf471','壽陳崇清侍郎','王邁','宋','宋诗','song-poetry','','[]','笑把荷囊下紫霄，人傳千載鶴歸遼。',64,'全唐诗/poet.song.195000.json','["笑把荷囊下紫霄，人傳千載鶴歸遼。", "精忠一片馳寅陛，樂事無窮繼午橋。", "垂釣滄浪聽欵乃，揮毫雲岫賦逍遥。", "今辰恰紀蓬壺瑞，南極橫陳埒斗杓。"]'),
('6cb77d69-33ef-4132-b405-22528ee33744','賀陳侍郎該宗祀告成加封清源郡侯二首告詞有緬懷耆德養老乞言等語  其一','王邁','宋','宋诗','song-poetry','','[]','錦書飛下字如鴉，從橐詞頭似相麻。',64,'全唐诗/poet.song.195000.json','["錦書飛下字如鴉，從橐詞頭似相麻。", "竣事明禋均雨露，緬懷耆德傲烟霞。", "雞窠佚老精神健，燕頷宜侯爵邑加。", "願體乞言珍重意，星馳驛騎奏忠嘉。"]'),
('44f7cab2-594e-4075-9fcf-c78e6de8c73d','賀陳侍郎該宗祀告成加封清源郡侯二首告詞有緬懷耆德養老乞言等語  其二','王邁','宋','宋诗','song-poetry','','[]','辭封來伴赤松遊，判作山中萬戶侯。',64,'全唐诗/poet.song.195000.json','["辭封來伴赤松遊，判作山中萬戶侯。", "一片葵心天北闕，十行芝檢殿西頭。", "淵洪端靜恩言厚，拊藉溫存眷禮優。", "國事多艱耆舊少，須公與作濟川舟。"]'),
('1a1262bc-c5f8-4c63-8874-0eef4deaee72','再和二首  其一','王邁','宋','宋诗','song-poetry','','[]','筆飛鸞鳳墨翻鴉，白玉堂中懶草麻。',64,'全唐诗/poet.song.195000.json','["筆飛鸞鳳墨翻鴉，白玉堂中懶草麻。", "得句批風仍抹月，怡神飲露更餐霞。", "公於軒冕浮名薄，帝念耆英寵禮加。", "丕衍修齡全晚節，洋洋一札聖言嘉。"]'),
('30251c19-6365-4a97-888f-aae330b8d8b2','再和二首  其二','王邁','宋','宋诗','song-poetry','','[]','壯歲清源曾倦游，今朝大郡又封侯。',64,'全唐诗/poet.song.195000.json','["壯歲清源曾倦游，今朝大郡又封侯。", "身安不用扶鳩杖，骨貴從知應虎頭。", "望闕承恩顔有喜，即家問政禮宜優。", "濟時事業需元老，莫遣空橫野渡舟。"]'),
('8bebd38f-f015-44e8-88a7-aa2892ec028b','送鄉先生林磻黄石講會','王邁','宋','宋诗','song-poetry','','[]','歲暮何時更遠遊，劉蕡下第我色羞。',64,'全唐诗/poet.song.195000.json','["歲暮何時更遠遊，劉蕡下第我色羞。", "陽春自古難爲和，明月如今肯暗投。", "宿諾不輕連璧友，新盟借重扞城侯。", "九江儻拒黿鼇餌，何處堪人下釣鈎。"]'),
('84259f90-c950-471d-8646-15fc67356291','賀謝景芳得第四男','王邁','宋','宋诗','song-poetry','','[]','每愛君家玉滿階，仙宮今又見琨臺。',64,'全唐诗/poet.song.195000.json','["每愛君家玉滿階，仙宮今又見琨臺。", "父兮定得鈴旗夢，母也須懷磬石胎。", "羯末封胡知有種，復臨泰壯看朋來。", "林家絡秀如聞此，好好來求依樣杯。"]'),
('54a69e0f-bd6f-4533-9c8c-dc94e2950c1e','賀弟綱得男','王邁','宋','宋诗','song-poetry','','[]','韓相由來紫府仙，微之曾侍玉皇前。',64,'全唐诗/poet.song.195000.json','["韓相由來紫府仙，微之曾侍玉皇前。", "羨君久矣崇真教，生子居然契道緣。", "料得玉麟親入夢，試看銅狄幾經年。", "不須草草爲湯餠，剩出犀錢醉四筵。"]'),
('3239f7f2-9a6a-436a-8814-cd3fec7f557f','寄鄭龍川子汝瞻巖翁二首一敘別懷一謝惠端硯  其一','王邁','宋','宋诗','song-poetry','','[]','汝瞻當日預文盟，七十人中最妙齡。',64,'全唐诗/poet.song.195000.json','["汝瞻當日預文盟，七十人中最妙齡。", "別久恨無書寄鴈，夜深猶記案帷螢。", "我叨天幸登科甲，子盍心期紹品丁。", "後會阿蒙須刮目，流聲不減國蘭馨。"]'),
('376639b5-48b7-443a-aec4-f6e53cbfb34b','寄鄭龍川子汝瞻巖翁二首一敘別懷一謝惠端硯  其二','王邁','宋','宋诗','song-poetry','','[]','寄我端溪玉一彎，文房取友此其端。',64,'全唐诗/poet.song.195000.json','["寄我端溪玉一彎，文房取友此其端。", "眼中厭看珊瑚樹，掌上忻擎紫馬肝。", "底用千金求國手，擬封九錫霸詞壇。", "他時游宦南州路，免載囊中隻石還。"]'),
('0c62c400-1070-4738-9eb3-998ef6fbbda5','離家','王邁','宋','宋诗','song-poetry','','[]','無端輕棄白雲坳，似被梅花喚出郊。',64,'全唐诗/poet.song.195000.json','["無端輕棄白雲坳，似被梅花喚出郊。", "歲律堂堂蛇赴壑，宦途役役燕營巢。", "數更聽雨情何極，憂國懷家睫不交。", "老了英雄天不管，那堪更被北山嘲。"]'),
('a15d9e1f-832a-4fba-9fcb-fa68b6102889','謝何察推鯽鱠','王邁','宋','宋诗','song-poetry','','[]','君家一筯萬錢拚，分我銀絲侑客歡。',64,'全唐诗/poet.song.195000.json','["君家一筯萬錢拚，分我銀絲侑客歡。", "芳餌得來珍丙穴，金刀落處照辛盤。", "腹腴差迫詩肩瘦，鱗活能生酒面寒。", "玉手行厨如許巧，說教魚婢學應難。"]'),
('424e05a2-66ee-4818-acf7-da4254b23e2f','別戴仲實','王邁','宋','宋诗','song-poetry','','[]','人生契好不在久，一日可當十年游。',64,'全唐诗/poet.song.195000.json','["人生契好不在久，一日可當十年游。", "共君三兩夜清話，洗我千萬斛奇愁。", "欲晴未晴雲閣雨，臨別惜別車停輈。", "異時扁舟下瀨渚，安道謹勿避子猷。"]'),
('6fb2960a-ba88-4464-8d45-e8b24b3f77dc','二月閲邸報','王邁','宋','宋诗','song-poetry','','[]','聞道邊頭數萬兵，倒戈歸我我遺民。',64,'全唐诗/poet.song.195000.json','["聞道邊頭數萬兵，倒戈歸我我遺民。", "處降失策國非國，清野無糧人食人。", "關外數州城不獵，山陽孤戍草無春。", "書生憂憤空頭白，自有經綸社稷臣。"]'),
('7d13ab44-f400-4718-a5cc-5184d1555262','感嘆時事','王邁','宋','宋诗','song-poetry','','[]','西風慘淡起愁雲，走檄飛書正糾紛。',64,'全唐诗/poet.song.195000.json','["西風慘淡起愁雲，走檄飛書正糾紛。", "劍器朝方驅冶匠，戈船夕又募新軍。", "馬肥已報高秋警，鶴唳那堪中夜聞。", "我輩憂邊心欲折，棘門灞上漫論勳。"]'),
('279e61d5-f9ae-4c3e-ba37-4b0753bd7145','聞倪正甫尚書遭臺評','王邁','宋','宋诗','song-poetry','','[]','人從捷徑博公侯，一老堂堂去不留。',64,'全唐诗/poet.song.195000.json','["人從捷徑博公侯，一老堂堂去不留。", "誰向帝前讒陸贄，不令王所著居州。", "修名已立公何欠，直道難行國可憂。", "安得上方三尺劍，爲渠斷取佞臣頭。"]'),
('d88f3ff2-112b-4091-9ce3-b2d5c5070b67','題王雙巖詩集後二首  其一','王邁','宋','宋诗','song-poetry','','[]','自是先生標致高，誦詩恍見萬人豪。',64,'全唐诗/poet.song.195000.json','["自是先生標致高，誦詩恍見萬人豪。", "清如金掌雙莖露，壯似錢塘八月濤。", "胸次無塵春拍拍，道腴有味樂陶陶。", "輶軒刻棗傳衡岳，留得芬芳伴楚騷。"]'),
('eb18a319-3283-4513-9334-5dfb261f0bd6','題王雙巖詩集後二首  其二','王邁','宋','宋诗','song-poetry','','[]','白首憂時意更長，明言六籍法皆良。',64,'全唐诗/poet.song.195000.json','["白首憂時意更長，明言六籍法皆良。", "先生不竟身前用，有子親傳肘後方。", "時論無人傳藥石，上醫著眼識膏肓。", "歸歟活國工夫辦，要續雙巖百世香。"]'),
('ad8f591a-c87d-4cde-bee8-f753a20f048f','寄題盧川容膝軒詩','王邁','宋','宋诗','song-poetry','','[]','誰將容膝榜軒楣，未見高人心領之。',64,'全唐诗/poet.song.195000.json','["誰將容膝榜軒楣，未見高人心領之。", "綠綺牙籤無長物，名芝芳茝是佳兒。", "卧看筆架成江夢，坐揖爐峰讀楚詞。", "諸謝風流應未遠，盧川今又種清規。"]'),
('92e35a56-328d-445c-8ba4-b4760795dd6d','送方潛仲入太學','王邁','宋','宋诗','song-poetry','','[]','英氣軒軒貫斗牛，春風匹馬辟雍遊。',64,'全唐诗/poet.song.195000.json','["英氣軒軒貫斗牛，春風匹馬辟雍遊。", "家庭競秀三株樹，伯仲相交五鳳樓。", "回首白雲添舊感，細聽夜雨入新愁。", "妙年唾掌收科第，會有歐公避一頭。"]'),
('6ab4d9fd-fc8e-48ab-b4c9-e263f2011e8f','石巴山買舟','王邁','宋','宋诗','song-poetry','','[]','年來機事付沙鷗，湖海萍蓬覺倦遊。',64,'全唐诗/poet.song.195000.json','["年來機事付沙鷗，湖海萍蓬覺倦遊。", "千里白雲關我恨，一江流水替人愁。", "快聞飛槳健於馬，底問前灘吼似牛。", "枕藉舟中君莫歎，人生何日不虛舟。"]'),
('42eeb8e7-970f-4035-bc27-2c56fcc566aa','陳方大弟宏父將省侍潮陽以詩約別','王邁','宋','宋诗','song-poetry','','[]','逆旅頻連風雨床，歸來蹤跡兩參商。',64,'全唐诗/poet.song.195000.json','["逆旅頻連風雨床，歸來蹤跡兩參商。", "誰知纔隔路三舍，不似相從天一方。", "壺山白認梅將雪，潮水黄知菊已霜。", "便去也須留驛道，欲携斗酒話彷徨。"]'),
('4a29f50d-9342-4255-b40d-fb63e6926dec','七月望後二日西湖會飲酒酣分韻賦詩得荷字','王邁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','波平烟霽晚風和，船到湖心水沒窩。',64,'全唐诗/poet.song.195000.json','["波平烟霽晚風和，船到湖心水沒窩。", "凉絕不知三伏暑，醉酣齊唱八仙歌。", "賞梅洞口憐和靖，種柳堤邊憶老坡。", "魚鑰他時如共直，好論舊事捲新荷。"]'),
('d7484881-01f7-4764-beba-ade5245fc5de','紹興戒珠寺讀右軍祠堂碑','王邁','宋','宋诗','song-poetry','','[]','先祠石刻摩挲久，華胄遥遥企慕勞。',64,'全唐诗/poet.song.195000.json','["先祠石刻摩挲久，華胄遥遥企慕勞。", "字古似觀秦急就，詞幽如讀楚離騷。", "不誇絕藝臨池學，只羨清風誓墓高。", "更有山居須問訊，擬携方士鍊金膏。"]'),
('9e66587f-8ab6-42cb-ae08-4031b64a7af9','蘭亭故居','王邁','宋','宋诗','song-poetry','','[]','弭節稽山樂事多，舊聞一一入搜羅。',64,'全唐诗/poet.song.195000.json','["弭節稽山樂事多，舊聞一一入搜羅。", "卧薪伯業今何在，喬木家聲久不磨。", "可笑兒曹憐野鶩，却輸道士辨籠鵝。", "不因禊帖風流遠，千載人誰數永和。"]'),
('307e8dd9-e0be-4a94-aa54-8c94cf8c1b4e','闕題','王邁','宋','宋诗','song-poetry','','[]','此亭形勝壓東州，吳越山川日夜浮。',64,'全唐诗/poet.song.195000.json','["此亭形勝壓東州，吳越山川日夜浮。", "萬頃怒濤胥憤烈，一舠明月蠡風流。", "悲鳴華表千年鶴，縹渺沙洲數點鷗。", "倦客來游空弔古，那堪更上最高樓。"]'),
('662ff205-52a7-4ff4-bd86-9460e68a785b','蓬萊閣','王邁','宋','宋诗','song-poetry','','[]','歷晉更唐歲月多，玩珠龍尚枕山阿。',64,'全唐诗/poet.song.195000.json','["歷晉更唐歲月多，玩珠龍尚枕山阿。", "絕憐蓬閣題元祐，敢擬蘭亭記永和。", "秦望數尖銜夕照，鏡湖一綫暗烟莎。", "登臨未盡匆匆去，奈此千巖萬壑何。"]'),
('601cd585-1a4a-45c6-a28b-586722885d68','飛雲樓','王邁','宋','宋诗','song-poetry','','[]','亭前一望水東流，更有雄樓在上頭。',64,'全唐诗/poet.song.195000.json','["亭前一望水東流，更有雄樓在上頭。", "燕子飛來春漠漠，鴟夷仙去水悠悠。", "神交故國三千里，目斷中原四百州。", "日暮片雲棲古樹，昔人留與後人愁。"]'),
('854f4eaa-4eda-402e-b823-abb36ef459b7','寓書吉祥寺臨去親友三人來訪','王邁','宋','宋诗','song-poetry','','[]','共指梅花笑裏看，詩腸清峭酒腸寬。',64,'全唐诗/poet.song.195000.json','["共指梅花笑裏看，詩腸清峭酒腸寬。", "一陽方長知春近，三友同來話歲寒。", "富貴迫人隨世膩，身心何日似僧閑。", "策勳茗椀匆匆去，不道樽前欠小蠻。"]'),
('fa97ca7b-0dd3-49ff-af2f-4dd07c54562b','永嘉何子善琴而有詩名一日携二妙見訪求詩','王邁','宋','宋诗','song-poetry','','[]','山川司馬遊曾慣，湖海元龍氣更豪。',64,'全唐诗/poet.song.195000.json','["山川司馬遊曾慣，湖海元龍氣更豪。", "詩眼具時穿月脇，琴聲妙處寫雲和。", "夫君隻手兼雙美，舉世何人賞此高。", "料得送窮文已辦，雪霜應柰歲寒柯。"]'),
('4330eb8c-7034-4b47-a6b6-c78d5d06e0ae','爲余君肅曰嚴母夫人壽','王邁','宋','宋诗','song-poetry','','[]','曾向瑶池穩泛槎，眼看西母佩飛霞。',64,'全唐诗/poet.song.195000.json','["曾向瑶池穩泛槎，眼看西母佩飛霞。", "定分天地沖和氣，來匹公侯富貴家。", "熊膽課兒心苦淡，魚軒錫命世榮華。", "樽前何物堪爲壽，笑指蟠桃幾度花。"]'),
('cfd9ac1f-37c7-4804-ad2d-f3cfa7f1e4a9','賀同年林簿同卿龜從新婚  其一','王邁','宋','宋诗','song-poetry','','[]','金華門外浥京塵，烏石山前結帨巾。',64,'全唐诗/poet.song.195000.json','["金華門外浥京塵，烏石山前結帨巾。", "翁壻相看冰映玉，庭闈一笑頰生春。", "昔言爾爾嫌隨俗，今喚卿卿喜有人。", "來歲夢蘭叶佳兆，犀錢玉果出娛賓。"]'),
('fa07e941-465b-4b4e-b436-7775149411c0','賀同年林簿同卿龜從新婚  其二','王邁','宋','宋诗','song-poetry','','[]','知君雅志厭奢豪，富貴相尋可得逃。',64,'全唐诗/poet.song.195000.json','["知君雅志厭奢豪，富貴相尋可得逃。", "雲母屏間穿雀目，銷金帳下醉羊羔。", "養生早悟眉爲斧，侍立須驚手有刀。", "老我詩成還失笑，膏粱未必勝糠糟。"]'),
('487e83ee-cfda-43f9-a68f-cf99fce19817','再和王君保定通判韻','王邁','宋','宋诗','song-poetry','','[]','覆雨翻雲市道交，公持正論息羣嘲。',64,'全唐诗/poet.song.195000.json','["覆雨翻雲市道交，公持正論息羣嘲。", "風高莫送翎毛短，春煖難生土脈磽。", "攻過每蒙奇藥賜，衛生更借好方抄。", "一陽來復駸駸泰，善類傾心望拔茅。"]'),
('325e6a08-d5c9-437f-b210-c9f231199ec0','和黄遇卿二白韻','王邁','宋','宋诗','song-poetry','','[]','晚來雲色半濃淡，雲外青山知有無。',64,'全唐诗/poet.song.195000.json','["晚來雲色半濃淡，雲外青山知有無。", "纔出六花誇舞女，又飛一白慰農夫。", "久無人說平淮事，空有天生訪戴圖。", "憂國寸心同皎潔，詩肩如鷺更清臞。"]'),
('40bd091a-8080-4887-b9cf-95b89151a111','寄陳起予宗夏二首  其一','王邁','宋','宋诗','song-poetry','','[]','道有窮通時屈伸，夫君氣槩豈長貧。',64,'全唐诗/poet.song.195000.json','["道有窮通時屈伸，夫君氣槩豈長貧。", "帳前弟子知無幾，膝上郎君最可人。", "苜蓿儘多聊一笑，栗梨見覓莫渠嗔。", "平生耿耿猶存否，五十端能貴買臣。"]'),
('e5a28f3b-03b3-4163-8714-99fef9e12376','寄陳起予宗夏二首  其二','王邁','宋','宋诗','song-poetry','','[]','昔共從師未裹頭，如今雙鬢各驚秋。',64,'全唐诗/poet.song.195000.json','["昔共從師未裹頭，如今雙鬢各驚秋。", "我無突兀萬間厦，君自昂藏百尺樓。", "風雨苦多時事惡，英雄未遇老天愁。", "相思一夜不成寐，早起題詩寄便郵。"]'),
('9f4a3d07-5ae8-4c3d-a4d9-11394f4b3e88','再和陳起予二首  其一','王邁','宋','宋诗','song-poetry','','[]','龍蟄藏身來者伸，不妨抱道且安貧。',64,'全唐诗/poet.song.195000.json','["龍蟄藏身來者伸，不妨抱道且安貧。", "晝眠經笥誇羣弟，夜擁綈袍憶故人。", "富貴未來招鬼笑，文章太好恐天嗔。", "安排禮樂三千字，寓目他年許得臣。"]'),
('c857c247-1de3-4dcc-b4f9-a3cf6cb15747','再和陳起予二首  其二','王邁','宋','宋诗','song-poetry','','[]','一誦君詩一點頭，華摛春艷氣凌秋。',64,'全唐诗/poet.song.195000.json','["一誦君詩一點頭，華摛春艷氣凌秋。", "耳邊厭聽兩蛙部，眼底新誇五鳳樓。", "花信風殘生酒興，竹枝歌罷動閨愁。", "蘭亭已近浮觴節，先把歸期話置郵。"]'),
('adb6cef4-e3c2-4b87-9244-309795158253','和後村劉甫紀夢','王邁','宋','宋诗','song-poetry','','[]','夢懷諫紙立前廂，夢覺披衣起細詳。',64,'全唐诗/poet.song.195000.json','["夢懷諫紙立前廂，夢覺披衣起細詳。", "斗粟舊謠仍抗奏，籝金往訓覺增光。", "穹官緊職一時事，令子直臣千載香。", "報答君親良有日，未應垂釣老滄浪。"]'),
('7bd44561-e735-4671-8cbf-2de24c82984a','贈郭五星若水叔清二首  其一','王邁','宋','宋诗','song-poetry','','[]','雙闕雲仍山澤儒，步占小技豈其徒。',64,'全唐诗/poet.song.195000.json','["雙闕雲仍山澤儒，步占小技豈其徒。", "家傳要眇先天學，腹有熒煌列宿圖。", "南海編書希代寶，西山一序護身符。", "二賢出處關天運，曾把流年細算無。"]'),
('ff609e32-1573-494f-8ac4-e0d769e25188','贈郭五星若水叔清二首  其二','王邁','宋','宋诗','song-poetry','','[]','淮蜀年來殺氣深，中州兵革亦相尋。',64,'全唐诗/poet.song.195000.json','["淮蜀年來殺氣深，中州兵革亦相尋。", "命懸逆賊狂夫手，憤激孤臣孽子心。", "人物眇然難倚仗，風濤如此恐胥沉。", "煩君夜起觀星斗，福德何時吳分臨。"]'),
('1bac786a-1357-4339-8214-f0c95bce2ad4','又贈劉鐵面五星','王邁','宋','宋诗','song-poetry','','[]','劉君腹貯一天星，搜索真機泣六丁。',64,'全唐诗/poet.song.195000.json','["劉君腹貯一天星，搜索真機泣六丁。", "少可舌端無軟語，秘傳肘後有全經。", "話盟在昔疑猶夢，詩讖如今果叶靈。", "我亦正爲貧作祟，雙眸贏得一番青。"]'),
('08d58bb4-812a-4d35-bd2d-11133ae2e721','送徐子學夢鯉赴梅教二首  其一','王邁','宋','宋诗','song-poetry','','[]','九州四海盡同年，德行公居一榜先。',64,'全唐诗/poet.song.195000.json','["九州四海盡同年，德行公居一榜先。", "太學何蕃名籍甚，南州孺子道巍然。", "此行莫笑儒官冷，立事須還晚節堅。", "聞說青衿齊引領，靈砂九轉待丹鉛。"]'),
('d448d1df-f593-4f31-94c3-2f0df4ff3a9c','送徐子學夢鯉赴梅教二首  其二','王邁','宋','宋诗','song-poetry','','[]','底官得似教官清，吏不能塵以道鳴。',64,'全唐诗/poet.song.195000.json','["底官得似教官清，吏不能塵以道鳴。", "三鱣堂前推老宿，百花洲上見諸生。", "斯文有脉煩珍護，何地無才要作成。", "朝列諸公半知己，匪朝吹上玉皇京。"]'),
('457d7a2b-8f02-46b9-8f78-001ff6e4cc67','和京教李景平  其一','王邁','宋','宋诗','song-poetry','','[]','父子才名壓二班，儒官咫尺近家山。',64,'全唐诗/poet.song.195000.json','["父子才名壓二班，儒官咫尺近家山。", "官閒人羨清華選，詩好天開笑粲顔。", "雌甲一生甘守拙，雄飛千里莫渠攀。", "骨凡自分仙難做，懶去從人學九還。"]'),
('d38fedba-245d-4a0d-a91e-466761a9b36d','和京教李景平  其二','王邁','宋','宋诗','song-poetry','','[]','美人清曉夢催班，老子心清只愛山。',64,'全唐诗/poet.song.195000.json','["美人清曉夢催班，老子心清只愛山。", "晚歲松筠留素節，艷春桃李付紅顔。", "官麤鶴料猶堪活，援寡龍門莫浪攀。", "滿眼飛騰霄漢上，誰知倦翼已思還。"]'),
('1c6c26a5-e80d-4081-b0d2-2236c1e91f3c','和京教李景平  其三','王邁','宋','宋诗','song-poetry','','[]','天上儀隣懶趁班，愁雲苦雨暗湖山。',64,'全唐诗/poet.song.195000.json','["天上儀隣懶趁班，愁雲苦雨暗湖山。", "絕憐黑黍紛披穗，空有决明鮮好顔。", "憂國寸心增感慨，趨時俗駕倦追攀。", "幕中幸自文書省，詩債無緣久不還。"]'),
('6ba8e00f-bd52-4123-8618-afff4d225c54','送黄少遇非熊守德慶','王邁','宋','宋诗','song-poetry','','[]','三紀間關歷宦途，蕭然全似一臞儒。',64,'全唐诗/poet.song.195000.json','["三紀間關歷宦途，蕭然全似一臞儒。", "恥趨東閤隳高節，甘向南州剖左符。", "悃愊不能爲健吏，清修端可律貪夫。", "羊城定見菊坡老，能爲蒼生一出無。"]'),
('2a2c4d9c-0536-480d-8bc2-a95238f5a0ad','送蜀名父之子程剛仲世德擢甲科二首  其一','王邁','宋','宋诗','song-poetry','','[]','一誦洋洋大對文，便知風骨是西人。',64,'全唐诗/poet.song.195000.json','["一誦洋洋大對文，便知風骨是西人。", "筆頭重有千鈞力，字面清無半點塵。", "衆羽羣中鳴鳳喙，潜淵深處摘龍鱗。", "丈夫出處關初節，歸去携名壽大椿。"]'),
('1745b02d-d94d-48b2-9cad-223ce03f407b','送蜀名父之子程剛仲世德擢甲科二首  其二','王邁','宋','宋诗','song-poetry','','[]','乃翁勇退急流中，家法森嚴在教忠。',64,'全唐诗/poet.song.195000.json','["乃翁勇退急流中，家法森嚴在教忠。", "有子清材如結綠，告君直氣貫晴虹。", "甲科更合放頭出，時論從來忌臆空。", "生長殊方同臭味，相期不朽是英雄。"]'),
('def7b127-47b3-45b2-9695-36767274bb50','賀宋兄令子縣尉之望擢第榮還','王邁','宋','宋诗','song-poetry','','[]','自從西笑便安排，果有佳音天上來。',64,'全唐诗/poet.song.195000.json','["自從西笑便安排，果有佳音天上來。", "縱靶少年親得雋，跨鞍老將幾銜枚。", "歡馳帝里泥金帖，喜溢親庭藥玉杯。", "造物與君良不薄，好將陰德厚栽培。"]'),
('6cd8a5ab-922e-4840-9780-5cb478522a99','用徐編修德夫韻賀其開藩旴江二首  其一','王邁','宋','宋诗','song-poetry','','[]','幾年泉谷養靈根，一立朝班敢盡言。',64,'全唐诗/poet.song.195000.json','["幾年泉谷養靈根，一立朝班敢盡言。", "鏁掣玉麟辭紺殿，符分金虎坐轅門。", "郡條上日新施設，民瘼微時預討論。", "勿鄙嚮來工珥筆，只將清浄鎮囂喧。"]'),
('e7158b46-5bab-49f4-bc28-fa58fade04b4','用徐編修德夫韻賀其開藩旴江二首  其二','王邁','宋','宋诗','song-poetry','','[]','君侯心事即蒼冥，諤諤曾同唯唯爭。',64,'全唐诗/poet.song.195000.json','["君侯心事即蒼冥，諤諤曾同唯唯爭。", "醫國奇方留後用，字民好事及今行。", "懸知夔卨班難繼，且入龔黄傳亦榮。", "天誘聖衷差易耳，正人得路致隆平。"]'),
('cf9ebea9-c7e8-481b-b926-a5bdf8bae351','壽南宗東巖四首  其一','王邁','宋','宋诗','song-poetry','','[]','公是崑臺紫府仙，中間一念墮塵緣。',64,'全唐诗/poet.song.195000.json','["公是崑臺紫府仙，中間一念墮塵緣。", "小猿驛口霜生甑，白鶴巖前月滿船。", "詩太迫人清似水，琴真知我直如絃。", "年來族老晨星少，獨魯靈光尚巋然。"]'),
('b3aad44f-ee3d-4a9b-8be6-0c13401644ae','壽南宗東巖四首  其二','王邁','宋','宋诗','song-poetry','','[]','杉風蘿月讀書樓，藜杖分光夜校讎。',64,'全唐诗/poet.song.195000.json','["杉風蘿月讀書樓，藜杖分光夜校讎。", "雙璧連科天啟齒，一珠照座客回頭。", "金閨通籍傳芳信，綵袖稱觥襯雅謳。", "浪說錦屏家慶好，銀潢元有此風流。"]'),
('3b52ad6e-cace-4b1c-90a8-0e07d1855395','壽南宗東巖四首  其三','王邁','宋','宋诗','song-poetry','','[]','新陽一信迸黄鐘，春到分枝若木叢。',64,'全唐诗/poet.song.195000.json','["新陽一信迸黄鐘，春到分枝若木叢。", "天爲萬人生李晟，朋來三壽頌僖公。", "松林古佛燒香報，粟洞羣仙注福同。", "欲識東巖長壽相，只看台背更方瞳。"]'),
('8b5f377e-0eb5-42f6-b8a9-2fec7606cc0e','壽南宗東巖四首  其四','王邁','宋','宋诗','song-poetry','','[]','萬斛龍文筆可扛，詩壇坐受百城降。',64,'全唐诗/poet.song.195000.json','["萬斛龍文筆可扛，詩壇坐受百城降。", "文章今代長庚李，福氣前朝戊子龐。", "見說明時延彥勝，可令屬籍欠鴻厖。", "餘干相業公須繼，先借雙旌涖是邦。"]'),
('8fc51266-3d37-470b-af32-60a57a729349','過新蓬二嶺','王邁','宋','宋诗','song-poetry','','[]','世路年來熟險巇，那堪炎火正宣威。',64,'全唐诗/poet.song.195000.json','["世路年來熟險巇，那堪炎火正宣威。", "足摩青壁頂頭過，心逐白雲天外飛。", "瀑布有聲愁客耳，山禽無語怪儒衣。", "田翁憐我鞋根濕，爲說林梢已夕暉。"]'),
('3b68e750-c2d1-4f94-a9a9-63e6cb209b63','閩嶺遥岑','王邁','宋','宋诗','song-poetry','','[]','天晴遥見七閩關，萬仞丹梯莫可攀。',64,'全唐诗/poet.song.195000.json','["天晴遥見七閩關，萬仞丹梯莫可攀。", "鳥度不離青嶂裏，客行多在白雲間。", "玉門遼邈誠虛設，蜀道崎嶇只等閑。", "擾擾路傍名利子，軒車南去幾人還。"]'),
('21112702-de44-452c-b30b-db17464a1315','送會之夢龍赴南安尉','王邁','宋','宋诗','song-poetry','','[]','儒生十九諳吏事，君自胸中有八窗。',64,'全唐诗/poet.song.195000.json','["儒生十九諳吏事，君自胸中有八窗。", "好去褆身師長吏，謹毋泄邇薄鄰邦。", "政聲要重車渠百，祥兆須來鸂鶒雙。", "自笑慳囊無可贐，篇詩獨不美羊腔。"]'),
('782afff3-9a67-4701-b85c-088e0604eef5','錢方言巖仲之泰尉尤溪二首  其一','王邁','宋','宋诗','song-poetry','','[]','莫作尋常一尉看，斯人能大所居官。',64,'全唐诗/poet.song.195000.json','["莫作尋常一尉看，斯人能大所居官。", "才高不數麒麟楦，氣盛曾排虎豹關。", "初筮事人須以直，有心及物莫辭難。", "此行有一爲君賀，刺史賢如元次山。"]'),
('7e7152ff-4fdb-4a52-a889-e80749b42c64','錢方言巖仲之泰尉尤溪二首  其二','王邁','宋','宋诗','song-poetry','','[]','一第歸來正黑頭，艾軒遺墨費旁搜。',64,'全唐诗/poet.song.195000.json','["一第歸來正黑頭，艾軒遺墨費旁搜。", "及瓜上日相催迫，鋟棗通宵細校讎。", "充類所行皆好事，立身何患不前修。", "故家常寶文公帖，謹勿逢人便有求。"]'),
('41c30240-ed90-4dcb-81f9-6d078da52972','寄婺州趙尚書立夫二首  其一','王邁','宋','宋诗','song-poetry','','[]','大雅千年一嗣音，人如美玉更良金。',64,'全唐诗/poet.song.195000.json','["大雅千年一嗣音，人如美玉更良金。", "清修山澤臞儒樣，惻怛河沙古佛心。", "北闕方瞻台斗踐，東嘉還借福星臨。", "中興宗衮留衣鉢，大有蒼生望作霖。"]'),
('b3cb6bb5-b827-4fc9-8fd0-c40a28b79732','寄婺州趙尚書立夫二首  其二','王邁','宋','宋诗','song-poetry','','[]','憶昔京畿入幕時，游從日淺辱深知。',64,'全唐诗/poet.song.195000.json','["憶昔京畿入幕時，游從日淺辱深知。", "每誇得士如溫造，幾度逢人說項斯。", "親見登瀛應擊節，近聞去國爲攢眉。", "江干餞別公先至，洪魏諸賢鼎鼎來。"]'),
('200c278a-72d0-437d-b828-19d50af1294d','游溫陵得未第之士四人作四愛詩 贈茂功茂叔','王邁','宋','宋诗','song-poetry','','[]','吾愛清源徐茂功，聲名捷出日方東。',64,'全唐诗/poet.song.195000.json','["吾愛清源徐茂功，聲名捷出日方東。", "高尻下首紛餘子，屈指論心幾鉅公。", "我定斯文宜館閣，人言科目滯英雄。", "直須一舉魁天下，方快鵬程萬里風。"]'),
('2a662bc5-6cca-4359-8438-9596c7d75054','游溫陵得未第之士四人作四愛詩 贈養仁若春','王邁','宋','宋诗','song-poetry','','[]','吾愛清源顔養仁，筆端有力重千鈞。',64,'全唐诗/poet.song.195000.json','["吾愛清源顔養仁，筆端有力重千鈞。", "奇才自合巍收第，他巧何妨且進身。", "我老無能惟喜士，君名若出定驚人。", "元宵相聚過寒食，不污東風一點塵。"]'),
('0f020899-5957-42c2-a974-6081ee9966f6','游溫陵得未第之士四人作四愛詩 贈順夫履信','王邁','宋','宋诗','song-poetry','','[]','吾愛清源陳順夫，妙齡足跡半江湖。',64,'全唐诗/poet.song.195000.json','["吾愛清源陳順夫，妙齡足跡半江湖。", "三湘舟裏詩成束，百尺樓前酒滿壺。", "科目豈淹真俊傑，世間誰數飽侏儒。", "長安貴宦門如市，還有樽前此客無。"]'),
('a39b0800-5e34-42da-81b2-b6d3f8a89cbd','游溫陵得未第之士四人作四愛詩 贈來叔泰來','王邁','宋','宋诗','song-poetry','','[]','清源吾愛陳來叔，紫帽家聲藹月評。',64,'全唐诗/poet.song.195000.json','["清源吾愛陳來叔，紫帽家聲藹月評。", "苦學心能通造化，擇交足不出門庭。", "人知長宋名先弟，誰識子由文勝兄。", "聽取搢紳傳好語，可軒後有兩魁星。"]'),
('a4c44bb3-4b4d-42d8-a423-74f80e893d7d','簡宗弟無逸稼主簿','王邁','宋','宋诗','song-poetry','','[]','朅來纔是早春時，過眼園林囀子規。',67,'全唐诗/poet.song.195000.json','["朅來纔是早春時，過眼園林囀子規。", "看絕交書君介癖，讀離騷賦我狂癡。", "斷無清夢飛蓬島，剩有{宀旲}搜到草池。", "聞說郎星遭孛彗，又添一恨上雙眉。"]'),
('8d9764d7-bde1-4b1a-ae4e-c16f45ea70e9','和林養正龜符惠詩','王邁','宋','宋诗','song-poetry','','[]','殿陛程文被十行，要搜鯁論獻朝堂。',64,'全唐诗/poet.song.195000.json','["殿陛程文被十行，要搜鯁論獻朝堂。", "點頭只欠饒三好，强項須教受一章。", "耿耿古心增骯髒，茫茫俗眼笑荒唐。", "大官羊肉非吾羨，一筯藜羹劣可嘗。"]'),
('1d4204e6-23a0-48cd-ae42-cde176236e60','賀洪景茂葉舍試平奏仍勉爲南宮之行  其一','王邁','宋','宋诗','song-poetry','','[]','鼓篋天庠正妙齡，同時行輩半先登。',64,'全唐诗/poet.song.195000.json','["鼓篋天庠正妙齡，同時行輩半先登。", "如今纔喜紅心中，當日幾成赤脚升。", "冀北羣空看走馬，溟南路闊快摶鵬。", "歸來新敞渠渠厦，笑我生涯冷似冰。"]'),
('c42f58f4-83ef-48e2-8bf9-1c3f95b769b4','賀洪景茂葉舍試平奏仍勉爲南宮之行  其二','王邁','宋','宋诗','song-poetry','','[]','萬仞浮屠已合尖，出門一笑謝虀鹽。',64,'全唐诗/poet.song.195000.json','["萬仞浮屠已合尖，出門一笑謝虀鹽。", "釣鰲滄海六連上，騎鶴揚州二得兼。", "讖應何仙符舊兆，夢魁余榜合新占。", "破荒吾邑須君輩，更看花從錦上添。"]'),
('9486d242-a6ba-42b5-9b05-b9297f3093c7','賀陳思表兄西上','王邁','宋','宋诗','song-poetry','','[]','誰言場屋似樗蒲，好手居然不解輸。',64,'全唐诗/poet.song.195000.json','["誰言場屋似樗蒲，好手居然不解輸。", "疊采三巡皆得注，結場一擲定成盧。", "月評須應狀元讖，風義新添家慶圖。", "科第假途餘事耳，方來宇宙要人扶。"]'),
('2347157e-8f21-42e6-8002-ad9536e0470e','賀陳講書謀仲諏璋慶','王邁','宋','宋诗','song-poetry','','[]','好是橙黄橘綠時，津津黄色上雙眉。',64,'全唐诗/poet.song.195000.json','["好是橙黄橘綠時，津津黄色上雙眉。", "十爲良月陽將長，一索成男喜可知。", "南外□房開宅相，西清荷橐長孫枝。", "青春拾芥收科第，須記麟庠客有詩。"]'),
('86af0582-f7de-477c-b9a8-955e1d3b68da','賊平賀本路史倉良叔彌忠四首  其一','王邁','宋','宋诗','song-poetry','','[]','實地從來着脚安，好脩纕蕙更紉蘭。',64,'全唐诗/poet.song.195000.json','["實地從來着脚安，好脩纕蕙更紉蘭。", "貴游淡似孤寒士，達宦貧於初品官。", "醫國名方留肘後，憂民心事集眉端。", "浮榮過眼同歸盡，獨魯靈光耐久看。"]'),
('26840de7-9c5f-42fa-b846-e223af77ca40','賊平賀本路史倉良叔彌忠四首  其二','王邁','宋','宋诗','song-poetry','','[]','建俗輕生自古然，况逢軍旅更饑年。',64,'全唐诗/poet.song.195000.json','["建俗輕生自古然，况逢軍旅更饑年。", "兩臺相顧長酸鼻，一飯無緣得下咽。", "發廩救荒寧計日，乞師請命屢牋天。", "賊平必欲論功報，鎮撫須居戰取先。"]'),
('3d5a266c-c429-4618-9771-b465eee9d27f','賊平賀本路史倉良叔彌忠四首  其三','王邁','宋','宋诗','song-poetry','','[]','六十青蚨米五升，兒童滿口說常平。',64,'全唐诗/poet.song.195000.json','["六十青蚨米五升，兒童滿口說常平。", "方愁饑火無聊頼，一沐恩波得並生。", "真佛現身來救度，老天著眼自分明。", "從今閩粵家生子，定把君侯姓作名。"]'),
('5b3d715f-e33b-4429-85e2-272536296339','賊平賀本路史倉良叔彌忠四首  其四','王邁','宋','宋诗','song-poetry','','[]','誨盜須知有自來，貪官污吏禍之胎。',64,'全唐诗/poet.song.195000.json','["誨盜須知有自來，貪官污吏禍之胎。", "殺人越貨甘殘忍，入市拏金不忌猜。", "誰與清朝申典憲，合將若屬寘渠魁。", "書生銳欲排閶闔，先誦民謠獻外臺。"]'),
('9d0c34a3-0dba-4637-a0ae-968816ddd982','寄惠安吳簿明輔子良權南安宰二首  其一','王邁','宋','宋诗','song-poetry','','[]','南安只是舊南安，敏手爲之便好看。',64,'全唐诗/poet.song.195000.json','["南安只是舊南安，敏手爲之便好看。", "事辦要先心肯辦，才難須信縣無難。", "錦遭傷後從新製，琴不調時改舊彈。", "見說笑談理繁劇，公餘何惜築詩壇。"]'),
('851cea98-e2b6-4632-a4d9-c75dc92154d6','寄惠安吳簿明輔子良權南安宰二首  其二','王邁','宋','宋诗','song-poetry','','[]','邑人見說漸相安，更把西山作樣看。',64,'全唐诗/poet.song.195000.json','["邑人見說漸相安，更把西山作樣看。", "有社有民行志易，不寬不猛得中難。", "設施新法須明允，掩蓋前愆莫糾彈。", "便作真王何用假，安排旗鼓即齋壇。"]'),
('496d6e5f-3ac4-4dad-bb72-4ddce8e598f7','題惠安頼汝恭溪山風月亭','王邁','宋','宋诗','song-poetry','','[]','亭俯清漪揖翠岑，好風吹面月盈襟。',64,'全唐诗/poet.song.195000.json','["亭俯清漪揖翠岑，好風吹面月盈襟。", "濯纓孺子滄浪興，抱膝高人梁父吟。", "流轉韶光蘭滿砌，婆娑秋景桂成林。", "爲君喚起棲梧鳳，瑞旦來儀磬樂音。"]'),
('b16f72d3-eba0-42ad-9120-220edf796b8f','送真西山赴召','王邁','宋','宋诗','song-poetry','','[]','一朝三命下金鑾，獨有先生出處難。',64,'全唐诗/poet.song.195000.json','["一朝三命下金鑾，獨有先生出處難。", "學術顔曾千載上，行藏呂范二公間。", "莫言一木難支厦，須向中流力障瀾。", "愛助蓋爲天下計，丈夫心事頗相關。"]'),
('a0a4cf47-743c-40d1-8f1d-c14953ce6b61','送吳魁君謀叔告赴召二首  其一','王邁','宋','宋诗','song-poetry','','[]','三載天庭出一魁，一魁豈是利名媒。',64,'全唐诗/poet.song.195000.json','["三載天庭出一魁，一魁豈是利名媒。", "熙寧如葉庸人耳，南渡惟張君子哉。", "臚唱若爲調衆論，囊封正要看人才。", "千年青史芬芳遠，過眼浮榮付儻來。"]'),
('04ec6328-61d4-4a43-9fc3-bd45aeecd6e9','送吳魁君謀叔告赴召二首  其二','王邁','宋','宋诗','song-poetry','','[]','盛名之下最難居，一節清忠自有餘。',64,'全唐诗/poet.song.195000.json','["盛名之下最難居，一節清忠自有餘。", "竪鐵脊梁須我輩，橫金腰帯聽伊渠。", "和戎自古迷當局，善類何時可得輿。", "抗論朝廷須正大，莫如鄉黨費分踈。"]'),
('1bab23a5-3f34-43fe-a0b9-e448753a740d','送徐茂功西上二首','王邁','宋','宋诗','song-poetry','','[]','有司具眼柬時髦，此士今纔入網羅。',64,'全唐诗/poet.song.195000.json','["有司具眼柬時髦，此士今纔入網羅。", "好去南宮平步過，向來東閣閲才多。", "孤忠畎畝常憂國，大對軒墀莫主和。", "有問臞翁消息者，官非不愛柰狂何。"]'),
('1b89dc43-5989-45d8-9e6b-c4158317e92f','送傅一新西上','王邁','宋','宋诗','song-poetry','','[]','此去蘭宮好策勛，子行真足張吾軍。',64,'全唐诗/poet.song.195000.json','["此去蘭宮好策勛，子行真足張吾軍。", "大鵬怒奮溟南翼，駿馬鳴驚冀北羣。", "直要安排醫國策，不徒戲作送窮文。", "逢人有問狂生者，爲說憂時已白紛。"]'),
('5a3fcbc1-f91c-4dae-a73b-c8b7c5cd59fa','送朱典卿履常上舍西上','王邁','宋','宋诗','song-poetry','','[]','天庠教育總英游，文行惟君擅兩優。',64,'全唐诗/poet.song.195000.json','["天庠教育總英游，文行惟君擅兩優。", "玉潤珠明盈咳唾，蘭薰雪白見操修。", "老天不錯須開眼，朱吏相逢定點頭。", "月裏一枝高斫處，向來我已爲君留。"]'),
('fb7e9015-e17d-472b-a3cf-ec9970594e7e','送張柔翁必强西上','王邁','宋','宋诗','song-poetry','','[]','說詩匡鼎筆如椽，此去雲霄穩着鞭。',64,'全唐诗/poet.song.195000.json','["說詩匡鼎筆如椽，此去雲霄穩着鞭。", "富貴恰當年五十，扶摇快上路三千。", "乃翁積種今歸子，是理乘除信有天。", "梅友面傳衣鉢好，題名更向萬人前。"]'),
('3aef12f7-2809-401f-9df5-d02ba559cab9','送黄東起西上','王邁','宋','宋诗','song-poetry','','[]','我友君居德行科，見君覺我汗顔多。',64,'全唐诗/poet.song.195000.json','["我友君居德行科，見君覺我汗顔多。", "筆端有韻珠盈唾，胸次無塵玉不磨。", "好去腰斤高斫桂，向來傳鉢有持荷。", "廣寒管領羣仙到，爲我慇懃謝月娥。"]'),
('32ac8a11-1b27-420b-a8c3-3817da05a5e4','送林元質彬之西上','王邁','宋','宋诗','song-poetry','','[]','二十年來共短檠，相親不減友于情。',64,'全唐诗/poet.song.195000.json','["二十年來共短檠，相親不減友于情。", "風高鶚版曾雙中，海闊鵬摶不計程。", "宣力棘圍新扁額，題詩梨嶺舊家聲。", "瓣香旦旦爲君祝，唾掌功名在此行。"]'),
('0199522a-ec2b-40b0-a675-bae72f25fa74','送陳君保作喆西征','王邁','宋','宋诗','song-poetry','','[]','非時何事欲西征，爲有悲風動紫荆。',64,'全唐诗/poet.song.195000.json','["非時何事欲西征，爲有悲風動紫荆。", "斜斷最憐鴻鴈影，急難方見鶺鴒情。", "北方寒地多冰雪，南國饑甿弄甲兵。", "扶旐東歸良不易，護持孝友有神明。"]'),
('849d30c7-9fc7-402c-aeac-da97e5a4b469','西征延平道中偶成','王邁','宋','宋诗','song-poetry','','[]','羣羽斜飛欲刺空，誰能翦翼向籠中。',64,'全唐诗/poet.song.195000.json','["羣羽斜飛欲刺空，誰能翦翼向籠中。", "客程跋涉二千里，年紀侵尋五十翁。", "酒有神通排磊塊，書無靈聖困英雄。", "相逢且說窮愁話，纔入修門莫說窮。"]'),
('7393ea56-5b01-4cd2-9821-44b64bbdd042','送鄭秉叔西征','王邁','宋','宋诗','song-poetry','','[]','聯轡而西三十程，風餐雨宿費經營。',64,'全唐诗/poet.song.195000.json','["聯轡而西三十程，風餐雨宿費經營。", "間關閲舊途經熟，老大逢新歷日驚。", "我正與時相枘鑿，君方隨詔赴弓旌。", "獨班賜第明年事，回首雲深谷口耕。"]'),
('08764484-82d3-4aad-b651-eac839a7441b','除夜宿江下逆旅呈甥陳宗器','王邁','宋','宋诗','song-poetry','','[]','在家隨俗坐守歲，逆旅無聊卧向晨。',64,'全唐诗/poet.song.195000.json','["在家隨俗坐守歲，逆旅無聊卧向晨。", "舊隠荒凉棲鶴怨，端門邂逅畫雞新。", "知非早似蘧伯玉，將貴誰欺朱買臣。", "幸自樽中留得酒，與君隨分慶長春。"]'),
('ff9bca96-d787-4b2a-921b-0712a3505e56','南劍倅趙用甫權郡有小集以祈晴不用妓移晚筵於潘司戶','王邁','宋','宋诗','song-poetry','','[]','君侯風誼薄雲高，軫念征夫跋涉勞。',64,'全唐诗/poet.song.195000.json','["君侯風誼薄雲高，軫念征夫跋涉勞。", "雅宴朝陪青玉案，餘歡晚屬念珠曹。", "嚮來驚下曾參杼，此去誰分范叔袍。", "齋閤祈晴行有應，免教雪虐更風饕。"]'),
('d01c95c8-6d60-421e-a3ed-dd09f1bacfa6','和龍溪陳宰璉景賜石馬橋韻橋乃其父崇清作倡','王邁','宋','宋诗','song-poetry','','[]','幾年公案一朝成，我覩爭先眼倍明。',64,'全唐诗/poet.song.195000.json','["幾年公案一朝成，我覩爭先眼倍明。", "勢面似呈新月樣，灘腰不作怒濤聲。", "鰲頭地踞三千尺，鵬路天開九萬程。", "荷橐瓣香元好在，陰功隠德慰平生。"]'),
('9e5e3159-f88c-489d-8ea7-5ab0366c02f9','又九月朔同諸將觀石馬橋','王邁','宋','宋诗','song-poetry','','[]','萬年石馬勝緣成，千丈金鰲跨水橫。',64,'全唐诗/poet.song.195000.json','["萬年石馬勝緣成，千丈金鰲跨水橫。", "法從福田勤播種，小菴心匠自經營。", "不緣打破工夫到，那得中流砥柱平。", "我輩濟川真事業，何時赤手活蒼生。"]'),
('8d16b6e9-3360-49af-a1f4-45e29e318a62','因發諸縣催科行移口占呈東倅','王邁','宋','宋诗','song-poetry','','[]','共乘別駕犯炎雲，入手文書費解紛。',64,'全唐诗/poet.song.195000.json','["共乘別駕犯炎雲，入手文書費解紛。", "搜見底囊供北餫，作無麫餠飽南軍。", "銅山欲乞從今賜，金浦何爲異昔聞。", "分得塵勞無著處，不知風月幾時分。"]'),
('8a70138e-2d5f-42ce-8198-4344d956144d','送黄同年京甫必昌赴廣西提幹二首  其一','王邁','宋','宋诗','song-poetry','','[]','黄甫才名二十年，蹉跎正坐不能圓。',64,'全唐诗/poet.song.195000.json','["黄甫才名二十年，蹉跎正坐不能圓。", "四書銳欲潜心聖，八品甘爲從事賢。", "東道樽前需客久，南軒印子待人傳。", "丈夫不必求知己，具眼分明有老天。"]'),
('12b33418-7dc7-4b12-beea-7875f64e14be','送黄同年京甫必昌赴廣西提幹二首  其二','王邁','宋','宋诗','song-poetry','','[]','君過羊城見菊坡，先生不出意如何。',64,'全唐诗/poet.song.195000.json','["君過羊城見菊坡，先生不出意如何。", "蜀噓淮沸人挺亂，京火郊雷天薦瘥。", "石介不親逢慶曆，龜山何策救宣和。", "狂生憂國頭如雪，送客無悰作好歌。"]'),
('da4f30cc-4488-4346-bff5-5c1a43b8997e','寄呈漳守李侍郎元善四首  其一','王邁','宋','宋诗','song-poetry','','[]','棠木筠溪手自栽，竹湖又剖竹符來。',64,'全唐诗/poet.song.195000.json','["棠木筠溪手自栽，竹湖又剖竹符來。", "祖孫相望風流盛，父老驩傳春意回。", "拔薤莫須施辣手，泛蓮似更欠清才。", "善人所至如甘雨，要洗漳民滿面埃。"]'),
('f9798a61-fa29-459b-b62b-58df379211e3','寄呈漳守李侍郎元善四首  其二','王邁','宋','宋诗','song-poetry','','[]','侍郎佛地位中人，一飯何嘗不念民。',64,'全唐诗/poet.song.195000.json','["侍郎佛地位中人，一飯何嘗不念民。", "涇渭同流須有別，雪霜殺物乃爲仁。", "揚清可使貪夫愧，去惡能令善者伸。", "自笑狂生太饒舌，見詩少喜定多嗔。"]'),
('7021fef3-5589-42c6-8386-29178f124621','寄呈漳守李侍郎元善四首  其三','王邁','宋','宋诗','song-poetry','','[]','嚮來大姓虐窮閭，千畝農田浚作渠。',64,'全唐诗/poet.song.195000.json','["嚮來大姓虐窮閭，千畝農田浚作渠。", "黠吏鷹豪爭攫肉，驕兒螂怒敢當車。", "老丞嫉惡無容忍，直筆誅奸欲剪鋤。", "解印此曹稱快甚，惟民與士最愁子。"]'),
('ee714f0b-b83b-4dfc-9c19-43a5b31f035e','寄呈漳守李侍郎元善四首  其四','王邁','宋','宋诗','song-poetry','','[]','陛前苦語犯龍鱗，朝退還遭丞相嗔。',64,'全唐诗/poet.song.195000.json','["陛前苦語犯龍鱗，朝退還遭丞相嗔。", "連削六階爲下吏，只饒一死與閒身。", "命天所付須安分，貧士之常莫語人。", "惟有梅花無冷暖，玉堂茅舍一般春。"]'),
('01063dc0-f84d-49f3-ae26-fef56575c309','寄南劍守陳寺丞宿','王邁','宋','宋诗','song-poetry','','[]','復齋出守劍津時，正直清廉真吏師。',64,'全唐诗/poet.song.195000.json','["復齋出守劍津時，正直清廉真吏師。", "遺愛昔嘗垂竹帛，徽音今又嗣塤箎。", "侯能培植甘棠茇，我欲摩挲常萼碑。", "千載福公家傳好，懷哉蜀士送行詩。"]'),
('578ad30f-ba9c-4449-b142-7a9c5c7028b5','送黄殿講成父赴廣東漕四首  其一','王邁','宋','宋诗','song-poetry','','[]','閩州長者舊家聲，德厚流光産俊英。',64,'全唐诗/poet.song.195000.json','["閩州長者舊家聲，德厚流光産俊英。", "火玉精神充戶牖，國蘭譽諝播爐亭。", "臨軒初試董晁策，抗對專尋濂洛盟。", "臚句一傳喑萬馬，祥雲五色捧魁星。"]'),
('d9999afa-313d-4014-bf1a-fee30b2e5cde','送黄殿講成父赴廣東漕四首  其二','王邁','宋','宋诗','song-poetry','','[]','剡曲蓮池徹底清，即馳雋軌上蓬瀛。',64,'全唐诗/poet.song.195000.json','["剡曲蓮池徹底清，即馳雋軌上蓬瀛。", "抽黄媲白羞時學，漬墨磨丹勘舊經。", "彤陛奏言殫藎直，玉皇動色賞忠精。", "胸中列宿舒芒耀，藜火光分太乙星。"]'),
('5740f1a5-7063-4f6c-9f48-b11900df5fb5','送黄殿講成父赴廣東漕四首  其三','王邁','宋','宋诗','song-poetry','','[]','金華重席被恩榮，蘭省還持多士衡。',64,'全唐诗/poet.song.195000.json','["金華重席被恩榮，蘭省還持多士衡。", "善類適然相牴牾，諸公可是費調停。", "自從陣脚一摇動，堪嘆棋枰幾變更。", "紫帽清源人刮目，朱轓炯炯見郎星。"]'),
('3c50d190-09fa-4296-b5e8-c531ca0b5044','送黄殿講成父赴廣東漕四首  其四','王邁','宋','宋诗','song-poetry','','[]','尺一催歸白玉京，浮雲偏妬月華明。',64,'全唐诗/poet.song.195000.json','["尺一催歸白玉京，浮雲偏妬月華明。", "鳳凰遠舉弋何慕，鶗鴂爭鳴草不馨。", "館列翹才難致仕，杖携靈壽莫扶傾。", "重瞳不見賈山久，猶駕軺車作德星。"]'),
('a4eb429b-0433-465f-82a9-2764371242c7','嘲解十首  其一','王邁','宋','宋诗','song-poetry','','[]','主聖時平諫諍無，子胡不善效轅駒。',64,'全唐诗/poet.song.195000.json','["主聖時平諫諍無，子胡不善效轅駒。", "庸庸隨物例多福，皦皦出塵良易汙。", "填海誰憐精衛苦，移山可笑此翁愚。", "鳴鐘鼎食不知愛，却愛山中飯糲粗。"]'),
('d88e4f97-c411-4995-8caa-da3048a1e070','嘲解十首  其二','王邁','宋','宋诗','song-poetry','','[]','杞天之下夜長吁，朝上封章肝膽刳。',64,'全唐诗/poet.song.195000.json','["杞天之下夜長吁，朝上封章肝膽刳。", "自是諸公忌生語，不應聖主怒狂夫。", "我將行禮敖嫌簡，子欲正名由笑迂。", "寧作首陽人餓死，不爲仗馬戀生芻。"]'),
('c375200f-2a8c-45f1-baf1-dbdbab7b6b5a','嘲解十首  其三','王邁','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','一相當朝總百官，升沉只在笑談間。',64,'全唐诗/poet.song.195000.json','["一相當朝總百官，升沉只在笑談間。", "及門炙手趨炎火，傾國將身靠泰山。", "子獨何人蜉撼樹，衆皆重足虎當關。", "仙舟已到蓬萊境，却被波神勒取還。"]'),
('7b28eee0-b935-44f5-bb8d-55b58024a96b','嘲解十首  其四','王邁','宋','宋诗','song-poetry','','[]','孤士每蒙丞相嗔，人心不泯是非真。',64,'全唐诗/poet.song.195000.json','["孤士每蒙丞相嗔，人心不泯是非真。", "瓘爲苦語攻姦蔡，銓出危言忤老秦。", "此事古來曾有樣，如今天下幾無人。", "西山夫子深窮理，能以逢干作保身。"]'),
('65df657e-6a15-418d-9cfa-72a6a7d9e64a','嘲解十首  其五','王邁','宋','宋诗','song-poetry','','[]','邊塵四面逐雲飛，正是英盧得志時。',64,'全唐诗/poet.song.195000.json','["邊塵四面逐雲飛，正是英盧得志時。", "西洛故疆將克復，北軍新銳屬羈縻。", "智名功勇渠何欠，跋扈飛揚子過疑。", "消得騰章來辨析，臺臣慮患可無詞。"]'),
('8c0fa878-a362-4e9f-a40d-832733a3265c','嘲解十首  其六','王邁','宋','宋诗','song-poetry','','[]','狄青心不負朝廷，跋扈人疑漸有萌。',64,'全唐诗/poet.song.195000.json','["狄青心不負朝廷，跋扈人疑漸有萌。", "琦不押班嬰衆怒，浚私鑄印被臺評。", "鉅公未免憂清議，之子如何諱此名。", "若使滿朝無一語，晚唐藩鎮禍胎成。"]'),
('3ed45b40-5924-4eb8-b74e-f1d260a121e2','嘲解十首  其七','王邁','宋','宋诗','song-poetry','','[]','西山名節太崢嶸，洪魏同時俱有聲。',64,'全唐诗/poet.song.195000.json','["西山名節太崢嶸，洪魏同時俱有聲。", "斥去不妨爲寶慶，出來亦只做端平。", "事師如子何爲諂，植黨旁人笑好名。", "婺女諫官良解事，正邪辨析極分明。"]'),
('bd571503-436b-41cc-8d5a-f4e2e3ba8cbe','嘲解十首  其八','王邁','宋','宋诗','song-poetry','','[]','三賢千載共襟期，出處存亡同一時。',64,'全唐诗/poet.song.195000.json','["三賢千載共襟期，出處存亡同一時。", "吾道非耶天詎測，斯人已矣我疇依。", "希文若在甘爲黨，邢恕無知却背師。", "坐此褫官吾不恨，恨他同傳是韓非。"]'),
('83242cc5-82ff-4f98-992f-7c0d931004e4','嘲解十首  其九','王邁','宋','宋诗','song-poetry','','[]','君臣大義等乾坤，兄弟何曾係大倫。',64,'全唐诗/poet.song.195000.json','["君臣大義等乾坤，兄弟何曾係大倫。", "齊霸分明誅子糾，唐宗决裂用讐臣。", "向時諸老空饒舌，何物狂生又犯鱗。", "一自蔣坡新語出，斯知世有讀書人。"]'),
('3750a2aa-4d62-45e8-9d45-d1aae8d34840','嘲解十首  其一○','王邁','宋','宋诗','song-poetry','','[]','霸者成功如彼卑，孔門童子恥稱之。',64,'全唐诗/poet.song.195000.json','["霸者成功如彼卑，孔門童子恥稱之。", "盡倫大舜斯爲至，有過周公不亦宜。", "古者責難誠意切，今人逢惡大經隳。", "若教新語宜垂世，可廢八章棠棣詩。"]'),
('1bb2302c-5276-491b-a76b-81ae92d91b12','聚物','王邁','宋','宋诗','song-poetry','','[]','臧穀亡羊等是癡，塞翁失馬浪成悲。',64,'全唐诗/poet.song.195000.json','["臧穀亡羊等是癡，塞翁失馬浪成悲。", "本非真鹿夢何準，未必無鰲釣且遲。", "蛟龍暫與蚖蛇肆，鴻鵠那教燕雀知。", "暮四朝三狙莫怒，會看挾乙走狐狸。"]'),
('a46c4b5f-b416-40d3-8fa6-86086c164908','和宗姪朝望公輔賀生朝韵','王邁','宋','宋诗','song-poetry','','[]','投閒久矣息心兵，臺上饑烏又一聲。',64,'全唐诗/poet.song.195000.json','["投閒久矣息心兵，臺上饑烏又一聲。", "湖海正須招隠士，朝廷終不赦狂生。", "剖開胸腹猶餘赤，削盡頭銜越樣清。", "坐看吾宗後來俊，西風再舉上鵬程。"]'),
('5d452751-9c8f-4e2b-9828-cd092591944b','生朝止客','王邁','宋','宋诗','song-poetry','','[]','白髮蒼顔五十三，北風不競又來南。',64,'全唐诗/poet.song.195000.json','["白髮蒼顔五十三，北風不競又來南。", "宦情於我蠟來淡，世味從渠蜜樣甘。", "烏哺劬勞恩未報，鴈行凄斷痛何堪。", "記生縱有一樽酒，忍與妻孥共醉酣。"]'),
('56cc538a-92b6-47f5-9cad-7581cbf59c06','寄延平史君馬德大天驥二首  其一','王邁','宋','宋诗','song-poetry','','[]','日誦江干餞別詩，端平局面改嘉熙。',64,'全唐诗/poet.song.195000.json','["日誦江干餞別詩，端平局面改嘉熙。", "調元金鼎人黄髮，宣化朱轓君白眉。", "否泰從來更代禪，乾坤此去願平夷。", "狂生迂闊真無用，飽飯山中倒接䍦。"]'),
('126537dd-e1df-4a34-bab9-aee6fbd7cf61','寄延平史君馬德大天驥二首  其二','王邁','宋','宋诗','song-poetry','','[]','君正青春我鬢絲，春闈舊夢是耶非。',64,'全唐诗/poet.song.195000.json','["君正青春我鬢絲，春闈舊夢是耶非。", "九方臯馬分明瘦，百里奚牛自在肥。", "欲去尋盟談繾綣，又愁鈎黨起幾微。", "乘車戴笠俱隨分，懷美人兮心奮飛。"]'),
('def7adc0-d13a-48fe-9fa3-bee6920171a2','送趙伯泳涯侍郎守溫陵  其一','王邁','宋','宋诗','song-poetry','','[]','泉是梅溪遺愛鄉，老倪復此種甘棠。',64,'全唐诗/poet.song.195000.json','["泉是梅溪遺愛鄉，老倪復此種甘棠。", "後來薦報西山政，歸去全無南物裝。", "籍甚三賢皆法從，勉哉一趙繼循良。", "萬安橋上傳佳話，七十年間四侍郎。"]'),
('408cb16c-f7a7-433b-b8ca-c782fd20398b','送趙伯泳涯侍郎守溫陵  其二','王邁','宋','宋诗','song-poetry','','[]','西山無物與泉民，底使民如父母親。',64,'全唐诗/poet.song.195000.json','["西山無物與泉民，底使民如父母親。", "凡日用間無不敬，滿腔子裏盡吾仁。", "我熏知見香猶舊，公滌中和印一新。", "願廣桐鄉依戀意，寒泉秋菊祀千春。"]'),
('97c23944-459d-451e-94a8-8e25a40281de','寄婺倅張同年渭叟併簡其婿黄元輔自然二首  其一','王邁','宋','宋诗','song-poetry','','[]','江峰映带武夷青，幾度携筇此地行。',64,'全唐诗/poet.song.195000.json','["江峰映带武夷青，幾度携筇此地行。", "韻士魁人鍾間氣，冰翁玉婿並時名。", "世方爭效十鑽巧，渠自不貪三字榮。", "料得平章風月暇，家書一閲萬金輕。"]'),
('6d50051c-cae9-4f96-ad6e-46e0e5d22fa8','寄婺倅張同年渭叟併簡其婿黄元輔自然二首  其二','王邁','宋','宋诗','song-poetry','','[]','同登當日鬢猶青，宦路還如跛鼈行。',64,'全唐诗/poet.song.195000.json','["同登當日鬢猶青，宦路還如跛鼈行。", "蒔藥山阿非貴相，叩頭殿下得狂名。", "著書平屋千年記，堆笏盈床一餉榮。", "安樂窩中無別法，只將世累放教輕。"]'),
('bc464d09-f95c-4fbc-a4af-de3548a5fb5b','呈竹軒張史君二首  其一','王邁','宋','宋诗','song-poetry','','[]','竹軒治郡政成時，却值王孫慶玉墀。',64,'全唐诗/poet.song.195000.json','["竹軒治郡政成時，却值王孫慶玉墀。", "無吏下鄉民點塔，捐田入學士礱碑。", "平反陰德堪娛母，清白家風更課兒。", "見說元宵燈不放，爲他百姓惜膏脂。"]'),
('b1a6cc08-c4da-49f7-95dd-f3ba9a319925','呈竹軒張史君二首  其二','王邁','宋','宋诗','song-poetry','','[]','日晡齋閤響鈴絛，鞅掌文書尚坐曹。',64,'全唐诗/poet.song.195000.json','["日晡齋閤響鈴絛，鞅掌文書尚坐曹。", "吏困行移愁脫腕，侯勤剖决快揮毫。", "維摩正爲衆生病，太守勝如從事勞。", "願養精神需大用，款陪齊客醉醇醪。"]'),
('c8c064b0-da54-42cb-9142-c1683f914cdd','和竹軒張史君來字韻二首  其一','王邁','宋','宋诗','song-poetry','','[]','金鳳傳呼紫馬來，壺山真面氣佳哉。',64,'全唐诗/poet.song.195000.json','["金鳳傳呼紫馬來，壺山真面氣佳哉。", "朝天有路鹿呈瑞，應物無心鷗不猜。", "黍穋熟時農洗甑，芰荷香裏客啣杯。", "官穹職峻人俱羨，最羨斑衣舞老萊。"]'),
('e3f8ef12-6098-4c61-ac81-2d56b94474d5','和竹軒張史君來字韻二首  其二','王邁','宋','宋诗','song-poetry','','[]','一自都門拂袖來，閒中歲月亦悠哉。',64,'全唐诗/poet.song.195000.json','["一自都門拂袖來，閒中歲月亦悠哉。", "填波精衛功良苦，享樂鶢鶋心自猜。", "老矣力衰難運甓，偶然興到且傳杯。", "君侯若使居王所，片善還能采草萊。"]'),
('a52ed4b8-56fb-4fc4-8fd5-a6a79bcb27b8','再用韻和張仁仲史君','王邁','宋','宋诗','song-poetry','','[]','五花入手眼增明，合主黌宮善類盟。',64,'全唐诗/poet.song.195000.json','["五花入手眼增明，合主黌宮善類盟。", "善教牖民師帥責，婉辭玉女父兄情。", "馬經定價增神駿，鴞亦懷音避惡名。", "從此心田去稂莠，沐侯化雨及時耕。"]'),
('d67d05fa-a367-4bdb-b33c-a2e896fb380a','用韻簡黄元輔二首  其一','王邁','宋','宋诗','song-poetry','','[]','不愛螭頭一點青，片言枘鑿拂衣行。',64,'全唐诗/poet.song.195000.json','["不愛螭頭一點青，片言枘鑿拂衣行。", "但憂負我平生學，豈願爭渠豎子名。", "天駿出閑駑飽秣，國蘭却佩艾敷榮。", "想君記得西山語，佳士從來去就輕。"]'),
('e8e352a8-e765-42c7-ae32-3439f8d90c0a','用韻簡黄元輔二首  其二','王邁','宋','宋诗','song-poetry','','[]','髮今如此不重青，醉後長歌折檻行。',64,'全唐诗/poet.song.195000.json','["髮今如此不重青，醉後長歌折檻行。", "老去一寒甘忍死，古來幾士得全名。", "稻畦蔬圃閒中樂，藥禁薇階膜外榮。", "所見略同君與我，不妨官小得人輕。"]'),
('2dc4ccf3-b55c-40a4-9cb2-c209ac25c195','山居即事','王邁','宋','宋诗','song-poetry','','[]','出處行藏不偶然，何曾由我總由天。',64,'全唐诗/poet.song.195000.json','["出處行藏不偶然，何曾由我總由天。", "收回紫陌紅塵足，來結青山綠水緣。", "萬籟鳴時仍瀑布，數鴉起處忽林烟。", "暮雲正爾商量雪，却被催詩雨插先。"]'),
('e752b10f-27d4-4022-b3e5-ea87a1726f24','秋夜對客','王邁','宋','宋诗','song-poetry','','[]','旋燒香鴨剔銀缸，風捲銀蟾上矮窗。',64,'全唐诗/poet.song.195000.json','["旋燒香鴨剔銀缸，風捲銀蟾上矮窗。", "詩癖苦無奇藥療，睡魔頼有建茶降。", "回環蛙部疑成兩，接續蟬笙不計雙。", "好友相看寧惜夜，滿懷秋思浩如江。"]'),
('dadce1af-8f4c-4b6d-a8fe-4d72dd811405','良月朔郊行問訊梅菊','王邁','宋','宋诗','song-poetry','','[]','夜半漸驚風作惡，朝來賸喜月爲良。',64,'全唐诗/poet.song.195000.json','["夜半漸驚風作惡，朝來賸喜月爲良。", "知梅有意商量雪，問菊何謀準備霜。", "和靖未吟先得趣，淵明欲斷已無腸。", "物情榮悴胡關我，獨酌悠然寓醉鄉。"]'),
('e772cdd7-be81-4156-a7be-054fc318673f','山中讀誠齋詩','王邁','宋','宋诗','song-poetry','','[]','萬首七言千絕句，九州四海一誠齋。',64,'全唐诗/poet.song.195000.json','["萬首七言千絕句，九州四海一誠齋。", "肝腸定不餐烟火，翰墨何曾着點埃。", "錦瑟月中彈不徹，雲濤天上瀉將來。", "巴西社裏陳黄遠，直下推渠作社魁。"]'),
('4a9d31a5-4996-473f-9458-d7f6b44d9789','夜讀杜詩契心喜成','王邁','宋','宋诗','song-poetry','','[]','夜永如年眠較遲，寒聲贔屭薄書幃。',64,'全唐诗/poet.song.195000.json','["夜永如年眠較遲，寒聲贔屭薄書幃。", "靜看香篆縈茶椀，細嚼檳榔當酒卮。", "詩卷一開明病眼，騷人千載契心期。", "偶逢會處點頭笑，早被燈花聖得知。"]'),
('78821a26-b62e-429f-b08e-96b9698a4fe1','除夕','王邁','宋','宋诗','song-poetry','','[]','憶昔都門值歲除，高樓張燭戲呼盧。',64,'全唐诗/poet.song.195000.json','["憶昔都門值歲除，高樓張燭戲呼盧。", "久依凈社參尊宿，難向新豐認酒徒。", "天子未知工草賦，鄰人或倩寫桃符。", "寒宵別有窮生活，點勘離騷擁地爐。"]'),
('0e38fbed-9f1b-45cc-a4da-ab1c1d1bfaac','枕上復用道間鄉字韻呈同人','王邁','宋','宋诗','song-poetry','','[]','爆竹聲中度歲忙，椒花杯上換春陽。',64,'全唐诗/poet.song.195000.json','["爆竹聲中度歲忙，椒花杯上換春陽。", "欠書元日神荼帖，又看新年傀儡場。", "客枕方酣千里夢，朝靴正踏五更霜。", "主翁須要惺惺在，富貴何如歸故鄉。"]'),
('320c1cfe-a701-4b62-a2cd-69b13a224778','元旦次日立春','王邁','宋','宋诗','song-poetry','','[]','年從爆火暗中移，椒栢迎歡上酒卮。',64,'全唐诗/poet.song.195000.json','["年從爆火暗中移，椒栢迎歡上酒卮。", "今日天晴宜麥熟，明朝春到報花知。", "好奇漫說雞千跖，行樂都來黍一炊。", "但得新年詩有料，不妨貧似去年時。"]'),
('beea65c7-95c6-4577-a2d3-8f2d89688a20','清明郊行','王邁','宋','宋诗','song-poetry','','[]','年例清明是暮春，今年春事却平分。',64,'全唐诗/poet.song.195000.json','["年例清明是暮春，今年春事却平分。", "故添一閏知天巧，欲探羣芳奈雨頻。", "烟樹對人愁脈脈，暮山似我老陳陳。", "感時莫灑花前淚，不道中原漲戰塵。"]'),
('a684982b-5045-413d-aed1-864841a92051','西軒春坐','王邁','宋','宋诗','song-poetry','','[]','容膝都盧屋一間，圖書左右任披翻。',64,'全唐诗/poet.song.195000.json','["容膝都盧屋一間，圖書左右任披翻。", "催詩急雨來迢遞，吹面凉風過等閒。", "生意無邊庭下草，清香不斷畹中蘭。", "日長無事真仙隠，作甚辛辛苦苦官。"]'),
('5b674c7d-a82d-4306-9159-803f4db58fae','夏雨','王邁','宋','宋诗','song-poetry','','[]','彌旬不雨懶龍乖，乾我茅齋一畝苔。',64,'全唐诗/poet.song.195000.json','["彌旬不雨懶龍乖，乾我茅齋一畝苔。", "火繖亭亭當午立，雷車隠隠半天來。", "催詩笑我孤吟苦，憂國愁眉八字開。", "池水甫能添幾許，兒童已報可浮杯。"]'),
('67071c95-e894-48d9-87a5-7a762c32bad7','送方德和大鏞赴漕','王邁','宋','宋诗','song-poetry','','[]','好風昨夜作秋天，吹送雛鵷上紫烟。',64,'全唐诗/poet.song.195000.json','["好風昨夜作秋天，吹送雛鵷上紫烟。", "慈母整裘顔有喜，難兄提鉢面相傳。", "策勛胄榜特餘事，努力巍科趁壯年。", "直數重陽到端午，快聆三捷凱歌還。"]'),
('4097b63d-7ed4-4a53-9f1a-dd62c6a26a6e','送方栻赴銓','王邁','宋','宋诗','song-poetry','','[]','笑提虹管試春闈，大手何妨小出奇。',64,'全唐诗/poet.song.195000.json','["笑提虹管試春闈，大手何妨小出奇。", "龍種嘶鳴喑萬馬，鹿麑辟易避孤羆。", "京城紙貴爭傳賦，便驛書來賸寄詩。", "老友生平識英物，要看修竹拂雲枝。"]'),
('60379ca2-6e05-4259-96dc-56338081088a','和劉編修潜夫讀近報蔣峴被逐二首  其一','王邁','宋','宋诗','song-poetry','','[]','讀報欣然共賦詩，古來忠佞各殊岐。',64,'全唐诗/poet.song.195000.json','["讀報欣然共賦詩，古來忠佞各殊岐。", "彼猶愧見蔣穎叔，君盍自期劉器之。", "惡草剪除雖一快，芳蘭銷歇已多時。", "懷哉康節先生語，作事莫教人縐眉。"]'),
('e54acc42-5eca-4eaf-9041-ac12710f1bbf','和劉編修潜夫讀近報蔣峴被逐二首  其二','王邁','宋','宋诗','song-poetry','','[]','兩載相依笑陸沉，鶉衣不羨錦爲衾。',64,'全唐诗/poet.song.195000.json','["兩載相依笑陸沉，鶉衣不羨錦爲衾。", "渠儂眩耀麒麟楦，我輩翻騰駑驥吟。", "朝去一凶憂稍歇，邊留五大禍尤深。", "棟梁培植誰之責，莫遣斧斤終日尋。"]'),
('b2fd6b18-411e-4c20-9598-ef9692449932','簡南劍倅趙用甫以夫同年二首  其一','王邁','宋','宋诗','song-poetry','','[]','元戎擇佐奏膚公，君以宗英在選中。',64,'全唐诗/poet.song.195000.json','["元戎擇佐奏膚公，君以宗英在選中。", "紫氣發硎光射斗，碧油草檄令飛風。", "莫嫌假手事權小，行拜真王位望穹。", "老我相期猶遠大，朱虛要立萬年功。"]'),
('fa41072c-f0fc-459f-98ce-3ccb7822df4b','簡南劍倅趙用甫以夫同年二首  其二','王邁','宋','宋诗','song-poetry','','[]','岊亭邂逅又輕離，時事更翻幾局棋。',64,'全唐诗/poet.song.195000.json','["岊亭邂逅又輕離，時事更翻幾局棋。", "游宦明知同旦過，出山聊復救朝饑。", "屠龍笑我真何用，躍馬追君已落遲。", "却有一般劣相肖，蘭階晚始長瓊枝。"]'),
('a59c14ef-a37e-45d0-afdf-e565c3fcbd7b','和趙倅二首  其一','王邁','宋','宋诗','song-poetry','','[]','一樣風清共月明，平分那得外斯盟。',64,'全唐诗/poet.song.195000.json','["一樣風清共月明，平分那得外斯盟。", "合將長與貳同傳，正恐君嫌譽過情。", "碑斷文昌須改制，臺高馬援却逃名。", "色絲黄絹儂無分，悔不文園着力耕。"]'),
('f5fb3adc-0553-4e60-94ff-20ba85aeb41a','和趙倅二首  其二','王邁','宋','宋诗','song-poetry','','[]','二車人物漢三明，來主壺山壽永盟。',64,'全唐诗/poet.song.195000.json','["二車人物漢三明，來主壺山壽永盟。", "衆口是碑均詠德，片言如秤不容情。", "斯文陰有扶持力，循吏何求烜赫名。", "早晚政成天上去，舊廛還憶老農耕。"]'),
('6106b212-50a1-4c69-bfec-5f08a33103bb','呈趙倅','王邁','宋','宋诗','song-poetry','','[]','別駕從來頭沓高，非關期奏壓宜敖。',64,'全唐诗/poet.song.195000.json','["別駕從來頭沓高，非關期奏壓宜敖。", "推敲今日韓饒賈，引避他年藺下頗。", "螂欲當車觀者笑，駟難及舌罪焉逃。", "小詩贖過無佳句，唐突西施又奈何。"]'),
('b61864d5-fbbd-457b-aed9-5ce59458a5b4','再呈趙倅','王邁','宋','宋诗','song-poetry','','[]','委齋坐我以春風，不事拘攣邊幅中。',64,'全唐诗/poet.song.195000.json','["委齋坐我以春風，不事拘攣邊幅中。", "俗子語言藏攫穽，丈夫胸腹等崆峒。", "虛舟相觸何心在，怒火雖炎一餉空。", "到底不如歸去好，扶犁戴笠作村翁。"]'),
('c84f9bb2-e512-4477-9394-fa3b6dd19bae','作郡庠修學增田記成諸職事招飲','王邁','宋','宋诗','song-poetry','','[]','頖宮輪奐一鮮明，多謝賢侯主夏盟。',64,'全唐诗/poet.song.195000.json','["頖宮輪奐一鮮明，多謝賢侯主夏盟。", "雞白碑成慚淺識，鵝黄酒滿認深情。", "回頭二十三年夢，接武千英萬俊名。", "來事可爲待卿等，狂生老去合歸耕。"]'),
('e0dd6c38-6071-4779-85e8-4c4aeda33e71','丹青閣','王邁','宋','宋诗','song-poetry','','[]','盛年憂國鬢毛蒼，諫疏端堪銘豆觴。',64,'全唐诗/poet.song.195000.json','["盛年憂國鬢毛蒼，諫疏端堪銘豆觴。", "行或使之苗膏雨，心乎愛矣藿傾陽。", "榮華不與羣兒競，名節須留千載長。", "試看丹青閣中句，吾宗有此好元方。"]'),
('b436e727-a9af-4932-9d41-c05f95555bc5','跋大庾令趙宗華時棣藏諸公帖','王邁','宋','宋诗','song-poetry','','[]','數帖凡經幾世藏，字漫黑暗欠裝潢。',64,'全唐诗/poet.song.195000.json','["數帖凡經幾世藏，字漫黑暗欠裝潢。", "孰賢孰否人千載，遺臭遺芳紙半張。", "憤世疾邪成怒駡，懷忠愛直轉凄凉。", "吾曹留面要相見，莫使人能議短長。"]'),
('9f673e3a-5fb1-4de9-989a-e8fae8191f10','偶書警俗','王邁','宋','宋诗','song-poetry','','[]','大雅吾無望古人，有常猶愈翟公門。',64,'全唐诗/poet.song.195000.json','["大雅吾無望古人，有常猶愈翟公門。", "貪榮但可驕妻妾，死義方堪托子孫。", "董生雞哺寧求報，元子雉媒莫少恩。", "俗物茫茫隨野馬，英雄千載赤心存。"]'),
('92971d02-6429-4bc8-aa49-0860cb77697a','師心主人作飛錫巖','王邁','宋','宋诗','song-poetry','','[]','巖頭古佛留心印，巖下高人新受持。',64,'全唐诗/poet.song.195000.json','["巖頭古佛留心印，巖下高人新受持。", "佛亦本來無隠現，人於悟處領希夷。", "莫嫌夢裏還談夢，且看奇中更有奇。", "他日證成羅漢果，相逢不必問伊誰。"]'),
('94bc5493-9384-4bda-a3f1-eae9a2d301fd','聽九座鈍菴禪師端午日外堂說法詩','王邁','宋','宋诗','song-poetry','','[]','人在塵中醉玉蒲，師於瓶裏瀉醍醐。',64,'全唐诗/poet.song.195000.json','["人在塵中醉玉蒲，師於瓶裏瀉醍醐。", "傳來雙徑清香遠，喚起叢林病骨蘇。", "炳炳毫光爭日月，琅琅舌本有江湖。", "他年泉下相逢處，解得龍山舊事無。"]'),
('6c381975-293a-48be-8cc8-bf1af502813d','輓趙東巖簡叔彥侯四首  其一','王邁','宋','宋诗','song-poetry','','[]','已矣東巖不憗遺，年來雅道日陵夷。',64,'全唐诗/poet.song.195000.json','["已矣東巖不憗遺，年來雅道日陵夷。", "臞儒得似顔徒幾，良吏能爲結輩誰。", "此老清修如玉屑，當官懇惻念茅茨。", "可憐一夜長庚隕，空使人懷殄瘁悲。"]'),
('36db8752-7f6d-45ff-a661-626765a741db','輓趙東巖簡叔彥侯四首  其二','王邁','宋','宋诗','song-poetry','','[]','建炎戎馬滿神京，殿撰橫身活一城。',64,'全唐诗/poet.song.195000.json','["建炎戎馬滿神京，殿撰橫身活一城。", "時宰忌功無表勸，老天福善自分明。", "人稱簪紱一門盛，公是瑛瑶間世生。", "珍重西山遺事跋，他年收入史官評。"]'),
('b79b546b-930a-42cf-bbe4-4af4717f66ca','輓趙東巖簡叔彥侯四首  其三','王邁','宋','宋诗','song-poetry','','[]','夔州歸後聖於詩，到墨池來字更奇。',64,'全唐诗/poet.song.195000.json','["夔州歸後聖於詩，到墨池來字更奇。", "嶽后前驅護丹竈，湘靈起舞聽朱徽。", "經行一夢遊仙枕，遺愛千年墮淚碑。", "俗物茫茫留不住，化爲遼鶴入雲飛。"]'),
('07df7c29-5840-4c17-ab6f-06c1f13da934','輓趙東巖簡叔彥侯四首  其四','王邁','宋','宋诗','song-poetry','','[]','召節飛來湘水濱，牋天乞取自由身。',64,'全唐诗/poet.song.195000.json','["召節飛來湘水濱，牋天乞取自由身。", "懸知壽杖宜扶孔，縱有蒲輪莫致申。", "老去最能堅晚節，復來應信有全人。", "朱虛不作更生死，誰爲蒼生問大鈞。"]'),
('e7e847a9-c6fa-4725-bec6-16dc91826781','輓邱制幹二首  其一','王邁','宋','宋诗','song-poetry','','[]','功名入手太匆匆，匹馬沙場氣貫虹。',64,'全唐诗/poet.song.195000.json','["功名入手太匆匆，匹馬沙場氣貫虹。", "詩好可能却敵騎，檄工不自愈頭風。", "死須厲賊言猶在，生不封侯命果窮。", "四十九年蘧伯玉，是非往事轉頭空。"]'),
('2c4b4942-e7e4-4969-b611-dfa5d86befa9','輓邱制幹二首  其二','王邁','宋','宋诗','song-poetry','','[]','曾見端平進士評，邱君磊落榜中英。',64,'全唐诗/poet.song.195000.json','["曾見端平進士評，邱君磊落榜中英。", "忘形爾汝同年集，馳志伊吾即日行。", "舉子能談真將略，元戎誇得好門生。", "可憐書劍渾無用，才力如何與命爭。"]'),
('bb4b0ce4-692d-4ada-8f4b-fe49f9c8f7c1','輓漳守鄭都承子敬四首  其一','王邁','宋','宋诗','song-poetry','','[]','饕相當朝舞大權，故將旌節博金錢。',64,'全唐诗/poet.song.195000.json','["饕相當朝舞大權，故將旌節博金錢。", "公嘗勇去三千石，天與閑居十六年。", "清苦膏粱餘子笑，孤高雲水一僧然。", "如何赤嶼丹霞地，夜半騎鯨上紫烟。"]'),
('04f8338f-07da-4a61-91a7-59012a69a301','輓漳守鄭都承子敬四首  其二','王邁','宋','宋诗','song-poetry','','[]','端平衆彥起彈冠，公作樞庭第一官。',64,'全唐诗/poet.song.195000.json','["端平衆彥起彈冠，公作樞庭第一官。", "君似仁皇從諫易，相非莊敏汰兵難。", "齊人一傅楚人衆，趙氏幾危劉氏安。", "君面更新風色惡，回思往事爲悽酸。"]'),
('1158d5aa-ab38-4a7b-8b0b-4d2af507fea6','輓漳守鄭都承子敬四首  其三','王邁','宋','宋诗','song-poetry','','[]','壺山閥閲例多賢，雪玉風標憶眼前。',64,'全唐诗/poet.song.195000.json','["壺山閥閲例多賢，雪玉風標憶眼前。", "正獻風猷復齋繼，蜀公素業肯亭傳。", "人於故國悲諸老，我爲吾州惜二仙。", "在昔靖康人物盡，却教老蔡雪垂肩。"]'),
('65c34181-88f2-45dc-94d1-1d02314b4ac9','輓漳守鄭都承子敬四首  其四','王邁','宋','宋诗','song-poetry','','[]','當日曾同鵷鷺羣，清漳風月又平分。',64,'全唐诗/poet.song.195000.json','["當日曾同鵷鷺羣，清漳風月又平分。", "輪囷肝膽憂時事，紬繹諸書洗吏氛。", "悔不佩韋成造次，幸猶掛劍答殷勤。", "隻雞斗酒來行酹，三十六灣生暮春。"]'),
('ca99394d-9eaf-4ca9-b033-daf028ff8053','輓陳直學二首  其一','王邁','宋','宋诗','song-poetry','','[]','領袖鄉庠四十年，被書誤得到華顛。',64,'全唐诗/poet.song.195000.json','["領袖鄉庠四十年，被書誤得到華顛。", "玉川大用不及試，東野古心常自鞭。", "抱疢二詩知命語，遺骸一偈小乘禪。", "修文地下非公願，生則當生兜率天。"]'),
('e95997fd-3054-4ee2-aa2e-2d2e859c0662','輓陳直學二首  其二','王邁','宋','宋诗','song-poetry','','[]','飽看布褐與軒裳，識破都如夢一場。',64,'全唐诗/poet.song.195000.json','["飽看布褐與軒裳，識破都如夢一場。", "失鹿蕉間空咄咄，騎鵬天上去堂堂。", "命真不遇才何負，人已無存德未忘。", "珍重騅甥歌挽些，他年有淚灑檳榔。"]'),
('f082361f-af50-4091-9da0-979e2284621d','輓趙南塘尚書汝談二首  其一','王邁','宋','宋诗','song-poetry','','[]','屈賈文章蚤善鳴，長楊制誥晚尤精。',64,'全唐诗/poet.song.195000.json','["屈賈文章蚤善鳴，長楊制誥晚尤精。", "天仙一念墮塵世，屬籍千年誰老成。", "賀表明明規寶慶，諫箴字字砭端平。", "不堪耆舊凋零盡，淚到南塘覺盡傾。"]'),
('46f18eac-576d-44dd-b77d-1b8449312eed','輓趙南塘尚書汝談二首  其二','王邁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一自黄臺詠摘瓜，傷心吾道竟非耶。',64,'全唐诗/poet.song.195000.json','["一自黄臺詠摘瓜，傷心吾道竟非耶。", "病來陶侃少獻替，老去謝安微誤差。", "萬里長江饒一曲，連城白璧略纖瑕。", "太玄草就無人識，付與知音弟子芭。"]'),
('7d445eea-7dcf-4bb8-8dfb-715d7d78344e','輓武剛方錄參','王邁','宋','宋诗','song-poetry','','[]','世科赫奕登相續，官守端方石介如。',64,'全唐诗/poet.song.195000.json','["世科赫奕登相續，官守端方石介如。", "無節能開河內廩，進身耻覓帝城書。", "秩終九品人稱屈，善積千年慶有餘。", "馬耳家聲無失墜，二雛努力大門閭。"]'),
('e2b17071-b1d9-4da1-93b7-27c375c15b67','輓致政朱司戶二首  其一','王邁','宋','宋诗','song-poetry','','[]','枕上功名淚不乾，鏡中勳業老猶看。',64,'全唐诗/poet.song.195000.json','["枕上功名淚不乾，鏡中勳業老猶看。", "起家喜有千金子，入手纔沾九品官。", "衮衮天朝來錫賚，匆匆人事異悲歡。", "最憐當日稱觴處，桂茂蘭芳萱草殘。"]'),
('9e5bc5d6-b05d-47bc-81b5-ab1cb925033c','輓致政朱司戶二首  其二','王邁','宋','宋诗','song-poetry','','[]','一生鐵硯費磨鑽，老去耽書廢食眠。',64,'全唐诗/poet.song.195000.json','["一生鐵硯費磨鑽，老去耽書廢食眠。", "不惜空門求利果，只將心事博長年。", "思賢已矣悲行路，福善昭然有老天。", "他日兒孫須鼎貴，燕山陰德賸流傳。"]'),
('f8014caf-135e-47c4-9b5a-4440ac2658ed','輓鄒帥母葉夫人二首  其一','王邁','宋','宋诗','song-poetry','','[]','詩書教子昔鄒母，燕喜寧親今魯侯。',64,'全唐诗/poet.song.195000.json','["詩書教子昔鄒母，燕喜寧親今魯侯。", "石窌疏封時陸續，魚軒迎養歲優游。", "精專十念湘山佛，髣髴三生閬苑儔。", "方擬繡輿扶上殿，不堪丹旐楚江頭。"]'),
('bad8ff07-319c-4589-b358-af65fa926fca','輓鄒帥母葉夫人二首  其二','王邁','宋','宋诗','song-poetry','','[]','昨依綠水芙蓉幙，得傍華堂萱草陰。',64,'全唐诗/poet.song.195000.json','["昨依綠水芙蓉幙，得傍華堂萱草陰。", "座末識裳蒙眄異，羹餘分潁念恩深。", "巢廬正灑萊衣淚，傳驛俄驚楚些音。", "二母生榮雖迥別，天寒陟屺一般心。"]'),
('53b661b7-7fba-480c-b475-9bd999de8593','試五墨五首  其一','王邁','宋','宋诗','song-poetry','','[]','雪齋凡數種，此種出清漳。',24,'全唐诗/poet.song.195000.json','["雪齋凡數種，此種出清漳。", "或作西齋號，南州許擅場。"]'),
('82dd94ca-7e5c-4eab-8ecb-f0afd7f8fbfc','試五墨五首  其二','王邁','宋','宋诗','song-poetry','','[]','長沙游玩地，多有墨工奇。',24,'全唐诗/poet.song.195000.json','["長沙游玩地，多有墨工奇。", "舊說胡光烈，今誇鄭子儀。"]'),
('97666c68-21c7-4a4b-b4da-800aa9b7279a','試五墨五首  其三','王邁','宋','宋诗','song-poetry','','[]','柯山葉茂實，膠法頗精堅。',24,'全唐诗/poet.song.195000.json','["柯山葉茂實，膠法頗精堅。", "潘李今何處，斯人得正傳。"]'),
('1ca4fa50-d45d-424e-8c40-4fe082105cce','試五墨五首  其四','王邁','宋','宋诗','song-poetry','','[]','齊峰何處是，似亦出柯山。',24,'全唐诗/poet.song.195000.json','["齊峰何處是，似亦出柯山。", "此是西山物，研磨雙淚潸。"]'),
('b86688d5-a61b-4fed-b57a-19ac40aedd80','試五墨五首  其五','王邁','宋','宋诗','song-poetry','','[]','墨上署臣字，必曾經進來。',24,'全唐诗/poet.song.195000.json','["墨上署臣字，必曾經進來。", "一年磨一寸，須作墨中魁。"]'),
('2db229db-00f9-4774-b9ca-da97e681f712','暮春即事','王邁','宋','宋诗','song-poetry','','[]','雲頭紅上三竿日，烟際青來數點峰。',32,'全唐诗/poet.song.195000.json','["雲頭紅上三竿日，烟際青來數點峰。", "桑柘熟時鳩喚雨，麥花黄後燕翻風。"]'),
('57c328da-fc38-4054-a749-20f395472310','歸舟過桐江晚風不順','王邁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江渺渺雨濛濛，自在扁舟一葉中。',32,'全唐诗/poet.song.195000.json','["長江渺渺雨濛濛，自在扁舟一葉中。", "欲識此行無可意，往來俱被打頭風。"]'),
('d6ac5f66-6ddd-4bf5-9700-f4ba233c7583','丙子詔後需捷四絕  其一','王邁','宋','宋诗','song-poetry','','[]','一面飛來打疊秋，農場已築管無憂。',32,'全唐诗/poet.song.195000.json','["一面飛來打疊秋，農場已築管無憂。", "吾儂種殖三年學，未省書田還有收。"]'),
('20216f31-c753-4972-8a64-46a401851dd0','丙子詔後需捷四絕  其二','王邁','宋','宋诗','song-poetry','','[]','促織牆陰唧唧吟，早催衣褐上寒砧。',32,'全唐诗/poet.song.195000.json','["促織牆陰唧唧吟，早催衣褐上寒砧。", "砧聲似助蛩聲切，勾引征夫萬里心。"]'),
('7a8b6bfc-e849-41a1-b93e-bd2033256c91','丙子詔後需捷四絕  其三','王邁','宋','宋诗','song-poetry','','[]','戰罷歸來月再盈，懸知得失繫心旌。',32,'全唐诗/poet.song.195000.json','["戰罷歸來月再盈，懸知得失繫心旌。", "應門稚子占蛛信，刺繡佳人聽鵲聲。"]'),
('30efcf1e-22f0-464c-b3dd-bfb4791b125e','丙子詔後需捷四絕  其四','王邁','宋','宋诗','song-poetry','','[]','勝負相持日已多，看棋人已爛仙柯。',32,'全唐诗/poet.song.195000.json','["勝負相持日已多，看棋人已爛仙柯。", "淮淝非久捷書到，還折門前屐齒麽。"]'),
('a45ab8f2-1740-408a-a501-38cf3fd69850','自贊善相','王邁','宋','宋诗','song-poetry','','[]','三分相士七分非，又似枯臞又似肥。',32,'全唐诗/poet.song.195000.json','["三分相士七分非，又似枯臞又似肥。", "好待功成名遂後，煩君只畫着蓑衣。"]'),
('57234c9b-cf6c-40ef-9516-5adbc4b1e434','畫工又作道裝','王邁','宋','宋诗','song-poetry','','[]','揚州節鉞非吾愛，肯要腰纏十萬錢。',32,'全唐诗/poet.song.195000.json','["揚州節鉞非吾愛，肯要腰纏十萬錢。", "只願天公多與壽，道巾野服伴胎仙。"]'),
('dc9bbb10-8e39-46c5-a59a-65e5cd19362b','贊彥廣兄喜相','王邁','宋','宋诗','song-poetry','','[]','數珠在手鹿隨身，一笑陶陶滿面春。',32,'全唐诗/poet.song.195000.json','["數珠在手鹿隨身，一笑陶陶滿面春。", "天地知他心事好，百年饒與作閒人。"]'),
