('d650d594-7715-4df5-93ae-30ad5f2f5a35','蘭花','王邁','宋','宋诗','song-poetry','','[]','見山堂裏小春寒，觴政詩囊甚有歡。',64,'全唐诗/poet.song.195000.json','["見山堂裏小春寒，觴政詩囊甚有歡。", "重客分明知小李，美人自在寫猗蘭。", "直須博去紉爲佩，只欠香來劣可餐。", "菊磵一枝尤灑落，不妨人作易芳看。"]'),
('11392f2c-1d3f-4e40-bcca-37cd7beeadbb','紅蛛','王邁','宋','宋诗','song-poetry','','[]','空裏游絲十丈長，直垂一顆絳紗囊。',32,'全唐诗/poet.song.195000.json','["空裏游絲十丈長，直垂一顆絳紗囊。", "儂無喜事何須爾，往報槐花舉子忙。"]'),
('732ecf9c-2a9d-4d1b-b4ea-617fc7dfca06','劉氏內政及二寵同孕','王邁','宋','宋诗','song-poetry','','[]','中秋過後纔十日，廣寒侍人遭譴謫。',96,'全唐诗/poet.song.195000.json','["中秋過後纔十日，廣寒侍人遭譴謫。", "墮在人間富貴家，依前不離姮娥側。", "劉郎風流世所無，醉中飲啖無精粗。", "三胎聞已俱孕秀，次第門外連懸弧。", "老子釋氏親抱送，想應屢入維熊夢。", "我今預作弄璋書，君須早辦湯餠供。"]'),
('3409ff99-3b52-406d-8448-415366a05b19','喬松歌','王邁','宋','宋诗','song-poetry','','[]','華陽有喬松，直幹千丈强。',156,'全唐诗/poet.song.195000.json','["華陽有喬松，直幹千丈强。", "盤根據厚土，勁直凌秋霜。", "不知種者誰，拱把由羲皇。", "不受秦人封，鐵立心慨慷。", "下有青牛蹲，中有琥珀藏。", "長恐蛟龍姿，夜逐雷雨翔。", "我願爲胎仙，高風下相羊。", "共此清與高，保此堅與剛。", "共聞堯舜君，至治垂衣裳。", "玉帛交萬國，朝覲開明堂。", "我願爲榱桷，翼松爲棟梁。", "斲此冰雪根，繪畫施青黄。", "萬古永不朽，長久天日光。"]'),
('d1b61117-3996-4b5d-8de8-c8e6f6529939','戴老堂爲城西林兄作','王邁','宋','宋诗','song-poetry','','[]','闕下唐時裔，城西戴老堂。',96,'全唐诗/poet.song.195000.json','["闕下唐時裔，城西戴老堂。", "熊丸甘子嗜，雞饌飽親嘗。", "至行薰吾里，精心契彼蒼。", "定知家慶遠，蘭桂賸流芳。", "環堵陳圖史，高堂奉旨甘。", "桂枝和月種，萱草鬭春酣。", "玉帝垣居北，老人星現南。", "重哉忠孝責，硬作脊梁檐。"]'),
('8d5328f0-0930-4f9a-9afe-695119fe4370','懷蔣力父監倉','王邁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','冰結長江少躍鱗，天寒不見鴈來賓。',64,'全唐诗/poet.song.195000.json','["冰結長江少躍鱗，天寒不見鴈來賓。", "翻雲覆雨羞餘子，霽月光風憶若人。", "丹穴鵷鶵行毓瑞，北堂燕喜倍生春。", "萬金消息何時到，一洗胸中萬斛塵。"]'),
('0de4fa3f-108c-4800-a46e-cdd28b799a6a','歲暮呈同行蔡實甫','王邁','宋','宋诗','song-poetry','','[]','人生聚散類團沙，偶得聯驂餞歲華。',64,'全唐诗/poet.song.195000.json','["人生聚散類團沙，偶得聯驂餞歲華。", "竹杖徐行忘了簥，村醪小酌勝如茶。", "鄉情喜似輕千里，詩味相投各一家。", "便好扶携玉京去，孤山深處看梅花。"]'),
('88d9e92e-80da-4e0b-bd9c-92b0408ac323','除夜共蔣力父有秋宿南浦館','王邁','宋','宋诗','song-poetry','','[]','客裏逢年酒半醺，篝燈課了送窮文。',64,'全唐诗/poet.song.195000.json','["客裏逢年酒半醺，篝燈課了送窮文。", "對牀共聽巴山雨，入夢休思巫峽雲。", "好整衣冠朝北闕，新栽桃李屬東君。", "平明各把菱花看，黄上眉間已十分。"]'),
('7d503fdd-1e85-4682-b979-e06674aca60c','寄林少忠因爲家叔再留之館  其一','王邁','宋','宋诗','song-poetry','','[]','擇師難似擇良醫，爭得奇功指俗迷。',64,'全唐诗/poet.song.195000.json','["擇師難似擇良醫，爭得奇功指俗迷。", "每羨君才如扁鵲，能爲後學發醯雞。", "作文須有奪胎法，卞惑先須刮膜篦。", "子姪明年看骨換，所求不止在刀圭。"]'),
('b6c3a9cd-af2a-403a-90de-fe140e169e76','寄林少忠因爲家叔再留之館  其二','王邁','宋','宋诗','song-poetry','','[]','年來師道孰知尊，溫飽何緣得浼君。',64,'全唐诗/poet.song.195000.json','["年來師道孰知尊，溫飽何緣得浼君。", "鴻鴈暫爲粱稻計，牛羊誰爲牧芻勤。", "琴書到處聊娛目，羽翼生時要薄雲。", "我偶書田收一熟，向來正亦病人芸。"]'),
('a62e97fc-711f-4406-9843-22e437a69ea4','送林日升景高之毗陵傅氏館','王邁','宋','宋诗','song-poetry','','[]','情好相投歲月深，那堪天外話離襟。',64,'全唐诗/poet.song.195000.json','["情好相投歲月深，那堪天外話離襟。", "京華濁暑鄰三伏，荆水清風直萬金。", "鴻鴈稻粱聊老計，蛟龍雲雨有初心。", "三年名遂榮歸去，椿桂堂前候好音。"]'),
('0f15a030-a713-45bd-91fa-3d89536dbd32','讀慶元黨人家乘  其一','王邁','宋','宋诗','song-poetry','','[]','羣僞欺天日，宋臣去國時。',48,'全唐诗/poet.song.195000.json','["羣僞欺天日，宋臣去國時。", "朝扶皇帝璽，暮植黨人碑。", "楚衆齊難勝，劉安晁遂危。", "抵龜公贊決，幾事併先知。"]'),
('d8026ebe-dd46-4c96-b392-e06bcec6f83e','讀慶元黨人家乘  其二','王邁','宋','宋诗','song-poetry','','[]','方喜儒宗用，無何學禁嚴。',48,'全唐诗/poet.song.195000.json','["方喜儒宗用，無何學禁嚴。", "甘心師管晏，絕口說伊濂。", "天豈斯文喪，人憂善類殲。", "一鳴公甚偉，直氣戢羣憸。"]'),
('d68c015e-5e9a-42bd-936a-de501ba19ff4','讀慶元黨人家乘  其三','王邁','宋','宋诗','song-poetry','','[]','石顯權傾帝，穰侯勢逼王。',48,'全唐诗/poet.song.195000.json','["石顯權傾帝，穰侯勢逼王。", "羣狐爭伺夜，丹鳳獨鳴陽。", "閶闔辭天仗，洋川佩郡章。", "誰嘗舒亶唾，有舌巧如簧。"]'),
('fff2b743-e306-45f4-b036-c1c53dc4126d','讀慶元黨人家乘  其四','王邁','宋','宋诗','song-poetry','','[]','侂怒如關虎，曦謀比井蛙。',48,'全唐诗/poet.song.195000.json','["侂怒如關虎，曦謀比井蛙。", "公乎拚一死，國爾自忘家。", "庾亮塵難汙，劉輿膩莫加。", "修名與姱節，皎皎玉無瑕。"]'),
('2eeaf1a8-421d-450e-8c65-3f003ca7ed08','讀慶元黨人家乘  其五','王邁','宋','宋诗','song-poetry','','[]','本朝諸大老，謚議兩忠公。',48,'全唐诗/poet.song.195000.json','["本朝諸大老，謚議兩忠公。", "公去道鄉遠，名垂太史同。", "一時無顯位，千載播清風。", "韓呂多孫子，毋須添乃翁。"]'),
('3f7370b9-6282-4b84-97db-b32b4fd28d78','讀慶元黨人家乘  其六','王邁','宋','宋诗','song-poetry','','[]','時流酣富貴，雅道冷如菰。',48,'全唐诗/poet.song.195000.json','["時流酣富貴，雅道冷如菰。", "甘附武韋勢，相師張孔諛。", "識汙隨竈婢，氣短事家奴。", "使讀忠公傳，還能泚顙無。"]'),
('59d0710f-37f8-406a-9727-3b0f65d7be4a','謝趙倅送雙雉臘蹄','王邁','宋','宋诗','song-poetry','','[]','文雉雙雙彩翼開，闖籠照水不驚猜。',32,'全唐诗/poet.song.195000.json','["文雉雙雙彩翼開，闖籠照水不驚猜。", "想君當日中牟化，带得桑田馴底來。"]'),
('e4be2b20-04c6-4037-888d-0b4a65135304','送白糍與囊山老子','王邁','宋','宋诗','song-poetry','','[]','東坡以春笋，名爲玉版師。',48,'全唐诗/poet.song.195000.json','["東坡以春笋，名爲玉版師。", "我獨謂玉版，正可名白糍。", "喫笋令人瘦，喫糍充人饑。", "慧眼曰不然，不如飲水肥。"]'),
('409de62f-fd6f-4390-a7ff-567cde69c457','謝永福陳夢得見訪','王邁','宋','宋诗','song-poetry','','[]','枝筇來訪白雲坳，絕異紅塵勢利交。',64,'全唐诗/poet.song.195000.json','["枝筇來訪白雲坳，絕異紅塵勢利交。", "把酒爲君澆磊磈，携詩就我定推敲。", "不曾出市曾龐老，安得爲雲逐孟郊。", "古錦囊中多秀句，家元書史莫徒抄。"]'),
('58f3cefc-3bd4-4c30-9746-d9c2c9219a1b','送螃蟹','王邁','宋','宋诗','song-poetry','','[]','昔人瞻蟹憚監州，今獻霜螯助拍浮。',32,'全唐诗/poet.song.195000.json','["昔人瞻蟹憚監州，今獻霜螯助拍浮。", "料得監州應笑領，無腸公子也風流。"]'),
('90e76aab-5e38-4fee-85e3-2aefc3f88dbf','壽丞相','王邁','宋','宋诗','song-poetry','','[]','翼戴三朝冕有蟬，歸來今作地行仙。',64,'全唐诗/poet.song.195000.json','["翼戴三朝冕有蟬，歸來今作地行仙。", "且看宮闕蕭何第，未泛江湖范蠡船。", "老境已憐周尚父，慶門方似漢韋賢。", "一盃仰祝椿松壽，歲歲流觴八日前。"]'),
('d379bf45-c137-4532-923a-3ff1b76625f1','壽徐直院','王邁','宋','宋诗','song-poetry','','[]','新春三六慶生申，曾立螭頭作近臣。',64,'全唐诗/poet.song.195000.json','["新春三六慶生申，曾立螭頭作近臣。", "論諫獨先聞藥石，代言何止見絲綸。", "漢星今日仍和虜，蹇叔當時最慮秦。", "萬古波濤看砥柱，祝君不必假靈椿。"]'),
('3cd95a21-0884-468b-ab22-e0ff8c6b834c','壽太守','王邁','宋','宋诗','song-poetry','','[]','生申維嶽詠崧高，孕秀儲精歲月多。',64,'全唐诗/poet.song.195000.json','["生申維嶽詠崧高，孕秀儲精歲月多。", "盛旦上元開甲子，前朝令節紀中和。", "銅符暫剖雄藩印，寶鴨行鳴禁路歌。", "天祐名臣錫難老，好將銅狄屢摩挲。"]'),
('5fec35f0-2830-4263-9361-07be00b991ff','壽彭簿','王邁','宋','宋诗','song-poetry','','[]','武夷深處有台仙，嶽降元肖六日前。',64,'全唐诗/poet.song.195000.json','["武夷深處有台仙，嶽降元肖六日前。", "早挾雄文偕漢史，晚將奇策對堯天。", "一官祭竈真遊戲，萬里摶風吏勉旃。", "早晚菑川再惟上，好將名姓壓英躔。"]'),
('d8d0f4e8-c050-4b72-89fc-d9ea11702436','壽鄭青山','王邁','宋','宋诗','song-poetry','','[]','蒼龍拂曉掛高寒，飛鞚翩然出帝關。',64,'全唐诗/poet.song.195000.json','["蒼龍拂曉掛高寒，飛鞚翩然出帝關。", "九釀黄封中聖酒，一盃紅入上台顔。", "閹雛生怕韓公召，宮妾尤驚富相還。", "獨有帝心懷舊弼，未應霖雨閣青山。"]'),
('864fbc43-2009-40f3-8159-ec1f69b07208','壽陳貢元','王邁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','潘胸萬卷富文章，天産英賢生玉皇。',64,'全唐诗/poet.song.195000.json','["潘胸萬卷富文章，天産英賢生玉皇。", "後日嶽神逢誕節，今朝昴宿出呈祥。", "秋風鶚表聲名遠，春浪龍門姓字香。", "來歲壽觴何處飲，西湖三月正韶光。"]'),
('74c16fac-b6b9-4d90-99b1-cf480a20aceb','壽丘曹','王邁','宋','宋诗','song-poetry','','[]','三分辰月一分過，天産真仙積慶多。',64,'全唐诗/poet.song.195000.json','["三分辰月一分過，天産真仙積慶多。", "西國玉枝家世襲，霸陵銅狄手長摩。", "功名本自歸談笑，壽考何勞着詠歌。", "行直紫宸清夜宿，共驚蓮炬認鳴珂。"]'),
('bb215ecc-f017-4c82-97e9-99ac411689ca','叔壽姪','王邁','宋','宋诗','song-poetry','','[]','纔經六日便頒春，還是長庚初度辰。',64,'全唐诗/poet.song.195000.json','["纔經六日便頒春，還是長庚初度辰。", "蘭砌聲名千載舊，竹林風月幾時新。", "詩書本是吾家事，燈火須勤汝輩親。", "未把金盃爲壽祝，且期及第爲親榮。"]'),
('41778369-7240-43bd-bc60-114af176771b','句  其一','王邁','宋','宋诗','song-poetry','','[]','月香試看尤清絕，一在枝頭一在窗。',16,'全唐诗/poet.song.195000.json','["月香試看尤清絕，一在枝頭一在窗。"]'),
('5e056f5b-87a8-478c-91c1-df426409726d','句  其二','王邁','宋','宋诗','song-poetry','','[]','未知死所先期死，自笑狂生老更狂。',16,'全唐诗/poet.song.195000.json','["未知死所先期死，自笑狂生老更狂。"]'),
('8177398a-23e4-4e9d-a197-e15e10423f24','賦薛侯','陳郁','宋','宋诗','song-poetry','','[]','薛侯俊健如生猱，不識中原生土豪。',192,'全唐诗/poet.song.195000.json','["薛侯俊健如生猱，不識中原生土豪。", "蛇矛丈八常在手，駱馬蕃鞍雲錦袍。", "往屬嫖姚探虎穴，狐鳴蕭蕭風立髮。", "短韉淋血斬將歸，夜斲堅冰濡馬渴。", "中都久住武城坊，屋頭養駱如養羊。", "枯萁不飽籬壁盡，狹巷怒蹄盆盎傷。", "只今栖栖守環堵，五月樵風吹宿莽。", "千金夜出酬市兒，客帳晝眠聽戲鼓。", "邊人視死亦尋常，笑裏辭家登戰場。", "銓勞定次屈壯士，兩眼熒熒收淚光。", "齒堅食肉何曾老，騎馬身輕飛一鳥。", "焉知不將萬人行，橫槊秋風賀蘭道。"]'),
('e0fb6001-0181-49a9-9b5c-2be8f0477910','天賜白','陳郁','宋','宋诗','song-poetry','','[]','君不見書生鎸羌勒兵入，羌來薄城束縛急。',195,'全唐诗/poet.song.195000.json','["君不見書生鎸羌勒兵入，羌來薄城束縛急。", "蠟丸飛出辭大家，帳下健兒紛雨泣。", "鑿沙到石終無水，擾擾萬人如渴蟻。", "挽絙竊出兩將軍，敵箭飛來風掠耳。", "道傍神馬白雪毛，噤口不嘶深夜逃。", "忽聞漢語米脂下，黑霧壓城風怒號。", "脫身歸來對刀筆，短衣射虎朝朝出。", "自椎雜寶塗箭創，心折骨驚如昨日。", "穀城魯公天下雄，陰陵一跌兵刀窮。", "檥舟不渡謝亭長，有何面目歸江東。", "將軍偶生名已弱，鐵花暗澀龍文鍔。", "縞帳肥芻酬馬恩，閒望旄頭向西落。"]'),
('db8d3dd1-6b32-44d0-8ad0-18962e977ad5','淮東楚客','陳郁','宋','宋诗','song-poetry','','[]','淮邦産寶皆奇士，楚客能詞只小夫。',32,'全唐诗/poet.song.195000.json','["淮邦産寶皆奇士，楚客能詞只小夫。", "些語凄凉君自感，未應山色獨關渠。"]'),
('3a2818e6-b4b9-4923-ba26-ca9425a4357f','題梅仙觀','陳郁','宋','宋诗','song-poetry','','[]','進了忠言隠姓名，萬年香火此山靈。',32,'全唐诗/poet.song.195000.json','["進了忠言隠姓名，萬年香火此山靈。", "可憐沉醉功名者，血染咸陽喚不醒。"]'),
('93928c1d-2de0-4c27-ab58-50cf84201e8b','石湖歸途','陳郁','宋','宋诗','song-poetry','','[]','人與西風結約來，芙蓉花氣撲吟杯。',32,'全唐诗/poet.song.195000.json','["人與西風結約來，芙蓉花氣撲吟杯。", "曲塘好處都行遍，带得一身秋色回。"]'),
('725e5e84-6d52-42fc-9841-f274b383b54e','城東看柳','陳郁','宋','宋诗','song-poetry','','[]','翻煖爲寒一信風，畫橋南北岸西東。',32,'全唐诗/poet.song.195000.json','["翻煖爲寒一信風，畫橋南北岸西東。", "春歸楊柳無私意，深淺青黄自不同。"]'),
('7c8ffa94-5752-4f51-a818-b303b42c4534','上林歸鴉','陳郁','宋','宋诗','song-poetry','','[]','夕陽鴉背歛殘紅，萬點飛歸傍帝宮。',32,'全唐诗/poet.song.195000.json','["夕陽鴉背歛殘紅，萬點飛歸傍帝宮。", "應是上林棲宿穩，可曾驚散月明中。"]'),
('7966c7ec-6f96-417c-90f3-adc5a91a3ec1','友人官滿','陳郁','宋','宋诗','song-poetry','','[]','三年官滿冰霜潔，一日春回宇宙寬。',32,'全唐诗/poet.song.195000.json','["三年官滿冰霜潔，一日春回宇宙寬。", "曾向廳前種楊柳，綠陰留與後人看。"]'),
('89fed75d-f217-452d-9d64-9972964cef50','東園書所見','陳郁','宋','宋诗','song-poetry','','[]','娉婷游女步東園，曲徑相逢一少年。',32,'全唐诗/poet.song.195000.json','["娉婷游女步東園，曲徑相逢一少年。", "不肯比肩花下過，含羞却立海棠邊。"]'),
('7cd9d7ce-8738-493c-965d-e7faee33a3a9','苦吟','陳郁','宋','宋诗','song-poetry','','[]','水驛荒寒天正霜，夜深吟苦未成章。',32,'全唐诗/poet.song.195000.json','["水驛荒寒天正霜，夜深吟苦未成章。", "閉門不管庭前月，分付梅花自主張。"]'),
('69ef1f2e-83a8-4ad3-9a70-2f39c92eb658','蘇堤曉望','陳郁','宋','宋诗','song-poetry','','[]','荷邊清露襲人衣，風裏明蟾浴曉池。',32,'全唐诗/poet.song.195000.json','["荷邊清露襲人衣，風裏明蟾浴曉池。", "涼影潤香吟不得，手扳堤柳立多時。"]'),
('853dec20-8de3-4a7e-8b17-eaa340d91f4b','山行聞春禽','陳郁','宋','宋诗','song-poetry','','[]','初陽烘霽途，繁陰布幽林。',60,'全唐诗/poet.song.195000.json','["初陽烘霽途，繁陰布幽林。", "山禽互嘲哳，爲我流好音。", "傾耳須臾閒，已快清冷心。", "飛蓋何爲者，傲睨松之陰。", "翻然移他枝，餘弄不可尋。"]'),
('8f84c871-b6c5-48cf-92fd-e65f1eb63c2a','景靈宮孟享','陳郁','宋','宋诗','song-poetry','','[]','幸驂恭謝覩繁華，馬上歸來戴御花。',32,'全唐诗/poet.song.195000.json','["幸驂恭謝覩繁華，馬上歸來戴御花。", "老婦稚兒相顧問，也頒春色到詩家。"]'),
('4d27c347-7285-48f8-8609-8ecf323ae737','自贊','陳郁','宋','宋诗','song-poetry','','[]','年方九秩開，丹臉映碧眼。',54,'全唐诗/poet.song.195000.json','["年方九秩開，丹臉映碧眼。", "習靜寸心安，味窮百事懶。", "由中以致和，聞道亦非晚。", "噫，十年譔述幸隨龍，二聖在天應默眷。"]'),
('f374317a-70c7-4437-a6ac-54da5690bd54','賦翁仲','陳郁','宋','宋诗','song-poetry','','[]','銅仙擎露秋風表，珍重劉郎千萬壽。',99,'全唐诗/poet.song.195000.json','["銅仙擎露秋風表，珍重劉郎千萬壽。", "老瞞攘鼎貽孫謀，因逼此仙俱受垢。", "仙寧折骨拒非招，恥爲姦雄效奔走。", "污名翁仲俾司門，口不能言心自否。", "洛陽宮殿一灰飛，天上此標獨長久。", "君不見堂堂冠劍隠霸城，萬古六丁驅鬼守。"]'),
('4efec225-fea4-4185-8b05-4a2e70d0236a','偕潘寒巖陳定軒遊石湖次定軒韻','陳郁','宋','宋诗','song-poetry','','[]','貂裘絨帽護輕寒，坐馬端如坐席安。',64,'全唐诗/poet.song.195000.json','["貂裘絨帽護輕寒，坐馬端如坐席安。", "自別石湖三月去，又携玉友一番看。", "霜催菊磵風悽惻，雨浹蘆汀水渺漫。", "欲寄吟懷須勝地，千金同此買魚竿。"]'),
('99c5ab61-7c83-4cb5-85cd-08f3e78db52a','題梅花便面','陳郁','宋','宋诗','song-poetry','','[]','白團橫寫向南枝，冷蘂寒梢手自持。',32,'全唐诗/poet.song.195000.json','["白團橫寫向南枝，冷蘂寒梢手自持。", "絕似曉空凉影裏，月明中有桂花時。"]'),
('c3fe022b-dad1-4421-82e8-8bb102d88284','題林可山爲倪龍輔所作梅村圖後','陳郁','宋','宋诗','song-poetry','','[]','當年一句月黄昏，香到梅邊七世孫。',32,'全唐诗/poet.song.195000.json','["當年一句月黄昏，香到梅邊七世孫。", "應愛君詩似和靖，爲君依樣畫西村。"]'),
('6e46ffa2-bc15-425c-8d46-fef1e90c59f4','倦遊','陳郁','宋','宋诗','song-poetry','','[]','水於東江皆臣妾，山到衡陽無弟兄。',32,'全唐诗/poet.song.195000.json','["水於東江皆臣妾，山到衡陽無弟兄。", "兩處經行都已遍，老夫誰更別關情。"]'),
('0eabce8b-6de9-4575-a49d-9a909619aad5','贈東華老真鍾逸士','陳郁','宋','宋诗','song-poetry','','[]','衣冠凉薄亦端嚴，爲到貧時解養廉。',64,'全唐诗/poet.song.195000.json','["衣冠凉薄亦端嚴，爲到貧時解養廉。", "京洛家風今尚在，宗王恩禮舊曾沾。", "談高堅白囊無底，詞縱題紅筆退尖。", "自說學仙曾有遇，欲歸巖壑理抽添。"]'),
('03b20696-bb71-4324-a9f0-2bbb3095aee9','製梅花湯','陳郁','宋','宋诗','song-poetry','','[]','南枝開處覓春光，摘得冰葩蜜甕藏。',32,'全唐诗/poet.song.195000.json','["南枝開處覓春光，摘得冰葩蜜甕藏。", "留煮午湯消暑渴，吟騷牙頰有浮香。"]'),
('baf0af98-bb47-4aab-afb1-7fe71983e797','憶浪顛','陳郁','宋','宋诗','song-poetry','','[]','偶同鄉友校吟編，因得平安到浪顛。',64,'全唐诗/poet.song.195000.json','["偶同鄉友校吟編，因得平安到浪顛。", "心不干時清似水，髮緣憂國白於棉。", "半生景慕空千里，一紙寒溫廢二年。", "何日支筇隨此老，秋巖和菊薦冰泉。"]'),
('53c2a59a-de12-4162-9149-263fa9e20742','憶錢春塘','陳郁','宋','宋诗','song-poetry','','[]','識面論心已半生，買山無計得同盟。',64,'全唐诗/poet.song.195000.json','["識面論心已半生，買山無計得同盟。", "行藏爲是關天理，會聚因難遂客情。", "月戶評春花影澹，風廊逃暑竹聲清。", "安舲何日來城角，細舉前吟爲再賡。"]'),
('d4040c00-2bbe-4ce3-98af-1b949877aa2d','贈醫官吳將使','陳郁','宋','宋诗','song-poetry','','[]','不合生來愛苦吟，書淫傳癖到于今。',32,'全唐诗/poet.song.195000.json','["不合生來愛苦吟，書淫傳癖到于今。", "江湖未遇醫治手，煩向詩脾謾一鍼。"]'),
('a2f1a2b9-a753-4345-befb-289878969a09','贈僧玘長老','陳郁','宋','宋诗','song-poetry','','[]','客單近掛屋東偏，細看家風似閬仙。',64,'全唐诗/poet.song.195000.json','["客單近掛屋東偏，細看家風似閬仙。", "爲載月舡來茂苑，因披雲衲出潭田。", "詩篇熟誦如持咒，句法旁參若勘禪。", "既是西來須會意，此心還許野人傳。"]'),
('73a42a92-2656-496e-9a71-55149129fe5b','贈道士李岫雲','陳郁','宋','宋诗','song-poetry','','[]','聞說讀黄庭，經年遠俗情。',48,'全唐诗/poet.song.195000.json','["聞說讀黄庭，經年遠俗情。", "爲能參溟涬，因不賦清平。", "客滿轉呼酒，詩高偏避名。", "謫仙遊戲耳，終有玉函迎。"]'),
('c6397c48-6e95-4398-9a1c-b6d1d4c34cfb','贈絲桐墨蕙呂能甫淮東制閫之客','陳郁','宋','宋诗','song-poetry','','[]','子向詩書外，尤於藝事優。',48,'全唐诗/poet.song.195000.json','["子向詩書外，尤於藝事優。", "桐絲傳古意，蘭墨寫離愁。", "黄閣能知己，朱衣必點頭。", "從來奇特士，何患不封侯。"]'),
('96d3a05e-8234-40cb-a9bf-ed87ada8c36f','贈鴻宿洲淮士','陳郁','宋','宋诗','song-poetry','','[]','洲沙宛在水中央，荻屋蓬窗似野航。',64,'全唐诗/poet.song.195000.json','["洲沙宛在水中央，荻屋蓬窗似野航。", "不戰棄城誰執咎，偷生避地子何傷。", "賣力已化諸山寨，沽酒從開萬戶坊。", "如此撫摩能幾日，流民端可復耕桑。"]'),
('870aa96c-77ee-4344-804b-63de86829690','次韻贈張秋巖','陳郁','宋','宋诗','song-poetry','','[]','清高非一事，最好是吟懷。',48,'全唐诗/poet.song.195000.json','["清高非一事，最好是吟懷。", "吳會相逢日，春風入酒杯。", "雪舟回石浦，雲戶掩秋崖。", "合作蘭臺客，朝家有逸才。"]'),
('c003d803-e3c0-442f-93fe-7a4232618bd6','贈施秋渚','陳郁','宋','宋诗','song-poetry','','[]','四海東洲老，傳家有阿戎。',48,'全唐诗/poet.song.195000.json','["四海東洲老，傳家有阿戎。", "簪纓百年後，燈火一窗中。", "買宅鄰臺府，開園界水宮。", "山房喜相近，來往便詩筒。"]'),
('e9adfba9-d7af-4c6e-87ae-b6c3c2381615','贈翁運幹','陳郁','宋','宋诗','song-poetry','','[]','春陽和且澄，榆烟裊新燧。',84,'全唐诗/poet.song.195000.json','["春陽和且澄，榆烟裊新燧。", "茲晨適解后，萬象獻嫵媚。", "悠哉高堂人，軒冕莫能累。", "頗珍湖海游，漸摩仁與義。", "因之玄思清，筆力挽春意。", "人生匪得朋，一欣何所寄。", "相期風花城，年年同健醉。"]'),
('fc58e11f-f7a4-4fce-8a7c-2fe0c49a0897','以七字律羽扇贈行','陳郁','宋','宋诗','song-poetry','','[]','匹馬東淮兩月奇，歸銜俄爾带新資。',64,'全唐诗/poet.song.195000.json','["匹馬東淮兩月奇，歸銜俄爾带新資。", "吟高已中唐人律，名重宜魁浙漕闈。", "彩舫香衝荷葉去，捷旗榮與菊花期。", "贈君羽扇還知否，文陣千軍可一揮。"]'),
('7d5d52c2-b5b6-4d3d-8263-4e752a4729c9','贈勉周濟川','陳郁','宋','宋诗','song-poetry','','[]','坐窗長記別時愁，欲訊平安尚未由。',64,'全唐诗/poet.song.195000.json','["坐窗長記別時愁，欲訊平安尚未由。", "客袂重來驚日久，義懷高甚薄雲浮。", "論心句好能令喜，到骨貧深不足憂。", "更向吟邊策勳業，江湖近日欠清流。"]'),
('7ae3bbda-72fc-4bbf-969c-6b4725800cb9','贈竹林翁','陳郁','宋','宋诗','song-poetry','','[]','爲竹爲花號不同，一般騷雅一般翁。',32,'全唐诗/poet.song.195000.json','["爲竹爲花號不同，一般騷雅一般翁。", "東風紅紫飄零後，須看琅玕立雪中。"]'),
('196855c6-2917-4832-8ba5-72929ee5bfbb','寄編修龔郎中','陳郁','宋','宋诗','song-poetry','','[]','說着池陽舊歲時，星郎事業世皆知。',64,'全唐诗/poet.song.195000.json','["說着池陽舊歲時，星郎事業世皆知。", "淮人自古真堪用，天下如今尚可爲。", "江南烽高黄塞近，街頭箭急赤囊馳。", "多應規撫煩君往，橫槊隨賡薄伐詩。"]'),
('64d06cd2-7bb0-4fa2-b638-70a7b77cd5db','毛梧竹惠詩趁韻答贈','陳郁','宋','宋诗','song-poetry','','[]','三衢不住住王城，因向江湖得令名。',64,'全唐诗/poet.song.195000.json','["三衢不住住王城，因向江湖得令名。", "朝士有書常倦答，騷壇分韻每先成。", "事臨口畫無遺策，交以心期肯待盟。", "貽我高吟粘屋壁，琅篇珠字照山楹。"]'),
('d8e5ab70-9547-48e5-a14c-4d93a3c3dfe9','答王雪窗惠詩','陳郁','宋','宋诗','song-poetry','','[]','窗以雪爲名，窗中人亦清。',48,'全唐诗/poet.song.195000.json','["窗以雪爲名，窗中人亦清。", "聽無多淡話，含不盡幽情。", "世態秋雲薄，吟懷霽月明。", "似聞藏古硯，石眼可曾晴。"]'),
('af18d479-5832-45d6-b6ac-6f22b5dd082e','次韻謝鄉陳浪顛  其一','陳郁','宋','宋诗','song-poetry','','[]','聞有上江船，令人喜欲顛。',48,'全唐诗/poet.song.195000.json','["聞有上江船，令人喜欲顛。", "烹魚開尺素，被毳得純棉。", "細讀蠅頭字，誰欺鶴髮年。", "那堪寄來句，清比醉翁泉。"]'),
('16127fea-d51c-4e47-86a7-ce332ccd5c11','次韻謝鄉陳浪顛  其二','陳郁','宋','宋诗','song-poetry','','[]','流浪江湖久，空餘雪雨顛。',48,'全唐诗/poet.song.195000.json','["流浪江湖久，空餘雪雨顛。", "才無時展布，愁與病纏綿。", "暮景知前事，榮途看少年。", "終然歸去是，家自有林泉。"]'),
('2e6e024a-2ac9-46a8-a46b-6db2689cf227','郭戇菴惠詩爲謝','陳郁','宋','宋诗','song-poetry','','[]','相思長只認文星，霽後闌干卜夜憑。',64,'全唐诗/poet.song.195000.json','["相思長只認文星，霽後闌干卜夜憑。", "萬斛筆頭非錄錄，七年袍色未青青。", "字肩米老神尤健，詩角唐人氣欲陵。", "尚擬酒邊論契闊，看君談笑吸滄溟。"]'),
('288ba7af-a3fb-455c-972e-3f4693eeea66','姜石帚貽書寄詩謝','陳郁','宋','宋诗','song-poetry','','[]','貪卧蘇臺一片雲，嘉招虛辱遠移文。',64,'全唐诗/poet.song.195000.json','["貪卧蘇臺一片雲，嘉招虛辱遠移文。", "吟人多半來投刺，倦客深慚自閉門。", "路隔江潮兼夕到，居連地勢兩州分。", "酬恩別有男兒事，它日逢君仔細論。"]'),
('0d6c7f6b-2b96-4f0d-82cd-5c3cf9b84003','荼䕷次友人韻','陳郁','宋','宋诗','song-poetry','','[]','紅紫委空塵，猶鋪一架春。',48,'全唐诗/poet.song.195000.json','["紅紫委空塵，猶鋪一架春。", "素瑶堆艷潔，綠带裊芳新。", "走雪詩能聖，扶香花有神。", "風流付杯酌，留與醉吟人。"]'),
('7f8b1a29-7dd0-4898-831f-9e7bf3069c56','洪橋客窗枕上','陳郁','宋','宋诗','song-poetry','','[]','桐葉飄零月似冰，並河燈火夜寒生。',32,'全唐诗/poet.song.195000.json','["桐葉飄零月似冰，並河燈火夜寒生。", "闌干倦倚投床去，卧聽趨朝過馬聲。"]'),
('215f0da9-975d-49ae-8c02-5bbe9b0fcf3b','聽楊君彈古操','陳郁','宋','宋诗','song-poetry','','[]','年來雅道類聾瘖，到處笙歌只勸淫。',64,'全唐诗/poet.song.195000.json','["年來雅道類聾瘖，到處笙歌只勸淫。", "肯抱焦桐閑訪隠，應思塵世少知音。", "離鸞別鵠皆風月，二典三盤不古今。", "聞子細彈千載事，吟夫已見聖人心。"]'),
('98dc79cc-bfad-4ba2-98a9-d463d85e1143','憶古襄州西教場打毬','陳郁','宋','宋诗','song-poetry','','[]','憶參元帥古襄州，幾度莎場馬打毬。',32,'全唐诗/poet.song.195000.json','["憶參元帥古襄州，幾度莎場馬打毬。", "鞍轡閙裝都一樣，野夫不着皂貂裘。"]'),
('c44b2df2-db16-49fc-93ad-aea1b6a0410a','得盧蒲江劉懲齋倡和墨','陳郁','宋','宋诗','song-poetry','','[]','天錫吟箋慰老懷，筆花文藻卷中開。',64,'全唐诗/poet.song.195000.json','["天錫吟箋慰老懷，筆花文藻卷中開。", "二分者作有如此，一世之雄安在哉。", "疁邑墳荒惟宿草，玉堂人去幾秋槐。", "詩仙應赴詩家供，一展寒齋定一來。"]'),
('e0e3d8af-9aa7-4e6d-a27b-4f900a7df538','觀鑄劍','陳郁','宋','宋诗','song-poetry','','[]','良鐵曾收漢益州，規模因塑古吳鈎。',64,'全唐诗/poet.song.195000.json','["良鐵曾收漢益州，規模因塑古吳鈎。", "鑪安吉位分龍虎，火逸神光射斗牛。", "入水淬鋒疑電閃，臨崖發刃有星浮。", "知君斬却樓蘭了，戲袖青蛇住十洲。"]'),
('63d12337-33f0-4357-89d3-9a8050d197c8','過列山廟下','陳郁','宋','宋诗','song-poetry','','[]','撾鼓揚旗向石頭，列山山下使人愁。',32,'全唐诗/poet.song.195000.json','["撾鼓揚旗向石頭，列山山下使人愁。", "風前獨倚危檣立，遥認西淮四五州。"]'),
('5cda8613-6903-4f22-a728-9d593e4f7adb','山中','陳郁','宋','宋诗','song-poetry','','[]','自入山中二十年，抗塵有道即爲仙。',64,'全唐诗/poet.song.195000.json','["自入山中二十年，抗塵有道即爲仙。", "差科難到耽閑地，種穫因無負郭田。", "細事亦參齊物論，大還長勘娛真篇。", "詩成不敢題崖石，怕有江湖姓字傳。"]'),
('1d975242-b3ac-4ffe-a470-97bb5e68b7f6','秋潭爲吳仲益賦','陳郁','宋','宋诗','song-poetry','','[]','不留一葉山骨瘦，祇浸幾星波影寒。',32,'全唐诗/poet.song.195000.json','["不留一葉山骨瘦，祇浸幾星波影寒。", "中有高人倚空闊，絕疑珠墮水晶盤。"]'),
('76056f3b-9c39-4e50-b8ad-2a4391e7ffc5','爲證無得賦竹山','陳郁','宋','宋诗','song-poetry','','[]','好山雖可愛，懶入翠重重。',48,'全唐诗/poet.song.195000.json','["好山雖可愛，懶入翠重重。", "靜看千竿玉，清如五老峰。", "徑陰禪履潤，林密佛香濃。", "靈運知師意，無勞躡屐躡。"]'),
('52fc728e-53f7-484d-8806-e783e6688d8d','空谷有幽蘭','陳郁','宋','宋诗','song-poetry','','[]','空谷有幽蘭，孤根倚白石。',72,'全唐诗/poet.song.195000.json','["空谷有幽蘭，孤根倚白石。", "清晨作奇芬，凡卉各跼蹐。", "公子偶相值，□枝置錦席。", "敷榮忽變悴，色不貸一夕。", "信知傾國姿，羞任桃李責。", "所以富豪兒，睥睨林下客。"]'),
('285bb580-f184-4889-84aa-63cbebb6fb08','昔人貴松柏','陳郁','宋','宋诗','song-poetry','','[]','昔人貴松柏，爲有霜雪姿。',48,'全唐诗/poet.song.195000.json','["昔人貴松柏，爲有霜雪姿。", "折以贈遠別，歲寒心不移。", "願言且珍藏，聊慰千日思。", "青青隕秋黄，勿同楊柳絲。"]'),
('2b3be40a-b44f-46f0-8c8d-e2b9414eb15e','虞美人草','陳郁','宋','宋诗','song-poetry','','[]','彭城高會日置酒，猴冠猶在婦人手。',96,'全唐诗/poet.song.195000.json','["彭城高會日置酒，猴冠猶在婦人手。", "倉皇垓下已重圍，四面悲吟雜刁斗。", "當年舉珮不倒戈，到此空餘慷慨歌。", "虞兮反袂交淹泣，欲幸從兮可奈何。", "怨入青蕪知幾歲，舞恨摇芳無別意。", "妾身恨不事英雄，果是英雄安有淚。"]'),
('4e104d39-41ea-46d8-8b03-33eb764ca470','趙園看白牡丹','陳郁','宋','宋诗','song-poetry','','[]','園林物物挾春光，獨許名花壓衆芳。',64,'全唐诗/poet.song.195000.json','["園林物物挾春光，獨許名花壓衆芳。", "雨艷寒輕清入骨，雪膚香瑩白含章。", "仙人聚土誇能染，學士承恩賦倚粧。", "幾欲寶酥煎洛蘂，遲回未忍折雲裳。"]'),
('c4f94f9d-40ed-4c6c-aa80-12079311ddd3','看落花','陳郁','宋','宋诗','song-poetry','','[]','飛紅飄白自交加，過了春光只嘆嗟。',32,'全唐诗/poet.song.195000.json','["飛紅飄白自交加，過了春光只嘆嗟。", "識得歲寒松竹耐，始知園圃謾栽花。"]'),
('c3e1c747-4362-48a4-8e9e-4e09bbc501ca','鶑燕','陳郁','宋','宋诗','song-poetry','','[]','紅杏牆連柳外門，春風池接暖烟村。',32,'全唐诗/poet.song.195000.json','["紅杏牆連柳外門，春風池接暖烟村。", "陽和世界無分別，各自營巢長子孫。"]'),
('819677c6-bd26-4792-9e6b-fda5b3c961d5','射雁馬上口占','陳郁','宋','宋诗','song-poetry','','[]','脫手弦聲破曉寒，鴈身和箭衮花團。',32,'全唐诗/poet.song.195000.json','["脫手弦聲破曉寒，鴈身和箭衮花團。", "簷前曝背山翁喜，催喚兒孫逐馬看。"]'),
('50c7bb46-9e36-4d42-b71b-f6feb7894d95','得狸奴','陳郁','宋','宋诗','song-poetry','','[]','穿魚新聘一銜蟬，人說狸花最直錢。',64,'全唐诗/poet.song.195000.json','["穿魚新聘一銜蟬，人說狸花最直錢。", "舊日畜來多不捕，于今得此始安眠。", "牡丹影裏嬉成畫，薄荷香中醉欲顛。", "却是能知春信息，有聲堪恨復堪憐。"]'),
('20d5ac9a-aff0-418b-8a7f-b76452fb8532','書江亭壁','陳郁','宋','宋诗','song-poetry','','[]','人間風浪最傾危，君自深藏了不知。',32,'全唐诗/poet.song.195000.json','["人間風浪最傾危，君自深藏了不知。", "只恐隨流禹門去，又翻頭角露天池。"]'),
('ea6b6706-de1c-42f6-817f-5b3acbfb685f','爲薛叔載賦海隠','陳郁','宋','宋诗','song-poetry','','[]','見有闌干便艤航，不知炎日熬沙場。',32,'全唐诗/poet.song.195000.json','["見有闌干便艤航，不知炎日熬沙場。", "多應高枕歸篷下，夢到此亭都是凉。"]'),
('374fe77f-3b3b-4e98-bd07-8b837c6e3ffa','木庵爲吳應祥隃賦','陳郁','宋','宋诗','song-poetry','','[]','木主乎東義近仁，斯庵名此稱斯人。',32,'全唐诗/poet.song.195000.json','["木主乎東義近仁，斯庵名此稱斯人。", "遥知虛室蕭閒地，生意滿懷都是春。"]'),
('db1cedbd-fc0f-4e60-88f0-385d9289b257','得琴硯古雅堂','陳郁','宋','宋诗','song-poetry','','[]','端溪湮塞焦桐已，羅旅文房尚奢侈。',194,'全唐诗/poet.song.195000.json','["端溪湮塞焦桐已，羅旅文房尚奢侈。", "古風雅志莫養成，從此詞章墮彫靡。", "仙巖名士獨不然，家有琴硯皆世傳。", "熨焦蛇斷互左右，俾受彈弄供磨研。", "耳根筆澤千載意，字□挽回淳朴味。", "乃知舊物是筌蹄，薰染皇墳歸繭紙。", "百篇因之奏帝傍，帝賚文美承恩光。", "歸來築堂標古雅，家學始末示不忘。", "邇來相傳貴珠玉，或侈金屏誇綉縟。", "心遊目視溺豪華，繼發一言流近俗。", "嗟余僻好惟古文，敬此堂名如敬君。", "何時登堂相撫玩，古雅之意期與君平分。"]'),
('811d3bbc-de71-40b0-ae63-9a49f418cbac','琵琶亭','陳郁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','二嘆潯陽送客翁，忍將吾道等秋蓬。',64,'全唐诗/poet.song.195000.json','["二嘆潯陽送客翁，忍將吾道等秋蓬。", "煢然商婦千呼至，貴甚監州一笑同。", "力學本爲明德計，能文祇是立言工。", "琶琵亭下愁情遠，付與長江寫不窮。"]'),
('fdd56d0a-1021-499f-83b0-21a40b7e5b8d','題王南杰遠明樓','陳郁','宋','宋诗','song-poetry','','[]','重欄俯江湄，四箔捲雲表。',48,'全唐诗/poet.song.195000.json','["重欄俯江湄，四箔捲雲表。", "晴暉爍纖翳，萬里歸一眇。", "清高樓上人，眼闊天地小。", "何當倚秋空，吟送飛鴻杳。"]'),
('8567b3fb-b3e3-49ac-b6fd-d1b49743c2d8','題朱氏隠閑樓','陳郁','宋','宋诗','song-poetry','','[]','卜築雖城市，心安跡亦安。',48,'全唐诗/poet.song.195000.json','["卜築雖城市，心安跡亦安。", "一樓深自適，萬事少相干。", "月向重簷待，山於曲檻看。", "門前車馬客，未必識天寬。"]'),
('dbbe2dad-290e-497d-acc6-d7871f0e3307','爲古艾鄭子剛賦可軒  其一','陳郁','宋','宋诗','song-poetry','','[]','未赴功名且釣船，忽勤王事即貂蟬。',32,'全唐诗/poet.song.195000.json','["未赴功名且釣船，忽勤王事即貂蟬。", "丈夫出處隨時變，須卜此心然不然。"]'),
('3062df32-9b76-40fa-9ff1-ddae1359799c','爲古艾鄭子剛賦可軒  其二','陳郁','宋','宋诗','song-poetry','','[]','不容不辦屋三間，出即扃幽退隠閑。',32,'全唐诗/poet.song.195000.json','["不容不辦屋三間，出即扃幽退隠閑。", "我蔽一言君記取，黄扉未必似青山。"]'),
('47321b2c-1a8b-48ac-a733-6a520b554e06','爲朱柳州賦足庵','陳郁','宋','宋诗','song-poetry','','[]','名庵以足關天理，須向庵中靜處參。',64,'全唐诗/poet.song.195000.json','["名庵以足關天理，須向庵中靜處參。", "底事此心無所欠，祇緣與世不生貪。", "書淫過似專房樂，蔬食多於列鼎甘。", "却怪紫芝曾漏泄，從來坤勢闕東南。"]'),
('6ec25109-a636-4a4e-8923-78a6ccb2c029','遊葛氏山堂','陳郁','宋','宋诗','song-poetry','','[]','催詩雨裏載杯盤，名勝園林得借閑。',64,'全唐诗/poet.song.195000.json','["催詩雨裏載杯盤，名勝園林得借閑。", "百五日當春事閙，十三人坐宴堂寬。", "都拋世味言談外，盡出家藏意玩間。", "不是主人風度遠，客遊那有許清歡。"]'),
('38d146d6-dfcd-4b80-a4dc-483d401e9546','閉戶','陳郁','宋','宋诗','song-poetry','','[]','坐到心清有妙香，蒲團紙帳任更長。',32,'全唐诗/poet.song.195000.json','["坐到心清有妙香，蒲團紙帳任更長。", "閉門不受庭前月，分付梅花自主張。"]'),
('3a280c4b-2711-4240-a891-66a9bdea00c3','倚樓','陳郁','宋','宋诗','song-poetry','','[]','一聲新鴈一聲秋，獨向江樓倚莫愁。',32,'全唐诗/poet.song.195000.json','["一聲新鴈一聲秋，獨向江樓倚莫愁。", "江上片雲將雨去，却留殘照管汀洲。"]'),
('0ac94798-c76e-4e45-b1bd-92134da10efe','多景樓眺望','陳郁','宋','宋诗','song-poetry','','[]','江淮萬里天，歷歷在樓前。',48,'全唐诗/poet.song.195000.json','["江淮萬里天，歷歷在樓前。", "對景獨登覽，因思幾變遷。", "雲橫秋水外，鳥度夕陽邊。", "倦倚闌干北，令人思黯然。"]'),
('71f04bcf-1d66-459e-a2ef-aefcd4198fd2','商驛樓東望有感','陳郁','宋','宋诗','song-poetry','','[]','山川去接漢江東，曾伴隋侯醉此中。',64,'全唐诗/poet.song.195000.json','["山川去接漢江東，曾伴隋侯醉此中。", "歌遶夜梁珠宛轉，舞嬌春席雪朦朧。", "棠遺善政陰猶在，薤送哀聲事已空。", "惆悵知音竟難得，兩行清淚白楊風。"]'),
('1c0f6d4e-012a-432c-b01a-69e71502b747','爲僧如賦深居','陳郁','宋','宋诗','song-poetry','','[]','禪居自合入山林，闤闠之中豈是深。',32,'全唐诗/poet.song.195000.json','["禪居自合入山林，闤闠之中豈是深。", "須信道人清似水，佳城如住海波心。"]'),
('79ede7df-583c-4be5-abae-f6d39ce6f178','登法海寺小閣','陳郁','宋','宋诗','song-poetry','','[]','絕頂危梯緩步登，俯空幽閣據崚嶒。',32,'全唐诗/poet.song.195000.json','["絕頂危梯緩步登，俯空幽閣據崚嶒。", "不知吟到無窮處，但覺一層高一層。"]'),
('38adfda3-39ce-4be4-9cb5-8104ac1a5cb8','題治平寺壁','陳郁','宋','宋诗','song-poetry','','[]','越君嘗膽苦心摧，娃館春風正酒杯。',64,'全唐诗/poet.song.195000.json','["越君嘗膽苦心摧，娃館春風正酒杯。", "絃管但知連夜樂，旌旗先已過溪來。", "麋衝曉霧遊荒苑，鴉立斜陽噪古臺。", "野客不談興廢事，綠陰深處摘青梅。"]'),
('f04463b8-846b-4dc5-a3a8-54af98e10c05','宿普化庵','陳郁','宋','宋诗','song-poetry','','[]','貪翫水雲鄉，來遲到夕陽。',48,'全唐诗/poet.song.195000.json','["貪翫水雲鄉，來遲到夕陽。", "艤舡依釣石，欹枕借禪床。", "衾薄疑秋老，茶多覺夜長。", "節庵湖海客，語下不尋常。"]'),
('80dd4af6-f064-4ce7-b58e-43eecc67f55f','題林月巖冷泉詩後','陳郁','宋','宋诗','song-poetry','','[]','巖裏空寒玉有聲，亭前淵靜鏡生明。',32,'全唐诗/poet.song.195000.json','["巖裏空寒玉有聲，亭前淵靜鏡生明。", "從他流入香塵去，不礙源頭徹底清。"]'),
('c594d88c-c17b-4e12-ba41-7d164124f320','讀淮陰侯傳','陳郁','宋','宋诗','song-poetry','','[]','必得真王乃鎮齊，假王雖有亦奚爲。',32,'全唐诗/poet.song.195000.json','["必得真王乃鎮齊，假王雖有亦奚爲。", "區區呂姥何能爾，自是將軍不三思。"]'),
('37a4395e-81f2-4f2d-a829-e300097b8cfa','讀唐子西漂母傳','陳郁','宋','宋诗','song-poetry','','[]','識得英雄爲理貧，果能誅項滅三秦。',32,'全唐诗/poet.song.195000.json','["識得英雄爲理貧，果能誅項滅三秦。", "老增事去方撞斗，羞見沙頭澼絖人。"]'),
('22fbcb30-29ef-4cd2-b046-2cc98430b80b','讀容齋三筆記','陳郁','宋','宋诗','song-poetry','','[]','大曆謀臣匪盡忠，時君好佛遂成風。',64,'全唐诗/poet.song.195000.json','["大曆謀臣匪盡忠，時君好佛遂成風。", "詳陳福業因元載，輕授儀同付不空。", "此日有丘猶血刃，後來無賞失邊功。", "代宗繆濫惟何甚，千古容齋直筆公。"]'),
('9751b653-a0ef-49e5-8cea-715f30e21719','送胡月山歸湖山','陳郁','宋','宋诗','song-poetry','','[]','知從清淺水邊來，標致孤高似老梅。',64,'全唐诗/poet.song.195000.json','["知從清淺水邊來，標致孤高似老梅。", "華館久同佳客住，錦囊多爲貴人開。", "消除世慮抄花譜，發越吟情戀酒杯。", "記取逋仙欠詩嗣，古祠香火莫塵埃。"]'),
('52f4ef4d-911c-460f-ade0-f7d6d1cac6ab','送竹嶼韓議事遊邊','陳郁','宋','宋诗','song-poetry','','[]','風雪垂垂歲欲除，若爲驅馬問長途。',64,'全唐诗/poet.song.195000.json','["風雪垂垂歲欲除，若爲驅馬問長途。", "才兼文武如君少，量納江湖近日無。", "吟旅筆靈花璀璨，带行刀古血模糊。", "經從渭水須留款，恐有論心老釣徒。"]'),
('34534694-56f4-4e8a-be8b-4a83cefd3e4c','壽史相','陳郁','宋','宋诗','song-poetry','','[]','崧高當日慶生申，先占韶光恰一旬。',64,'全唐诗/poet.song.195000.json','["崧高當日慶生申，先占韶光恰一旬。", "勳業已追□伊佐，文章獨造孟軻醇。", "千齡社稷資盤石，萬國黎元入化鈞。", "餘事吏將商麯糵，一時取作鳳城春。"]'),
('621436b9-0ff1-4a74-a4ab-7ca7a9d84bf9','淮西何總卿','陳郁','宋','宋诗','song-poetry','','[]','頻年增竈起邊兵，給餉誰先足萬營。',64,'全唐诗/poet.song.195000.json','["頻年增竈起邊兵，給餉誰先足萬營。", "凡有求焉皆越從，不言功者尚爲卿。", "朝家豈是無公議，督府如何不動情。", "我爲箋天天已許，且將勳業換長生。"]'),
('4408eb29-c042-4e9b-a033-ceea7e89accc','壽黄復庵','陳郁','宋','宋诗','song-poetry','','[]','移家載雪河橋住，吟過餘寒不出門。',80,'全唐诗/poet.song.195000.json','["移家載雪河橋住，吟過餘寒不出門。", "人遣奚奴傳吉語，天教詞客壽清樽。", "上林開到梨花了，次第牡丹紅欲笑。", "眉端聞說點微黄，應捧金牋承密詔。", "名隨春色滿乾坤，涪水之翁有耳孫。"]'),
('7ff382e1-caca-46b9-8095-9ed4ad5532e6','壽毛荷塘','陳郁','宋','宋诗','song-poetry','','[]','嘗於勸耕日，杯酒祝騷人。',48,'全唐诗/poet.song.195000.json','["嘗於勸耕日，杯酒祝騷人。", "年與我俱老，友惟君最仁。", "種蓮知性靜，吟草見天真。", "處世安如此，鬢毛應耐春。"]'),
('940576bb-f22e-4056-a6fb-02e187fda932','贈眼齒科林殿幹','陳郁','宋','宋诗','song-poetry','','[]','眼必延厥光，齒必全厥剛。',76,'全唐诗/poet.song.195000.json','["眼必延厥光，齒必全厥剛。", "裂眥不足貴，所貴者目瞭。", "穿齦不足畏，所畏者唇亡。", "故恃明者必察，恃剛者必傷。", "此林氏子以是語語我，我亦以是語信其醫之良，因墨之右方。"]'),
('d19f6892-5a19-4804-b41f-a2529f7215a8','贈醫士','陳郁','宋','宋诗','song-poetry','','[]','榆花着雨亂飄時，是處調虞費上池。',32,'全唐诗/poet.song.195000.json','["榆花着雨亂飄時，是處調虞費上池。", "好試平生醫國手，呼盧作五有天知。"]'),
('9299d88f-426a-4e47-867c-04a6013e8d84','贈談命','陳郁','宋','宋诗','song-poetry','','[]','術不與今同，清名亦可宗。',48,'全唐诗/poet.song.195000.json','["術不與今同，清名亦可宗。", "學雖精象數，妙亦發鴻蒙。", "政自愁傍午，胡爲說併衝。", "生來忘利祿，祗合問詩窮。"]'),
('a14b3b12-650b-4088-ab68-010db976ddb5','送詩友歸西湖','陳郁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','詩到西湖漸逼真，便當於此老吟身。',64,'全唐诗/poet.song.195000.json','["詩到西湖漸逼真，便當於此老吟身。", "舉頭莫看王侯面，失脚恐爲名利人。", "千載留芳惟好句，百年得意總微塵。", "鑱君姓字中興集，留伴梅花歲歲春。"]'),
('295900af-a727-4350-8547-e07a0cf74ef9','送友人赴鄉舉','陳郁','宋','宋诗','song-poetry','','[]','我方治地種秋芳，君亦濡毫擬擅場。',32,'全唐诗/poet.song.195000.json','["我方治地種秋芳，君亦濡毫擬擅場。", "待得君歸醉重九，捷旗如我菊花黄。"]'),
('2fd1e677-d616-4c4e-9372-4dfeb8f774e1','句  其一','陳郁','宋','宋诗','song-poetry','','[]','闢戶夜通月，掬泉朝飲星。',12,'全唐诗/poet.song.195000.json','["闢戶夜通月，掬泉朝飲星。"]'),
('5ae22923-5061-4688-913c-f7f5e84fac45','句  其二','陳郁','宋','宋诗','song-poetry','','[]','煖爆花巖日，晴眠蘚石烟。',12,'全唐诗/poet.song.195000.json','["煖爆花巖日，晴眠蘚石烟。"]'),
('6858a5a3-56b0-402b-9992-aec2f6d39d14','句  其三','陳郁','宋','宋诗','song-poetry','','[]','地曠日難晚，海寬天欲浮。',12,'全唐诗/poet.song.195000.json','["地曠日難晚，海寬天欲浮。"]'),
('78567662-cb0e-4ff3-918c-28c9ca17ac53','句  其四','陳郁','宋','宋诗','song-poetry','','[]','與子纔分手，何人更賞心。',12,'全唐诗/poet.song.195000.json','["與子纔分手，何人更賞心。"]'),
('c5f8acce-64a4-4cec-858e-9f491f18e34e','句  其五','陳郁','宋','宋诗','song-poetry','','[]','遊歸雲衲破，定起石床溫。',12,'全唐诗/poet.song.195000.json','["遊歸雲衲破，定起石床溫。"]'),
('10c57aba-ed33-46ce-bd61-313840d496d9','句  其六','陳郁','宋','宋诗','song-poetry','','[]','道至無偏黨，心何有重輕。',12,'全唐诗/poet.song.195000.json','["道至無偏黨，心何有重輕。"]'),
('27820644-5a3b-4afc-b3fe-202223e1dc20','句  其七','陳郁','宋','宋诗','song-poetry','','[]','萬事豈容人有意，一春多被雨無情。',16,'全唐诗/poet.song.195000.json','["萬事豈容人有意，一春多被雨無情。"]'),
('53a8c6fb-824f-47ff-8372-c94be059a6bb','句','王太沖','宋','宋诗','song-poetry','','[]','惟有楊花思空闊，正零落處是開時。',16,'全唐诗/poet.song.195000.json','["惟有楊花思空闊，正零落處是開時。"]'),
('d05e1df1-9bc2-46a2-b287-633107a7d794','淳祐七年丁未十一月朔蔡久軒自江東提刑歸抵家時三館諸公以風霜隨氣節河漢下文章分韻賦詩送別得隨字','王撝','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','嵯峨武夷山，中有梁棟姿。',288,'全唐诗/poet.song.195000.json','["嵯峨武夷山，中有梁棟姿。", "鳳凰鳴高崗，隠見視其時。", "孰若阿房宮，下容五丈旗。", "孰奏簫韶樂，和聲召來儀。", "才大古難用，論高人先知。", "晦翁千載人，源流有餘師。", "衣傳正大學，時吐蹇諤辭。", "國步方險艱，憂端終南齊。", "袖有濟時策，真言琅玕披。", "忠嘉許稷契，不事激與隨。", "辯論黼座側，聽納天顔怡。", "林林陛楯郎，相顧胥嘆咨。", "中有張萬福，拜賀太平基。", "正頼中流柱，障瀾使東之。", "胡爲勇於去，神龍不容覊。", "平生廉靖操，爲國張四維。", "西風送漢節，凜凜生霜威。", "皇華馳周隰，晝錦輝繡衣。", "清臺占二星，今夕躔已移。", "江右九州地，俗弊民已疲。", "高褰赤帷裳，下照及隠微。", "刑清民乃服，莠除苗始滋。", "烹鮮戒政擾，漏魚寧網稀。", "要令珥筆俗，洗心學書詩。"]'),
('69d702c9-f581-44a1-8017-a067eabe6f48','句','王撝','宋','宋诗','song-poetry','','[]','蘭臺舊家學，胡不紹箕裘。',12,'全唐诗/poet.song.195000.json','["蘭臺舊家學，胡不紹箕裘。"]'),
('dd4c6a48-619d-4df4-8cbf-8730fb34de02','隠真洞','趙汝造','宋','宋诗','song-poetry','','[]','鼎湖劍佩有遺蹤，唐室真人羽化同。',64,'全唐诗/poet.song.195000.json','["鼎湖劍佩有遺蹤，唐室真人羽化同。", "九轉藥成丹竈冷，五雲車去玉堂空。", "仙家日月蓬壺裏，塵世烟花夢寐中。", "徒有舊山流水畔，古松枝葉苦吟風。"]'),
('9dd97bc6-2f94-4196-8e82-b5f9d5d143ab','題萬壽圓覺院  其一','吳鋼','宋','宋诗','song-poetry','','[]','梵室香飄隔竹聞，壁間肆筆爛奎文。',32,'全唐诗/poet.song.195000.json','["梵室香飄隔竹聞，壁間肆筆爛奎文。", "山深翠輦經行處，猶卧從龍數點雲。"]'),
('73f2ea22-0047-4ef1-a5e7-618b34aad0e2','題萬壽圓覺院  其二','吳鋼','宋','宋诗','song-poetry','','[]','地偏境靜人無事，雨後風柔物可情。',32,'全唐诗/poet.song.195000.json','["地偏境靜人無事，雨後風柔物可情。", "山鳥定知琴意好，倚花渾不作春聲。"]'),
('5a6bcc24-9bee-4581-903b-02a30a72ee6b','題褒親崇壽寺','吳鋼','宋','宋诗','song-poetry','','[]','坳徑石䶥齖，梅枝礙竹斜。',48,'全唐诗/poet.song.195000.json','["坳徑石䶥齖，梅枝礙竹斜。", "舊封妃子墓，殘照覺王家。", "亭砌旋風葉，巖流出洞花。", "飽參塵世味，得似野僧茶。"]'),
('db5bb329-5f7e-434a-9a2d-55c1e8d9c6f0','以久字韻賦翁仲','錢穎','宋','宋诗','song-poetry','','[]','武皇騎龍朝帝后，露濕銅仙古苔繡。',115,'全唐诗/poet.song.195000.json','["武皇騎龍朝帝后，露濕銅仙古苔繡。", "景初命名翁與仲，無復衣冠仍漢舊。", "桓圭大劍高嵯峨，不動如山嚴鎮守。", "豈知屹立司馬門，九鼎暗移司馬手。", "變遷陵谷亦何易，洛陽塵埃一回首。", "因嗟寵辱非可常，世間何者爲長久。", "君不見後來荆棘埋銅駝，坐想失身橫隴畝。"]'),
('88416418-ec16-4c6d-be9f-312e9e0d1a95','再入臺','錢穎','宋','宋诗','song-poetry','','[]','紫綸飛下會稽山，衣繡歸來冠豸冠。',64,'全唐诗/poet.song.195000.json','["紫綸飛下會稽山，衣繡歸來冠豸冠。", "驄馬長鳴天路熟，棲鳥重認禁枝寒。", "人憂時世方多事，我喜朝廷看諫官。", "堯舜君民身稷契，不爲容易不爲難。"]'),
('823a5d4b-ae3a-4cef-ad23-ae3aa7cd7866','秋胡子','錢穎','宋','宋诗','song-poetry','','[]','郎恩葉薄妾冰清，郎說黄金妾不應。',32,'全唐诗/poet.song.195000.json','["郎恩葉薄妾冰清，郎說黄金妾不應。", "若使偶然通一笑，半生誰信守孤燈。"]'),
('1e895e9a-8fd8-4a1c-9b33-899a06acb818','題隠者所居','儲泳','宋','宋诗','song-poetry','','[]','盡日掩柴門，何人得見君。',48,'全唐诗/poet.song.195000.json','["盡日掩柴門，何人得見君。", "只因喧寂異，似有聖凡分。", "瀑近夜疑雨，山深晴亦雲。", "傳聞九霄翮，落羽正紛紛。"]'),
('9e760f11-963c-44a2-a1c2-a732deb5d917','秋夕懷友','儲泳','宋','宋诗','song-poetry','','[]','樓高不敢眺，愁思滿滄洲。',48,'全唐诗/poet.song.195000.json','["樓高不敢眺，愁思滿滄洲。", "有夢隔千里，無書過一秋。", "晴風吹野樹，落日照寒流。", "客裏添蕭索，何時得共游。"]'),
('925c8fc7-2754-424e-b34b-bebe68c10896','題胡琴窗方徑','儲泳','宋','宋诗','song-poetry','','[]','詩窮推不去，終有惡圓心。',48,'全唐诗/poet.song.195000.json','["詩窮推不去，終有惡圓心。", "樓倚風烟外，琴橫星斗沉。", "行看花四面，坐對竹千尋。", "却笑陶彭澤，歸來荒草深。"]'),
('949ea513-1d29-4ae2-9f61-af0f72115954','清閟軒','儲泳','宋','宋诗','song-poetry','','[]','萬竹中央住，清心自愛持。',48,'全唐诗/poet.song.195000.json','["萬竹中央住，清心自愛持。", "不除傷砌笋，慵洗宿禽枝。", "影落翻經處，聲敲入定時。", "重泥新雪壁，留待客題詩。"]'),
('454f8f45-b84d-4dcb-9e2d-17d60ff25235','送春','儲泳','宋','宋诗','song-poetry','','[]','送春歸去後，身却在天涯。',48,'全唐诗/poet.song.195000.json','["送春歸去後，身却在天涯。", "有夢忘爲客，見書如到家。", "樓空初入燕，柳暗欲藏鴉。", "故苑新桃李，閑開一度花。"]'),
('3b22e923-ea20-4847-bd14-5ba611176aa7','聞采石分司芸隠訃','儲泳','宋','宋诗','song-poetry','','[]','忽聞千里訃，涕淚已交橫。',48,'全唐诗/poet.song.195000.json','["忽聞千里訃，涕淚已交橫。", "遽奪英雄去，不教功業成。", "人疑藏六甲，天使伴長庚。", "惆悵青山夢，分明坐兩楹。"]'),
('84503dea-86ff-4186-858d-573daf13b089','小園','儲泳','宋','宋诗','song-poetry','','[]','墾葦栽花柳，園林小小成。',48,'全唐诗/poet.song.195000.json','["墾葦栽花柳，園林小小成。", "旋分黄菊本，新扁草堂名。", "池水通湖活，江風過竹清。", "不期車馬到，足自稱幽情。"]'),
('272a2ae9-87ab-401c-8971-eb33bfa1224a','亭下','儲泳','宋','宋诗','song-poetry','','[]','亭下冷泉清，松深地絕塵。',48,'全唐诗/poet.song.195000.json','["亭下冷泉清，松深地絕塵。", "細看門外樹，幾換寺中人。", "別嶂孤猿曉，幽花百鳥春。", "坐來危石上，疑是比丘身。"]'),
('ec4937ca-da00-4fab-98d8-afcf641e035c','思歸','儲泳','宋','宋诗','song-poetry','','[]','客樓高處望，獨立對斜暉。',48,'全唐诗/poet.song.195000.json','["客樓高處望，獨立對斜暉。", "負郭有田在，故山何日歸。", "秋深楊柳薄，水闊鷺鷥飛。", "風景正蕭索，何堪聞搗衣。"]'),
('4c8d7316-c8ca-438c-87b4-846ddbc59ef7','送人遊邊','儲泳','宋','宋诗','song-poetry','','[]','邊風吹鴈至，君却向邊遊。',48,'全唐诗/poet.song.195000.json','["邊風吹鴈至，君却向邊遊。", "正立功名日，去防關塞秋。", "看鵰因撚箭，調馬試呈毬。", "奏凱歸時節，應須萬戶侯。"]'),
('cb220ced-6392-4458-b68f-9c281b5bbf41','送兄潮舉','儲泳','宋','宋诗','song-poetry','','[]','老來偏惜別，此別更關情。',48,'全唐诗/poet.song.195000.json','["老來偏惜別，此別更關情。", "水陸三千里，舟車一月程。", "鴈聲鄉思遠，鸞影旅魂驚。", "楊柳彫零盡，無枝可贈行。"]'),
('c36df679-bc71-4d7f-86b0-df4fd162e4b5','寄兄玉老','儲泳','宋','宋诗','song-poetry','','[]','雷陽路迢遞，回首亦關心。',48,'全唐诗/poet.song.195000.json','["雷陽路迢遞，回首亦關心。", "重別因輕諾，遠行多近吟。", "客懷秋色早，歸夢嶺雲深。", "莫以書無益，人來惜萬金。"]'),
('ab2c352f-7f96-4254-a915-4bfb47d69ae0','淀山寺','儲泳','宋','宋诗','song-poetry','','[]','無路接塵寰，中流擁翠鬟。',48,'全唐诗/poet.song.195000.json','["無路接塵寰，中流擁翠鬟。", "望中疑有寺，游處若無山。", "過雨行雲濕，衝風釣艇還。", "龜邊舊鷗鷺，心事頗相關。"]'),
('adee8ee1-d001-4a41-b162-c062a135d031','悼古鏡果佛慧法師','儲泳','宋','宋诗','song-poetry','','[]','霜毛垂半頂，說法國王前。',48,'全唐诗/poet.song.195000.json','["霜毛垂半頂，說法國王前。", "定裏修千劫，佛中添一員。", "謚尊終後賜，真諦在時傳。", "講下諸徒弟，焚香石塔邊。"]'),
('aafd34f0-e5a3-44d0-8fa0-d283c3f06029','送陳雲崖','儲泳','宋','宋诗','song-poetry','','[]','出門即遠道，君去有誰令。',48,'全唐诗/poet.song.195000.json','["出門即遠道，君去有誰令。", "詩價侯門賤，時情客路輕。", "晚雲歸獨樹，寒雨暗荒城。", "此地還相別，誰能不動情。"]'),
('7a204287-397e-44b7-9adf-0b2811742bd9','送盧萍齋','儲泳','宋','宋诗','song-poetry','','[]','當春雁北飛，之子獨南歸。',48,'全唐诗/poet.song.195000.json','["當春雁北飛，之子獨南歸。", "寒暑本無定，去來應有機。", "柳烟迷客棹，花露濕征衣。", "明月人千里，相思消息稀。"]'),
('476f8c83-2cb7-4448-85e3-3750b01baa0b','紅藥','儲泳','宋','宋诗','song-poetry','','[]','紅藥階前半吐葩，露枝已入貴人家。',32,'全唐诗/poet.song.195000.json','["紅藥階前半吐葩，露枝已入貴人家。", "不如庭下無名草，一度春風一度花。"]'),
('6a0a7350-3101-4ded-85a9-42999429c85e','涵虛閣','儲泳','宋','宋诗','song-poetry','','[]','菊秋梅臘百花春，過眼年華醉夢身。',32,'全唐诗/poet.song.195000.json','["菊秋梅臘百花春，過眼年華醉夢身。", "今日不因登此閣，不知人世是紅塵。"]'),
('811517bd-2a59-4059-b86c-b5307bac3068','春日郊行','儲泳','宋','宋诗','song-poetry','','[]','東風吹著便成花，粧點園林賣酒家。',32,'全唐诗/poet.song.195000.json','["東風吹著便成花，粧點園林賣酒家。", "田野可栽閑草木，十分春色在桑麻。"]'),
('72da868b-677f-42af-850e-5f12bf0fc5ff','柬藏一','儲泳','宋','宋诗','song-poetry','','[]','靈竺山前滿逕苔，遊春車馬可曾來。',32,'全唐诗/poet.song.195000.json','["靈竺山前滿逕苔，遊春車馬可曾來。", "共君便欲携尊去，一樹海棠花正開。"]'),
('f70bf49f-12fd-4a42-8b94-6b3ed20a5cef','胡定齋惠墨求詩','儲泳','宋','宋诗','song-poetry','','[]','萬杵玄霜玉兔魂，刀圭煉就許平分。',32,'全唐诗/poet.song.195000.json','["萬杵玄霜玉兔魂，刀圭煉就許平分。", "流珠輕滴銀蟾露，化作催詩一片雲。"]'),
('3d2516d0-218b-4dcc-a2d5-33c7afd80aa7','春晝','儲泳','宋','宋诗','song-poetry','','[]','亭院深深春晝長，度窗蜂影去來忙。',32,'全唐诗/poet.song.195000.json','["亭院深深春晝長，度窗蜂影去來忙。", "自從野菜花開後，一月熏爐不炷香。"]'),
('e09dce0d-1241-4d35-a69a-be4754ad4b00','送人','儲泳','宋','宋诗','song-poetry','','[]','昨日含愁始送春，今朝又復送行人。',32,'全唐诗/poet.song.195000.json','["昨日含愁始送春，今朝又復送行人。", "江頭楊柳不須折，那與愁眉替得顰。"]'),
('2f80cf93-1f20-4139-aa98-f7e65f05a6ec','覺來','儲泳','宋','宋诗','song-poetry','','[]','西風吹夢過錢塘，獨上孤山叩冷香。',32,'全唐诗/poet.song.195000.json','["西風吹夢過錢塘，獨上孤山叩冷香。", "紙帳四垂燈影薄，覺來疑是月昏黄。"]'),
('aacf41a4-3b53-4c83-b06d-656d141bd013','登漣漪閣','儲泳','宋','宋诗','song-poetry','','[]','傑閣枕平川，秋光淡遠烟。',48,'全唐诗/poet.song.195000.json','["傑閣枕平川，秋光淡遠烟。", "窗開林外景，影占水中天。", "野色歸吟笛，征帆過客船。", "危欄人徙倚，縹緲十洲仙。"]'),
('9fa73f91-bc28-4189-8288-b34ba198378d','光風霽月亭','儲泳','宋','宋诗','song-poetry','','[]','一段風流出自然，中和氣候嫩凉天。',32,'全唐诗/poet.song.195000.json','["一段風流出自然，中和氣候嫩凉天。", "百年心事無人會，付與茅亭伴呂仙。"]'),
('ab2a560a-b1ff-4517-b020-4ffb716a4a84','題梅塢畫推蓬梅','儲泳','宋','宋诗','song-poetry','','[]','冰魂銷不盡，招得上南枝。',24,'全唐诗/poet.song.195000.json','["冰魂銷不盡，招得上南枝。", "依約橫斜影，紗窗月上時。"]'),
('2cd96428-b8ae-49e2-8fef-12d8eab2969a','月巖','儲泳','宋','宋诗','song-poetry','','[]','天然合成璧，落月透巖暉。',48,'全唐诗/poet.song.195000.json','["天然合成璧，落月透巖暉。", "不盡團圓影，應知晦蝕機。", "騎蟾人已去，擣藥兔忘歸。", "惟有婆娑桂，吹香度客衣。"]'),
('2abecdc5-775e-40ba-a069-4495a6e15d62','嘉定二年秋重游洞霄','胡衍','宋','宋诗','song-poetry','','[]','餘杭泉石欠幽探，浄拂衣塵入翠嵐。',64,'全唐诗/poet.song.195000.json','["餘杭泉石欠幽探，浄拂衣塵入翠嵐。", "九鎖山門雲上下，一峯天柱殿西南。", "元封舊事無人記，德壽仙游有客談。", "痛飲丹泉卧玄石，松風滿耳夢初酣。"]'),
('a0fc5cec-2866-4e28-87bf-927f90fd69b6','次許宰普惠院祈雨韵','莊夢說','宋','宋诗','song-poetry','','[]','華鯨呼客響修廊，杖履來遊薝葡堂。',64,'全唐诗/poet.song.196000.json','["華鯨呼客響修廊，杖履來遊薝葡堂。", "宰堵擎天光繚繞，遠山排闥翠昂藏。", "高僧宴坐鬚髯古，縣尹新題詩句香。", "喚雨雨來端有驗，會看行旅不齎糧。"]'),
('c9a489ec-8b28-49cf-b81a-41ded612f1b7','采藥','潘彙征','宋','宋诗','song-poetry','','[]','采藥歸來抱膝吟，烟霞情性愛山林。',32,'全唐诗/poet.song.196000.json','["采藥歸來抱膝吟，烟霞情性愛山林。", "不留蹤迹在圖畫，三十六峰何處尋。"]'),
('3390c045-bb09-4af1-97d7-21f11d8a933b','挽張都諫文肅公','郭磊卿','宋','宋诗','song-poetry','','[]','更從別駕立朝端，白簡風生憲府寒。',64,'全唐诗/poet.song.196000.json','["更從別駕立朝端，白簡風生憲府寒。", "宣室每前深夜席，木天時染秘書翰。", "琴思中散人何在，鶴返遼陽影已單。", "聖主愴然爲輟食，九原莫作淚空漫。"]'),
('010ebb1e-dc0a-41d9-b148-dabad3bac2a9','偶題','郭磊卿','宋','宋诗','song-poetry','','[]','更無清興在杯觴，不用蒲葵扇自凉。',32,'全唐诗/poet.song.196000.json','["更無清興在杯觴，不用蒲葵扇自凉。", "月色靜時山鶴叫，一庭秋景藕花香。"]'),
('d7e55378-6d2b-45a4-97a1-ce154cd54d03','柳詞','郭磊卿','宋','宋诗','song-poetry','','[]','春風垂柳絲，只向庭前住。',52,'全唐诗/poet.song.196000.json','["春風垂柳絲，只向庭前住。", "妾心逐征夫，萬里天南去。", "柳枝縱多綿，妾夢不知數。", "少年學得畫雙眉，今日看看作愁具。"]'),
('0c3c6c77-4fea-47b3-a642-981b8880603c','和戴石屏  其一','王伯大','宋','宋诗','song-poetry','','[]','赤地我民苦，寸心天我知。',48,'全唐诗/poet.song.196000.json','["赤地我民苦，寸心天我知。", "元元爭救死，凜凜强扶危。", "備具先三日，憂端彼一時。", "倏然返生意，人力豈能爲。"]'),
('4b88fd26-6524-40be-9159-c8d004530a04','和戴石屏  其二','王伯大','宋','宋诗','song-poetry','','[]','叫得神明力，挽回天地心。',48,'全唐诗/poet.song.196000.json','["叫得神明力，挽回天地心。", "連朝被甘澤，既雨積重陰。", "水滿田高下，涼生秋淺深。", "老癃幸無死，一飽慶從今。"]'),
('aed585ae-57e2-40e0-92c4-17fe66674478','贈戴石屏','王伯大','宋','宋诗','song-poetry','','[]','詩老相過鬢已星，吟魂未減昔年清。',32,'全唐诗/poet.song.196000.json','["詩老相過鬢已星，吟魂未減昔年清。", "揮毫不著塵埃語，盡把梅花巧琢成。"]'),
('d2c705c3-d65b-4789-99c5-f07787858da5','丹青閣','王伯大','宋','宋诗','song-poetry','','[]','傑閣岧嶢倚碧蒼，菊花時節此持觴。',64,'全唐诗/poet.song.196000.json','["傑閣岧嶢倚碧蒼，菊花時節此持觴。", "市聲一段隔秋水，橋影半空橫夕陽。", "挺挺霜筠排壑立，涓涓石溜引山長。", "人言絕頂多奇觀，安得閑身宿上方。"]'),
('56e4db65-abde-410b-8bbb-ce76021485ab','山中憶兄弟','項容孫','宋','宋诗','song-poetry','','[]','鴻雁不成行，飄零歲月長。',48,'全唐诗/poet.song.196000.json','["鴻雁不成行，飄零歲月長。", "一身三處夢，五夜九回腸。", "積雪欺茅屋，孤燈照錦囊。", "何當聽夜雨，却話此凄凉。"]'),
('c083595d-c896-4fb8-ab29-585bbda2d596','送楊司戶','邢凱','宋','宋诗','song-poetry','','[]','德大拙於用，數奇真可憐。',48,'全唐诗/poet.song.196000.json','["德大拙於用，數奇真可憐。", "民曹清到骨，雞肋受尊拳。", "謾失塞翁馬，終還子敬氈。", "桂林羅雋士，安穩泛紅蓮。"]'),
('976ad795-aa90-4212-8d2c-bc4407068ad8','辛卯上提刑平寇歌','邢凱','宋','宋诗','song-poetry','','[]','陳公籌策今子房，衣綉持斧征南方。',240,'全唐诗/poet.song.196000.json','["陳公籌策今子房，衣綉持斧征南方。", "親督貔貅效深入，悉孛狗鼠無留藏。", "二帥宣威既電擊，羣校賈勇爭奮揚。", "束身來降三百寨，所餘一二猶陸梁。", "平固恃險連百丈，僭擬官號熊與張。", "一朝駢首俱就縛，是謂擒賊先擒王。", "捷書夜至連清晝，不聞傳箭赤白囊。", "駸駸良民皆安堵，憧憧道路多行商。", "妖氛頓掃賣刀劍，祥風初扇催耕桑。", "紹定四年調玉燭，薰蒸六合爲金穰。", "第功行封先指授，凌青遡紫將翱翔。", "元戎煌煌賜紫軸，裨將一一露龍光。", "振旅歸來神螺岡，笳鼓競飛聲洋洋。", "櫜弓載戢綠沈鎗，旄頭星滅漢道昌。", "雅宜飲至滿浮觴，細柳烟籠春晝長。"]'),
('2d72df4f-7b0f-4cdb-ad8e-f7586cd79468','上丞相平淮頌','邢凱','宋','宋诗','song-poetry','','[]','皇矣聖宋，立國以仁。',240,'全唐诗/poet.song.196000.json','["皇矣聖宋，立國以仁。", "兼愛南北，爰暨介鱗。", "蠢茲逆全，假義倈臣。", "給以餽餫，列之簪紳。", "鷹飽別敭，浸無忌憚。", "邊臣戕賊，居民塗炭。", "據我鹽城，喻口植幹。", "繼逼海陵，恣爲泮奐。", "璽書飛下，皇威赫然。", "聲罪致討，忿激普天。", "許之節鋮，副以金錢。", "奮忠效命，誰不爭先。", "粵有世臣，虜使元帥。", "羅致英才，虓將雲會。", "賈勇摧鋒，前無堅對。", "逆全授首，維陽城外。", "昔平淮蔡，惟斷成功。", "至平澤潞，伐謀羣雄。", "聖君賢相，視昔則同。", "山陽腥膻，一洗而空。", "鉅姦伏誅，殊方仰德。", "鯨波不驚，狼烟永息。", "男耕女桑，四民安職。", "玉燭既調，金穰可必。"]'),
('4865d7ba-f30b-421e-beb6-b33649ad8602','菘圃','豐翔','宋','宋诗','song-poetry','','[]','林塘草樹接江干，一日三回涉圃看。',32,'全唐诗/poet.song.196000.json','["林塘草樹接江干，一日三回涉圃看。", "柴戶反關生事了，晚菘種盡雨漫漫。"]'),
('d87aebc5-0fe5-4b79-86ba-dde0060582d1','句','朱晉','宋','宋诗','song-poetry','','[]','冰玉詞新吐，塵埃氣不留。',12,'全唐诗/poet.song.196000.json','["冰玉詞新吐，塵埃氣不留。"]'),
('89f537eb-370c-45eb-b1c6-dc6721a8fc06','題會江驛','徐清叟','宋','宋诗','song-poetry','','[]','高閣盈千尺，征人借一棲。',48,'全唐诗/poet.song.196000.json','["高閣盈千尺，征人借一棲。", "水連天上下，山會浙東西。", "炊甑榮枯幻，浮雲出處齊。", "感時心欲醉，風雨更凄迷。"]');
